#[derive(Debug)]
pub struct Vm {
    config: VmConfig,
    heap: Heap,
    api_protections: ApiProtectionRegistry,
    entry: VmEntryState,
    #[allow(dead_code)]
    call_frame_storage: JscCallFrameStorage,
    #[allow(dead_code)]
    entry_frame_storage: JscEntryFrameStorage,
    exceptions: ExceptionState,
    structures: RuntimeStructures,
    caches: RuntimeCaches,
    globals: GlobalRuntimeState,
    services: VmServices,
    execution: ExecutionContextStack,
    registers: RegisterFile,
    interpreter_root_scope: InterpreterRootSyncScope,
    active_dispatch_budget: Option<DispatchBudget>,
    gc_execution: VmGcExecutionState,
    tiering: VmTieringIntegration,
    generated_call_link_candidate_table_cache:
        RefCell<Vec<GeneratedCallLinkCandidateTableCacheEntry>>,
    generated_property_sidecar_projection_cache:
        RefCell<Vec<GeneratedPropertySidecarProjectionCacheEntry>>,
    generated_direct_call_hot_slots: RefCell<Vec<GeneratedDirectCallHotSlot>>,
    baseline_platform_executable_residencies: Vec<ExecutableMemoryPlatformResidency>,
    p6_x86_64_callable_retained_return_tables: Vec<P6X86_64CallableRetainedReturnTable>,
    code_blocks: CodeBlockRegistry,
    executables: ExecutableRegistry,
    generated_direct_call_deferred_rooting_depth: u32,
    next_source_bytecompiler_session_id: u64,
    next_p15_auto_baseline_native_entry_id: u32,
    next_p15_auto_baseline_generated_code_id: u32,
    // Batch 1 call-dispatch measurement: cumulative count of how many times the
    // five skippable IC/tiering safepoint passes were actually INVOKED (a single
    // increment per prologue/epilogue/resume safepoint that took the full
    // branch, i.e. when owner_has_any_safepoint_plan_work was true OR the drain
    // returned pending work). Lets a probe observe per-call pass invocations drop
    // to ~0 on a hot call path with no registered plans. Plain counter (one
    // usize) so the release octane_probe can read it; not behind cfg(test).
    safepoint_pass_full_branch_invocations: u64,
    // Batch 2 call-dispatch steady-state memo. Owner-keyed cache of the
    // (fingerprint, plan_generation) under which the five idempotent IC/tiering
    // safepoint passes last ran to completion for that owner. In
    // `run_ic_tiering_safepoint`, an owner that HAS plans but whose CodeBlock
    // fingerprint AND the global plan_generation both still match its recorded
    // memo is in steady state, so re-running the (post-hoist) idempotent passes
    // is observably a no-op and is skipped. A bytecode change bumps the
    // fingerprint; any six-table plan mutation (for any owner) bumps
    // plan_generation; either mismatch forces the full path next safepoint. This
    // is the Rust analogue of C++ JSC materializing ICs/call links per-LINK
    // (LLIntSlowPaths.cpp setUpCall/linkFor), not once per call: once a link is
    // materialized and nothing has changed, the per-call work is gone.
    ic_tiering_safepoint_memo: HashMap<CodeBlockId, (BaselineBytecodeSnapshotFingerprint, u64)>,
    #[cfg(test)]
    no_gc_execution_depth_observations_for_test: Vec<VmNoGcExecutionDepthObservationForTest>,
}

