fn function_value_return_transform_destination(
    transform: FunctionValueReturnTransform,
) -> Option<VirtualRegister> {
    match transform {
        FunctionValueReturnTransform::WriteValue { destination }
        | FunctionValueReturnTransform::WriteTruthy { destination }
        | FunctionValueReturnTransform::WriteConstant { destination, .. } => Some(destination),
        FunctionValueReturnTransform::ContinueIgnoringValue => None,
    }
}

struct RuntimeHelperRootMapDispatchHost<'host, H> {
    inner: &'host mut H,
    root_slots: Vec<GeneratedRuntimeHelperRootSlot>,
}

impl<'host, H> RuntimeHelperRootMapDispatchHost<'host, H> {
    fn new(inner: &'host mut H, root_slots: Vec<GeneratedRuntimeHelperRootSlot>) -> Self {
        Self { inner, root_slots }
    }

    fn descriptor_is_allowed(
        &self,
        descriptor: &crate::interpreter::RegisterRootDescriptor,
    ) -> bool {
        self.root_slots
            .iter()
            .any(|slot| slot.frame == descriptor.frame && slot.slot == descriptor.slot)
    }
}

impl<H: DispatchHost> DispatchHost for RuntimeHelperRootMapDispatchHost<'_, H> {
    fn targeted_register_roots(
        &mut self,
        heap: &mut Heap,
        snapshot: &ExecutionRootSnapshot,
    ) -> Result<Vec<TargetedRootRecord>, ExecutionError> {
        let filtered_register_roots = snapshot
            .register_roots
            .iter()
            .copied()
            .filter(|descriptor| self.descriptor_is_allowed(descriptor))
            .collect::<Vec<_>>();
        if filtered_register_roots.len() != self.root_slots.len() {
            return Err(ExecutionError::RegisterOutOfBounds);
        }

        let filtered_snapshot = ExecutionRootSnapshot {
            frame_roots: Vec::new(),
            register_roots: filtered_register_roots,
        };
        let allowed_roots = filtered_snapshot
            .register_roots
            .iter()
            .map(|descriptor| descriptor.root)
            .collect::<Vec<_>>();
        let targeted = self
            .inner
            .targeted_register_roots(heap, &filtered_snapshot)?;

        for record in &targeted {
            if !allowed_roots.contains(&record.root) {
                return Err(ExecutionError::BaselineGeneratedExecutionRejected);
            }
        }

        for descriptor in &filtered_snapshot.register_roots {
            let Some(payload) = descriptor.cell_payload else {
                continue;
            };
            let target =
                heap.cell_for_payload(payload)
                    .ok_or(ExecutionError::UnresolvedRegisterRoot {
                        slot: descriptor.slot,
                    })?;
            match targeted
                .iter()
                .find(|record| record.root == descriptor.root)
            {
                Some(record) if record.target == target => {}
                _ => return Err(ExecutionError::BaselineGeneratedExecutionRejected),
            }
        }

        Ok(targeted
            .into_iter()
            .filter(|record| allowed_roots.contains(&record.root))
            .collect())
    }

    fn finalize_function_value_property_observation(
        &mut self,
        heap: &mut Heap,
        observation: crate::interpreter::FunctionValuePropertyObservation,
        outcome: FunctionValuePropertyOperationOutcome,
    ) -> Result<(), ExecutionError> {
        self.inner
            .finalize_function_value_property_observation(heap, observation, outcome)
    }

    fn function_value_property_return_truthy(&mut self, value: RuntimeValue) -> bool {
        self.inner.function_value_property_return_truthy(value)
    }

    fn dispatch_instruction(
        &mut self,
        state: &mut DispatchState<'_>,
        instruction: DispatchInstruction<'_>,
    ) -> DispatchOutcome {
        self.inner.dispatch_instruction(state, instruction)
    }
}

// C++ JSC's LLInt handles op_loop_hint by running checkSwitchToJITForLoop and
// calling _llint_loop_osr, which returns a baseline entry target for the current
// LoopHint bytecode index. Rust keeps that boundary in a host wrapper so the
// interpreter can finish targeted-root cleanup before the VM borrows itself to
// gate/materialize and enter baseline code.
struct VmLoopHintDispatchHost<'host, H> {
    inner: &'host mut H,
    tiering: &'host mut tiering::VmTieringIntegration,
    owner: CodeBlockId,
    policy: TieringPolicy,
}

impl<'host, H> VmLoopHintDispatchHost<'host, H> {
    fn new(
        inner: &'host mut H,
        tiering: &'host mut tiering::VmTieringIntegration,
        owner: CodeBlockId,
        policy: TieringPolicy,
    ) -> Self {
        Self {
            inner,
            tiering,
            owner,
            policy,
        }
    }

    const fn observes_loop_hints(&self) -> bool {
        matches!(
            self.policy,
            TieringPolicy::BaselineAllowed | TieringPolicy::OptimizingAllowed
        )
    }
}

