    fn generated_direct_call_hot_slot_for_handoff(
        &self,
        handoff: &BaselineGeneratedJsCallHandoff,
        direct: &BaselineGeneratedJsDirectCall,
    ) -> Option<GeneratedDirectCallHotSlot> {
        let epoch = self.generated_call_link_projection_epoch();
        let mut slots = self.generated_direct_call_hot_slots.borrow_mut();
        slots.retain(|slot| slot.projection_epoch == epoch);
        slots
            .iter()
            .find(|slot| {
                slot.owner == handoff.resume.owner
                    && slot.opcode == handoff.resume.opcode
                    && slot.bytecode_index == handoff.resume.bytecode_index
                    && slot.candidate == direct.candidate
                    && slot.authorization == direct.authorization
                    && slot.callee_object == direct.callee_object
                    && slot.argument_count_including_this == direct.argument_count_including_this
            })
            .cloned()
    }

    fn install_generated_direct_call_hot_slot(
        &self,
        owner: CodeBlockId,
        opcode: CoreOpcode,
        bytecode_index: BytecodeIndex,
        direct: &BaselineGeneratedJsDirectCall,
        preferred_route: VmGeneratedDirectCallTransactionRoute,
    ) {
        if !matches!(opcode, CoreOpcode::Call | CoreOpcode::CallWithThis) {
            return;
        }
        if !matches!(
            preferred_route,
            VmGeneratedDirectCallTransactionRoute::GeneratedEntry
                | VmGeneratedDirectCallTransactionRoute::NativeEntry
        ) {
            return;
        }
        let epoch = self.generated_call_link_projection_epoch();
        let slot = GeneratedDirectCallHotSlot {
            owner,
            opcode,
            bytecode_index,
            projection_epoch: epoch,
            candidate: direct.candidate.clone(),
            authorization: direct.authorization,
            callee_object: direct.callee_object,
            argument_count_including_this: direct.argument_count_including_this,
            preferred_route,
            rootless_generated_entry_proof: None,
        };
        let mut slots = self.generated_direct_call_hot_slots.borrow_mut();
        slots.retain(|slot| slot.projection_epoch == epoch);
        if let Some(existing) = slots.iter_mut().find(|existing| {
            existing.owner == slot.owner
                && existing.opcode == slot.opcode
                && existing.bytecode_index == slot.bytecode_index
                && existing.callee_object == slot.callee_object
                && existing.argument_count_including_this == slot.argument_count_including_this
        }) {
            *existing = slot;
            return;
        }
        if slots.len() >= GENERATED_DIRECT_CALL_HOT_SLOT_RETAIN_LIMIT {
            slots.remove(0);
        }
        slots.push(slot);
    }

    fn remember_generated_direct_call_hot_slot_rootless_generated_entry_proof(
        &self,
        validation: &GeneratedJsDirectCallValidation,
        artifact_id: JitCodeId,
        bytecode_snapshot: BaselineBytecodeSnapshotFingerprint,
        proof: GeneratedDirectCallRootlessGeneratedEntryProof,
    ) {
        if !validation.hot_slot_hit
            || validation.preferred_route
                != Some(VmGeneratedDirectCallTransactionRoute::GeneratedEntry)
        {
            return;
        }

        let epoch = self.generated_call_link_projection_epoch();
        let proof_cache = GeneratedDirectCallRootlessProofCache {
            epoch: self.generated_direct_call_rootless_proof_epoch(),
            target_code_block_id: validation.target_code_block_id,
            artifact_id,
            bytecode_snapshot,
            proof,
        };
        let mut slots = self.generated_direct_call_hot_slots.borrow_mut();
        slots.retain(|slot| slot.projection_epoch == epoch);
        if let Some(slot) = slots.iter_mut().find(|slot| {
            slot.owner == validation.owner
                && slot.opcode == validation.opcode
                && slot.bytecode_index == validation.bytecode_index
                && slot.candidate == validation.direct_call.candidate
                && slot.authorization == validation.direct_call.authorization
                && slot.callee_object == validation.direct_call.callee_object
                && slot.argument_count_including_this
                    == validation.direct_call.argument_count_including_this
                && slot.preferred_route == VmGeneratedDirectCallTransactionRoute::GeneratedEntry
        }) {
            slot.rootless_generated_entry_proof = Some(proof_cache);
        }
    }

    fn generated_direct_call_hot_slot_projections_for_owner(
        &self,
        owner: CodeBlockId,
    ) -> Vec<BaselineGeneratedJsDirectCallHotSlot> {
        let epoch = self.generated_call_link_projection_epoch();
        let slots = self.generated_direct_call_hot_slots.borrow();
        slots
            .iter()
            .filter(|slot| slot.owner == owner)
            .filter(|slot| slot.projection_epoch == epoch)
            .map(|slot| BaselineGeneratedJsDirectCallHotSlot {
                candidate: slot.candidate.clone(),
                authorization: slot.authorization,
                callee_object: slot.callee_object,
                argument_count_including_this: slot.argument_count_including_this,
            })
            .collect()
    }

