    #[allow(dead_code)]
    pub(crate) fn finalize_completed_collection(
        &mut self,
        kind: crate::gc::CollectionKind,
    ) -> VmCollectionCompletionRecord {
        let heap_phase_before = self.heap.phase();
        self.heap.leave_phase();
        let property_load_megamorphic_cache_aging = self
            .tiering
            .record_property_load_megamorphic_cache_collection_completion(kind);
        VmCollectionCompletionRecord {
            kind,
            heap_phase_before,
            heap_phase_after: self.heap.phase(),
            property_load_megamorphic_cache_aging,
        }
    }

