    #[allow(dead_code)]
    pub(crate) fn materialize_baseline_executable_artifact(
        &mut self,
        owner: CodeBlockId,
        artifact: &JitCodeArtifact,
        link_finalization: &LinkBufferFinalizationRecord,
        executable_residency: &ExecutableMemoryResidencyRecord,
    ) -> BaselineExecutableMaterializationRecord {
        let bytecode_snapshot = self.baseline_materialization_bytecode_snapshot(owner);

        let request =
            BaselineExecutableMaterializationRequest::from_artifact_with_link_finalization_and_residency(
                owner,
                artifact,
                bytecode_snapshot,
                BaselineExecutableMaterializationAuthority::VmMainThread,
                link_finalization,
                executable_residency,
            );
        self.tiering
            .record_baseline_executable_materialization(request)
    }

    #[allow(dead_code)]
    pub(crate) fn materialize_baseline_platform_executable_artifact(
        &mut self,
        owner: CodeBlockId,
        artifact: &JitCodeArtifact,
        link_finalization: &LinkBufferFinalizationRecord,
        linked_bytes: &[u8],
    ) -> Result<BaselineExecutableMaterializationRecord, ExecutableMemoryPlatformResidencyError>
    {
        let platform_residency = materialize_platform_executable_memory_residency(
            ExecutableMemoryPlatformResidencyRequest::new(
                self.next_platform_residency_first_ordinal(),
                link_finalization,
                linked_bytes,
            ),
        )?;
        let materialization = self.materialize_baseline_executable_artifact(
            owner,
            artifact,
            link_finalization,
            &platform_residency.residency,
        );
        if matches!(
            materialization.outcome,
            BaselineExecutableMaterializationOutcome::Accepted
        ) {
            self.baseline_platform_executable_residencies
                .push(platform_residency);
        }

        Ok(materialization)
    }

    fn baseline_materialization_bytecode_snapshot(
        &self,
        owner: CodeBlockId,
    ) -> Option<BaselineBytecodeSnapshotFingerprint> {
        if self.code_block_owner_is_live(owner) {
            self.code_blocks.get(owner).and_then(|record| {
                BaselineBytecodeEligibilityProof::fingerprint_code_block_snapshot(
                    record.code_block(),
                )
                .ok()
            })
        } else {
            None
        }
    }

    fn next_platform_residency_first_ordinal(&self) -> ExecutableMemoryOperationOrdinal {
        const PLATFORM_RESIDENCY_OPERATION_COUNT: u64 = 5;
        ExecutableMemoryOperationOrdinal(
            (self.baseline_platform_executable_residencies.len() as u64)
                .saturating_mul(PLATFORM_RESIDENCY_OPERATION_COUNT)
                .saturating_add(1),
        )
    }

    fn next_p15_auto_baseline_native_entry_install_request(
        &mut self,
        owner: CodeBlockId,
    ) -> P6X86_64SemanticBaselineNativeEntryInstallRequest {
        let next = if self.next_p15_auto_baseline_native_entry_id
            < P15_AUTO_BASELINE_NATIVE_ENTRY_ID_BASE
        {
            P15_AUTO_BASELINE_NATIVE_ENTRY_ID_BASE
        } else {
            self.next_p15_auto_baseline_native_entry_id
                .checked_add(1)
                .filter(|id| *id >= P15_AUTO_BASELINE_NATIVE_ENTRY_ID_BASE)
                .unwrap_or(P15_AUTO_BASELINE_NATIVE_ENTRY_ID_BASE)
        };
        self.next_p15_auto_baseline_native_entry_id = next;
        P6X86_64SemanticBaselineNativeEntryInstallRequest {
            owner,
            code_id: JitCodeId(P15_AUTO_BASELINE_NATIVE_CODE_ID_BASE + u64::from(next)),
            native_code: NativeCodeId(next),
            allocation: ExecutableAllocationId(
                P15_AUTO_BASELINE_NATIVE_ALLOCATION_ID_BASE + u64::from(next),
            ),
            slot: JitCodeSlot(next),
        }
    }

    fn next_p15_auto_baseline_generated_code_artifact_ids(
        &mut self,
    ) -> (JitCodeId, BaselineGeneratedCodeBodyId) {
        let next = if self.next_p15_auto_baseline_generated_code_id
            < P15_AUTO_BASELINE_NATIVE_ENTRY_ID_BASE
        {
            P15_AUTO_BASELINE_NATIVE_ENTRY_ID_BASE
        } else {
            self.next_p15_auto_baseline_generated_code_id
                .checked_add(1)
                .filter(|id| *id >= P15_AUTO_BASELINE_NATIVE_ENTRY_ID_BASE)
                .unwrap_or(P15_AUTO_BASELINE_NATIVE_ENTRY_ID_BASE)
        };
        self.next_p15_auto_baseline_generated_code_id = next;
        (
            JitCodeId(P15_AUTO_BASELINE_GENERATED_CODE_ID_BASE + u64::from(next)),
            BaselineGeneratedCodeBodyId(P15_AUTO_BASELINE_GENERATED_BODY_ID_BASE + u64::from(next)),
        )
    }

    fn selected_entry_plan_p15_auto_baseline_install_mode(
        &self,
        owner: CodeBlockId,
        code_block: &CodeBlock,
        selection: &TierEntryPlanSelection,
        gate: Option<&BaselineEntryGateRecord>,
    ) -> Option<P15AutoBaselineInstallMode> {
        if !matches!(
            selection.request.policy,
            TieringPolicy::BaselineAllowed | TieringPolicy::OptimizingAllowed
        ) {
            return None;
        }

        let Some(plan) = selection.selected_plan else {
            return None;
        };
        if plan.kind != TierPlanKind::BaselineFromBytecode || plan.to_tier != JitType::Baseline {
            return None;
        }

        match gate {
            Some(gate) if gate.outcome == BaselineEntryGateOutcome::MissingArtifact => {
                Some(P15AutoBaselineInstallMode::MissingEntryArtifact)
            }
            Some(gate)
                if gate.outcome
                    == BaselineEntryGateOutcome::NativeEntryReadyButExecutionDisabled
                    && gate.generated_artifact.is_none()
                    && self.p15_disabled_native_generated_install_should_retry(owner) =>
            {
                // C++ JSC has one architecture-native BaselineJITCode entry on
                // the CodeBlock once LLInt OSR/JIT compile succeeds. Rust can
                // also record non-callable x86_64 semantic bytes on arm64 for
                // proof/audit purposes; that disabled native artifact must not
                // block the portable generated baseline body from becoming the
                // executable residency for this owner.
                Some(P15AutoBaselineInstallMode::DisabledNativeEntryArtifact)
            }
            Some(gate)
                if gate.outcome == BaselineEntryGateOutcome::Eligible
                    && gate.generated_artifact.is_some()
                    && gate.native_artifact.is_none()
                    && self.p15_supplemental_native_install_should_retry_generated_owner(owner)
                    && Self::p15_code_block_has_generated_owner_call_continuation(
                        owner, code_block,
                    ) =>
            {
                Some(P15AutoBaselineInstallMode::SupplementalNativeForGeneratedOwner)
            }
            _ => None,
        }
    }

    fn p15_supplemental_native_install_should_retry_generated_owner(
        &self,
        owner: CodeBlockId,
    ) -> bool {
        !self
            .tiering
            .baseline_entry_auto_materializations()
            .iter()
            .rev()
            .any(|record| {
                record.owner == owner
                    && record.generated.is_none()
                    && matches!(
                        record.native,
                        BaselineEntryAutoNativeMaterializationOutcome::Failed {
                            generated_fallback_allowed: false,
                            ..
                        }
                    )
            })
    }

    fn p15_disabled_native_generated_install_should_retry(&self, owner: CodeBlockId) -> bool {
        !self
            .tiering
            .baseline_entry_auto_materializations()
            .iter()
            .rev()
            .any(|record| {
                record.owner == owner
                    && record.native
                        == BaselineEntryAutoNativeMaterializationOutcome::SkippedDisabledNativeEntry
                    && !matches!(
                        record.generated,
                        Some(BaselineEntryAutoGeneratedMaterializationOutcome::Installed)
                    )
            })
    }

    fn p15_host_blocked_native_generated_install_should_retry(&self, owner: CodeBlockId) -> bool {
        !self
            .tiering
            .baseline_entry_auto_materializations()
            .iter()
            .rev()
            .any(|record| {
                record.owner == owner
                    && record.native
                        == BaselineEntryAutoNativeMaterializationOutcome::SkippedHostBlockedX86_64NativeEntry
                    && !matches!(
                        record.generated,
                        Some(BaselineEntryAutoGeneratedMaterializationOutcome::Installed)
                    )
            })
    }

    fn p15_code_block_has_generated_owner_call_continuation(
        owner: CodeBlockId,
        code_block: &CodeBlock,
    ) -> bool {
        let Some(owner_map) =
            derive_baseline_generated_owner_continuation_map_from_code_block(code_block, owner)
                .ok()
                .and_then(|derivation| derivation.metadata)
        else {
            return false;
        };

        (0..owner_map.call_site_count()).any(|index| {
            owner_map.call_site_at(index).is_some_and(|site| {
                site.owner == owner
                    && site.kind == BaselineGeneratedOwnerContinuationKind::Call
                    && matches!(site.opcode, CoreOpcode::Call | CoreOpcode::CallWithThis)
            })
        })
    }

    fn selected_entry_code_block_matches_registered_code_block(
        &self,
        owner: CodeBlockId,
        code_block: &CodeBlock,
    ) -> bool {
        let Some(registered) = self.code_blocks.get(owner) else {
            return false;
        };
        let Ok(selected_snapshot) =
            BaselineBytecodeEligibilityProof::fingerprint_code_block_snapshot(code_block)
        else {
            return false;
        };
        let Ok(registered_snapshot) =
            BaselineBytecodeEligibilityProof::fingerprint_code_block_snapshot(
                registered.code_block(),
            )
        else {
            return false;
        };
        selected_snapshot == registered_snapshot
    }

    fn p15_auto_native_install_failure_reason(
        error: &P6X86_64SemanticBaselineNativeEntryInstallError,
    ) -> BaselineEntryAutoNativeMaterializationFailure {
        match error {
            P6X86_64SemanticBaselineNativeEntryInstallError::CodeBlockOwnerNotLive { .. } => {
                BaselineEntryAutoNativeMaterializationFailure::CodeBlockOwnerNotLive
            }
            P6X86_64SemanticBaselineNativeEntryInstallError::CodeBlockNotRegistered { .. } => {
                BaselineEntryAutoNativeMaterializationFailure::CodeBlockNotRegistered
            }
            P6X86_64SemanticBaselineNativeEntryInstallError::EligibilityProof { .. } => {
                BaselineEntryAutoNativeMaterializationFailure::EligibilityProof
            }
            P6X86_64SemanticBaselineNativeEntryInstallError::Lowering { .. } => {
                BaselineEntryAutoNativeMaterializationFailure::Lowering
            }
            P6X86_64SemanticBaselineNativeEntryInstallError::BackendContract { .. } => {
                BaselineEntryAutoNativeMaterializationFailure::BackendContract
            }
            P6X86_64SemanticBaselineNativeEntryInstallError::InstructionSelection { .. } => {
                BaselineEntryAutoNativeMaterializationFailure::InstructionSelection
            }
            P6X86_64SemanticBaselineNativeEntryInstallError::SemanticByteEmission { .. } => {
                BaselineEntryAutoNativeMaterializationFailure::SemanticByteEmission
            }
            P6X86_64SemanticBaselineNativeEntryInstallError::OwnerContinuationMap { .. } => {
                BaselineEntryAutoNativeMaterializationFailure::OwnerContinuationMap
            }
            P6X86_64SemanticBaselineNativeEntryInstallError::OwnerContinuationNativeBinding {
                ..
            } => BaselineEntryAutoNativeMaterializationFailure::OwnerContinuationNativeBinding,
            P6X86_64SemanticBaselineNativeEntryInstallError::CurrentCodeBlockSnapshotInvalid {
                ..
            } => BaselineEntryAutoNativeMaterializationFailure::CurrentCodeBlockSnapshotInvalid,
            P6X86_64SemanticBaselineNativeEntryInstallError::CurrentCodeBlockSnapshotMismatch {
                ..
            } => BaselineEntryAutoNativeMaterializationFailure::CurrentCodeBlockSnapshotMismatch,
            P6X86_64SemanticBaselineNativeEntryInstallError::ArtifactInvalid { .. } => {
                BaselineEntryAutoNativeMaterializationFailure::ArtifactInvalid
            }
            P6X86_64SemanticBaselineNativeEntryInstallError::MachineCodeEmission { .. } => {
                BaselineEntryAutoNativeMaterializationFailure::MachineCodeEmission
            }
            P6X86_64SemanticBaselineNativeEntryInstallError::LinkBufferLayout { .. } => {
                BaselineEntryAutoNativeMaterializationFailure::LinkBufferLayout
            }
            P6X86_64SemanticBaselineNativeEntryInstallError::LinkCopyRejected { .. } => {
                BaselineEntryAutoNativeMaterializationFailure::LinkCopyRejected
            }
            P6X86_64SemanticBaselineNativeEntryInstallError::LinkFinalizationRejected {
                ..
            } => BaselineEntryAutoNativeMaterializationFailure::LinkFinalizationRejected,
            P6X86_64SemanticBaselineNativeEntryInstallError::LinkFinalizationByteEvidence {
                ..
            } => BaselineEntryAutoNativeMaterializationFailure::LinkFinalizationByteEvidence,
            P6X86_64SemanticBaselineNativeEntryInstallError::PlatformResidency { .. } => {
                BaselineEntryAutoNativeMaterializationFailure::PlatformResidency
            }
            P6X86_64SemanticBaselineNativeEntryInstallError::MaterializationRejected { .. } => {
                BaselineEntryAutoNativeMaterializationFailure::MaterializationRejected
            }
            P6X86_64SemanticBaselineNativeEntryInstallError::PlatformResidencyStorageMissing => {
                BaselineEntryAutoNativeMaterializationFailure::PlatformResidencyStorageMissing
            }
            P6X86_64SemanticBaselineNativeEntryInstallError::InstallRejected { .. } => {
                BaselineEntryAutoNativeMaterializationFailure::InstallRejected
            }
            P6X86_64SemanticBaselineNativeEntryInstallError::DisabledReadinessMissing {
                ..
            } => BaselineEntryAutoNativeMaterializationFailure::DisabledReadinessMissing,
            P6X86_64SemanticBaselineNativeEntryInstallError::DisabledReadinessRejected {
                ..
            } => BaselineEntryAutoNativeMaterializationFailure::DisabledReadinessRejected,
            P6X86_64SemanticBaselineNativeEntryInstallError::DisabledReadinessCallableAuthority {
                ..
            } => BaselineEntryAutoNativeMaterializationFailure::DisabledReadinessCallableAuthority,
            P6X86_64SemanticBaselineNativeEntryInstallError::EnabledReadinessRejected {
                ..
            } => BaselineEntryAutoNativeMaterializationFailure::EnabledReadinessRejected,
            P6X86_64SemanticBaselineNativeEntryInstallError::EnabledReadinessCallableAuthority {
                ..
            } => BaselineEntryAutoNativeMaterializationFailure::EnabledReadinessCallableAuthority,
            P6X86_64SemanticBaselineNativeEntryInstallError::EmissionProvenance { .. } => {
                BaselineEntryAutoNativeMaterializationFailure::EmissionProvenance
            }
        }
    }

    fn p15_auto_native_install_failure_detail(
        error: &P6X86_64SemanticBaselineNativeEntryInstallError,
    ) -> Option<BaselineEntryAutoNativeMaterializationDetail> {
        match error {
            P6X86_64SemanticBaselineNativeEntryInstallError::Lowering { error } => {
                Some(BaselineEntryAutoNativeMaterializationDetail::Lowering(
                    BaselineNativeLoweringFailureDetail::from_lowering_error(error),
                ))
            }
            P6X86_64SemanticBaselineNativeEntryInstallError::BackendContract { error } => {
                // Rust-only diagnostic scaffolding: C++ JSC's linkFor()/entrypointFor()
                // observes prepared, finalized JIT code, while this incomplete Rust backend can
                // reject a generated native contract before materialization. Keep the collapsed
                // failure reason stable and expose the contract detail for parity triage only.
                // Oversized-file exception: this narrow mapper belongs beside the existing
                // auto-materialization telemetry until the VM/tiering extraction batch owns it.
                Some(BaselineEntryAutoNativeMaterializationDetail::BackendContract(
                    BaselineNativeBackendContractFailureDetail::from_backend_contract_error(error),
                ))
            }
            P6X86_64SemanticBaselineNativeEntryInstallError::SemanticByteEmission { error } => {
                Some(
                    BaselineEntryAutoNativeMaterializationDetail::SemanticByteEmission(
                        BaselineNativeSemanticByteEmissionFailureDetail::from_semantic_byte_emission_error(error),
                    ),
                )
            }
            _ => None,
        }
    }

    fn p15_arm64_return_seed_backend_contract_allows_x86_semantic_fallback(
        error: &P6X86_64BaselineBackendContractError,
    ) -> bool {
        matches!(
            error,
            P6X86_64BaselineBackendContractError::UnsupportedOpcodeSubset {
                emitter: BaselineMachineCodeEmitterKind::P6Arm64NoCallNoHeapReturnSeedSubset,
                expected: BaselineSupportedOpcodeSubset::P6ConstantsMovesReturnInt32Arithmetic,
                ..
            }
        )
    }

    fn emit_p6_x86_64_callable_semantic_from_lowering_plan(
        plan: &P6X86_64BaselineLoweringPlan,
        owner_continuation_map: Option<&BaselineGeneratedOwnerContinuationMapMetadata>,
    ) -> Result<
        P6X86_64BaselineSemanticByteEmissionResult,
        P6X86_64SemanticBaselineNativeEntryInstallError,
    > {
        // C++ JSC's linkFor()/prepareForExecution() prepares the callee and then
        // entrypointFor() publishes the current platform entry. This x86_64 semantic
        // path is the native callable path on x86_64 and the fallback artifact path for
        // Rust's return-seed-only ARM64 callable backend until the full ARM64 backend is
        // ported.
        // Oversized-file exception: this narrow policy helper stays beside the current
        // VM install path until the JSC-mapped backend extraction owns both branches.
        let backend_contract =
            record_p6_x86_64_baseline_backend_contract_from_plan(plan).map_err(|error| {
                P6X86_64SemanticBaselineNativeEntryInstallError::BackendContract { error }
            })?;
        let selection =
            select_p6_x86_64_baseline_instructions(&backend_contract).map_err(|error| {
                P6X86_64SemanticBaselineNativeEntryInstallError::InstructionSelection { error }
            })?;
        emit_p6_x86_64_baseline_callable_semantic_bytes_with_owner_continuation_map(
            backend_contract,
            selection,
            owner_continuation_map,
        )
        .map_err(|error| {
            P6X86_64SemanticBaselineNativeEntryInstallError::SemanticByteEmission { error }
        })
    }

    fn p15_native_auto_install_failure_allows_generated_fallback(
        error: &P6X86_64SemanticBaselineNativeEntryInstallError,
    ) -> bool {
        matches!(
            error,
            P6X86_64SemanticBaselineNativeEntryInstallError::EligibilityProof { .. }
                | P6X86_64SemanticBaselineNativeEntryInstallError::Lowering { .. }
                | P6X86_64SemanticBaselineNativeEntryInstallError::BackendContract { .. }
                | P6X86_64SemanticBaselineNativeEntryInstallError::InstructionSelection { .. }
                | P6X86_64SemanticBaselineNativeEntryInstallError::SemanticByteEmission { .. }
                | P6X86_64SemanticBaselineNativeEntryInstallError::OwnerContinuationMap { .. }
                | P6X86_64SemanticBaselineNativeEntryInstallError::OwnerContinuationNativeBinding { .. }
        )
    }

    fn p15_auto_generated_install_failure_reason(
        error: &BaselineGeneratedCodeInstallError,
    ) -> BaselineEntryAutoGeneratedMaterializationFailure {
        match error {
            BaselineGeneratedCodeInstallError::OwnerNotLive => {
                BaselineEntryAutoGeneratedMaterializationFailure::OwnerNotLive
            }
            BaselineGeneratedCodeInstallError::CodeBlockNotRegistered => {
                BaselineEntryAutoGeneratedMaterializationFailure::CodeBlockNotRegistered
            }
            BaselineGeneratedCodeInstallError::DependencyPolicy(_) => {
                BaselineEntryAutoGeneratedMaterializationFailure::DependencyPolicy
            }
            BaselineGeneratedCodeInstallError::Eligibility { .. } => {
                BaselineEntryAutoGeneratedMaterializationFailure::Eligibility
            }
            BaselineGeneratedCodeInstallError::Artifact { .. } => {
                BaselineEntryAutoGeneratedMaterializationFailure::Artifact
            }
        }
    }

    fn p15_auto_generated_install_failure_detail(
        error: &BaselineGeneratedCodeInstallError,
    ) -> Option<BaselineEntryAutoGeneratedMaterializationDetail> {
        match error {
            BaselineGeneratedCodeInstallError::Eligibility { stage, error } => Some(
                BaselineEntryAutoGeneratedMaterializationDetail::Eligibility {
                    stage: *stage,
                    error: error.clone(),
                },
            ),
            BaselineGeneratedCodeInstallError::Artifact { stage, error } => {
                Some(BaselineEntryAutoGeneratedMaterializationDetail::Artifact {
                    stage: *stage,
                    error: error.clone(),
                })
            }
            _ => None,
        }
    }

    fn p15_auto_install_generated_baseline_artifact(
        &mut self,
        owner: CodeBlockId,
    ) -> (
        BaselineEntryAutoGeneratedMaterializationOutcome,
        Option<BaselineEntryAutoGeneratedMaterializationDetail>,
    ) {
        let (code_id, body_id) = self.next_p15_auto_baseline_generated_code_artifact_ids();
        match self.install_baseline_generated_code_artifact(
            owner,
            code_id,
            body_id,
            BaselineInstallDependencyPolicy::Allow,
        ) {
            Ok(_) => (
                BaselineEntryAutoGeneratedMaterializationOutcome::Installed,
                None,
            ),
            Err(error) => (
                BaselineEntryAutoGeneratedMaterializationOutcome::Failed {
                    reason: Self::p15_auto_generated_install_failure_reason(&error),
                },
                Self::p15_auto_generated_install_failure_detail(&error),
            ),
        }
    }

    fn p15_native_auto_install_requires_generated_host_fallback(
        &self,
        record: &P6X86_64SemanticBaselineNativeEntryInstallRecord,
    ) -> bool {
        record
            .enabled_readiness
            .as_ref()
            .and_then(|readiness| readiness.callable)
            .map(|callable| !self.can_execute_baseline_native_entry_kind(callable.kind()))
            .unwrap_or(false)
    }

    fn try_p15_auto_install_selected_baseline_entry(
        &mut self,
        owner: CodeBlockId,
        code_block: &CodeBlock,
        selection: &TierEntryPlanSelection,
        gate: Option<BaselineEntryGateRecord>,
    ) {
        let Some(install_mode) = self.selected_entry_plan_p15_auto_baseline_install_mode(
            owner,
            code_block,
            selection,
            gate.as_ref(),
        ) else {
            return;
        };
        if !self.selected_entry_code_block_matches_registered_code_block(owner, code_block) {
            return;
        }

        if install_mode == P15AutoBaselineInstallMode::DisabledNativeEntryArtifact {
            let (generated, generated_detail) =
                self.p15_auto_install_generated_baseline_artifact(owner);
            self.tiering.record_baseline_entry_auto_materialization(
                BaselineEntryAutoMaterializationRequest {
                    owner,
                    requested_tier: JitType::Baseline,
                    native:
                        BaselineEntryAutoNativeMaterializationOutcome::SkippedDisabledNativeEntry,
                    native_detail: None,
                    generated: Some(generated),
                    generated_detail,
                },
            );
            return;
        }

        let request = self.next_p15_auto_baseline_native_entry_install_request(owner);
        match self.install_p6_x86_64_callable_semantic_baseline_native_entry(request) {
            Ok(record) => {
                let (generated, generated_detail) = if install_mode
                    == P15AutoBaselineInstallMode::MissingEntryArtifact
                    && self.p15_native_auto_install_requires_generated_host_fallback(&record)
                {
                    // C++ JSC only publishes BaselineJITCode produced by the
                    // current CPU backend. Rust's P6 x86_64 emitter can still
                    // record valid semantic/provenance bytes on arm64, but
                    // that metadata-only callable readiness must not suppress
                    // the portable generated baseline body that is host-safe.
                    let (generated, generated_detail) =
                        self.p15_auto_install_generated_baseline_artifact(owner);
                    (Some(generated), generated_detail)
                } else {
                    (None, None)
                };
                self.tiering.record_baseline_entry_auto_materialization(
                    BaselineEntryAutoMaterializationRequest {
                        owner,
                        requested_tier: JitType::Baseline,
                        native: BaselineEntryAutoNativeMaterializationOutcome::Installed,
                        native_detail: None,
                        generated,
                        generated_detail,
                    },
                );
            }
            Err(error) => {
                let generated_fallback_allowed = install_mode
                    == P15AutoBaselineInstallMode::MissingEntryArtifact
                    && Self::p15_native_auto_install_failure_allows_generated_fallback(&error);
                let native = BaselineEntryAutoNativeMaterializationOutcome::Failed {
                    reason: Self::p15_auto_native_install_failure_reason(&error),
                    generated_fallback_allowed,
                };
                let native_detail = Self::p15_auto_native_install_failure_detail(&error);
                let (generated, generated_detail) = if generated_fallback_allowed {
                    let (generated, generated_detail) =
                        self.p15_auto_install_generated_baseline_artifact(owner);
                    (Some(generated), generated_detail)
                } else {
                    (None, None)
                };
                self.tiering.record_baseline_entry_auto_materialization(
                    BaselineEntryAutoMaterializationRequest {
                        owner,
                        requested_tier: JitType::Baseline,
                        native,
                        native_detail,
                        generated,
                        generated_detail,
                    },
                );
            }
        }
    }

    fn try_p15_auto_install_selected_baseline_entry_with_no_gc_suspension(
        &mut self,
        region: &mut VmNoGcRegion,
        owner: CodeBlockId,
        code_block: &CodeBlock,
        selection: &TierEntryPlanSelection,
        gate: Option<BaselineEntryGateRecord>,
    ) -> Result<(), NoGcAutoInstallFailure> {
        if self
            .selected_entry_plan_p15_auto_baseline_install_mode(
                owner,
                code_block,
                selection,
                gate.as_ref(),
            )
            .is_none()
        {
            return Ok(());
        }

        let suspended = match self.suspend_no_gc_execution_region() {
            Ok(suspended) => suspended,
            Err(_) => return Err(NoGcAutoInstallFailure::ActiveRegion),
        };
        self.try_p15_auto_install_selected_baseline_entry(owner, code_block, selection, gate);
        match self.resume_no_gc_execution_region(suspended) {
            Ok(resumed) => {
                *region = resumed;
                Ok(())
            }
            Err(_) => {
                let _ = self.abandon_suspended_no_gc_execution_region(suspended);
                Err(NoGcAutoInstallFailure::AbandonedRegion)
            }
        }
    }

    #[allow(dead_code)]
    pub(crate) fn install_baseline_artifact(
        &mut self,
        owner: CodeBlockId,
        artifact: JitCodeArtifact,
        materialization: Option<&BaselineExecutableMaterializationRecord>,
        slot: JitCodeSlot,
        dependency_policy: BaselineInstallDependencyPolicy,
    ) -> BaselineInstallRecord {
        let owner_liveness = if self.code_block_owner_is_live(owner) {
            BaselineInstallOwnerLiveness::Live
        } else {
            BaselineInstallOwnerLiveness::NotLive
        };
        let artifact_has_valid_entry = artifact.validate_baseline_entry_artifact(owner).is_ok();
        let eligibility = self.baseline_install_eligibility_from_current_code_block(
            owner,
            owner_liveness,
            artifact_has_valid_entry,
            P6_GENERATED_OPCODE_SUBSET,
        );
        self.install_baseline_artifact_with_eligibility(
            BaselineArtifactInstallWithEligibilityRequest {
                owner,
                artifact,
                materialization,
                slot,
                dependency_policy,
                owner_liveness,
                artifact_has_valid_entry,
                eligibility,
                // This generic install entry has no property-handoff plan in scope,
                // so it emits no property IC sites: zero record slots, mirroring a
                // baseline `CodeBlock` with `m_unlinkedPropertyInlineCaches.size() == 0`.
                property_inline_cache_site_count: 0,
            },
        )
    }

    fn install_baseline_artifact_with_eligibility(
        &mut self,
        request: BaselineArtifactInstallWithEligibilityRequest<'_>,
    ) -> BaselineInstallRecord {
        let BaselineArtifactInstallWithEligibilityRequest {
            owner,
            artifact,
            materialization,
            slot,
            dependency_policy,
            owner_liveness,
            artifact_has_valid_entry,
            eligibility,
            property_inline_cache_site_count,
        } = request;

        let materialization_accepted = match materialization {
            Some(materialization) if owner_liveness == BaselineInstallOwnerLiveness::Live => {
                self.tiering
                    .validate_baseline_executable_materialization_for_install(
                        owner,
                        &artifact,
                        materialization,
                    )
                    .is_ok()
                    && match (&eligibility, materialization.bytecode_snapshot) {
                        (BaselineInstallEligibility::Proven(proof), Some(bytecode_snapshot)) => {
                            proof.bytecode_snapshot_fingerprint() == bytecode_snapshot
                        }
                        (BaselineInstallEligibility::Proven(_), None) => true,
                        _ => false,
                    }
            }
            _ => false,
        };
        let code_block_mutation = if owner_liveness == BaselineInstallOwnerLiveness::Live
            && dependency_policy == BaselineInstallDependencyPolicy::Allow
            && artifact_has_valid_entry
            && materialization_accepted
            && matches!(&eligibility, BaselineInstallEligibility::Proven(_))
        {
            match self.code_blocks.install_baseline_jit_slot(
                owner,
                CodeBlockMutationAuthority::VmMainThread,
                slot,
                property_inline_cache_site_count,
            ) {
                Some(Ok(())) => BaselineInstallCodeBlockMutation::Succeeded,
                Some(Err(error)) => BaselineInstallCodeBlockMutation::Rejected(
                    BaselineInstallCodeBlockMutationRejection::CodeBlockMutation(error),
                ),
                None => BaselineInstallCodeBlockMutation::Rejected(
                    BaselineInstallCodeBlockMutationRejection::CodeBlockNotRegistered,
                ),
            }
        } else {
            BaselineInstallCodeBlockMutation::NotAttempted
        };

        self.tiering
            .record_baseline_install(BaselineInstallRequest {
                owner,
                artifact: &artifact,
                materialization,
                owner_liveness,
                dependency_policy,
                code_block_mutation,
                eligibility,
            })
    }

    fn baseline_install_eligibility_from_current_code_block(
        &self,
        owner: CodeBlockId,
        owner_liveness: BaselineInstallOwnerLiveness,
        artifact_has_valid_entry: bool,
        opcode_subset: BaselineSupportedOpcodeSubset,
    ) -> BaselineInstallEligibility {
        if owner_liveness != BaselineInstallOwnerLiveness::Live || !artifact_has_valid_entry {
            return BaselineInstallEligibility::Missing;
        }

        match self.code_blocks.get(owner) {
            Some(record) => {
                let snapshot = self.tiering.baseline_install_snapshot(owner);
                match BaselineBytecodeEligibilityRecord::proof_from_code_block_snapshot(
                    record.code_block(),
                    owner,
                    snapshot,
                    opcode_subset,
                    Vec::new(),
                ) {
                    Ok(proof) => BaselineInstallEligibility::Proven(proof),
                    Err(error) => BaselineInstallEligibility::Rejected(
                        BaselineInstallEligibilityRejection::DerivationFailed { error },
                    ),
                }
            }
            None => BaselineInstallEligibility::Rejected(
                BaselineInstallEligibilityRejection::CodeBlockNotRegistered,
            ),
        }
    }

    #[allow(dead_code)]
