    fn install_baseline_generated_code_artifact_internal(
        &mut self,
        owner: CodeBlockId,
        code_id: JitCodeId,
        body_id: BaselineGeneratedCodeBodyId,
        runtime_helper_plan: Option<BaselineGeneratedRuntimeHelperPlanMetadata>,
        property_handoff_plan: Option<BaselineGeneratedPropertyHandoffPlanMetadata>,
        dependency_policy: BaselineInstallDependencyPolicy,
    ) -> Result<BaselineGeneratedCodeArtifact, BaselineGeneratedCodeInstallError> {
        if !self.code_block_owner_is_live(owner) {
            return Err(BaselineGeneratedCodeInstallError::OwnerNotLive);
        }
        if dependency_policy != BaselineInstallDependencyPolicy::Allow {
            return Err(BaselineGeneratedCodeInstallError::DependencyPolicy(
                dependency_policy,
            ));
        }

        let record = self
            .code_blocks
            .get(owner)
            .ok_or(BaselineGeneratedCodeInstallError::CodeBlockNotRegistered)?;
        let snapshot = self.tiering.baseline_install_snapshot(owner);
        let code_block = record.code_block();
        let BaselineGeneratedRuntimeHelperPlanDerivation {
            metadata: derived_runtime_helper_plan,
            safepoints: runtime_helper_safepoints,
        } = match runtime_helper_plan.as_ref() {
            Some(runtime_helper_plan) => {
                validate_baseline_generated_runtime_helper_plan_against_code_block(
                    code_block,
                    owner,
                    runtime_helper_plan,
                )
            }
            None => {
                derive_baseline_generated_runtime_helper_plan_from_code_block(code_block, owner)
            }
        }
        .map_err(|error| BaselineGeneratedCodeInstallError::Eligibility {
            stage: BaselineGeneratedCodeInstallStage::RuntimeHelperPlan,
            error,
        })?;
        let runtime_helper_plan = match runtime_helper_plan {
            Some(runtime_helper_plan) => Some(runtime_helper_plan),
            None => derived_runtime_helper_plan,
        };
        let BaselineGeneratedPropertyHandoffPlanDerivation {
            metadata: derived_property_handoff_plan,
        } = match property_handoff_plan.as_ref() {
            Some(property_handoff_plan) => {
                validate_baseline_generated_property_handoff_plan_against_current_code_block(
                    code_block,
                    owner,
                    property_handoff_plan,
                )
            }
            None => {
                // C++ JSC's Baseline JIT creates fresh baseline property IC slots
                // from the profiled CodeBlock's current metadata
                // (`JIT::addUnlinkedPropertyInlineCache` ->
                // `CodeBlock::setupWithUnlinkedBaselineCode`), so generated
                // install must not reject a valid site just because an existing
                // bytecode IC already warmed.
                derive_baseline_generated_property_handoff_plan_from_current_code_block_metadata(
                    code_block, owner,
                )
            }
        }
        .map_err(|error| BaselineGeneratedCodeInstallError::Eligibility {
            stage: BaselineGeneratedCodeInstallStage::PropertyHandoffPlan,
            error,
        })?;
        let property_handoff_plan = match property_handoff_plan {
            Some(property_handoff_plan) => Some(property_handoff_plan),
            None => derived_property_handoff_plan,
        };
        let owner_continuation_map =
            derive_baseline_generated_owner_continuation_map_from_code_block(code_block, owner)
                .map_err(|error| BaselineGeneratedCodeInstallError::Eligibility {
                    stage: BaselineGeneratedCodeInstallStage::OwnerContinuationMap,
                    error,
                })?
                .metadata;
        let proof =
            BaselineBytecodeEligibilityRecord::proof_from_code_block_snapshot_for_mixed_vm_install(
                code_block,
                owner,
                snapshot,
                P6_GENERATED_OPCODE_SUBSET,
                runtime_helper_safepoints,
                runtime_helper_plan.as_ref(),
            )
            .map_err(|error| BaselineGeneratedCodeInstallError::Eligibility {
                stage: BaselineGeneratedCodeInstallStage::MixedEligibilityProof,
                error,
            })?;

        let body = BaselineGeneratedCodeBody::new(body_id, P6_GENERATED_OPCODE_SUBSET);
        let artifact = if runtime_helper_plan.is_some()
            || property_handoff_plan.is_some()
            || owner_continuation_map.is_some()
        {
            BaselineGeneratedCodeArtifact::new_with_runtime_helper_and_property_handoff_plans(
                code_id,
                owner,
                proof,
                body,
                BaselineGeneratedCodeMetadataPlans::new(
                    runtime_helper_plan,
                    property_handoff_plan,
                    owner_continuation_map,
                ),
                CodeLiveness::Live,
                CodeFinalizationAuthority::MainThread,
            )
        } else {
            BaselineGeneratedCodeArtifact::new(
                code_id,
                owner,
                proof,
                body,
                CodeLiveness::Live,
                CodeFinalizationAuthority::MainThread,
            )
        }
        .map_err(|error| BaselineGeneratedCodeInstallError::Artifact {
            stage: BaselineGeneratedCodeInstallStage::ArtifactConstruction,
            error,
        })?;

        self.tiering
            .record_baseline_generated_code_artifact(owner, artifact)
            .map_err(|error| BaselineGeneratedCodeInstallError::Artifact {
                stage: BaselineGeneratedCodeInstallStage::ArtifactRegistration,
                error,
            })
    }

    pub fn enter_no_gc_execution_region(&mut self) -> VmNoGcRegion {
        let heap_scope = self.heap.enter_no_gc_scope();
        self.gc_execution.enter_no_gc_region(heap_scope)
    }

    pub fn leave_no_gc_execution_region(
        &mut self,
        region: VmNoGcRegion,
    ) -> Result<VmNoGcRegion, VmGcIntegrationError> {
        let active = self.gc_execution.validate_leave_no_gc_region(region)?;
        self.leave_heap_no_gc_scope(active.heap_scope())?;
        self.gc_execution.leave_no_gc_region(active)
    }

    pub fn suspend_no_gc_execution_region(
        &mut self,
    ) -> Result<VmSuspendedNoGcRegion, VmGcIntegrationError> {
        let active = self.gc_execution.validate_suspend_no_gc_region()?;
        self.leave_heap_no_gc_scope(active.heap_scope())?;
        match self.gc_execution.suspend_no_gc_region() {
            Ok(suspended) => Ok(suspended),
            Err(error) => {
                let restored = self.heap.enter_no_gc_scope();
                debug_assert_eq!(restored, active.heap_scope());
                Err(error)
            }
        }
    }

    pub fn resume_no_gc_execution_region(
        &mut self,
        suspended: VmSuspendedNoGcRegion,
    ) -> Result<VmNoGcRegion, VmGcIntegrationError> {
        self.gc_execution.validate_resume_no_gc_region(suspended)?;
        let expected_suspended_heap_depth = suspended.restore_heap_scope_depth().saturating_sub(1);
        self.validate_heap_no_gc_depth(expected_suspended_heap_depth)?;
        let heap_scope = self.heap.enter_no_gc_scope();
        if heap_scope.depth != suspended.restore_heap_scope_depth() {
            let _ = self.heap.leave_no_gc_scope(heap_scope);
            return Err(VmGcIntegrationError::NoGcRegionDepthMismatch {
                expected: suspended.restore_heap_scope_depth(),
                actual: heap_scope.depth,
            });
        }
        let suspended = suspended.with_heap_scope(heap_scope);
        match self.gc_execution.resume_no_gc_region(suspended) {
            Ok(region) => Ok(region),
            Err(error) => {
                let _ = self.heap.leave_no_gc_scope(heap_scope);
                Err(error)
            }
        }
    }

    fn abandon_suspended_no_gc_execution_region(
        &mut self,
        suspended: VmSuspendedNoGcRegion,
    ) -> Result<(), VmGcIntegrationError> {
        let expected_suspended_heap_depth = suspended.restore_heap_scope_depth().saturating_sub(1);
        self.validate_heap_no_gc_depth(expected_suspended_heap_depth)?;
        self.gc_execution.abandon_suspended_no_gc_region(suspended)
    }

    pub fn evaluate_heap_operation(
        &self,
        operation: HeapSemanticOperation,
    ) -> Result<crate::gc::HeapSemanticGrant, HeapSemanticError> {
        evaluate_heap_semantics(
            self.heap.state_descriptor(),
            HeapMutationAuthority::Mutator,
            operation,
        )
    }

    fn validate_heap_no_gc_depth(&self, expected: u32) -> Result<(), VmGcIntegrationError> {
        let actual = self.heap.no_gc_scope_depth();
        if actual == expected {
            Ok(())
        } else {
            Err(VmGcIntegrationError::NoGcRegionDepthMismatch { expected, actual })
        }
    }

    fn leave_heap_no_gc_scope(
        &mut self,
        scope: NoGcScopeDepth,
    ) -> Result<(), VmGcIntegrationError> {
        let expected = scope.depth;
        self.heap.leave_no_gc_scope(scope).map_err(|_| {
            VmGcIntegrationError::NoGcRegionDepthMismatch {
                expected,
                actual: self.heap.no_gc_scope_depth(),
            }
        })
    }

    pub fn execution_root_snapshot(
        &self,
    ) -> Result<ExecutionRootSnapshot, crate::gc::RootSetSemanticError> {
        self.execution
            .root_snapshot(self.heap.id(), &self.registers)
    }

    pub fn heap_snapshot_hook(&self) -> VmHeapSnapshotHook {
        let execution_roots = self
            .execution_root_snapshot()
            .map(|snapshot| snapshot.precise_root_records())
            .unwrap_or_default();
        let exception_roots = self
            .exceptions
            .root_descriptors(self.heap.id())
            .into_iter()
            .map(|descriptor| descriptor.root)
            .collect();
        let entry_roots = self
            .entry
            .root_scopes()
            .map(|scope| scope.root)
            .collect::<Vec<_>>();
        let global_roots = self.global_root_descriptors();

        VmHeapSnapshotHook {
            builder: self.heap.heap_snapshot_builder(),
            statistics: self.heap.statistics(),
            entry_roots,
            execution_roots,
            exception_roots,
            global_roots,
            active_entry_depth: self.entry.entry_depth(),
            active_frame_depth: self.execution.frame_depth(),
            no_gc_scope_depth: self.gc_execution.no_gc_scope_depth(),
        }
    }

    pub fn execute_code_block<H: DispatchHost>(
        &mut self,
        code_block_id: CodeBlockId,
        code_block: &CodeBlock,
        host: &mut H,
        config: DispatchConfig,
    ) -> ExecutionCompletion {
        let entry_kind = self
            .execution
            .active_entry()
            .map(|entry| entry.record.kind())
            .unwrap_or(crate::interpreter::ExecutionEntryKind::Program);
        if self.active_dispatch_budget.is_some() {
            return self.execute_code_block_with_entry_kind(
                code_block_id,
                code_block,
                host,
                config,
                entry_kind,
            );
        }

        // C++ enters JS through VMEntryScope and keeps watchdog/trap state on
        // the VM for the active execution stack. Rust's dispatch-step cap is a
        // diagnostic probe guard for the bytecode interpreter and generated
        // re-interpreter shim, so the mutable budget is installed only at the
        // outer VM entry and nested calls/generated resumes spend from it.
        self.active_dispatch_budget = Some(DispatchBudget::from_config(config));
        let completion = self.execute_code_block_with_entry_kind(
            code_block_id,
            code_block,
            host,
            config,
            entry_kind,
        );
        self.active_dispatch_budget = None;
        completion
    }

    fn execute_code_block_with_entry_kind<H: DispatchHost>(
        &mut self,
        code_block_id: CodeBlockId,
        code_block: &CodeBlock,
        host: &mut H,
        config: DispatchConfig,
        entry_kind: crate::interpreter::ExecutionEntryKind,
    ) -> ExecutionCompletion {
        let mut region = self.enter_no_gc_execution_region();
        // Batch 1: drain runs unconditionally inside run_ic_tiering_safepoint;
        // the five idempotent passes are skipped when this owner has no
        // registered plans and the drain reported no pending work.
        self.run_ic_tiering_safepoint(code_block_id, code_block, host);
        let top_frame = self.execution.top_frame().cloned();
        let entry_selection = self
            .tiering
            .select_interpreter_entry_plan(TierEntryRequest {
                owner: code_block_id,
                entry_kind,
                bytecode_index: top_frame.as_ref().and_then(|frame| frame.bytecode_index),
                frame: top_frame.as_ref().map(|frame| frame.id),
                stack_frame: None,
                bytecode_size: Some(
                    code_block
                        .unlinked()
                        .instructions()
                        .instruction_count()
                        .try_into()
                        .unwrap_or(u32::MAX),
                ),
                inline_cache_count: inline_cache_count(code_block),
                policy: self.config.tiering_policy(),
            });
        let pre_install_gate = self
            .tiering
            .baseline_entry_gate_for_plan(code_block_id, entry_selection.selected_plan);
        match self.try_p15_auto_install_selected_baseline_entry_with_no_gc_suspension(
            &mut region,
            code_block_id,
            code_block,
            &entry_selection,
            pre_install_gate,
        ) {
            Ok(()) => {}
            Err(NoGcAutoInstallFailure::ActiveRegion) => {
                return self.finish_execute_code_block_gc_boundary_failure(
                    Some(region),
                    code_block_id,
                    entry_kind,
                )
            }
            Err(NoGcAutoInstallFailure::AbandonedRegion) => {
                return self.finish_execute_code_block_gc_boundary_failure(
                    None,
                    code_block_id,
                    entry_kind,
                );
            }
        }
        // C++ setUpCall does no per-call root work (llint/LLIntSlowPaths.cpp
        // :2106); the boundary snapshot is consumed only on the
        // FallbackToInterpreter branch inside commit_interpreter_entry_decision.
        // Defer the O(stack-depth x frame-width) root scan into a thunk over
        // disjoint field borrows so it runs lazily at the same stack/root state
        // (no mutation happens between here and the decision) and only when a
        // fallback actually records it; ordinary entries discard it unused.
        let heap = &self.heap;
        let execution = &self.execution;
        let registers = &self.registers;
        let gc_execution = &self.gc_execution;
        let entry = &self.entry;
        let entry_decision = self
            .tiering
            .commit_interpreter_entry_decision(entry_selection, || {
                compute_fallback_boundary_snapshot(heap, execution, registers, gc_execution, entry)
            });
        self.record_baseline_native_entry_launch_descriptor_if_ready(
            code_block_id,
            code_block,
            &entry_decision,
        );
        let mut completion_path = entry_decision.execution_path;
        let mut completion = match entry_decision.decision {
            TierEntryDecision::EnterOptimized {
                tier: JitType::Baseline,
            } if self.config.baseline_generated_execution_enabled() => {
                #[cfg(test)]
                self.record_no_gc_execution_depth_observation_for_test(
                    VmNoGcExecutionPathForTest::GeneratedEntry,
                );
                self.execute_baseline_generated_code_in_current_region(
                    code_block_id,
                    code_block,
                    top_frame.as_ref().map(|frame| frame.id),
                    entry_decision.entry_kind,
                    entry_decision.current_tier,
                    host,
                    config,
                )
            }
            TierEntryDecision::EnterOptimized {
                tier: JitType::Baseline,
            } => {
                // C++ JSC would enter LLInt or real baseline JITCode through
                // addressForCall(); this diagnostic mode declines Rust's
                // temporary generated bytecode shim and stays in the interpreter.
                completion_path = TierEntryExecutionPath::Interpreter;
                self.execute_interpreter_code_block_in_current_region(
                    code_block_id,
                    code_block,
                    host,
                    config,
                )
            }
            TierEntryDecision::EnterNative {
                tier: JitType::Baseline,
            } => {
                #[cfg(test)]
                self.record_no_gc_execution_depth_observation_for_test(
                    VmNoGcExecutionPathForTest::NativeEntry,
                );
                match self.execute_baseline_native_entry_shim_in_current_region(
                    code_block_id,
                    code_block,
                    top_frame.as_ref().map(|frame| frame.id),
                    &entry_decision,
                    host,
                    config,
                ) {
                    BaselineNativeEntryVmExecution::Native(completion) => completion,
                    BaselineNativeEntryVmExecution::InterpreterFallback(completion) => {
                        completion_path = TierEntryExecutionPath::Interpreter;
                        completion
                    }
                    BaselineNativeEntryVmExecution::DeferredRootedInterpreterFallback {
                        completion,
                        roots,
                    } => {
                        completion_path = TierEntryExecutionPath::Interpreter;
                        match self.cleanup_baseline_native_entry_deferred_roots(roots) {
                            Ok(()) => completion,
                            Err(error) => ExecutionCompletion::Failed(error),
                        }
                    }
                    BaselineNativeEntryVmExecution::P6SideExitReentry(_) => {
                        ExecutionCompletion::Failed(
                            ExecutionError::BaselineGeneratedExecutionRejected,
                        )
                    }
                    BaselineNativeEntryVmExecution::P9OwnerPostCallReentry(_) => {
                        ExecutionCompletion::Failed(
                            ExecutionError::BaselineGeneratedExecutionRejected,
                        )
                    }
                }
            }
            _ => self.execute_interpreter_code_block_in_current_region(
                code_block_id,
                code_block,
                host,
                config,
            ),
        };
        loop {
            completion = match completion {
                ExecutionCompletion::OrdinaryBytecodeCall(request) => self
                    .execute_ordinary_bytecode_call_request_in_current_region(
                        *request,
                        code_block_id,
                        code_block,
                        host,
                        config,
                    ),
                ExecutionCompletion::OrdinaryBytecodeConstruct(request) => self
                    .execute_ordinary_bytecode_construct_request_in_current_region(
                        *request,
                        code_block_id,
                        code_block,
                        host,
                        config,
                    ),
                ExecutionCompletion::FunctionValueCall(request) => self
                    .execute_function_value_call_request_in_current_region(
                        *request,
                        code_block_id,
                        code_block,
                        host,
                        config,
                    ),
                // C++ JSC globalFuncEval -> executeEval (indirect/global eval).
                ExecutionCompletion::EvalRequest(request) => self
                    .execute_eval_request_in_current_region(
                        *request,
                        code_block_id,
                        code_block,
                        host,
                        config,
                    ),
                ExecutionCompletion::BaselineLoopHandoff(handoff) => {
                    match self.execute_baseline_loop_handoff_completion_in_current_region(
                        &mut region,
                        code_block_id,
                        code_block,
                        handoff,
                        entry_kind,
                        host,
                        config,
                    ) {
                        Ok((completion, path)) => {
                            completion_path = path;
                            completion
                        }
                        Err(NoGcAutoInstallFailure::ActiveRegion) => {
                            return self.finish_execute_code_block_gc_boundary_failure(
                                Some(region),
                                code_block_id,
                                entry_kind,
                            )
                        }
                        Err(NoGcAutoInstallFailure::AbandonedRegion) => {
                            return self.finish_execute_code_block_gc_boundary_failure(
                                None,
                                code_block_id,
                                entry_kind,
                            );
                        }
                    }
                }
                done => {
                    completion = done;
                    break;
                }
            };
        }
        self.drain_interpreter_property_store_observations_for_generated_property_plan(
            code_block_id,
            top_frame.as_ref().map(|frame| frame.id),
            code_block,
            host,
        );
        host.discard_property_store_observations();
        // Batch 1: symmetric epilogue safepoint -- same guard as the prologue.
        self.run_ic_tiering_safepoint(code_block_id, code_block, host);
        let completion = self.leave_no_gc_region_with_completion(region, completion);
        self.tiering.record_execution_completion(
            code_block_id,
            entry_kind,
            &completion,
            self.execution.frame_depth(),
            completion_path,
        );
        completion
    }

    fn finish_execute_code_block_gc_boundary_failure(
        &mut self,
        active_region: Option<VmNoGcRegion>,
        code_block_id: CodeBlockId,
        entry_kind: crate::interpreter::ExecutionEntryKind,
    ) -> ExecutionCompletion {
        let completion = ExecutionCompletion::Failed(ExecutionError::GcBoundaryViolation);
        let completion = match active_region {
            Some(region) => self.leave_no_gc_region_with_completion(region, completion),
            None => completion,
        };
        self.tiering.record_execution_completion(
            code_block_id,
            entry_kind,
            &completion,
            self.execution.frame_depth(),
            TierEntryExecutionPath::Interpreter,
        );
        completion
    }

    // Batch 1 of the call-dispatch constant-factor plan. The IC/tiering
    // safepoint that runs in the execute_code_block prologue, the symmetric
    // epilogue, and the generated-resume refresh. The cheap soundness drain runs
    // UNCONDITIONALLY (it pulls from the global host invalidation/watchpoint
    // queues -- drain_pending_property_load_structure_chain_invalidations /
    // drain_pending_property_load_guard_watchpoint_events -- which are not
    // owner-scoped, so they must always be serviced). The other five passes are
    // idempotent and each filters owner==this-owner FIRST, so when the owner has
    // NO registered plans/candidates they do filtering work and find nothing.
    //
    // C++ JSC does this IC/call-link materialization per-LINK (llint_default_call
    // -> linkFor, LLIntSlowPaths.cpp:613-627; setUpCall, LLIntSlowPaths.cpp:2106),
    // NOT once per call. The Rust driver re-entered this safepoint on every
    // nested call, paying twelve filter passes (six prologue + six epilogue) per
    // call for the overwhelmingly common callee with no plans. We restore the
    // C++ "no work when nothing is registered" behavior by skipping the five
    // idempotent passes when owner_has_any_safepoint_plan_work is false AND the
    // always-on drain reported no pending work. If the drain returns non-empty,
    // we take the full path regardless of the predicate (pending invalidation may
    // have just retired/queued plan work this entry must service). This is a pure
    // presence-check guard around already-idempotent work: no shared mutable
    // state, no epoch/memo, no change to control flow, no-GC nesting, or counters.
    //
    // SOUNDNESS NOTE on `pending`: drain_pending_property_load_runtime_invalidations
    // returns ONLY the watchpoint-event Vec; the structure-chain drain it also runs
    // has its result discarded. That is sound here because the structure-chain drain's
    // only effect is aging the global megamorphic property-load cache, and NONE of the
    // five skippable passes read that cache -- so a discarded structure-chain result
    // can never imply pass work the skip would miss. The watchpoint drain, by contrast,
    // clears affected ICs inline and its non-empty result is exactly when new pass work
    // can exist, which is why `pending.is_empty()` is the correct gate.
    //
    // Batch 2 of the call-dispatch constant-factor plan extends Batch 1's
    // no-plans skip to a STEADY-STATE skip. An owner that HAS plans but has had
    // ZERO six-table plan mutations since its last full pass (richards: 57
    // call-link ICs are created during warmup, then nothing changes across ~6M
    // entries) was still re-running the five idempotent passes every call -- pure
    // waste, since each pass filters owner-first and early-returns when already
    // attached/materialized. Batch 2 keys an owner memo on
    // (CodeBlock snapshot fingerprint, global plan_generation): if both still
    // match the value under which the passes last completed for this owner, the
    // passes are skipped. Two correctness preconditions hold:
    //   (1) The hoisted prototype-load DataIC re-arm below runs UNCONDITIONALLY
    //       before any skip, so the only work the memo gates is idempotent.
    //   (2) plan_generation bumps on EVERY six-table mutation (any owner) and the
    //       fingerprint bumps on any CodeBlock bytecode change, so a memo hit is
    //       observably identical to re-running the (idempotent) passes.
    fn run_ic_tiering_safepoint<H: DispatchHost>(
        &mut self,
        code_block_id: CodeBlockId,
        code_block: &CodeBlock,
        host: &mut H,
    ) {
        let pending = self.drain_pending_property_load_runtime_invalidations(host);

        // Compute the CodeBlock snapshot fingerprint ONCE (the hoisted re-arm and
        // the memo both need it). `None` on a decode failure: the re-arm is
        // skipped (it would have early-returned on the same Err inside the pass),
        // and the memo is neither consulted nor recorded, so the full path is
        // taken whenever there is any plan work -- the safe default.
        let fingerprint =
            BaselineBytecodeEligibilityProof::fingerprint_code_block_snapshot(code_block).ok();

        // STEP 2 (Batch 2): HOISTED prototype-load DataIC re-arm. Runs
        // UNCONDITIONALLY, before the skip decision. This re-resolves and
        // re-writes holder cell pointers every entry an attachment is live -- a
        // genuine per-call side effect that the memo must never skip. It is cheap
        // and a no-op for owners with no armed depth-1 prototype-load DataICs (it
        // early-returns on an empty guarded candidate table).
        if let Some(fingerprint) = fingerprint {
            self.arm_resident_prototype_load_data_ic_records_at_safepoint(
                code_block_id,
                fingerprint,
                host,
            );
        }

        let has_plan_work = self
            .tiering
            .owner_has_any_safepoint_plan_work(code_block_id);

        // Batch 1 skip: owner has NO plans AND the drain reported nothing. There
        // is no idempotent pass work and no memo to consult.
        if !has_plan_work && pending.is_empty() {
            return;
        }

        // Batch 2 steady-state skip: when the drain was empty (so no host event
        // can have queued new pass work) and the owner HAS plans, consult the
        // memo. A drain-non-empty entry never consults the memo and always takes
        // the full path (pending invalidation may have just retired/queued plan
        // work this entry must service) -- this preserves Batch 1's gate exactly.
        //
        // IDEMPOTENCY ASSUMPTION (load-bearing): a memo hit is sound only because
        // the five skipped passes are idempotent given (fingerprint, plan_generation)
        // -- they re-derive nothing once attached/materialized. There is ONE pass
        // whose work also depends on RUNTIME HEAP LIVENESS, not on the six plan
        // tables or the fingerprint: clear_stale_metadata_only_call_link_inline_caches_at_safepoint
        // tests call_link_executable_cell_is_live (heap allocation_records), which
        // can flip live->dead WITHOUT any six-table mutation or fingerprint change.
        // This is benign TODAY because no production path destroys a published
        // executable cell during an interpreter run (invalidate_cell has only
        // test/fixture callers; there is no GC sweep mid-run). C++ JSC clears dead
        // call links eagerly via GC finalizeUnconditionally/visitWeak, not per-call
        // polling. WHEN a real GC-driven call-link finalization is added, it MUST
        // route the retire through the clear recorders (record_call_link_inline_cache_clear
        // / retire_call_link_inline_cache_metadata_for_clear), which bump
        // plan_generation -- otherwise this memo would skip the stale-clear and a
        // dead link would stay live. Do not add a mid-run executable-cell destroyer
        // without that epoch bump.
        if pending.is_empty() {
            if let Some(fingerprint) = fingerprint {
                if let Some(&(memo_fingerprint, memo_generation)) =
                    self.ic_tiering_safepoint_memo.get(&code_block_id)
                {
                    if memo_fingerprint == fingerprint
                        && memo_generation == self.tiering.plan_generation()
                    {
                        return;
                    }
                }
            }
        }

        // FULL path: the five idempotent passes. The full-branch counter is
        // incremented ONLY here (as in Batch 1) so the probe sees per-call pass
        // invocations collapse on a steady-state hot call path.
        self.safepoint_pass_full_branch_invocations = self
            .safepoint_pass_full_branch_invocations
            .saturating_add(1);
        self.materialize_and_attach_guarded_property_load_inline_caches_at_safepoint(
            code_block_id,
            code_block,
            host,
        );
        self.attach_metadata_only_non_guarded_property_inline_cache_cases_at_safepoint(
            code_block_id,
            code_block,
        );
        self.reserve_descriptor_only_structure_stub_repatch_transactions_at_safepoint(
            code_block_id,
            code_block,
        );
        self.clear_stale_metadata_only_call_link_inline_caches_at_safepoint(
            code_block_id,
            code_block,
        );
        self.recheck_metadata_only_call_link_attachment_plans_at_safepoint(
            code_block_id,
            code_block,
        );

        // Record the memo under the POST-pass plan_generation: the passes above
        // may have inserted/transitioned plan entries (e.g. attaching this
        // owner's first IC), which bumped plan_generation; recording the value
        // after they run is what lets a subsequent unchanged entry hit and skip.
        // The fingerprint cannot change here (the passes hold a shared &CodeBlock
        // and never call invalidate_snapshot_fingerprint).
        if let Some(fingerprint) = fingerprint {
            self.ic_tiering_safepoint_memo
                .insert(code_block_id, (fingerprint, self.tiering.plan_generation()));
        }
    }

    // Batch 1 measurement accessor: cumulative full-branch (non-skipped)
    // invocations of the five idempotent IC/tiering safepoint passes. Read by the
    // octane_probe to show per-call pass invocations collapse to ~0 on a hot call
    // path whose callees have no registered plans.
    pub fn safepoint_pass_full_branch_invocations(&self) -> u64 {
        self.safepoint_pass_full_branch_invocations
    }

    // Batch 2 test hook: overwrite the stored fingerprint half of an owner's
    // safepoint memo with a deterministically different value so the NEXT
    // safepoint sees a fingerprint mismatch and is forced onto the full path --
    // exercising the "CodeBlock bytecode change -> memo miss" transition. Returns
    // true iff a memo entry existed to corrupt. A registered CodeBlock's snapshot
    // fingerprint is immutable in practice (no `&mut` accessor survives
    // registration), so this is the only deterministic way a test can drive the
    // fingerprint-mismatch branch with an entry still present.
    #[cfg(test)]
    fn corrupt_ic_tiering_safepoint_memo_fingerprint_for_test(
        &mut self,
        owner: CodeBlockId,
        replacement_fingerprint: BaselineBytecodeSnapshotFingerprint,
    ) -> bool {
        if let Some(entry) = self.ic_tiering_safepoint_memo.get_mut(&owner) {
            assert_ne!(
                entry.0, replacement_fingerprint,
                "test must supply a fingerprint distinct from the memoized one"
            );
            entry.0 = replacement_fingerprint;
            return true;
        }
        false
    }

    #[cfg(test)]
    fn ic_tiering_safepoint_memo_contains_for_test(&self, owner: CodeBlockId) -> bool {
        self.ic_tiering_safepoint_memo.contains_key(&owner)
    }

    #[cfg(test)]
    fn record_no_gc_execution_depth_observation_for_test(
        &mut self,
        path: VmNoGcExecutionPathForTest,
    ) {
        self.no_gc_execution_depth_observations_for_test.push(
            VmNoGcExecutionDepthObservationForTest {
                path,
                vm_depth: self.gc_execution.no_gc_scope_depth(),
                heap_depth: self.heap.no_gc_scope_depth(),
            },
        );
    }

    fn record_baseline_native_entry_launch_descriptor_if_ready(
        &mut self,
        owner: CodeBlockId,
        code_block: &CodeBlock,
        entry_decision: &TierEntryDecisionRecord,
    ) {
        let Some(gate) = entry_decision.baseline_entry_gate.as_ref() else {
            return;
        };
        if !matches!(
            gate.outcome,
            BaselineEntryGateOutcome::NativeEntryReady
                | BaselineEntryGateOutcome::NativeEntryReadyButExecutionDisabled
        ) {
            return;
        }
        let Some(readiness) = self
            .tiering
            .baseline_native_entry_readiness_for_gate(&gate)
            .cloned()
        else {
            return;
        };
        if let Some(descriptor) = readiness.descriptor {
            if let Some(callable) = readiness.callable {
                if !self.can_execute_baseline_native_entry_kind(callable.kind()) {
                    return;
                }
                if matches!(
                    callable.kind(),
                    BaselineNativeEntryCallableKind::P6X86_64EmittedSemanticCAbiEntry
                        | BaselineNativeEntryCallableKind::P6Arm64EmittedSemanticCAbiEntry
                ) && self
                    .platform_residency_index_for_native_entry(&readiness, &descriptor)
                    .is_none()
                {
                    return;
                }
            }
        }
        match gate.outcome {
            BaselineEntryGateOutcome::NativeEntryReady => {
                let Some(readiness_snapshot) = readiness.bytecode_snapshot else {
                    return;
                };
                let Ok(actual_snapshot) =
                    BaselineBytecodeEligibilityProof::fingerprint_code_block_snapshot(code_block)
                else {
                    return;
                };
                if actual_snapshot != readiness_snapshot {
                    return;
                }
            }
            BaselineEntryGateOutcome::NativeEntryReadyButExecutionDisabled => {
                if let Some(readiness_snapshot) = readiness.bytecode_snapshot {
                    let Ok(actual_snapshot) =
                        BaselineBytecodeEligibilityProof::fingerprint_code_block_snapshot(
                            code_block,
                        )
                    else {
                        return;
                    };
                    if actual_snapshot != readiness_snapshot {
                        return;
                    }
                }
            }
            _ => {}
        }
        let Some((scope, call_frame)) = self.baseline_native_entry_launch_metadata(
            owner,
            code_block,
            entry_decision.entry_kind,
        ) else {
            return;
        };
        if let Ok(descriptor) = VmEntryLaunchDescriptor::baseline_native_entry(
            scope,
            call_frame,
            gate.clone(),
            &readiness,
        ) {
            let executable = code_block.link_context().owner_executable;
            let mut publication_request =
                ExecutableEntryPublicationRequest::from_launch_descriptor(descriptor.clone())
                    .with_executable(executable);
            if let Some(slot) = code_block.entrypoints().baseline_jit() {
                publication_request = publication_request.with_baseline_jit_slot(slot);
            }
            match executable {
                Some(executable) => {
                    let publication = self.executables.publish_baseline_native_entry(
                        executable,
                        publication_request.clone(),
                        code_block,
                    );
                    if matches!(
                        publication,
                        ExecutableRegistryEntryPublication::NotRegistered
                    ) {
                        let _ = self
                            .code_blocks
                            .publish_executable_entry(owner, publication_request);
                    }
                }
                None => {
                    let _ = self
                        .code_blocks
                        .publish_executable_entry(owner, publication_request);
                }
            }
            self.entry.record_launch_descriptor(descriptor);
        }
    }

    fn baseline_native_entry_launch_metadata(
        &self,
        owner: CodeBlockId,
        code_block: &CodeBlock,
        entry_kind: crate::interpreter::ExecutionEntryKind,
    ) -> Option<(VmEntryLaunchScope, VmEntryCallFrameMetadata)> {
        let active_entry = self.execution.active_entry()?;
        let top_frame = self.execution.top_frame()?;
        let (
            mut entry_code_block,
            global_object,
            entry_this,
            context,
            entry_callee,
            mut provided,
            mut specialization,
        ) = match &active_entry.record {
            ExecutionEntryRecord::Program(entry) => (
                entry.code_block,
                Some(entry.global_object),
                entry.this_value,
                None,
                None,
                top_frame.argument_count_including_this.saturating_sub(1),
                CodeSpecializationKind::Call,
            ),
            ExecutionEntryRecord::Function(entry) => (
                entry.code_block,
                None,
                entry.this_value,
                entry.context,
                Some(entry.function),
                entry.argument_count,
                entry.specialization,
            ),
            ExecutionEntryRecord::Eval(entry) => (
                entry.code_block,
                None,
                entry.this_value,
                None,
                None,
                top_frame.argument_count_including_this.saturating_sub(1),
                CodeSpecializationKind::Call,
            ),
            ExecutionEntryRecord::Module(entry) => (
                entry.code_block,
                None,
                entry.sent_value,
                Some(entry.module_environment),
                None,
                top_frame.argument_count_including_this.saturating_sub(1),
                CodeSpecializationKind::Call,
            ),
        };
        if entry_kind == crate::interpreter::ExecutionEntryKind::Function
            && top_frame.code_block == Some(owner)
            && active_entry.record.code_block() != owner
        {
            entry_code_block = owner;
            provided = top_frame.argument_count_including_this.saturating_sub(1);
            specialization = CodeSpecializationKind::Call;
        }
        if entry_kind == crate::interpreter::ExecutionEntryKind::Construct
            && top_frame.code_block == Some(owner)
            && active_entry.record.code_block() != owner
        {
            entry_code_block = owner;
            provided = top_frame.argument_count_including_this.saturating_sub(1);
            specialization = CodeSpecializationKind::Construct;
        }
        let argument_count_including_this = top_frame.argument_count_including_this;
        let formal_argument_count_including_this =
            code_block.unlinked().frame().num_parameters_including_this;
        let padded_argument_count = argument_count_including_this
            .max(provided.saturating_add(1))
            .max(formal_argument_count_including_this);
        Some((
            VmEntryLaunchScope {
                owner,
                entry_code_block: Some(entry_code_block),
                active_entry_frame: Some(active_entry.id),
                previous_entry_frame: active_entry.previous_entry,
                saved_top_call_frame: active_entry.saved_top_frame,
                active_top_call_frame: Some(top_frame.id),
            },
            VmEntryCallFrameMetadata {
                frame: top_frame.id,
                entry_frame: top_frame.entry,
                caller_frame: top_frame.caller,
                code_block: top_frame.code_block,
                callee: top_frame.callee.or(entry_callee),
                callee_value: top_frame.callee_value,
                context,
                global_object,
                entry_value: VmEntryLaunchArgumentValue::This(entry_this),
                argument_count_including_this,
                provided_argument_count: provided,
                padded_argument_count,
                specialization,
                arity_mode: ArityCheckMode::AlreadyChecked,
            },
        ))
    }

    fn execute_interpreter_code_block_in_current_region<H: DispatchHost>(
        &mut self,
        code_block_id: CodeBlockId,
        code_block: &CodeBlock,
        host: &mut H,
        config: DispatchConfig,
    ) -> ExecutionCompletion {
        let mut host = VmLoopHintDispatchHost::new(
            host,
            &mut self.tiering,
            code_block_id,
            self.config.tiering_policy(),
        );
        let mut local_dispatch_budget = DispatchBudget::from_config(config);
        let dispatch_budget = self
            .active_dispatch_budget
            .as_mut()
            .unwrap_or(&mut local_dispatch_budget);
        execute_code_block_deferring_ordinary_calls_with_root_scope_and_dispatch_budget(
            InterpreterExecutionState {
                stack: &mut self.execution,
                registers: &mut self.registers,
                exceptions: &mut self.exceptions,
                heap: &mut self.heap,
            },
            code_block_id,
            code_block,
            &mut host,
            dispatch_budget,
            &mut self.interpreter_root_scope,
        )
    }

    fn baseline_loop_handoff_entry_selection(
        &self,
        owner: CodeBlockId,
        code_block: &CodeBlock,
        handoff: BaselineLoopHandoffRequest,
        entry_kind: crate::interpreter::ExecutionEntryKind,
    ) -> Result<TierEntryPlanSelection, ExecutionError> {
        let resume = handoff.resume;
        let plan = handoff.selected_plan;
        if resume.code_block != owner {
            return Err(ExecutionError::CodeBlockMismatch {
                expected: owner,
                actual: Some(resume.code_block),
            });
        }
        if plan.owner != owner
            || plan.kind != TierPlanKind::BaselineFromBytecode
            || plan.to_tier != JitType::Baseline
        {
            return Err(ExecutionError::BaselineGeneratedExecutionRejected);
        }
        let instruction = code_block
            .decoded_instruction_at(resume.bytecode_index)
            .map_err(|_| ExecutionError::BaselineGeneratedExecutionRejected)?;
        if CoreOpcode::from_opcode(instruction.opcode) != Some(CoreOpcode::LoopHint) {
            return Err(ExecutionError::BaselineGeneratedExecutionRejected);
        }

        Ok(TierEntryPlanSelection {
            request: TierEntryRequest {
                owner,
                entry_kind,
                bytecode_index: Some(resume.bytecode_index),
                frame: Some(resume.frame),
                stack_frame: None,
                bytecode_size: Some(
                    code_block
                        .unlinked()
                        .instructions()
                        .instruction_count()
                        .try_into()
                        .unwrap_or(u32::MAX),
                ),
                inline_cache_count: inline_cache_count(code_block),
                policy: self.config.tiering_policy(),
            },
            selected_plan: Some(plan),
            current_tier: plan.from_tier,
            counters: plan.profile.counters,
            thresholds: plan.profile.thresholds,
        })
    }

    fn continue_interpreter_after_declined_loop_handoff<H: DispatchHost>(
        &mut self,
        handoff: BaselineLoopHandoffRequest,
        code_block: &CodeBlock,
        host: &mut H,
        config: DispatchConfig,
    ) -> ExecutionCompletion {
        let Some(next) = handoff.next_bytecode_index else {
            return ExecutionCompletion::Returned(RuntimeValue::undefined());
        };
        self.execute_baseline_fallback_in_current_region(
            BaselineFallbackRequest::new(handoff.resume.code_block, handoff.resume.frame, next),
            code_block,
            host,
            config,
        )
    }

    fn execute_baseline_loop_handoff_completion_in_current_region<H: DispatchHost>(
        &mut self,
        _region: &mut VmNoGcRegion,
        owner: CodeBlockId,
        code_block: &CodeBlock,
        handoff: BaselineLoopHandoffRequest,
        entry_kind: crate::interpreter::ExecutionEntryKind,
        host: &mut H,
        config: DispatchConfig,
    ) -> Result<(ExecutionCompletion, TierEntryExecutionPath), NoGcAutoInstallFailure> {
        let selection = match self
            .baseline_loop_handoff_entry_selection(owner, code_block, handoff, entry_kind)
        {
            Ok(selection) => selection,
            Err(error) => {
                return Ok((
                    ExecutionCompletion::Failed(error),
                    TierEntryExecutionPath::Interpreter,
                ))
            }
        };
        let pre_install_gate = self
            .tiering
            .baseline_entry_gate_for_plan(owner, selection.selected_plan);
        let has_generated_loop_entry = pre_install_gate
            .as_ref()
            .filter(|gate| gate.outcome == BaselineEntryGateOutcome::Eligible)
            .is_some_and(|gate| {
                self.config.baseline_generated_execution_enabled()
                    && gate.generated_artifact.is_some()
            });
        if !has_generated_loop_entry {
            // C++ _llint_loop_osr jumps to JITCodeMap::find(current LoopHint).
            // JITCodeMap is keyed only by bytecode index; BaselineJITCode's
            // call/property side tables are finalized separately from the map,
            // and runtime-helper bytecodes are not filtered out as OSR targets.
            // Rust generated baseline mirrors that by reading the active frame
            // bytecode index on entry and using artifact metadata during
            // execution. Emitted native baseline still lacks a per-bytecode
            // LoopHint entry map, and the diagnostic policy may also disable
            // Rust's generated bytecode shim, so those cases remain on the
            // interpreter-decline path here.
            return Ok((
                self.continue_interpreter_after_declined_loop_handoff(
                    handoff, code_block, host, config,
                ),
                TierEntryExecutionPath::Interpreter,
            ));
        }

        // Same lazy boundary as execute_code_block_with_entry_kind: defer the
        // root scan into a thunk so it runs only on the FallbackToInterpreter
        // branch that consumes it, at the identical stack/root state.
        let heap = &self.heap;
        let execution = &self.execution;
        let registers = &self.registers;
        let gc_execution = &self.gc_execution;
        let entry = &self.entry;
        let entry_decision = self
            .tiering
            .commit_interpreter_entry_decision(selection, || {
                compute_fallback_boundary_snapshot(heap, execution, registers, gc_execution, entry)
            });
        self.record_baseline_native_entry_launch_descriptor_if_ready(
            owner,
            code_block,
            &entry_decision,
        );

        // C++ _llint_loop_osr jumps to JITCodeMap::find(current LoopHint).
        // Rust baseline bodies do not yet expose a per-bytecode code-location
        // map; generated baseline reads the active frame's bytecode index, so
        // the VM marks the frame at LoopHint before entering baseline.
        self.execution
            .mark_top_bytecode_index(handoff.resume.bytecode_index);

        match entry_decision.decision {
            TierEntryDecision::EnterOptimized {
                tier: JitType::Baseline,
            } if self.config.baseline_generated_execution_enabled() => {
                #[cfg(test)]
                self.record_no_gc_execution_depth_observation_for_test(
                    VmNoGcExecutionPathForTest::GeneratedEntry,
                );
                Ok((
                    self.execute_baseline_generated_code_in_current_region(
                        owner,
                        code_block,
                        Some(handoff.resume.frame),
                        entry_decision.entry_kind,
                        entry_decision.current_tier,
                        host,
                        config,
                    ),
                    TierEntryExecutionPath::GeneratedCode(JitType::Baseline),
                ))
            }
            TierEntryDecision::EnterNative {
                tier: JitType::Baseline,
            } => Ok((
                self.continue_interpreter_after_declined_loop_handoff(
                    handoff, code_block, host, config,
                ),
                TierEntryExecutionPath::Interpreter,
            )),
            _ => Ok((
                self.continue_interpreter_after_declined_loop_handoff(
                    handoff, code_block, host, config,
                ),
                TierEntryExecutionPath::Interpreter,
            )),
        }
    }

    fn execute_baseline_native_entry_shim_in_current_region<H: DispatchHost>(
        &mut self,
        code_block_id: CodeBlockId,
        code_block: &CodeBlock,
        expected_frame: Option<CallFrameId>,
        entry_decision: &TierEntryDecisionRecord,
        host: &mut H,
        config: DispatchConfig,
    ) -> BaselineNativeEntryVmExecution {
        let fallback = |vm: &mut Self, host: &mut H| {
            BaselineNativeEntryVmExecution::InterpreterFallback(
                vm.execute_interpreter_code_block_in_current_region(
                    code_block_id,
                    code_block,
                    host,
                    config,
                ),
            )
        };

        let Some(gate) = entry_decision.baseline_entry_gate.as_ref() else {
            return fallback(self, host);
        };
        self.try_execute_baseline_native_entry_shim_for_gate_in_current_region(
            code_block_id,
            code_block,
            expected_frame,
            entry_decision.entry_kind,
            entry_decision.current_tier,
            gate,
            host,
            config,
            true,
        )
        .unwrap_or_else(|| fallback(self, host))
    }

    fn try_execute_baseline_native_entry_shim_for_gate_in_current_region<H: DispatchHost>(
        &mut self,
        code_block_id: CodeBlockId,
        code_block: &CodeBlock,
        expected_frame: Option<CallFrameId>,
        entry_kind: crate::interpreter::ExecutionEntryKind,
        current_tier: JitType,
        gate: &BaselineEntryGateRecord,
        host: &mut H,
        config: DispatchConfig,
        allow_interpreter_fallback: bool,
    ) -> Option<BaselineNativeEntryVmExecution> {
        if gate.outcome != BaselineEntryGateOutcome::NativeEntryReady {
            return None;
        }
        let Some(readiness) = self
            .tiering
            .baseline_native_entry_readiness_for_gate(gate)
            .cloned()
        else {
            return None;
        };
        if readiness.execution_policy != BaselineNativeEntryExecutionPolicy::Enabled
            || readiness.outcome != BaselineNativeEntryReadinessOutcome::Ready
        {
            return None;
        }
        let Some(callable) = readiness.callable else {
            return None;
        };
        if !self.can_execute_baseline_native_entry_kind(callable.kind()) {
            return None;
        }
        let Some(descriptor) = readiness.descriptor else {
            return None;
        };
        let Some(artifact) = gate.native_artifact else {
            return None;
        };
        if artifact.owner != code_block_id
            || descriptor.owner != code_block_id
            || descriptor.artifact_id != artifact.id
            || descriptor.native_symbol != artifact.native_code
            || descriptor.machine_code != artifact.machine_code
            || descriptor.machine_range != artifact.machine_code.range
            || descriptor.entrypoint != artifact.entrypoint
            || descriptor.baseline_abi_proof != artifact.baseline_abi_proof
            || callable.validate_for_descriptor(&descriptor).is_err()
        {
            return None;
        }
        let Some(readiness_snapshot) = readiness.bytecode_snapshot else {
            return None;
        };
        let Ok(actual_snapshot) =
            BaselineBytecodeEligibilityProof::fingerprint_code_block_snapshot(code_block)
        else {
            return None;
        };
        if actual_snapshot != readiness_snapshot {
            return None;
        }
        let Some(expected_frame) = expected_frame else {
            return None;
        };
        let Some((scope, call_frame)) =
            self.baseline_native_entry_launch_metadata(code_block_id, code_block, entry_kind)
        else {
            return None;
        };
        let Ok(launch_descriptor) = VmEntryLaunchDescriptor::baseline_native_entry(
            scope,
            call_frame,
            gate.clone(),
            &readiness,
        ) else {
            return None;
        };
        match launch_descriptor.dispatch {
            VmEntryDispatchSelection::BaselineNative(
                BaselineNativeDispatchTokenSelection::NormalEntry { token },
            ) if token == callable.token() => {}
            _ => return None,
        }

        Some(match callable.kind() {
            BaselineNativeEntryCallableKind::P6PureBaselineNativeEntryShim => self
                .execute_p6_pure_baseline_native_entry_shim_in_current_region(
                    code_block,
                    P6PureNativeShimDispatch {
                        code_block_id,
                        expected_frame,
                        entry_kind,
                        current_tier,
                        callable,
                        allow_interpreter_fallback,
                    },
                    host,
                    config,
                ),
            BaselineNativeEntryCallableKind::P6X86_64EmittedSemanticCAbiEntry => self
                .execute_p6_x86_64_emitted_semantic_native_entry_in_current_region(
                    code_block,
                    P6EmittedNativeDispatch {
                        code_block_id,
                        expected_frame,
                        entry_kind,
                        current_tier,
                        bytecode_snapshot: actual_snapshot,
                        readiness: &readiness,
                        descriptor: &descriptor,
                        allow_interpreter_fallback,
                    },
                    host,
                    config,
                ),
            BaselineNativeEntryCallableKind::P6Arm64EmittedSemanticCAbiEntry => self
                .execute_p6_arm64_emitted_semantic_native_entry_in_current_region(
                    code_block,
                    P6EmittedNativeDispatch {
                        code_block_id,
                        expected_frame,
                        entry_kind,
                        current_tier,
                        bytecode_snapshot: actual_snapshot,
                        readiness: &readiness,
                        descriptor: &descriptor,
                        allow_interpreter_fallback,
                    },
                    arm64_native_entry::prove_arm64_native_entry_launch_descriptor_for_callable(
                        &launch_descriptor,
                        callable,
                    )
                    .ok()?,
                    host,
                    config,
                ),
        })
    }

    fn execute_p6_pure_baseline_native_entry_shim_in_current_region<H: DispatchHost>(
        &mut self,
        code_block: &CodeBlock,
        dispatch: P6PureNativeShimDispatch,
        host: &mut H,
        config: DispatchConfig,
    ) -> BaselineNativeEntryVmExecution {
        match execute_baseline_p6_native_entry_shim(BaselineNativeEntryShimExecutionRequest {
            callable: dispatch.callable,
            owner: dispatch.code_block_id,
            code_block,
            expected_frame: dispatch.expected_frame,
            execution: InterpreterExecutionState {
                stack: &mut self.execution,
                registers: &mut self.registers,
                exceptions: &mut self.exceptions,
                heap: &mut self.heap,
            },
        }) {
            Ok(BaselineNativeEntryShimExecutionResult::Completed(completion)) => {
                BaselineNativeEntryVmExecution::Native(completion)
            }
            Ok(BaselineNativeEntryShimExecutionResult::Fallback(fallback_request)) => {
                if !dispatch.allow_interpreter_fallback {
                    return BaselineNativeEntryVmExecution::Native(ExecutionCompletion::Failed(
                        ExecutionError::BaselineGeneratedExecutionRejected,
                    ));
                }
                self.record_baseline_generated_fallback(
                    dispatch.code_block_id,
                    dispatch.entry_kind,
                    dispatch.current_tier,
                    fallback_request,
                );
                let request = fallback_request.request;
                BaselineNativeEntryVmExecution::InterpreterFallback(
                    self.execute_baseline_fallback_in_current_region(
                        request, code_block, host, config,
                    ),
                )
            }
            Err(BaselineNativeEntryShimExecutionError::Execution(error)) => {
                BaselineNativeEntryVmExecution::Native(ExecutionCompletion::Failed(error))
            }
            Err(_) if dispatch.allow_interpreter_fallback => {
                BaselineNativeEntryVmExecution::InterpreterFallback(
                    self.execute_interpreter_code_block_in_current_region(
                        dispatch.code_block_id,
                        code_block,
                        host,
                        config,
                    ),
                )
            }
            Err(_) => BaselineNativeEntryVmExecution::Native(ExecutionCompletion::Failed(
                ExecutionError::BaselineGeneratedExecutionRejected,
            )),
        }
    }

    fn execute_p6_arm64_emitted_semantic_native_entry_in_current_region<H: DispatchHost>(
        &mut self,
        code_block: &CodeBlock,
        dispatch: P6EmittedNativeDispatch<'_>,
        _launch_proof: arm64_native_entry::Arm64NativeEntryLaunchProof,
        host: &mut H,
        config: DispatchConfig,
    ) -> BaselineNativeEntryVmExecution {
        let fallback = |vm: &mut Self, host: &mut H| {
            if dispatch.allow_interpreter_fallback {
                BaselineNativeEntryVmExecution::InterpreterFallback(
                    vm.execute_interpreter_code_block_in_current_region(
                        dispatch.code_block_id,
                        code_block,
                        host,
                        config,
                    ),
                )
            } else {
                BaselineNativeEntryVmExecution::Native(ExecutionCompletion::Failed(
                    ExecutionError::BaselineGeneratedExecutionRejected,
                ))
            }
        };
        if !self.can_execute_p6_arm64_emitted_native_entry() {
            return fallback(self, host);
        }
        let vm = NonNull::from(&mut *self).cast::<c_void>();
        let mut invocation = P6Arm64CallableNativeInvocation::Entry {
            entry_offset: dispatch.descriptor.machine_range.start_offset,
        };
        loop {
            if let Some(reason) = self.exceptions.termination() {
                return BaselineNativeEntryVmExecution::Native(ExecutionCompletion::Terminated(
                    reason,
                ));
            }
            let Some(active_frame) = self.execution.top_frame() else {
                return fallback(self, host);
            };
            let active_frame_id = active_frame.id;
            let active_frame_code_block = active_frame.code_block;
            let active_callee_value = active_frame.callee_value;
            let active_register_window = active_frame.register_window;
            if active_frame_id != dispatch.expected_frame
                || active_frame_code_block != Some(dispatch.code_block_id)
            {
                return fallback(self, host);
            }
            if p6_code_block_uses_load_callee(code_block) && active_callee_value.is_none() {
                return fallback(self, host);
            }
            let callee_value_bits = active_callee_value
                .unwrap_or_else(RuntimeValue::undefined)
                .encoded()
                .0;
            let Some(platform_residency_index) = self
                .platform_residency_index_for_native_entry(dispatch.readiness, dispatch.descriptor)
            else {
                return fallback(self, host);
            };
            let Ok(frame_base) = self
                .registers
                .borrow_active_frame_base_for_raw_native_entry(active_register_window)
            else {
                return fallback(self, host);
            };
            let ic_store_base = self
                .code_blocks
                .get(dispatch.code_block_id)
                .map(|registered| registered.code_block())
                .and_then(|resident| resident.baseline_jit_data_record_store_base())
                .and_then(|base| NonNull::new(base as *mut c_void))
                .unwrap_or_else(NonNull::<c_void>::dangling);
            let request = match invocation {
                P6Arm64CallableNativeInvocation::Entry { entry_offset } => {
                    ExecutableMemoryP6CallRequest::new(
                        entry_offset,
                        vm,
                        frame_base.as_non_null(),
                        callee_value_bits,
                        ic_store_base,
                    )
                }
                P6Arm64CallableNativeInvocation::P6SideExitReentry(reentry) => reentry
                    .call_request(
                        vm,
                        frame_base.as_non_null(),
                        callee_value_bits,
                        ic_store_base,
                    ),
            };
            let call_result = self.baseline_platform_executable_residencies
                [platform_residency_index]
                .evidence
                .compartment
                .call_p6_arm64_entry(request);
            let Ok(result) = call_result else {
                return fallback(self, host);
            };
            match p6_arm64_emitted_semantic_native_raw_return(result.encoded_js_value_bits) {
                Ok(P6Arm64EmittedSemanticNativeRawReturn::RuntimeValue(value)) => {
                    return BaselineNativeEntryVmExecution::Native(ExecutionCompletion::Returned(
                        value,
                    ));
                }
                Ok(P6Arm64EmittedSemanticNativeRawReturn::RetainedP6SideExit(payload)) => {
                    match self
                        .execute_p6_x86_64_callable_retained_native_exit_payload_in_current_region(
                            code_block, &dispatch, payload, host, config,
                        ) {
                        BaselineNativeEntryVmExecution::P6SideExitReentry(reentry) => {
                            // Public ARM64 branch-aware callable admission stays
                            // disabled. This private path consumes only a VM-
                            // resolved retained P6 fallback target after the
                            // active frame, callee, frame-base, IC-store, and
                            // platform checks above have been revalidated.
                            invocation = P6Arm64CallableNativeInvocation::P6SideExitReentry(
                                P6NativeSideExitReentryCallBridge::new(reentry),
                            );
                            continue;
                        }
                        execution => {
                            return p6_arm64_reject_side_exit_reentry_execution(execution);
                        }
                    }
                }
                Err(error) => {
                    return BaselineNativeEntryVmExecution::Native(ExecutionCompletion::Failed(
                        error,
                    ));
                }
            }
        }
    }

    fn execute_p6_x86_64_emitted_semantic_native_entry_in_current_region<H: DispatchHost>(
        &mut self,
        code_block: &CodeBlock,
        dispatch: P6EmittedNativeDispatch<'_>,
        host: &mut H,
        config: DispatchConfig,
    ) -> BaselineNativeEntryVmExecution {
        let initial_invocation = P6X86_64CallableNativeInvocation::Entry {
            entry_offset: dispatch.descriptor.machine_range.start_offset,
        };
        self.execute_p6_x86_64_emitted_semantic_native_invocation_in_current_region(
            code_block,
            dispatch,
            initial_invocation,
            host,
            config,
        )
    }

    fn execute_p6_x86_64_emitted_semantic_native_invocation_in_current_region<H: DispatchHost>(
        &mut self,
        code_block: &CodeBlock,
        dispatch: P6EmittedNativeDispatch<'_>,
        initial_invocation: P6X86_64CallableNativeInvocation,
        host: &mut H,
        config: DispatchConfig,
    ) -> BaselineNativeEntryVmExecution {
        let fallback = |vm: &mut Self, host: &mut H| {
            if dispatch.allow_interpreter_fallback {
                BaselineNativeEntryVmExecution::InterpreterFallback(
                    vm.execute_interpreter_code_block_in_current_region(
                        dispatch.code_block_id,
                        code_block,
                        host,
                        config,
                    ),
                )
            } else {
                BaselineNativeEntryVmExecution::Native(ExecutionCompletion::Failed(
                    ExecutionError::BaselineGeneratedExecutionRejected,
                ))
            }
        };
        if !self.can_execute_p6_x86_64_emitted_native_entry() {
            return fallback(self, host);
        }

        let vm = NonNull::from(&mut *self).cast::<c_void>();
        let mut invocation = initial_invocation;
        let mut remaining_native_backedges = config.max_steps;
        loop {
            if let Some(reason) = self.exceptions.termination() {
                return BaselineNativeEntryVmExecution::Native(ExecutionCompletion::Terminated(
                    reason,
                ));
            }
            let Some(active_frame) = self.execution.top_frame() else {
                return fallback(self, host);
            };
            if active_frame.id != dispatch.expected_frame
                || active_frame.code_block != Some(dispatch.code_block_id)
            {
                return fallback(self, host);
            }
            let active_callee_value = active_frame.callee_value;
            if p6_code_block_uses_load_callee(code_block) && active_callee_value.is_none() {
                return fallback(self, host);
            }
            let callee_value_bits = active_callee_value
                .unwrap_or_else(RuntimeValue::undefined)
                .encoded()
                .0;
            let window = active_frame.register_window;
            let Some(platform_residency_index) = self
                .platform_residency_index_for_native_entry(dispatch.readiness, dispatch.descriptor)
            else {
                return fallback(self, host);
            };
            let Ok(frame_base) = self
                .registers
                .borrow_active_frame_base_for_raw_native_entry(window)
            else {
                return fallback(self, host);
            };
            // Baseline data-IC record store base seeded into r13
            // (GPRInfo::jitDataRegister) by the P6 prologue. Mirrors C++ baseline
            // code addressing `BaselineJITData` via the jitDataRegister.
            //
            // CAVEAT (CodeBlock::Clone vs the resident store): the `code_block`
            // argument may be a CLONE of the registered code block (callers pass a
            // borrowed/cloned `&CodeBlock`), and a clone deep-copies the data-IC `Box`
            // into a NEW base that generated code never addresses and that the P10-miss
            // writeback never mutates. The store r13 must point at is the ONE
            // registry-held `Rc`-shared instance whose store STEP A installed and
            // STEP C writes back -- so seed r13 from the registered instance, not the
            // argument. When the store is absent / has zero IC sites, supply a dangling
            // pointer: the self-load DataIC is only emitted for sites with a sized
            // store (a non-empty store base is present whenever any GetByName self-load
            // fast path can run), and non-DataIC entries only move r13 into a
            // callee-saved register without dereferencing it (the P9 dangling
            // metadata-table fallback analog).
            let ic_store_base = self
                .code_blocks
                .get(dispatch.code_block_id)
                .map(|registered| registered.code_block())
                .and_then(|resident| resident.baseline_jit_data_record_store_base())
                .and_then(|base| NonNull::new(base as *mut c_void))
                .unwrap_or_else(NonNull::<c_void>::dangling);
            let call_result = match invocation {
                P6X86_64CallableNativeInvocation::Entry { entry_offset } => self
                    .baseline_platform_executable_residencies[platform_residency_index]
                    .evidence
                    .compartment
                    .call_p6_x86_64_entry(ExecutableMemoryP6CallRequest::new(
                        entry_offset,
                        vm,
                        frame_base.as_non_null(),
                        callee_value_bits,
                        ic_store_base,
                    )),
                P6X86_64CallableNativeInvocation::P6SideExitReentry(reentry) => self
                    .baseline_platform_executable_residencies[platform_residency_index]
                    .evidence
                    .compartment
                    .call_p6_x86_64_entry(reentry.call_request(
                        vm,
                        frame_base.as_non_null(),
                        callee_value_bits,
                        ic_store_base,
                    )),
                P6X86_64CallableNativeInvocation::P9OwnerPostCallReentry(reentry) => {
                    let Some(metadata_table_base) =
                        NonNull::new(reentry.metadata_table_base_address as *mut c_void)
                    else {
                        return BaselineNativeEntryVmExecution::Native(
                            ExecutionCompletion::Failed(
                                ExecutionError::BaselineGeneratedExecutionRejected,
                            ),
                        );
                    };
                    self.baseline_platform_executable_residencies[platform_residency_index]
                        .evidence
                        .compartment
                        .call_p9_x86_64_owner_post_call_reentry(
                            ExecutableMemoryP9PostCallReentryRequest::new(
                                reentry.entry_offset,
                                vm,
                                frame_base.as_non_null(),
                                reentry.result_bits,
                                metadata_table_base,
                                callee_value_bits,
                            ),
                        )
                }
            };

            let Ok(result) = call_result else {
                return fallback(self, host);
            };
            match p6_p9_p10_p14_x86_64_callable_native_return_payload(result.encoded_js_value_bits)
            {
                Ok(Some(P6P9P10P14X86_64CallableNativeReturnPayload::P6(payload))) => {
                    match self
                        .execute_p6_x86_64_callable_retained_native_exit_payload_in_current_region(
                            code_block, &dispatch, payload, host, config,
                        ) {
                        BaselineNativeEntryVmExecution::P6SideExitReentry(reentry) => {
                            invocation =
                                P6X86_64CallableNativeInvocation::P6SideExitReentry(
                                    P6NativeSideExitReentryCallBridge::new(reentry),
                                );
                            continue;
                        }
                        execution => return execution,
                    }
                }
                Ok(Some(P6P9P10P14X86_64CallableNativeReturnPayload::P9(payload))) => {
                    match self
                        .execute_p9_x86_64_callable_retained_js_call_native_exit_payload_in_current_region(
                            code_block, &dispatch, payload, host, config,
                        ) {
                        BaselineNativeEntryVmExecution::P9OwnerPostCallReentry(reentry) => {
                            invocation =
                                P6X86_64CallableNativeInvocation::P9OwnerPostCallReentry(reentry);
                            continue;
                        }
                        execution => return execution,
                    }
                }
                Ok(Some(P6P9P10P14X86_64CallableNativeReturnPayload::P10(payload))) => {
                    return self
                        .execute_p10_x86_64_callable_retained_property_native_exit_payload_in_current_region(
                            code_block, &dispatch, payload, host, config,
                        );
                }
                Ok(Some(P6P9P10P14X86_64CallableNativeReturnPayload::P14(payload))) => {
                    let next_entry_offset = match self
                        .execute_p14_x86_64_callable_loop_backedge_safepoint_in_current_region(
                            code_block, &dispatch, payload,
                        ) {
                        Ok(entry_offset) => entry_offset,
                        Err(error) => {
                            return BaselineNativeEntryVmExecution::Native(
                                ExecutionCompletion::Failed(error),
                            )
                        }
                    };
                    if remaining_native_backedges == 0 {
                        return BaselineNativeEntryVmExecution::Native(
                            ExecutionCompletion::Failed(ExecutionError::DispatchStepLimitExceeded),
                        );
                    }
                    remaining_native_backedges = remaining_native_backedges.saturating_sub(1);
                    invocation = P6X86_64CallableNativeInvocation::Entry {
                        entry_offset: next_entry_offset,
                    };
                    continue;
                }
                Ok(None) => {}
                Err(error) => {
                    return BaselineNativeEntryVmExecution::Native(ExecutionCompletion::Failed(
                        error,
                    ));
                }
            }

            return BaselineNativeEntryVmExecution::Native(ExecutionCompletion::Returned(
                RuntimeValue::from_encoded(EncodedJsValue(result.encoded_js_value_bits)),
            ));
        }
    }

    fn execute_p6_x86_64_callable_retained_native_exit_payload_in_current_region<
        H: DispatchHost,
    >(
        &mut self,
        code_block: &CodeBlock,
        dispatch: &P6EmittedNativeDispatch<'_>,
        payload: P6X86_64BaselineSideExitReturnPayload,
        host: &mut H,
        config: DispatchConfig,
    ) -> BaselineNativeEntryVmExecution {
        let runtime_helper = self
            .p6_x86_64_callable_runtime_helper_native_exit_return_site_for_payload(
                dispatch, payload,
            );
        let side_exit =
            self.p6_x86_64_callable_side_exit_return_site_for_payload(dispatch, payload);

        match (runtime_helper, side_exit) {
            (Some(runtime_helper), None) => self
                .execute_p6_x86_64_callable_runtime_helper_native_exit_in_current_region(
                    code_block,
                    dispatch,
                    runtime_helper,
                    host,
                    config,
                ),
            (None, Some(side_exit)) => {
                self.record_p6_x86_64_callable_side_exit_fallback(dispatch, &side_exit, code_block);
                self.execute_p6_x86_64_callable_side_exit_fallback_in_current_region(
                    code_block, dispatch, side_exit, host, config,
                )
            }
            (None, None) | (Some(_), Some(_)) => BaselineNativeEntryVmExecution::Native(
                ExecutionCompletion::Failed(ExecutionError::BaselineGeneratedExecutionRejected),
            ),
        }
    }

    fn execute_p6_x86_64_callable_side_exit_fallback_in_current_region<H: DispatchHost>(
        &mut self,
        code_block: &CodeBlock,
        dispatch: &P6EmittedNativeDispatch<'_>,
        side_exit: P6X86_64CallableSideExitReturnSite,
        host: &mut H,
        config: DispatchConfig,
    ) -> BaselineNativeEntryVmExecution {
        let mut active_register_roots = Vec::new();
        let mut active_frame_roots = Vec::new();
        if let Err(error) = self.sync_generated_direct_call_deferred_nonlocal_roots(
            dispatch.expected_frame,
            host,
            &mut active_register_roots,
            &mut active_frame_roots,
        ) {
            let cleanup = cleanup_targeted_root_sets(
                &mut self.heap,
                &mut active_register_roots,
                &mut active_frame_roots,
            );
            return BaselineNativeEntryVmExecution::Native(ExecutionCompletion::Failed(
                cleanup.err().unwrap_or(error),
            ));
        }
        let completion = if Self::p6_x86_64_callable_side_exit_single_dispatch_resume_allowed(
            code_block, &side_exit,
        ) {
            let outcome = execute_single_dispatch(
                InterpreterExecutionState {
                    stack: &mut self.execution,
                    registers: &mut self.registers,
                    exceptions: &mut self.exceptions,
                    heap: &mut self.heap,
                },
                SingleDispatchRequest::new(
                    dispatch.code_block_id,
                    dispatch.expected_frame,
                    side_exit.bytecode_index,
                ),
                code_block,
                host,
            );
            let native_reentry = match self.p6_x86_64_callable_side_exit_native_reentry_invocation(
                code_block, dispatch, &side_exit, &outcome,
            ) {
                Ok(native_reentry) => native_reentry,
                Err(error) => {
                    let cleanup = cleanup_targeted_root_sets(
                        &mut self.heap,
                        &mut active_register_roots,
                        &mut active_frame_roots,
                    );
                    return BaselineNativeEntryVmExecution::Native(ExecutionCompletion::Failed(
                        cleanup.err().unwrap_or(error),
                    ));
                }
            };
            if let Some(native_reentry) = native_reentry {
                let completion = match cleanup_targeted_root_sets(
                    &mut self.heap,
                    &mut active_register_roots,
                    &mut active_frame_roots,
                ) {
                    Ok(()) => {
                        return BaselineNativeEntryVmExecution::P6SideExitReentry(native_reentry)
                    }
                    Err(error) => ExecutionCompletion::Failed(error),
                };
                return BaselineNativeEntryVmExecution::Native(completion);
            }
            self.finish_generated_single_dispatch_handoff_in_current_region(
                GeneratedSingleDispatchResume {
                    owner: dispatch.code_block_id,
                    frame: dispatch.expected_frame,
                    bytecode_index: side_exit.bytecode_index,
                },
                outcome,
                code_block,
                host,
                config,
            )
        } else {
            let request = BaselineFallbackRequest::new(
                dispatch.code_block_id,
                dispatch.expected_frame,
                side_exit.bytecode_index,
            );
            self.execute_baseline_fallback_in_current_region(request, code_block, host, config)
        };
        if self.generated_direct_call_deferred_rooting_is_active() {
            return BaselineNativeEntryVmExecution::DeferredRootedInterpreterFallback {
                completion,
                roots: BaselineNativeEntryDeferredRoots {
                    active_register_roots,
                    active_frame_roots,
                },
            };
        }
        let completion = match cleanup_targeted_root_sets(
            &mut self.heap,
            &mut active_register_roots,
            &mut active_frame_roots,
        ) {
            Ok(()) => completion,
            Err(error) => ExecutionCompletion::Failed(error),
        };
        BaselineNativeEntryVmExecution::InterpreterFallback(completion)
    }

    fn p6_x86_64_callable_side_exit_native_reentry_invocation(
        &self,
        code_block: &CodeBlock,
        dispatch: &P6EmittedNativeDispatch<'_>,
        side_exit: &P6X86_64CallableSideExitReturnSite,
        outcome: &SingleDispatchOutcome,
    ) -> Result<Option<P6CallableSideExitNativeReentryInvocation>, ExecutionError> {
        let opcode = p6_core_opcode_at_bytecode_index(code_block, side_exit.bytecode_index);
        let Some(native_reentry_target) =
            p6_side_exit_native_reentry_target_for_single_dispatch_outcome(
                side_exit, opcode, outcome,
            )
        else {
            return Ok(None);
        };
        let bytecode_snapshot =
            BaselineBytecodeEligibilityProof::fingerprint_code_block_snapshot(code_block)
                .map_err(|_| ExecutionError::BaselineGeneratedExecutionRejected)?;
        if bytecode_snapshot != dispatch.bytecode_snapshot {
            return Err(ExecutionError::BaselineGeneratedExecutionRejected);
        }
        code_block
            .decoded_instruction_at(native_reentry_target.resume_bytecode_index)
            .map_err(|_| ExecutionError::BaselineGeneratedExecutionRejected)?;
        let entry_offset = p6_allocation_relative_entry_offset_for_side_exit_resume(
            dispatch,
            native_reentry_target.resume_entry_offset,
        )?;
        Ok(Some(P6CallableSideExitNativeReentryInvocation {
            entry_offset,
        }))
    }

    fn p6_x86_64_callable_side_exit_single_dispatch_resume_allowed(
        code_block: &CodeBlock,
        side_exit: &P6X86_64CallableSideExitReturnSite,
    ) -> bool {
        let Some(opcode) = p6_core_opcode_at_bytecode_index(code_block, side_exit.bytecode_index)
        else {
            return false;
        };
        if matches!(
            (side_exit.reason, opcode),
            (
                P6X86_64BaselineSelectedSideExitReason::NonInt32Operand
                    | P6X86_64BaselineSelectedSideExitReason::Overflow,
                CoreOpcode::AddInt32 | CoreOpcode::SubInt32 | CoreOpcode::MulInt32
            ) | (
                P6X86_64BaselineSelectedSideExitReason::NegativeZero,
                CoreOpcode::MulInt32
            ) | (
                P6X86_64BaselineSelectedSideExitReason::UnsupportedToNumberOperand,
                CoreOpcode::ToNumber
            )
        ) {
            return true;
        }

        if side_exit.reason != P6X86_64BaselineSelectedSideExitReason::UnsupportedTruthinessOperand
            || opcode != CoreOpcode::JumpIfFalse
        {
            return false;
        }
        p6_jump_if_false_truthiness_side_exit_single_dispatch_native_resume_allowed(
            code_block, side_exit,
        )
    }

    fn cleanup_baseline_native_entry_deferred_roots(
        &mut self,
        mut roots: BaselineNativeEntryDeferredRoots,
    ) -> Result<(), ExecutionError> {
        cleanup_targeted_root_sets(
            &mut self.heap,
            &mut roots.active_register_roots,
            &mut roots.active_frame_roots,
        )
    }

    fn execute_p6_x86_64_callable_runtime_helper_native_exit_in_current_region<H: DispatchHost>(
        &mut self,
        code_block: &CodeBlock,
        dispatch: &P6EmittedNativeDispatch<'_>,
        site: P6X86_64CallableRuntimeHelperNativeExitReturnSite,
        host: &mut H,
        config: DispatchConfig,
    ) -> BaselineNativeEntryVmExecution {
        let Ok(current_snapshot) =
            BaselineBytecodeEligibilityProof::fingerprint_code_block_snapshot(code_block)
        else {
            return BaselineNativeEntryVmExecution::Native(ExecutionCompletion::Failed(
                ExecutionError::BaselineGeneratedExecutionRejected,
            ));
        };
        if current_snapshot != dispatch.bytecode_snapshot {
            return BaselineNativeEntryVmExecution::Native(ExecutionCompletion::Failed(
                ExecutionError::BaselineGeneratedExecutionRejected,
            ));
        }
        let handoff = site.handoff_for_dispatch(dispatch);
        let outcome = self
            .dispatch_generated_runtime_helper_handoff_in_current_region(handoff, code_block, host);
        BaselineNativeEntryVmExecution::Native(
            self.finish_generated_single_dispatch_handoff_in_current_region(
                GeneratedSingleDispatchResume::from_runtime_helper(handoff),
                outcome,
                code_block,
                host,
                config,
            ),
        )
    }

    fn execute_p9_x86_64_callable_retained_js_call_native_exit_payload_in_current_region<
        H: DispatchHost,
    >(
        &mut self,
        code_block: &CodeBlock,
        dispatch: &P6EmittedNativeDispatch<'_>,
        payload: P9X86_64BaselineJsCallNativeExitReturnPayload,
        host: &mut H,
        config: DispatchConfig,
    ) -> BaselineNativeEntryVmExecution {
        let site = match self
            .p9_x86_64_callable_js_call_native_exit_return_site_for_payload(dispatch, payload)
        {
            Ok(site) => site,
            Err(error) => {
                return BaselineNativeEntryVmExecution::Native(ExecutionCompletion::Failed(error))
            }
        };
        if let Err(error) =
            self.validate_p9_x86_64_callable_js_call_native_exit_site(code_block, dispatch, &site)
        {
            return BaselineNativeEntryVmExecution::Native(ExecutionCompletion::Failed(error));
        }
        let owner_post_call_proof =
            if matches!(site.opcode, CoreOpcode::Call | CoreOpcode::CallWithThis) {
                let proof = match self
                    .p9_x86_64_owner_post_call_return_target_proof_for_payload(dispatch, payload)
                {
                    Ok(proof) => proof,
                    Err(error) => {
                        return BaselineNativeEntryVmExecution::Native(ExecutionCompletion::Failed(
                            error,
                        ))
                    }
                };
                if let Err(error) = self
                    .validate_p9_x86_64_owner_post_call_return_target_proof_for_site(
                        dispatch, &site, &proof,
                    )
                {
                    return BaselineNativeEntryVmExecution::Native(ExecutionCompletion::Failed(
                        error,
                    ));
                }
                Some(proof)
            } else {
                None
            };

        let Some(active_frame) = self.execution.top_frame() else {
            return BaselineNativeEntryVmExecution::Native(ExecutionCompletion::Failed(
                ExecutionError::NoActiveFrame,
            ));
        };
        if active_frame.id != dispatch.expected_frame
            || active_frame.code_block != Some(dispatch.code_block_id)
        {
            return BaselineNativeEntryVmExecution::Native(ExecutionCompletion::Failed(
                ExecutionError::BaselineGeneratedExecutionRejected,
            ));
        }
        let window = active_frame.register_window;
        self.execution.mark_top_bytecode_index(site.bytecode_index);
        let instruction = match code_block.decoded_instruction_at(site.bytecode_index) {
            Ok(instruction) => instruction,
            Err(_) => {
                return BaselineNativeEntryVmExecution::Native(ExecutionCompletion::Failed(
                    ExecutionError::BaselineGeneratedExecutionRejected,
                ))
            }
        };
        let mut handoff = {
            let execution = InterpreterExecutionState {
                stack: &mut self.execution,
                registers: &mut self.registers,
                exceptions: &mut self.exceptions,
                heap: &mut self.heap,
            };
            match baseline_generated_js_call_handoff(
                dispatch.code_block_id,
                dispatch.expected_frame,
                window,
                code_block,
                &execution,
                instruction,
            ) {
                Ok(handoff) => handoff,
                Err(_) => {
                    return BaselineNativeEntryVmExecution::Native(ExecutionCompletion::Failed(
                        ExecutionError::BaselineGeneratedExecutionRejected,
                    ))
                }
            }
        };
        if let Err(error) =
            self.validate_p9_x86_64_js_call_native_exit_handoff(&handoff, code_block, &site)
        {
            return BaselineNativeEntryVmExecution::Native(ExecutionCompletion::Failed(error));
        }

        let direct_call = if self.generated_direct_call_deferred_rooting_is_active() {
            None
        } else {
            match self.p9_x86_64_authorized_generated_js_direct_call_for_native_exit(
                &handoff, code_block, &site, host,
            ) {
                Ok(direct_call) => direct_call,
                Err(error) => {
                    return BaselineNativeEntryVmExecution::Native(ExecutionCompletion::Failed(
                        error,
                    ))
                }
            }
        };
        let Some(direct_call) = direct_call else {
            let resume = GeneratedSingleDispatchResume::from_js_call(&handoff);
            let outcome = self.dispatch_generated_js_call_handoff_in_current_region(
                handoff, code_block, host, config,
            );
            return BaselineNativeEntryVmExecution::Native(
                self.finish_generated_single_dispatch_handoff_in_current_region(
                    resume, outcome, code_block, host, config,
                ),
            );
        };
        handoff.direct_call = Some(Box::new(direct_call));
        let resume = GeneratedSingleDispatchResume::from_js_call(&handoff);
        if let Some(proof) = owner_post_call_proof.as_ref() {
            match self.execute_generated_js_direct_call_transaction_with_return_mode(
                handoff,
                code_block,
                host,
                config,
                GeneratedJsDirectCallReturnMode::OwnerPostCallReentry(proof),
            ) {
                GeneratedJsDirectCallTransactionResult::P9OwnerPostCallReentry(reentry) => {
                    return BaselineNativeEntryVmExecution::P9OwnerPostCallReentry(reentry);
                }
                GeneratedJsDirectCallTransactionResult::Outcome(outcome) => {
                    return BaselineNativeEntryVmExecution::Native(
                        self.finish_generated_single_dispatch_handoff_in_current_region(
                            resume, outcome, code_block, host, config,
                        ),
                    );
                }
            }
        }
        let outcome = self.dispatch_generated_js_call_handoff_in_current_region(
            handoff, code_block, host, config,
        );
        BaselineNativeEntryVmExecution::Native(
            self.finish_generated_single_dispatch_handoff_in_current_region(
                resume, outcome, code_block, host, config,
            ),
        )
    }

    fn execute_p10_x86_64_callable_retained_property_native_exit_payload_in_current_region<
        H: DispatchHost,
    >(
        &mut self,
        code_block: &CodeBlock,
        dispatch: &P6EmittedNativeDispatch<'_>,
        payload: P10X86_64BaselinePropertyNativeExitReturnPayload,
        host: &mut H,
        config: DispatchConfig,
    ) -> BaselineNativeEntryVmExecution {
        let site = match self
            .p10_x86_64_callable_property_native_exit_return_site_for_payload(dispatch, payload)
        {
            Ok(site) => site,
            Err(error) => {
                return BaselineNativeEntryVmExecution::Native(ExecutionCompletion::Failed(error))
            }
        };
        let instruction = match self
            .validate_p10_x86_64_callable_property_native_exit_site(code_block, dispatch, &site)
        {
            Ok(instruction) => instruction,
            Err(error) => {
                return BaselineNativeEntryVmExecution::Native(ExecutionCompletion::Failed(error))
            }
        };
        let handoff = match baseline_generated_property_handoff(
            dispatch.code_block_id,
            dispatch.expected_frame,
            instruction,
            &site.site,
        ) {
            Ok(handoff) => handoff,
            Err(_) => {
                return BaselineNativeEntryVmExecution::Native(ExecutionCompletion::Failed(
                    ExecutionError::BaselineGeneratedExecutionRejected,
                ))
            }
        };
        if handoff.requires_no_gc_exit_reentry != site.site.requires_no_gc_exit_reentry
            || handoff.may_throw != site.site.may_throw
        {
            return BaselineNativeEntryVmExecution::Native(ExecutionCompletion::Failed(
                ExecutionError::BaselineGeneratedExecutionRejected,
            ));
        }

        // FIX 3: a GetByName property native exit reaching this slow path means the
        // inline self-load DataIC fast path did NOT satisfy the load this time (the
        // record was SENTINEL/unfilled, or its runtime structure guard missed). Count
        // it so DataIC residency is measurable: once the record is written back and the
        // base structure stabilizes, the structure guard hits inline and stays
        // resident, so this slow-path-exit count flattens. GetByName is the only
        // DataIC-admissible self-load opcode (`p10_select_property_native_exit`), so it
        // is the right residency signal.
        if site.site.opcode == CoreOpcode::GetByName {
            self.tiering.record_data_ic_self_load_slow_path_exit();
        }

        if matches!(
            site.site.opcode,
            CoreOpcode::GetByName | CoreOpcode::GetGlobalObjectProperty | CoreOpcode::GetByValue
        ) {
            match self.execute_p11_property_load_sidecar_for_p10_native_exit_in_current_region(
                code_block,
                dispatch,
                instruction,
                &site.site,
                host,
                config,
            ) {
                Ok(Some(completion)) => {
                    return BaselineNativeEntryVmExecution::Native(completion);
                }
                Ok(None) => {}
                Err(error) => {
                    return BaselineNativeEntryVmExecution::Native(ExecutionCompletion::Failed(
                        error,
                    ));
                }
            }
        } else if matches!(
            site.site.opcode,
            CoreOpcode::PutByName | CoreOpcode::PutGlobalObjectProperty | CoreOpcode::PutByValue
        ) {
            match self.execute_p13_property_store_sidecar_for_p10_native_exit_in_current_region(
                code_block,
                dispatch,
                instruction,
                &site.site,
                host,
                config,
            ) {
                Ok(Some(completion)) => {
                    return BaselineNativeEntryVmExecution::Native(completion);
                }
                Ok(None) => {}
                Err(error) => {
                    return BaselineNativeEntryVmExecution::Native(ExecutionCompletion::Failed(
                        error,
                    ));
                }
            }
        } else if matches!(site.site.opcode, CoreOpcode::InById | CoreOpcode::InByVal) {
            match self.execute_p13_property_has_sidecar_for_p10_native_exit_in_current_region(
                code_block,
                dispatch,
                instruction,
                &site.site,
                host,
                config,
            ) {
                Ok(Some(completion)) => {
                    return BaselineNativeEntryVmExecution::Native(completion);
                }
                Ok(None) => {}
                Err(error) => {
                    return BaselineNativeEntryVmExecution::Native(ExecutionCompletion::Failed(
                        error,
                    ));
                }
            }
        }

        let resume = GeneratedSingleDispatchResume::from_property(handoff);
        let outcome = self.dispatch_generated_property_handoff_in_current_region(
            handoff, code_block, host, config,
        );
        BaselineNativeEntryVmExecution::Native(
            self.finish_generated_single_dispatch_handoff_in_current_region(
                resume, outcome, code_block, host, config,
            ),
        )
    }

    fn execute_p14_x86_64_callable_loop_backedge_safepoint_in_current_region(
        &mut self,
        code_block: &CodeBlock,
        dispatch: &P6EmittedNativeDispatch<'_>,
        payload: P14X86_64BaselineLoopBackedgeReturnPayload,
    ) -> Result<u32, ExecutionError> {
        let site =
            self.p14_x86_64_callable_loop_backedge_return_site_for_payload(dispatch, payload)?;
        let bytecode_snapshot =
            BaselineBytecodeEligibilityProof::fingerprint_code_block_snapshot(code_block)
                .map_err(|_| ExecutionError::BaselineGeneratedExecutionRejected)?;
        if bytecode_snapshot != dispatch.bytecode_snapshot {
            return Err(ExecutionError::BaselineGeneratedExecutionRejected);
        }
        let active_frame = self
            .execution
            .top_frame()
            .ok_or(ExecutionError::NoActiveFrame)?;
        if active_frame.id != dispatch.expected_frame
            || active_frame.code_block != Some(dispatch.code_block_id)
        {
            return Err(ExecutionError::BaselineGeneratedExecutionRejected);
        }
        if site.owner != dispatch.code_block_id || site.owner != dispatch.descriptor.owner {
            return Err(ExecutionError::BaselineGeneratedExecutionRejected);
        }
        let instruction = code_block
            .decoded_instruction_at(site.bytecode_index)
            .map_err(|_| ExecutionError::BaselineGeneratedExecutionRejected)?;
        if CoreOpcode::from_opcode(instruction.opcode) != Some(site.opcode)
            || p14_branch_kind_for_opcode(site.opcode) != Some(site.kind)
        {
            return Err(ExecutionError::BaselineGeneratedExecutionRejected);
        }
        let target_operand_index = match site.opcode {
            CoreOpcode::Jump => 0,
            CoreOpcode::JumpIfNotNullish | CoreOpcode::JumpIfFalse => 1,
            _ => return Err(ExecutionError::BaselineGeneratedExecutionRejected),
        };
        let target = instruction
            .bytecode_index_operand(target_operand_index)
            .map_err(|_| ExecutionError::BaselineGeneratedExecutionRejected)?;
        if target != site.target_bytecode_index || target >= site.bytecode_index {
            return Err(ExecutionError::BaselineGeneratedExecutionRejected);
        }
        code_block
            .decoded_instruction_at(target)
            .map_err(|_| ExecutionError::BaselineGeneratedExecutionRejected)?;

        let entry_offset = p14_allocation_relative_entry_offset_for_loop_backedge(dispatch, site)?;
        self.execution.mark_top_bytecode_index(site.bytecode_index);
        self.tiering.observe_loop_backedge(
            dispatch.code_block_id,
            self.config.tiering_policy(),
            site.bytecode_index,
        );
        Ok(entry_offset)
    }

    fn execute_p11_property_load_sidecar_for_p10_native_exit_in_current_region<H: DispatchHost>(
        &mut self,
        code_block: &CodeBlock,
        dispatch: &P6EmittedNativeDispatch<'_>,
        instruction: DecodedInstruction<'_>,
        site: &BaselineGeneratedPropertyHandoffSite,
        host: &mut H,
        config: DispatchConfig,
    ) -> Result<Option<ExecutionCompletion>, ExecutionError> {
        let bytecode_snapshot =
            BaselineBytecodeEligibilityProof::fingerprint_code_block_snapshot(code_block)
                .map_err(|_| ExecutionError::BaselineGeneratedExecutionRejected)?;
        if bytecode_snapshot != dispatch.bytecode_snapshot {
            return Err(ExecutionError::BaselineGeneratedExecutionRejected);
        }
        self.drain_pending_property_load_runtime_invalidations(host);

        let attached_property_ic_candidates = self
            .code_blocks
            .attached_property_inline_cache_candidates_for_owner(
                dispatch.code_block_id,
                bytecode_snapshot,
                self.tiering.property_inline_cache_attachment_records(),
            );
        let structure_stub_property_ic_candidates = self
            .code_blocks
            .structure_stub_property_inline_cache_candidates_for_owner(
                dispatch.code_block_id,
                bytecode_snapshot,
                self.tiering.property_inline_cache_attachment_records(),
            );
        let Ok(property_load_plan_table) = self
            .tiering
            .property_load_access_case_plan_table_for_owner_with_attached_and_structure_stubs(
                dispatch.code_block_id,
                bytecode_snapshot,
                &attached_property_ic_candidates,
                &structure_stub_property_ic_candidates,
            )
        else {
            return Ok(None);
        };
        let Ok(guarded_candidate_table) = self
            .tiering
            .property_load_guarded_candidate_table_for_owner_with_attached(
                dispatch.code_block_id,
                bytecode_snapshot,
                &attached_property_ic_candidates,
            )
        else {
            return Ok(None);
        };
        let Ok(megamorphic_load_candidate_table) = self
            .tiering
            .generated_property_load_megamorphic_candidate_table_for_owner(
                dispatch.code_block_id,
                bytecode_snapshot,
            )
        else {
            return Ok(None);
        };
        let store_candidate_table = self
            .tiering
            .property_store_mutation_candidate_table_for_owner_with_attached(
                dispatch.code_block_id,
                bytecode_snapshot,
                &attached_property_ic_candidates,
            )
            .ok();
        let megamorphic_store_candidate_table = self
            .tiering
            .generated_property_store_megamorphic_candidate_table_for_owner(
                dispatch.code_block_id,
                bytecode_snapshot,
            )
            .ok();
        let has_store_sidecar_table = store_candidate_table
            .as_ref()
            .is_some_and(|table| !table.is_empty())
            || megamorphic_store_candidate_table
                .as_ref()
                .is_some_and(|table| !table.is_empty());
        if property_load_plan_table.is_empty()
            && guarded_candidate_table.is_empty()
            && megamorphic_load_candidate_table.is_empty()
        {
            return Ok(None);
        }

        let active_frame = self
            .execution
            .top_frame()
            .ok_or(ExecutionError::NoActiveFrame)?;
        if active_frame.id != dispatch.expected_frame
            || active_frame.code_block != Some(dispatch.code_block_id)
        {
            return Err(ExecutionError::BaselineGeneratedExecutionRejected);
        }
        let window = active_frame.register_window;
        self.execution.mark_top_bytecode_index(site.bytecode_index);

        let (
            result,
            destination_root_sync_requests,
            probe_miss_records,
            guarded_probe_miss_records,
            store_probe_miss_records,
            store_mutation_rejection_records,
        ) = {
            let mut sidecars = BaselineGeneratedPropertyExecutionSidecars::new(
                host,
                Some((&property_load_plan_table, &guarded_candidate_table)),
                store_candidate_table
                    .as_ref()
                    .filter(|table| !table.is_empty()),
            )
            .with_property_load_megamorphic_candidate_table(Some(&megamorphic_load_candidate_table))
            .with_property_store_megamorphic_candidate_table(
                megamorphic_store_candidate_table
                    .as_ref()
                    .filter(|table| !table.is_empty()),
            );
            let attempt = BaselineGeneratedPropertyLoadSidecarProbeAttempt {
                owner: dispatch.code_block_id,
                frame: dispatch.expected_frame,
                window,
                code_block,
                instruction,
                site,
            };
            let property_handoff_plan_derivation = if has_store_sidecar_table
                && site.opcode == CoreOpcode::GetByName
            {
                derive_baseline_generated_property_handoff_plan_from_current_code_block_metadata(
                    code_block,
                    dispatch.code_block_id,
                )
                .ok()
            } else {
                None
            };
            let property_handoff_plan = property_handoff_plan_derivation
                .as_ref()
                .and_then(|derivation| derivation.metadata.as_ref())
                .map(|metadata| metadata.borrowed_plan());
            let increment_numeric_mode = if self.generated_direct_call_deferred_rooting_is_active()
            {
                BaselineGeneratedPropertyIncrementNumericMode::Int32NoOverflow
            } else {
                BaselineGeneratedPropertyIncrementNumericMode::AnyNumber
            };
            let result = if has_store_sidecar_table && site.opcode == CoreOpcode::GetByName {
                execute_baseline_generated_property_load_or_increment_sidecar_probe(
                    &mut sidecars,
                    &mut InterpreterExecutionState {
                        stack: &mut self.execution,
                        registers: &mut self.registers,
                        exceptions: &mut self.exceptions,
                        heap: &mut self.heap,
                    },
                    attempt,
                    property_handoff_plan,
                    increment_numeric_mode,
                )
            } else {
                execute_baseline_generated_property_load_sidecar_probe(
                    &mut sidecars,
                    &mut InterpreterExecutionState {
                        stack: &mut self.execution,
                        registers: &mut self.registers,
                        exceptions: &mut self.exceptions,
                        heap: &mut self.heap,
                    },
                    attempt,
                )
                .map(|hit| hit.map(BaselineGeneratedPropertyLoadOrIncrementSidecarProbeResult::Hit))
            }
            .map_err(|error| match error {
                BaselineGeneratedExecutionError::Execution(error) => error,
                _ => ExecutionError::BaselineGeneratedExecutionRejected,
            })?;
            (
                result,
                sidecars.destination_root_sync_requests().to_vec(),
                sidecars.property_load_probe_miss_records().to_vec(),
                sidecars.guarded_property_load_probe_miss_records().to_vec(),
                sidecars.property_store_probe_miss_records().to_vec(),
                sidecars
                    .property_store_mutation_rejection_records()
                    .to_vec(),
            )
        };

        self.record_generated_property_load_sidecar_probe_miss_records(
            bytecode_snapshot,
            &probe_miss_records,
            &guarded_probe_miss_records,
        );
        self.record_generated_property_store_sidecar_probe_miss_records(
            bytecode_snapshot,
            &store_probe_miss_records,
        );
        for rejection in store_mutation_rejection_records {
            self.tiering
                .record_generated_property_store_mutation_rejection(
                    VmGeneratedPropertyStoreMutationRejectionRequest {
                        owner: rejection.owner,
                        bytecode_index: rejection.bytecode_index,
                        bytecode_snapshot,
                        slot: rejection.slot,
                        store_plan_ordinal: rejection.store_plan_ordinal,
                        readiness_ordinal: rejection.readiness_ordinal,
                        key: rejection.key,
                        plan_kind: rejection.plan_kind,
                        base_structure: rejection.base_structure,
                        planned_new_structure: rejection.planned_new_structure,
                        planned_offset: rejection.offset,
                        stored_value_kind: rejection.stored_value_kind,
                        reason: rejection.reason,
                    },
                );
        }

        let Some(result) = result else {
            return Ok(None);
        };

        let mut active_destination_roots = Vec::new();
        let completion = match self.sync_generated_property_load_destination_roots(
            host,
            &destination_root_sync_requests,
            &mut active_destination_roots,
        ) {
            Ok(()) => match result {
                BaselineGeneratedPropertyLoadOrIncrementSidecarProbeResult::Hit(hit) => self
                    .finish_generated_single_dispatch_handoff_in_current_region(
                        GeneratedSingleDispatchResume {
                            owner: dispatch.code_block_id,
                            frame: dispatch.expected_frame,
                            bytecode_index: site.bytecode_index,
                        },
                        SingleDispatchOutcome::Continue(hit.next_bytecode_index),
                        code_block,
                        host,
                        config,
                    ),
                BaselineGeneratedPropertyLoadOrIncrementSidecarProbeResult::Property(handoff) => {
                    let resume = GeneratedSingleDispatchResume::from_property(handoff);
                    let outcome = self.dispatch_generated_property_handoff_in_current_region(
                        handoff, code_block, host, config,
                    );
                    self.finish_generated_single_dispatch_handoff_in_current_region(
                        resume, outcome, code_block, host, config,
                    )
                }
            },
            Err(error) => ExecutionCompletion::Failed(error),
        };
        Ok(Some(self.finish_generated_property_load_destination_roots(
            &mut active_destination_roots,
            completion,
        )))
    }

    fn execute_p13_property_store_sidecar_for_p10_native_exit_in_current_region<H: DispatchHost>(
        &mut self,
        code_block: &CodeBlock,
        dispatch: &P6EmittedNativeDispatch<'_>,
        instruction: DecodedInstruction<'_>,
        site: &BaselineGeneratedPropertyHandoffSite,
        host: &mut H,
        config: DispatchConfig,
    ) -> Result<Option<ExecutionCompletion>, ExecutionError> {
        let bytecode_snapshot =
            BaselineBytecodeEligibilityProof::fingerprint_code_block_snapshot(code_block)
                .map_err(|_| ExecutionError::BaselineGeneratedExecutionRejected)?;
        if bytecode_snapshot != dispatch.bytecode_snapshot {
            return Err(ExecutionError::BaselineGeneratedExecutionRejected);
        }

        let attached_property_ic_candidates = self
            .code_blocks
            .attached_property_inline_cache_candidates_for_owner(
                dispatch.code_block_id,
                bytecode_snapshot,
                self.tiering.property_inline_cache_attachment_records(),
            );
        let Ok(store_candidate_table) = self
            .tiering
            .property_store_mutation_candidate_table_for_owner_with_attached(
                dispatch.code_block_id,
                bytecode_snapshot,
                &attached_property_ic_candidates,
            )
        else {
            return Ok(None);
        };
        let Ok(megamorphic_store_candidate_table) = self
            .tiering
            .generated_property_store_megamorphic_candidate_table_for_owner(
                dispatch.code_block_id,
                bytecode_snapshot,
            )
        else {
            return Ok(None);
        };
        if store_candidate_table.is_empty() && megamorphic_store_candidate_table.is_empty() {
            return Ok(None);
        }

        let active_frame = self
            .execution
            .top_frame()
            .ok_or(ExecutionError::NoActiveFrame)?;
        if active_frame.id != dispatch.expected_frame
            || active_frame.code_block != Some(dispatch.code_block_id)
        {
            return Err(ExecutionError::BaselineGeneratedExecutionRejected);
        }
        let window = active_frame.register_window;
        self.execution.mark_top_bytecode_index(site.bytecode_index);

        let (hit, store_probe_miss_records, store_mutation_rejection_records) = {
            let mut sidecars = BaselineGeneratedPropertyExecutionSidecars::new(
                host,
                None,
                Some(&store_candidate_table),
            )
            .with_property_store_megamorphic_candidate_table(Some(
                &megamorphic_store_candidate_table,
            ));
            let hit = execute_baseline_generated_property_store_sidecar_probe(
                &mut sidecars,
                &mut InterpreterExecutionState {
                    stack: &mut self.execution,
                    registers: &mut self.registers,
                    exceptions: &mut self.exceptions,
                    heap: &mut self.heap,
                },
                BaselineGeneratedPropertyStoreSidecarProbeAttempt {
                    owner: dispatch.code_block_id,
                    frame: dispatch.expected_frame,
                    window,
                    code_block,
                    instruction,
                    site,
                },
            )
            .map_err(|error| match error {
                BaselineGeneratedExecutionError::Execution(error) => error,
                _ => ExecutionError::BaselineGeneratedExecutionRejected,
            })?;
            (
                hit,
                sidecars.property_store_probe_miss_records().to_vec(),
                sidecars
                    .property_store_mutation_rejection_records()
                    .to_vec(),
            )
        };

        self.record_generated_property_store_sidecar_probe_miss_records(
            bytecode_snapshot,
            &store_probe_miss_records,
        );
        for rejection in store_mutation_rejection_records {
            self.tiering
                .record_generated_property_store_mutation_rejection(
                    VmGeneratedPropertyStoreMutationRejectionRequest {
                        owner: rejection.owner,
                        bytecode_index: rejection.bytecode_index,
                        bytecode_snapshot,
                        slot: rejection.slot,
                        store_plan_ordinal: rejection.store_plan_ordinal,
                        readiness_ordinal: rejection.readiness_ordinal,
                        key: rejection.key,
                        plan_kind: rejection.plan_kind,
                        base_structure: rejection.base_structure,
                        planned_new_structure: rejection.planned_new_structure,
                        planned_offset: rejection.offset,
                        stored_value_kind: rejection.stored_value_kind,
                        reason: rejection.reason,
                    },
                );
        }

        let Some(hit) = hit else {
            return Ok(None);
        };

        Ok(Some(
            self.finish_generated_single_dispatch_handoff_in_current_region(
                GeneratedSingleDispatchResume {
                    owner: dispatch.code_block_id,
                    frame: dispatch.expected_frame,
                    bytecode_index: site.bytecode_index,
                },
                SingleDispatchOutcome::Continue(hit.next_bytecode_index),
                code_block,
                host,
                config,
            ),
        ))
    }

