    fn validate_p10_x86_64_callable_property_native_exit_site<'code>(
        &self,
        code_block: &'code CodeBlock,
        dispatch: &P6EmittedNativeDispatch<'_>,
        site: &P10X86_64CallablePropertyNativeExitReturnSite,
    ) -> Result<DecodedInstruction<'code>, ExecutionError> {
        if site.site.owner != dispatch.code_block_id
            || !matches!(
                site.site.opcode,
                CoreOpcode::GetByName
                    | CoreOpcode::GetGlobalObjectProperty
                    | CoreOpcode::PutByName
                    | CoreOpcode::PutGlobalObjectProperty
                    | CoreOpcode::GetByValue
                    | CoreOpcode::PutByValue
                    | CoreOpcode::InById
                    | CoreOpcode::InByVal
            )
            || site.encoded_payload.low_tag()
                != P10_X86_64_BASELINE_PROPERTY_NATIVE_EXIT_RETURN_PAYLOAD_LOW_TAG
        {
            return Err(ExecutionError::BaselineGeneratedExecutionRejected);
        }

        let active_frame = self
            .execution
            .top_frame()
            .ok_or(ExecutionError::NoActiveFrame)?;
        if active_frame.id != dispatch.expected_frame
            || active_frame.code_block != Some(dispatch.code_block_id)
        {
            return Err(ExecutionError::BaselineGeneratedExecutionRejected);
        }

        let current_snapshot =
            BaselineBytecodeEligibilityProof::fingerprint_code_block_snapshot(code_block)
                .map_err(|_| ExecutionError::BaselineGeneratedExecutionRejected)?;
        if current_snapshot != dispatch.bytecode_snapshot {
            return Err(ExecutionError::BaselineGeneratedExecutionRejected);
        }
        let registered_code_block = self
            .code_blocks
            .get(dispatch.code_block_id)
            .ok_or(ExecutionError::BaselineGeneratedExecutionRejected)?
            .code_block();
        let registered_snapshot =
            BaselineBytecodeEligibilityProof::fingerprint_code_block_snapshot(
                registered_code_block,
            )
            .map_err(|_| ExecutionError::BaselineGeneratedExecutionRejected)?;
        if registered_snapshot != dispatch.bytecode_snapshot {
            return Err(ExecutionError::BaselineGeneratedExecutionRejected);
        }

        validate_baseline_generated_property_handoff_site_metadata(&site.site)
            .map_err(|_| ExecutionError::BaselineGeneratedExecutionRejected)?;
        validate_baseline_generated_property_handoff_site_against_current_code_block(
            code_block,
            dispatch.code_block_id,
            &site.site,
        )
        .map_err(|_| ExecutionError::BaselineGeneratedExecutionRejected)?;

        let instruction = code_block
            .decoded_instruction_at(site.site.bytecode_index)
            .map_err(|_| ExecutionError::BaselineGeneratedExecutionRejected)?;
        let opcode = CoreOpcode::from_opcode(instruction.opcode)
            .ok_or(ExecutionError::BaselineGeneratedExecutionRejected)?;
        if opcode != site.site.opcode || instruction.bytecode_index != site.site.bytecode_index {
            return Err(ExecutionError::BaselineGeneratedExecutionRejected);
        }
        let expected_operand_count = if matches!(
            opcode,
            CoreOpcode::GetGlobalObjectProperty | CoreOpcode::PutGlobalObjectProperty
        ) {
            2
        } else {
            3
        };
        if instruction.operands.len() != expected_operand_count {
            return Err(ExecutionError::BaselineGeneratedExecutionRejected);
        }
        let property_key_from_operand =
            |operand_index: usize| -> Result<PropertyKey, ExecutionError> {
                match instruction
                    .operand(operand_index)
                    .map_err(|_| ExecutionError::BaselineGeneratedExecutionRejected)?
                {
                    crate::bytecode::Operand::IdentifierIndex(identifier_index) => {
                        Ok(PropertyKey::from_identifier(Identifier::from_atom(
                            AtomId::from_table_slot(identifier_index),
                        )))
                    }
                    _ => Err(ExecutionError::BaselineGeneratedExecutionRejected),
                }
            };
        match (opcode, site.operands) {
            (
                CoreOpcode::GetByName,
                P10X86_64BaselinePropertyNativeExitOperands::GetByName { destination, base },
            ) => {
                let actual_destination = instruction
                    .register_operand(0)
                    .map_err(|_| ExecutionError::BaselineGeneratedExecutionRejected)?;
                let actual_base = instruction
                    .register_operand(1)
                    .map_err(|_| ExecutionError::BaselineGeneratedExecutionRejected)?;
                let property_key = property_key_from_operand(2)?;
                if actual_destination != destination
                    || actual_base != base
                    || PropertyCacheKey::Key(property_key) != site.site.property_key
                {
                    return Err(ExecutionError::BaselineGeneratedExecutionRejected);
                }
            }
            (
                CoreOpcode::GetLength,
                P10X86_64BaselinePropertyNativeExitOperands::GetLength { destination, base },
            ) => {
                // Same `[dest, base, identifier]` shape as GetByName; slow-path-only
                // native exit, validated identically (FIX 2: GetLength is a canonical
                // property-handoff site).
                let actual_destination = instruction
                    .register_operand(0)
                    .map_err(|_| ExecutionError::BaselineGeneratedExecutionRejected)?;
                let actual_base = instruction
                    .register_operand(1)
                    .map_err(|_| ExecutionError::BaselineGeneratedExecutionRejected)?;
                let property_key = property_key_from_operand(2)?;
                if actual_destination != destination
                    || actual_base != base
                    || PropertyCacheKey::Key(property_key) != site.site.property_key
                {
                    return Err(ExecutionError::BaselineGeneratedExecutionRejected);
                }
            }
            (
                CoreOpcode::GetGlobalObjectProperty,
                P10X86_64BaselinePropertyNativeExitOperands::GetGlobalObjectProperty {
                    destination,
                },
            ) => {
                let actual_destination = instruction
                    .register_operand(0)
                    .map_err(|_| ExecutionError::BaselineGeneratedExecutionRejected)?;
                let property_key = property_key_from_operand(1)?;
                if actual_destination != destination
                    || PropertyCacheKey::Key(property_key) != site.site.property_key
                {
                    return Err(ExecutionError::BaselineGeneratedExecutionRejected);
                }
            }
            (
                CoreOpcode::PutByName,
                P10X86_64BaselinePropertyNativeExitOperands::PutByName { base, value },
            ) => {
                let actual_base = instruction
                    .register_operand(0)
                    .map_err(|_| ExecutionError::BaselineGeneratedExecutionRejected)?;
                let property_key = property_key_from_operand(1)?;
                let actual_value = instruction
                    .register_operand(2)
                    .map_err(|_| ExecutionError::BaselineGeneratedExecutionRejected)?;
                if actual_base != base
                    || PropertyCacheKey::Key(property_key) != site.site.property_key
                    || actual_value != value
                {
                    return Err(ExecutionError::BaselineGeneratedExecutionRejected);
                }
            }
            (
                CoreOpcode::PutGlobalObjectProperty,
                P10X86_64BaselinePropertyNativeExitOperands::PutGlobalObjectProperty { value },
            ) => {
                let property_key = property_key_from_operand(0)?;
                let actual_value = instruction
                    .register_operand(1)
                    .map_err(|_| ExecutionError::BaselineGeneratedExecutionRejected)?;
                if PropertyCacheKey::Key(property_key) != site.site.property_key
                    || actual_value != value
                {
                    return Err(ExecutionError::BaselineGeneratedExecutionRejected);
                }
            }
            (
                CoreOpcode::GetByValue,
                P10X86_64BaselinePropertyNativeExitOperands::GetByValue {
                    destination,
                    base,
                    property,
                },
            ) => {
                let actual_destination = instruction
                    .register_operand(0)
                    .map_err(|_| ExecutionError::BaselineGeneratedExecutionRejected)?;
                let actual_base = instruction
                    .register_operand(1)
                    .map_err(|_| ExecutionError::BaselineGeneratedExecutionRejected)?;
                let actual_property = instruction
                    .register_operand(2)
                    .map_err(|_| ExecutionError::BaselineGeneratedExecutionRejected)?;
                if actual_destination != destination
                    || actual_base != base
                    || actual_property != property
                    || PropertyCacheKey::RuntimeValue(actual_property) != site.site.property_key
                {
                    return Err(ExecutionError::BaselineGeneratedExecutionRejected);
                }
            }
            (
                CoreOpcode::PutByValue,
                P10X86_64BaselinePropertyNativeExitOperands::PutByValue {
                    base,
                    property,
                    value,
                },
            ) => {
                let actual_base = instruction
                    .register_operand(0)
                    .map_err(|_| ExecutionError::BaselineGeneratedExecutionRejected)?;
                let actual_property = instruction
                    .register_operand(1)
                    .map_err(|_| ExecutionError::BaselineGeneratedExecutionRejected)?;
                let actual_value = instruction
                    .register_operand(2)
                    .map_err(|_| ExecutionError::BaselineGeneratedExecutionRejected)?;
                if actual_base != base
                    || actual_property != property
                    || PropertyCacheKey::RuntimeValue(actual_property) != site.site.property_key
                    || actual_value != value
                {
                    return Err(ExecutionError::BaselineGeneratedExecutionRejected);
                }
            }
            (
                CoreOpcode::InById,
                P10X86_64BaselinePropertyNativeExitOperands::InById { destination, base },
            ) => {
                let actual_destination = instruction
                    .register_operand(0)
                    .map_err(|_| ExecutionError::BaselineGeneratedExecutionRejected)?;
                let actual_base = instruction
                    .register_operand(1)
                    .map_err(|_| ExecutionError::BaselineGeneratedExecutionRejected)?;
                let property_key = property_key_from_operand(2)?;
                if actual_destination != destination
                    || actual_base != base
                    || PropertyCacheKey::Key(property_key) != site.site.property_key
                {
                    return Err(ExecutionError::BaselineGeneratedExecutionRejected);
                }
            }
            (
                CoreOpcode::InByVal,
                P10X86_64BaselinePropertyNativeExitOperands::InByVal {
                    destination,
                    base,
                    property,
                },
            ) => {
                let actual_destination = instruction
                    .register_operand(0)
                    .map_err(|_| ExecutionError::BaselineGeneratedExecutionRejected)?;
                let actual_base = instruction
                    .register_operand(1)
                    .map_err(|_| ExecutionError::BaselineGeneratedExecutionRejected)?;
                let actual_property = instruction
                    .register_operand(2)
                    .map_err(|_| ExecutionError::BaselineGeneratedExecutionRejected)?;
                if actual_destination != destination
                    || actual_base != base
                    || actual_property != property
                    || PropertyCacheKey::RuntimeValue(actual_property) != site.site.property_key
                {
                    return Err(ExecutionError::BaselineGeneratedExecutionRejected);
                }
            }
            _ => return Err(ExecutionError::BaselineGeneratedExecutionRejected),
        }
        Ok(instruction)
    }

    fn validate_p9_x86_64_callable_js_call_native_exit_site(
        &self,
        code_block: &CodeBlock,
        dispatch: &P6EmittedNativeDispatch<'_>,
        site: &P9X86_64CallableJsCallNativeExitReturnSite,
    ) -> Result<(), ExecutionError> {
        if site.owner != dispatch.code_block_id
            || site.encoded_payload.low_tag()
                != P9_X86_64_BASELINE_JS_CALL_NATIVE_EXIT_RETURN_PAYLOAD_LOW_TAG
        {
            return Err(ExecutionError::BaselineGeneratedExecutionRejected);
        }
        let current_snapshot =
            BaselineBytecodeEligibilityProof::fingerprint_code_block_snapshot(code_block)
                .map_err(|_| ExecutionError::BaselineGeneratedExecutionRejected)?;
        if current_snapshot != dispatch.bytecode_snapshot {
            return Err(ExecutionError::BaselineGeneratedExecutionRejected);
        }
        let registered_code_block = self
            .code_blocks
            .get(dispatch.code_block_id)
            .ok_or(ExecutionError::BaselineGeneratedExecutionRejected)?
            .code_block();
        let registered_snapshot =
            BaselineBytecodeEligibilityProof::fingerprint_code_block_snapshot(
                registered_code_block,
            )
            .map_err(|_| ExecutionError::BaselineGeneratedExecutionRejected)?;
        if registered_snapshot != dispatch.bytecode_snapshot {
            return Err(ExecutionError::BaselineGeneratedExecutionRejected);
        }

        let plan_site = site.as_plan_site();
        validate_baseline_generated_js_call_native_exit_site_metadata(&plan_site)
            .map_err(|_| ExecutionError::BaselineGeneratedExecutionRejected)?;
        validate_baseline_generated_js_call_native_exit_site_against_code_block(
            code_block,
            dispatch.code_block_id,
            &plan_site,
        )
        .map_err(|_| ExecutionError::BaselineGeneratedExecutionRejected)?;
        Ok(())
    }

    fn validate_p9_x86_64_owner_post_call_return_target_proof_shape(
        &self,
        dispatch: &P6EmittedNativeDispatch<'_>,
        proof: &P9X86_64BaselineOwnerPostCallReturnTargetProof,
    ) -> Result<(), ExecutionError> {
        let result_profile_byte_len = proof
            .result_profile_end_offset
            .checked_sub(proof.result_profile_offset)
            .ok_or(ExecutionError::BaselineGeneratedExecutionRejected)?;
        let metadata_store_profile = proof.result_profile_status
            == P9X86_64BaselineOwnerCallResultProfileStatus::X86_64MetadataTableRelativeStore64;
        let expected_result_seed = if metadata_store_profile {
            P9X86_64BaselineOwnerPostCallReentryResultSeed::X86_64CAbiThirdArgumentRdxToRaxFourthArgumentRcxToR12
        } else {
            P9X86_64BaselineOwnerPostCallReentryResultSeed::X86_64CAbiThirdArgumentRdxToRax
        };
        let metadata_seed_shape_valid = if metadata_store_profile {
            proof.post_call_reentry_metadata_table_seed_offset
                == Some(proof.post_call_reentry_result_seed_end_offset)
                && proof
                    .post_call_reentry_metadata_table_seed_end_offset
                    .is_some_and(|end| end == proof.post_call_reentry_jump_offset)
                && proof.result_profile_binding.is_some_and(|binding| {
                    proof.post_call_reentry_metadata_table_base_address
                        == Some(binding.metadata_table_base_address)
                })
        } else {
            proof.post_call_reentry_metadata_table_seed_offset.is_none()
                && proof
                    .post_call_reentry_metadata_table_seed_end_offset
                    .is_none()
                && proof
                    .post_call_reentry_metadata_table_base_address
                    .is_none()
                && proof.post_call_reentry_result_seed_end_offset
                    == proof.post_call_reentry_jump_offset
        };
        if proof.owner != dispatch.code_block_id
            || proof.linked_size_bytes != dispatch.descriptor.machine_range.size_bytes
            || proof.post_call_target_start_offset == proof.native_exit_stub_start_offset
            || proof.post_call_target_start_offset == proof.resume_instruction_start_offset
            || proof.post_call_target_start_offset >= proof.post_call_target_end_offset
            || proof
                .post_call_target_end_offset
                .checked_sub(proof.post_call_target_start_offset)
                != Some(proof.post_call_target_byte_len)
            || proof.reset_sp_status
                != P9X86_64BaselineOwnerCallResetSpStatus::P6CallableAbiNoJsStackPointerRegister
            || proof.reset_sp_offset != proof.post_call_target_start_offset
            || proof.reset_sp_end_offset != proof.result_profile_offset
            || !matches!(
                proof.result_profile_status,
                P9X86_64BaselineOwnerCallResultProfileStatus::MetadataPending
                    | P9X86_64BaselineOwnerCallResultProfileStatus::DisabledByPolicy
                    | P9X86_64BaselineOwnerCallResultProfileStatus::X86_64MetadataTableRelativeStore64
            )
            || (metadata_store_profile && result_profile_byte_len != 8)
            || (!metadata_store_profile && result_profile_byte_len != 1)
            || !self
                .p9_x86_64_owner_post_call_result_profile_binding_matches_current_code_block(proof)
            || proof.result_profile_end_offset != proof.result_store_offset
            || proof.result_store_offset >= proof.resume_jump_offset
            || proof.resume_jump_end_offset > proof.post_call_target_end_offset
            || proof.post_call_reentry_stub_start_offset == proof.native_exit_stub_start_offset
            || proof.post_call_reentry_stub_start_offset == proof.post_call_target_start_offset
            || proof.post_call_reentry_stub_start_offset == proof.resume_instruction_start_offset
            || proof.post_call_reentry_stub_start_offset >= proof.post_call_reentry_stub_end_offset
            || proof
                .post_call_reentry_stub_end_offset
                .checked_sub(proof.post_call_reentry_stub_start_offset)
                != Some(proof.post_call_reentry_stub_byte_len)
            || proof.post_call_reentry_callable_prologue_offset
                != proof.post_call_reentry_stub_start_offset
            || proof.post_call_reentry_callable_prologue_end_offset
                != proof.post_call_reentry_result_seed_offset
            || proof.post_call_reentry_result_seed != expected_result_seed
            || !metadata_seed_shape_valid
            || proof.post_call_reentry_jump_end_offset > proof.post_call_reentry_stub_end_offset
            || proof.post_call_reentry_jump_target_start_offset
                != proof.post_call_target_start_offset
            || proof.post_call_reentry_stub_end_offset
                > dispatch.descriptor.machine_range.size_bytes
            || proof.post_call_target_end_offset > dispatch.descriptor.machine_range.size_bytes
        {
            return Err(ExecutionError::BaselineGeneratedExecutionRejected);
        }
        Ok(())
    }

    fn validate_p9_x86_64_owner_post_call_return_target_proof_for_site(
        &self,
        dispatch: &P6EmittedNativeDispatch<'_>,
        site: &P9X86_64CallableJsCallNativeExitReturnSite,
        proof: &P9X86_64BaselineOwnerPostCallReturnTargetProof,
    ) -> Result<(), ExecutionError> {
        if proof.encoded_payload != site.encoded_payload
            || proof.call_bytecode_index != site.bytecode_index
            || proof.opcode != site.opcode
            || proof.destination != site.destination
        {
            return Err(ExecutionError::BaselineGeneratedExecutionRejected);
        }
        self.validate_p9_x86_64_owner_post_call_return_target_proof_shape(dispatch, proof)
    }

    fn p9_x86_64_owner_post_call_result_profile_binding_matches_current_code_block(
        &self,
        proof: &P9X86_64BaselineOwnerPostCallReturnTargetProof,
    ) -> bool {
        let Some(binding) = proof.result_profile_binding else {
            return false;
        };
        if binding.bytecode_index != proof.call_bytecode_index {
            return false;
        }
        let Ok(Some(target)) = self.code_blocks.call_result_value_profile_store_target(
            proof.owner,
            proof.opcode,
            proof.call_bytecode_index,
            proof.destination,
        ) else {
            return false;
        };
        binding.profile_slot == target.binding.profile_slot
            && binding.bytecode_index == target.binding.bytecode_index
            && binding.checkpoint == target.binding.checkpoint
            && binding.bucket_kind == target.binding.kind
            && binding.storage_generation == target.binding.storage_generation
            && binding.storage_generation == target.storage_generation
            && binding.value_profile_offset == target.binding.value_profile_offset
            && binding.metadata_table_displacement == target.binding.metadata_table_displacement
            && binding.metadata_table_base_address == target.metadata_table_base_address
            && binding.raw_bucket_address == target.raw_bucket_address
            && binding.raw_bucket_bytes == target.raw_bucket_bytes
            && binding.emission_policy == target.binding.emission_policy
    }

    fn validate_p9_x86_64_js_call_native_exit_handoff(
        &self,
        handoff: &BaselineGeneratedJsCallHandoff,
        code_block: &CodeBlock,
        site: &P9X86_64CallableJsCallNativeExitReturnSite,
    ) -> Result<(), ExecutionError> {
        if handoff.resume.owner != site.owner
            || handoff.resume.bytecode_index != site.bytecode_index
            || handoff.resume.opcode != site.opcode
            || handoff.continuation.destination() != site.destination
            || handoff.continuation.resume_bytecode_index() != site.resume_bytecode_index
            || handoff.continuation.argument_count_including_this()
                != site.provided_argument_count.saturating_add(1)
            || handoff.requires_no_gc_exit_reentry != site.requires_no_gc_exit_reentry
            || handoff.may_throw != site.may_throw
        {
            return Err(ExecutionError::BaselineGeneratedExecutionRejected);
        }
        match site.opcode {
            CoreOpcode::Call | CoreOpcode::CallWithThis => {
                self.validate_generated_js_call_handoff_continuation(handoff, code_block)
            }
            CoreOpcode::Construct => {
                self.validate_generated_js_construct_handoff_continuation(handoff, code_block)
            }
            _ => Err(ExecutionError::BaselineGeneratedExecutionRejected),
        }
    }

    fn p9_x86_64_authorized_generated_js_direct_call_for_native_exit<H: DispatchHost>(
        &mut self,
        handoff: &BaselineGeneratedJsCallHandoff,
        code_block: &CodeBlock,
        site: &P9X86_64CallableJsCallNativeExitReturnSite,
        host: &mut H,
    ) -> Result<Option<BaselineGeneratedJsDirectCall>, ExecutionError> {
        let bytecode_snapshot =
            BaselineBytecodeEligibilityProof::fingerprint_code_block_snapshot(code_block)
                .map_err(|_| ExecutionError::BaselineGeneratedExecutionRejected)?;
        let candidate_table = self.generated_call_link_candidate_table_for_owner_cached(
            handoff.resume.owner,
            bytecode_snapshot,
        )?;
        let candidates = candidate_table
            .candidates_for_bytecode_index(site.bytecode_index.offset())
            .cloned()
            .collect::<Vec<GeneratedCallLinkCandidate>>();
        if candidates.is_empty() {
            return Ok(None);
        }

        let Some(call_continuation) = handoff.continuation.as_call() else {
            return Ok(None);
        };
        let caller_window =
            validate_call_return_continuation(&self.execution, &self.registers, call_continuation)
                .map_err(|_| ExecutionError::BaselineGeneratedExecutionRejected)?;
        let callee_value = call_continuation
            .callee_value
            .ok_or(ExecutionError::BaselineGeneratedExecutionRejected)?;
        let callee_object = call_continuation.callee_object;
        let this_value = match site.opcode {
            CoreOpcode::Call => RuntimeValue::undefined(),
            CoreOpcode::CallWithThis => {
                let this_register = site
                    .this_register
                    .ok_or(ExecutionError::BaselineGeneratedExecutionRejected)?;
                self.registers
                    .read(caller_window, this_register, Some(code_block.constants()))
                    .map_err(|_| ExecutionError::BaselineGeneratedExecutionRejected)?
            }
            _ => return Err(ExecutionError::BaselineGeneratedExecutionRejected),
        };
        let this_object = this_value
            .as_cell()
            .and_then(|cell| self.heap.cell_for_payload(cell.pointer_payload_bits()))
            .map(ObjectId);
        let argument_count_including_this = site
            .provided_argument_count
            .checked_add(1)
            .ok_or(ExecutionError::BaselineGeneratedExecutionRejected)?;
        if call_continuation.argument_count_including_this != argument_count_including_this
            || (site.opcode == CoreOpcode::Call && site.this_register.is_some())
        {
            return Err(ExecutionError::BaselineGeneratedExecutionRejected);
        }

        let mut direct_calls = Vec::new();
        for candidate in candidates {
            let request = GeneratedCallLinkProbeRequest::new(
                &candidate,
                handoff.resume.owner,
                site.opcode,
                site.bytecode_index.offset(),
                argument_count_including_this,
                callee_value,
                callee_value.kind(),
                callee_object,
                this_value,
                this_value.kind(),
                this_object,
            );
            match DispatchHost::probe_generated_call_link(host, &mut self.heap, request) {
                GeneratedCallLinkProbeResult::DirectCall(authorization) => {
                    let Some(callee_object) = callee_object else {
                        self.tiering.record_generated_call_link_probe_miss(
                            VmGeneratedCallLinkProbeMissRequest {
                                owner: handoff.resume.owner,
                                bytecode_index: site.bytecode_index,
                                bytecode_snapshot,
                                slot: Some(candidate.slot),
                                attachment_ordinal: Some(candidate.attachment_ordinal),
                                attachment_plan_ordinal: Some(candidate.attachment_plan_ordinal),
                                install_recheck_ordinal: Some(candidate.install_recheck_ordinal),
                                boundary_validation_ordinal: candidate.boundary_validation_ordinal,
                                descriptor_ordinal: candidate.descriptor_ordinal,
                                observation_ordinal: candidate.observation_ordinal,
                                readiness_ordinal: candidate.readiness_ordinal,
                                target_executable: Some(candidate.target.executable),
                                target_callee: Some(candidate.target.callee),
                                target_code_block: Some(candidate.target.target_code_block),
                                target_boundary: Some(candidate.boundary.id),
                                direct_call_status: Some(candidate.direct_call_status),
                                reason: GeneratedCallLinkProbeMissReason::MissingCalleeIdentity,
                            },
                        );
                        continue;
                    };
                    direct_calls.push(BaselineGeneratedJsDirectCall {
                        candidate,
                        authorization,
                        callee_value,
                        callee_object,
                        this_value,
                        this_object,
                        argument_count_including_this,
                        setup_payload: None,
                    });
                }
                GeneratedCallLinkProbeResult::Blocked(blocked) => {
                    let _ = self.tiering.record_generated_call_link_probe_blocked(
                        VmGeneratedCallLinkProbeBlockedRequest {
                            owner: handoff.resume.owner,
                            bytecode_index: site.bytecode_index,
                            bytecode_snapshot,
                            slot: candidate.slot,
                            attachment_ordinal: candidate.attachment_ordinal,
                            attachment_plan_ordinal: candidate.attachment_plan_ordinal,
                            install_recheck_ordinal: candidate.install_recheck_ordinal,
                            boundary_validation_ordinal: candidate.boundary_validation_ordinal,
                            descriptor_ordinal: candidate.descriptor_ordinal,
                            observation_ordinal: candidate.observation_ordinal,
                            readiness_ordinal: candidate.readiness_ordinal,
                            target_executable: candidate.target.executable,
                            target_callee: candidate.target.callee,
                            target_code_block: candidate.target.target_code_block,
                            target_boundary: candidate.boundary.id,
                            direct_call_status: candidate.direct_call_status,
                            reason: blocked.reason,
                        },
                    );
                }
                GeneratedCallLinkProbeResult::Miss(miss) => {
                    self.tiering.record_generated_call_link_probe_miss(
                        VmGeneratedCallLinkProbeMissRequest {
                            owner: handoff.resume.owner,
                            bytecode_index: site.bytecode_index,
                            bytecode_snapshot,
                            slot: Some(candidate.slot),
                            attachment_ordinal: Some(candidate.attachment_ordinal),
                            attachment_plan_ordinal: Some(candidate.attachment_plan_ordinal),
                            install_recheck_ordinal: Some(candidate.install_recheck_ordinal),
                            boundary_validation_ordinal: candidate.boundary_validation_ordinal,
                            descriptor_ordinal: candidate.descriptor_ordinal,
                            observation_ordinal: candidate.observation_ordinal,
                            readiness_ordinal: candidate.readiness_ordinal,
                            target_executable: Some(candidate.target.executable),
                            target_callee: Some(candidate.target.callee),
                            target_code_block: Some(candidate.target.target_code_block),
                            target_boundary: Some(candidate.boundary.id),
                            direct_call_status: Some(candidate.direct_call_status),
                            reason: miss.reason,
                        },
                    );
                }
            }
        }

        match direct_calls.len() {
            0 => Ok(None),
            1 => Ok(direct_calls.pop()),
            _ => Err(ExecutionError::BaselineGeneratedExecutionRejected),
        }
    }

    fn p6_x86_64_callable_side_exit_return_site_for_payload(
        &self,
        dispatch: &P6EmittedNativeDispatch<'_>,
        payload: P6X86_64BaselineSideExitReturnPayload,
    ) -> Option<P6X86_64CallableSideExitReturnSite> {
        self.p6_x86_64_callable_retained_return_tables
            .iter()
            .rev()
            .find(|table| table.matches_dispatch(dispatch))
            .and_then(|table| {
                table
                    .side_exit_sites
                    .iter()
                    .find(|site| site.encoded_payload == payload)
                    .cloned()
            })
    }

    fn p9_x86_64_callable_js_call_native_exit_return_site_for_payload(
        &self,
        dispatch: &P6EmittedNativeDispatch<'_>,
        payload: P9X86_64BaselineJsCallNativeExitReturnPayload,
    ) -> Result<P9X86_64CallableJsCallNativeExitReturnSite, ExecutionError> {
        let mut matches = Vec::new();
        for table in self
            .p6_x86_64_callable_retained_return_tables
            .iter()
            .rev()
            .filter(|table| table.matches_dispatch(dispatch))
        {
            matches.extend(
                table
                    .js_call_exit_sites
                    .iter()
                    .filter(|site| site.encoded_payload == payload)
                    .cloned(),
            );
        }

        match matches.len() {
            1 => Ok(matches.remove(0)),
            _ => Err(ExecutionError::BaselineGeneratedExecutionRejected),
        }
    }

    #[allow(dead_code)]
    fn p9_x86_64_owner_post_call_return_target_proof_for_payload(
        &self,
        dispatch: &P6EmittedNativeDispatch<'_>,
        payload: P9X86_64BaselineJsCallNativeExitReturnPayload,
    ) -> Result<P9X86_64BaselineOwnerPostCallReturnTargetProof, ExecutionError> {
        let mut matches = Vec::new();
        for table in self
            .p6_x86_64_callable_retained_return_tables
            .iter()
            .rev()
            .filter(|table| table.matches_dispatch(dispatch))
        {
            let Some(binding) = table.owner_continuation_native_binding.as_ref() else {
                continue;
            };
            if binding.owner != dispatch.code_block_id
                || binding.linked_size_bytes != dispatch.descriptor.machine_range.size_bytes
            {
                continue;
            }
            matches.extend(
                binding
                    .call_continuations
                    .iter()
                    .filter(|continuation| continuation.encoded_payload == payload)
                    .filter_map(|continuation| continuation.post_call_return_target_proof.clone())
                    .filter(|proof| {
                        let Some(result_profile_byte_len) = proof
                            .result_profile_end_offset
                            .checked_sub(proof.result_profile_offset)
                        else {
                            return false;
                        };
                        let metadata_store_profile = proof.result_profile_status
                            == P9X86_64BaselineOwnerCallResultProfileStatus::X86_64MetadataTableRelativeStore64;
                        let expected_result_seed = if metadata_store_profile {
                            P9X86_64BaselineOwnerPostCallReentryResultSeed::X86_64CAbiThirdArgumentRdxToRaxFourthArgumentRcxToR12
                        } else {
                            P9X86_64BaselineOwnerPostCallReentryResultSeed::X86_64CAbiThirdArgumentRdxToRax
                        };
                        let metadata_seed_shape_valid = if metadata_store_profile {
                            proof.post_call_reentry_metadata_table_seed_offset
                                == Some(proof.post_call_reentry_result_seed_end_offset)
                                && proof
                                    .post_call_reentry_metadata_table_seed_end_offset
                                    .is_some_and(|end| end == proof.post_call_reentry_jump_offset)
                                && proof.result_profile_binding.is_some_and(|profile_binding| {
                                    proof.post_call_reentry_metadata_table_base_address
                                        == Some(profile_binding.metadata_table_base_address)
                                })
                        } else {
                            proof.post_call_reentry_metadata_table_seed_offset.is_none()
                                && proof
                                    .post_call_reentry_metadata_table_seed_end_offset
                                    .is_none()
                                && proof
                                    .post_call_reentry_metadata_table_base_address
                                    .is_none()
                                && proof.post_call_reentry_result_seed_end_offset
                                    == proof.post_call_reentry_jump_offset
                        };
                        proof.owner == dispatch.code_block_id
                            && proof.encoded_payload == payload
                            && proof.linked_size_bytes == binding.linked_size_bytes
                            && proof.linked_digest == binding.linked_digest
                            && proof.post_call_target_start_offset
                                != proof.native_exit_stub_start_offset
                            && proof.post_call_target_start_offset
                                != proof.resume_instruction_start_offset
                            && proof.post_call_target_start_offset
                                < proof.post_call_target_end_offset
                            && proof
                                .post_call_target_end_offset
                                .checked_sub(proof.post_call_target_start_offset)
                                == Some(proof.post_call_target_byte_len)
                            && proof.reset_sp_status
                                == P9X86_64BaselineOwnerCallResetSpStatus::P6CallableAbiNoJsStackPointerRegister
                            && proof.reset_sp_offset == proof.post_call_target_start_offset
                            && proof.reset_sp_end_offset == proof.result_profile_offset
                            && matches!(
                                proof.result_profile_status,
                                P9X86_64BaselineOwnerCallResultProfileStatus::MetadataPending
                                    | P9X86_64BaselineOwnerCallResultProfileStatus::DisabledByPolicy
                                    | P9X86_64BaselineOwnerCallResultProfileStatus::X86_64MetadataTableRelativeStore64
                            )
                            && (metadata_store_profile && result_profile_byte_len == 8
                                || !metadata_store_profile && result_profile_byte_len == 1)
                            && self.p9_x86_64_owner_post_call_result_profile_binding_matches_current_code_block(proof)
                            && proof.result_profile_end_offset == proof.result_store_offset
                            && proof.result_store_offset < proof.resume_jump_offset
                            && proof.resume_jump_end_offset <= proof.post_call_target_end_offset
                            && proof.post_call_reentry_stub_start_offset
                                != proof.native_exit_stub_start_offset
                            && proof.post_call_reentry_stub_start_offset
                                != proof.post_call_target_start_offset
                            && proof.post_call_reentry_stub_start_offset
                                != proof.resume_instruction_start_offset
                            && proof.post_call_reentry_stub_start_offset
                                < proof.post_call_reentry_stub_end_offset
                            && proof
                                .post_call_reentry_stub_end_offset
                                .checked_sub(proof.post_call_reentry_stub_start_offset)
                                == Some(proof.post_call_reentry_stub_byte_len)
                            && proof.post_call_reentry_callable_prologue_offset
                                == proof.post_call_reentry_stub_start_offset
                            && proof.post_call_reentry_callable_prologue_end_offset
                                == proof.post_call_reentry_result_seed_offset
                            && proof.post_call_reentry_result_seed == expected_result_seed
                            && metadata_seed_shape_valid
                            && proof.post_call_reentry_jump_end_offset
                                <= proof.post_call_reentry_stub_end_offset
                            && proof.post_call_reentry_jump_target_start_offset
                                == proof.post_call_target_start_offset
                            && proof.post_call_reentry_stub_start_offset
                                < dispatch.descriptor.machine_range.size_bytes
                            && proof.post_call_reentry_stub_end_offset
                                <= dispatch.descriptor.machine_range.size_bytes
                            && proof.post_call_target_start_offset
                                < dispatch.descriptor.machine_range.size_bytes
                            && proof.post_call_target_end_offset
                                <= dispatch.descriptor.machine_range.size_bytes
                    }),
            );
        }

        match matches.len() {
            1 => Ok(matches.remove(0)),
            _ => Err(ExecutionError::BaselineGeneratedExecutionRejected),
        }
    }

    fn p9_x86_64_owner_post_call_return_target_proof_for_generated_handoff(
        &self,
        dispatch: &P6EmittedNativeDispatch<'_>,
        handoff: &BaselineGeneratedJsCallHandoff,
    ) -> Result<Option<P9X86_64BaselineOwnerPostCallReturnTargetProof>, ExecutionError> {
        let Some(site) = handoff.owner_continuation else {
            return Ok(None);
        };
        validate_baseline_generated_owner_continuation_site_metadata(&site)
            .map_err(|_| ExecutionError::BaselineGeneratedExecutionRejected)?;
        if site.owner != handoff.resume.owner
            || site.owner != dispatch.code_block_id
            || site.call_bytecode_index != handoff.resume.bytecode_index
            || site.opcode != handoff.resume.opcode
            || !matches!(site.opcode, CoreOpcode::Call | CoreOpcode::CallWithThis)
            || site.destination != handoff.continuation.destination()
            || site.argument_count_including_this
                != handoff.continuation.argument_count_including_this()
            || site.resume_bytecode_index != handoff.continuation.resume_bytecode_index()
            || site.kind != BaselineGeneratedOwnerContinuationKind::Call
        {
            return Err(ExecutionError::BaselineGeneratedExecutionRejected);
        }

        let mut saw_matching_binding = false;
        let mut matches = Vec::new();
        for table in self
            .p6_x86_64_callable_retained_return_tables
            .iter()
            .rev()
            .filter(|table| table.matches_dispatch(dispatch))
        {
            let Some(binding) = table.owner_continuation_native_binding.as_ref() else {
                continue;
            };
            if binding.owner != dispatch.code_block_id
                || binding.bytecode_snapshot != dispatch.bytecode_snapshot
                || binding.linked_size_bytes != dispatch.descriptor.machine_range.size_bytes
            {
                return Err(ExecutionError::BaselineGeneratedExecutionRejected);
            }
            saw_matching_binding = true;
            let Some(continuation) =
                binding.call_continuation_for_bytecode_index(site.call_bytecode_index)
            else {
                continue;
            };
            if continuation.owner != site.owner
                || continuation.call_bytecode_index != site.call_bytecode_index
                || continuation.opcode != site.opcode
                || continuation.kind != BaselineGeneratedOwnerContinuationKind::Call
                || continuation.destination != site.destination
                || continuation.argument_count_including_this != site.argument_count_including_this
                || continuation.resume_bytecode_index != site.resume_bytecode_index
            {
                return Err(ExecutionError::BaselineGeneratedExecutionRejected);
            }
            let Some(proof) = continuation.post_call_return_target_proof.clone() else {
                return Err(ExecutionError::BaselineGeneratedExecutionRejected);
            };
            if proof.owner != continuation.owner
                || proof.encoded_payload != continuation.encoded_payload
                || proof.call_bytecode_index != continuation.call_bytecode_index
                || proof.opcode != continuation.opcode
                || proof.destination != continuation.destination
                || proof.linked_size_bytes != binding.linked_size_bytes
                || proof.linked_digest != binding.linked_digest
            {
                return Err(ExecutionError::BaselineGeneratedExecutionRejected);
            }
            self.validate_p9_x86_64_owner_post_call_return_target_proof_shape(dispatch, &proof)?;
            matches.push(proof);
        }

        match matches.len() {
            0 if saw_matching_binding => Err(ExecutionError::BaselineGeneratedExecutionRejected),
            0 => Ok(None),
            1 => Ok(matches.pop()),
            _ => Err(ExecutionError::BaselineGeneratedExecutionRejected),
        }
    }

    fn p9_x86_64_generated_handoff_owner_post_call_reentry_plan(
        &self,
        handoff: &BaselineGeneratedJsCallHandoff,
        code_block: &CodeBlock,
    ) -> Result<Option<P9GeneratedOwnerPostCallReentryPlan>, ExecutionError> {
        if handoff.direct_call.is_none()
            || !matches!(
                handoff.resume.opcode,
                CoreOpcode::Call | CoreOpcode::CallWithThis
            )
        {
            return Ok(None);
        }
        if handoff.owner_continuation.is_none() {
            return Ok(None);
        }
        self.validate_generated_js_call_handoff_owner_continuation(
            handoff,
            code_block,
            BaselineGeneratedOwnerContinuationKind::Call,
        )?;

        let Some(gate) = self
            .tiering
            .baseline_native_entry_gate_for_owner(handoff.resume.owner)
        else {
            return Ok(None);
        };
        if gate.outcome != BaselineEntryGateOutcome::NativeEntryReady {
            return Ok(None);
        }
        let readiness = self
            .tiering
            .baseline_native_entry_readiness_for_gate(&gate)
            .cloned()
            .ok_or(ExecutionError::BaselineGeneratedExecutionRejected)?;
        if readiness.execution_policy != BaselineNativeEntryExecutionPolicy::Enabled
            || readiness.outcome != BaselineNativeEntryReadinessOutcome::Ready
            || readiness.owner != handoff.resume.owner
        {
            return Err(ExecutionError::BaselineGeneratedExecutionRejected);
        }
        let callable = readiness
            .callable
            .ok_or(ExecutionError::BaselineGeneratedExecutionRejected)?;
        if callable.kind() != BaselineNativeEntryCallableKind::P6X86_64EmittedSemanticCAbiEntry {
            return Ok(None);
        }
        if !self.can_execute_p6_x86_64_emitted_native_entry() {
            return Ok(None);
        }
        let descriptor = readiness
            .descriptor
            .ok_or(ExecutionError::BaselineGeneratedExecutionRejected)?;
        let artifact = gate
            .native_artifact
            .ok_or(ExecutionError::BaselineGeneratedExecutionRejected)?;
        if artifact.owner != handoff.resume.owner
            || descriptor.owner != handoff.resume.owner
            || descriptor.artifact_id != artifact.id
            || descriptor.native_symbol != artifact.native_code
            || descriptor.machine_code != artifact.machine_code
            || descriptor.machine_range != artifact.machine_code.range
            || descriptor.entrypoint != artifact.entrypoint
            || descriptor.baseline_abi_proof != artifact.baseline_abi_proof
            || readiness.artifact_id != Some(artifact.id)
            || readiness.native_code != Some(artifact.native_code)
            || readiness.machine_code != Some(artifact.machine_code)
            || readiness.machine_range != Some(artifact.machine_code.range)
            || readiness.descriptor != Some(descriptor)
            || callable.validate_for_descriptor(&descriptor).is_err()
        {
            return Err(ExecutionError::BaselineGeneratedExecutionRejected);
        }

        let readiness_snapshot = readiness
            .bytecode_snapshot
            .ok_or(ExecutionError::BaselineGeneratedExecutionRejected)?;
        let actual_snapshot =
            BaselineBytecodeEligibilityProof::fingerprint_code_block_snapshot(code_block)
                .map_err(|_| ExecutionError::BaselineGeneratedExecutionRejected)?;
        let registered_code_block = self
            .code_blocks
            .get(handoff.resume.owner)
            .ok_or(ExecutionError::BaselineGeneratedExecutionRejected)?
            .code_block();
        let registered_snapshot =
            BaselineBytecodeEligibilityProof::fingerprint_code_block_snapshot(
                registered_code_block,
            )
            .map_err(|_| ExecutionError::BaselineGeneratedExecutionRejected)?;
        if actual_snapshot != readiness_snapshot || registered_snapshot != readiness_snapshot {
            return Err(ExecutionError::BaselineGeneratedExecutionRejected);
        }

        let active_frame = self
            .execution
            .top_frame()
            .ok_or(ExecutionError::NoActiveFrame)?;
        if active_frame.id != handoff.resume.frame
            || active_frame.code_block != Some(handoff.resume.owner)
        {
            return Err(ExecutionError::BaselineGeneratedExecutionRejected);
        }
        if self
            .platform_residency_index_for_native_entry(&readiness, &descriptor)
            .is_none()
        {
            return Err(ExecutionError::BaselineGeneratedExecutionRejected);
        }

        let (entry_kind, current_tier) = self.generated_resume_entry_context(handoff.resume.owner);
        let dispatch = P6EmittedNativeDispatch {
            code_block_id: handoff.resume.owner,
            expected_frame: handoff.resume.frame,
            entry_kind,
            current_tier,
            bytecode_snapshot: readiness_snapshot,
            readiness: &readiness,
            descriptor: &descriptor,
            allow_interpreter_fallback: false,
        };
        let Some(proof) = self
            .p9_x86_64_owner_post_call_return_target_proof_for_generated_handoff(
                &dispatch, handoff,
            )?
        else {
            return Ok(None);
        };

        Ok(Some(P9GeneratedOwnerPostCallReentryPlan {
            readiness,
            descriptor,
            proof,
        }))
    }

    fn p10_x86_64_callable_property_native_exit_return_site_for_payload(
        &self,
        dispatch: &P6EmittedNativeDispatch<'_>,
        payload: P10X86_64BaselinePropertyNativeExitReturnPayload,
    ) -> Result<P10X86_64CallablePropertyNativeExitReturnSite, ExecutionError> {
        let mut matches = Vec::new();
        for table in self
            .p6_x86_64_callable_retained_return_tables
            .iter()
            .rev()
            .filter(|table| table.matches_dispatch(dispatch))
        {
            matches.extend(
                table
                    .property_exit_sites
                    .iter()
                    .filter(|site| site.encoded_payload == payload)
                    .copied(),
            );
        }

        match matches.len() {
            1 => Ok(matches.remove(0)),
            _ => Err(ExecutionError::BaselineGeneratedExecutionRejected),
        }
    }

