    fn record_p6_x86_64_callable_side_exit_fallback(
        &mut self,
        dispatch: &P6EmittedNativeDispatch<'_>,
        side_exit: &P6X86_64CallableSideExitReturnSite,
        code_block: &CodeBlock,
    ) {
        let generated_baseline = self.p6_x86_64_callable_side_exit_generated_fallback_record(
            dispatch, side_exit, code_block,
        );
        let boundary = self.fallback_boundary_snapshot();
        self.tiering.record_optimized_call_fallback(
            OptimizedCallFallbackRequest {
                owner: dispatch.code_block_id,
                from_tier: dispatch.current_tier,
                attempted_tier: JitType::Baseline,
                reason: TierFallbackReason::UnsupportedTier,
                bytecode_index: Some(side_exit.bytecode_index),
                frame: Some(dispatch.expected_frame),
                stack_frame: None,
                entry_kind: dispatch.entry_kind,
                generated_baseline,
            },
            boundary,
        );
    }

    fn p6_x86_64_callable_side_exit_generated_fallback_record(
        &self,
        dispatch: &P6EmittedNativeDispatch<'_>,
        side_exit: &P6X86_64CallableSideExitReturnSite,
        code_block: &CodeBlock,
    ) -> Option<GeneratedBaselineFallbackRecord> {
        let opcode = p6_core_opcode_at_bytecode_index(code_block, side_exit.bytecode_index)?;
        let cause = match side_exit.reason {
            P6X86_64BaselineSelectedSideExitReason::Overflow => {
                GeneratedBaselineFallbackCause::Int32Overflow
            }
            P6X86_64BaselineSelectedSideExitReason::UnsupportedTruthinessOperand => {
                if opcode != CoreOpcode::JumpIfFalse {
                    return None;
                }
                let instruction = code_block
                    .decoded_instruction_at(side_exit.bytecode_index)
                    .ok()?;
                let register = instruction.register_operand(0).ok()?;
                let frame = self.execution.frame(dispatch.expected_frame)?;
                let value = self
                    .registers
                    .read(
                        frame.register_window,
                        register,
                        Some(code_block.constants()),
                    )
                    .ok()?;
                GeneratedBaselineFallbackCause::UnsupportedTruthinessOperand {
                    operand_index: 0,
                    register,
                    value_kind: value.kind(),
                }
            }
            P6X86_64BaselineSelectedSideExitReason::UnsupportedToNumberOperand => {
                if opcode != CoreOpcode::ToNumber {
                    return None;
                }
                let instruction = code_block
                    .decoded_instruction_at(side_exit.bytecode_index)
                    .ok()?;
                let register = instruction.register_operand(1).ok()?;
                let frame = self.execution.frame(dispatch.expected_frame)?;
                let value = self
                    .registers
                    .read(
                        frame.register_window,
                        register,
                        Some(code_block.constants()),
                    )
                    .ok()?;
                GeneratedBaselineFallbackCause::UnsupportedPrimitiveNumericCoercionOperand {
                    operand_index: 1,
                    register,
                    value_kind: value.kind(),
                }
            }
            P6X86_64BaselineSelectedSideExitReason::UnsupportedStrictEqualityOperand => {
                if !matches!(opcode, CoreOpcode::StrictEqual | CoreOpcode::StrictNotEqual) {
                    return None;
                }
                let instruction = code_block
                    .decoded_instruction_at(side_exit.bytecode_index)
                    .ok()?;
                let frame = self.execution.frame(dispatch.expected_frame)?;
                let left_register = instruction.register_operand(1).ok()?;
                let left = self
                    .registers
                    .read(
                        frame.register_window,
                        left_register,
                        Some(code_block.constants()),
                    )
                    .ok()?;
                let (operand_index, register, value_kind) =
                    if p6_native_strict_equality_side_exit_value_kind(left.kind()) {
                        (1, left_register, left.kind())
                    } else {
                        let right_register = instruction.register_operand(2).ok()?;
                        let right = self
                            .registers
                            .read(
                                frame.register_window,
                                right_register,
                                Some(code_block.constants()),
                            )
                            .ok()?;
                        if !p6_native_strict_equality_side_exit_value_kind(right.kind()) {
                            return None;
                        }
                        (2, right_register, right.kind())
                    };
                GeneratedBaselineFallbackCause::UnsupportedStrictEqualityOperand {
                    operand_index,
                    register,
                    value_kind,
                }
            }
            P6X86_64BaselineSelectedSideExitReason::NonInt32Operand
            | P6X86_64BaselineSelectedSideExitReason::NegativeZero => return None,
        };
        Some(GeneratedBaselineFallbackRecord {
            bytecode_index: side_exit.bytecode_index,
            opcode: GeneratedBaselineFallbackOpcode::Core(opcode),
            cause,
        })
    }

    fn platform_residency_index_for_native_entry(
        &self,
        readiness: &BaselineNativeEntryReadinessRecord,
        descriptor: &BaselineNativeEntryDescriptor,
    ) -> Option<usize> {
        let materialization = self
            .tiering
            .baseline_executable_materializations()
            .iter()
            .rev()
            .find(|materialization| {
                materialization.ordinal == readiness.materialization_ordinal
                    && materialization.owner == descriptor.owner
                    && materialization.artifact_id == descriptor.artifact_id
                    && materialization.native_code == Some(descriptor.native_symbol)
                    && materialization.machine_code == Some(descriptor.machine_code)
                    && materialization.machine_range == Some(descriptor.machine_range)
            })?;
        let executable_residency = materialization.executable_residency.as_ref()?;

        self.baseline_platform_executable_residencies
            .iter()
            .position(|platform_residency| {
                let mut comparable_platform_machine_code =
                    platform_residency.evidence.platform_machine_code;
                comparable_platform_machine_code.symbol = descriptor.machine_code.symbol;
                platform_residency.residency == *executable_residency
                    && platform_residency.evidence.finalized_machine_code == descriptor.machine_code
                    && comparable_platform_machine_code == descriptor.machine_code
            })
    }

    fn record_generated_call_link_probe_miss_records(
        &mut self,
        bytecode_snapshot: BaselineBytecodeSnapshotFingerprint,
        records: &[BaselineGeneratedCallLinkProbeMissRecord],
    ) {
        for record in records {
            self.tiering.record_generated_call_link_probe_miss(
                VmGeneratedCallLinkProbeMissRequest {
                    owner: record.owner,
                    bytecode_index: record.bytecode_index,
                    bytecode_snapshot,
                    slot: record.slot,
                    attachment_ordinal: record.attachment_ordinal,
                    attachment_plan_ordinal: record.attachment_plan_ordinal,
                    install_recheck_ordinal: record.install_recheck_ordinal,
                    boundary_validation_ordinal: record.boundary_validation_ordinal,
                    descriptor_ordinal: record.descriptor_ordinal,
                    observation_ordinal: record.observation_ordinal,
                    readiness_ordinal: record.readiness_ordinal,
                    target_executable: record.target_executable,
                    target_callee: record.target_callee,
                    target_code_block: record.target_code_block,
                    target_boundary: record.target_boundary,
                    direct_call_status: record.direct_call_status,
                    reason: record.reason,
                },
            );
        }
    }

    fn record_generated_property_load_sidecar_probe_miss_records(
        &mut self,
        bytecode_snapshot: BaselineBytecodeSnapshotFingerprint,
        probe_miss_records: &[BaselineGeneratedPropertyLoadProbeMissRecord],
        guarded_probe_miss_records: &[BaselineGeneratedGuardedPropertyLoadProbeMissRecord],
    ) {
        let mut aggregated_load_misses = 0usize;
        for miss in probe_miss_records {
            if self
                .tiering
                .should_record_generated_property_load_probe_miss_detail(miss.reason)
            {
                self.tiering.record_generated_property_load_probe_miss(
                    VmGeneratedPropertyLoadProbeMissRequest {
                        owner: miss.owner,
                        bytecode_index: miss.bytecode_index,
                        bytecode_snapshot,
                        key: miss.key,
                        base_structure: miss.base_structure,
                        offset: miss.offset,
                        reason: miss.reason,
                    },
                );
            } else {
                aggregated_load_misses = aggregated_load_misses.saturating_add(1);
            }
        }
        self.tiering
            .record_generated_property_load_probe_miss_count(aggregated_load_misses);
        let mut aggregated_guarded_load_misses = 0usize;
        for miss in guarded_probe_miss_records {
            if self
                .tiering
                .should_record_generated_guarded_property_load_probe_miss_detail(miss.reason)
            {
                self.tiering
                    .record_generated_guarded_property_load_probe_miss(
                        VmGeneratedGuardedPropertyLoadProbeMissRequest {
                            owner: miss.owner,
                            bytecode_index: miss.bytecode_index,
                            bytecode_snapshot,
                            slot: miss.slot,
                            guard_plan_ordinal: miss.guard_plan_ordinal,
                            materialization_ordinal: miss.materialization_ordinal,
                            dependency_ordinals: miss.dependency_ordinals.clone(),
                            binding_set_ids: miss.binding_set_ids.clone(),
                            candidate_kind: miss.candidate_kind,
                            base_structure: miss.base_structure,
                            reason: miss.reason,
                            requirement: miss.requirement,
                            key: miss.key,
                            prototype_depth: miss.prototype_depth,
                            chain_index: miss.chain_index,
                            outcome: miss.outcome,
                        },
                    );
            } else {
                aggregated_guarded_load_misses = aggregated_guarded_load_misses.saturating_add(1);
            }
        }
        self.tiering
            .record_generated_guarded_property_load_probe_miss_count(
                aggregated_guarded_load_misses,
            );
    }

