    fn sync_generated_property_load_destination_roots<H: DispatchHost>(
        &mut self,
        host: &mut H,
        requests: &[BaselineGeneratedPropertyLoadDestinationRootSyncRequest],
        active_roots: &mut Vec<RootRecord>,
    ) -> Result<(), ExecutionError> {
        if requests.is_empty() {
            return Ok(());
        }

        let mut requested_slots = Vec::new();
        for request in requests {
            let slot =
                self.generated_property_load_destination_slot(request.frame, request.destination)?;
            let requested = (request.frame, slot);
            if !requested_slots.contains(&requested) {
                requested_slots.push(requested);
            }
        }

        let snapshot = self.execution.register_root_snapshot_for_slots(
            self.heap.id(),
            &self.registers,
            &requested_slots,
        )?;
        if snapshot.register_roots.len() != requested_slots.len() {
            return Err(ExecutionError::RegisterOutOfBounds);
        }

        let allowed_roots = snapshot
            .register_roots
            .iter()
            .map(|descriptor| descriptor.root)
            .collect::<Vec<_>>();
        let targeted = host.targeted_register_roots(&mut self.heap, &snapshot)?;

        for record in &targeted {
            if !allowed_roots.contains(&record.root) {
                return Err(ExecutionError::BaselineGeneratedExecutionRejected);
            }
        }

        for descriptor in &snapshot.register_roots {
            let Some(payload) = descriptor.cell_payload else {
                if targeted.iter().any(|record| record.root == descriptor.root) {
                    return Err(ExecutionError::BaselineGeneratedExecutionRejected);
                }
                continue;
            };
            let target = self.heap.cell_for_payload(payload).ok_or(
                ExecutionError::UnresolvedRegisterRoot {
                    slot: descriptor.slot,
                },
            )?;
            match targeted
                .iter()
                .find(|record| record.root == descriptor.root)
            {
                Some(record) if record.target == target => {}
                _ => return Err(ExecutionError::BaselineGeneratedExecutionRejected),
            }
        }

        self.sync_generated_property_load_targeted_vm_roots(active_roots, targeted)
    }

    fn generated_property_load_destination_slot(
        &self,
        frame: CallFrameId,
        destination: VirtualRegister,
    ) -> Result<usize, ExecutionError> {
        let window = self
            .registers
            .active_windows()
            .iter()
            .find(|window| window.owner == frame)
            .copied()
            .ok_or(ExecutionError::NoActiveFrame)?;
        Self::register_slot_for_window(window, destination)
    }

    fn register_slot_for_window(
        window: crate::interpreter::RegisterWindow,
        register: VirtualRegister,
    ) -> Result<usize, ExecutionError> {
        if !register.is_valid() {
            return Err(ExecutionError::InvalidRegister);
        }
        if register.is_constant() {
            return Err(ExecutionError::CannotWriteConstant);
        }
        if let Some(index) = register.to_local_index() {
            let index = usize::try_from(index).map_err(|_| ExecutionError::RegisterOutOfBounds)?;
            if index >= window.local_count {
                return Err(ExecutionError::RegisterOutOfBounds);
            }
            return Ok(window.base + index);
        }
        if register.is_argument_or_header() {
            let raw = register.raw();
            if raw < window.this_offset.0 {
                return Err(ExecutionError::CannotAddressHeaderAsValue);
            }
            let index = usize::try_from(raw - window.this_offset.0)
                .map_err(|_| ExecutionError::RegisterOutOfBounds)?;
            if index >= window.argument_count {
                return Err(ExecutionError::RegisterOutOfBounds);
            }
            return Ok(window.argument_base + index);
        }
        Err(ExecutionError::InvalidRegister)
    }

    fn sync_generated_property_load_targeted_vm_roots(
        &mut self,
        active_roots: &mut Vec<RootRecord>,
        desired_records: Vec<TargetedRootRecord>,
    ) -> Result<(), ExecutionError> {
        let desired_records = desired_records
            .into_iter()
            .filter(|record| record.root.kind == RootKind::VMRegister)
            .collect::<Vec<_>>();
        let desired = TargetedRootSet::from_records(self.heap.id(), desired_records)?;
        let stale_roots = active_roots
            .iter()
            .copied()
            .filter(|root| {
                !desired
                    .records()
                    .iter()
                    .any(|record| record.root.id == root.id)
            })
            .collect::<Vec<_>>();

        for root in stale_roots {
            if self
                .heap
                .targeted_roots()
                .records()
                .iter()
                .any(|record| record.root == root)
            {
                self.heap
                    .unregister_targeted_root(root, RootSetMutationAuthority::VmRegisterFile)?;
            }
            active_roots.retain(|active| active.id != root.id);
        }

        for record in desired.records() {
            let existing = self
                .heap
                .targeted_roots()
                .records()
                .iter()
                .find(|existing| existing.root == record.root)
                .copied();
            match existing {
                Some(existing) if existing == *record => {
                    if !active_roots
                        .iter()
                        .any(|active| active.id == record.root.id)
                    {
                        active_roots.push(record.root);
                    }
                }
                Some(_) => {
                    self.heap.retarget_targeted_root(
                        *record,
                        RootSetMutationAuthority::VmRegisterFile,
                    )?;
                    if !active_roots
                        .iter()
                        .any(|active| active.id == record.root.id)
                    {
                        active_roots.push(record.root);
                    }
                }
                None => {
                    self.heap.register_targeted_root(
                        *record,
                        RootSetMutationAuthority::VmRegisterFile,
                    )?;
                    if !active_roots
                        .iter()
                        .any(|active| active.id == record.root.id)
                    {
                        active_roots.push(record.root);
                    }
                }
            }
        }

        Ok(())
    }

    fn finish_generated_property_load_destination_roots(
        &mut self,
        active_roots: &mut Vec<RootRecord>,
        completion: ExecutionCompletion,
    ) -> ExecutionCompletion {
        match self.cleanup_generated_property_load_destination_roots(active_roots) {
            Ok(()) => completion,
            Err(error) => ExecutionCompletion::Failed(error),
        }
    }

    fn finish_generated_property_load_destination_root_control(
        &mut self,
        active_roots: &mut Vec<RootRecord>,
        control: GeneratedExecutionControl,
    ) -> GeneratedExecutionControl {
        match self.cleanup_generated_property_load_destination_roots(active_roots) {
            Ok(()) => control,
            Err(error) => GeneratedExecutionControl::failed(error),
        }
    }

    fn cleanup_generated_property_load_destination_roots(
        &mut self,
        active_roots: &mut Vec<RootRecord>,
    ) -> Result<(), ExecutionError> {
        for root in std::mem::take(active_roots) {
            if self
                .heap
                .targeted_roots()
                .records()
                .iter()
                .any(|record| record.root == root)
            {
                self.heap
                    .unregister_targeted_root(root, RootSetMutationAuthority::VmRegisterFile)?;
            }
        }
        Ok(())
    }

    fn execute_generated_js_call_handoff_in_current_region<H: DispatchHost>(
        &mut self,
        handoff: BaselineGeneratedJsCallHandoff,
        code_block: &CodeBlock,
        host: &mut H,
        config: DispatchConfig,
    ) -> ExecutionCompletion {
        let control =
            self.execute_generated_js_call_handoff_control(handoff, code_block, host, config);
        self.drive_generated_execution_control(control, code_block, host, config)
    }

    fn execute_generated_js_call_handoff_control<H: DispatchHost>(
        &mut self,
        handoff: BaselineGeneratedJsCallHandoff,
        code_block: &CodeBlock,
        host: &mut H,
        config: DispatchConfig,
    ) -> GeneratedExecutionControl {
        let resume = GeneratedSingleDispatchResume::from_js_call(&handoff);
        match self.try_execute_generated_js_call_handoff_owner_post_call_reentry_control(
            &handoff, code_block, host, config,
        ) {
            Ok(Some(control)) => return control,
            Ok(None) => {}
            Err(error) => return GeneratedExecutionControl::failed(error),
        }
        let outcome = self.dispatch_generated_js_call_handoff_in_current_region(
            handoff, code_block, host, config,
        );
        self.finish_generated_single_dispatch_handoff_control(resume, outcome)
    }

    fn try_execute_generated_js_call_handoff_owner_post_call_reentry_control<H: DispatchHost>(
        &mut self,
        handoff: &BaselineGeneratedJsCallHandoff,
        code_block: &CodeBlock,
        host: &mut H,
        config: DispatchConfig,
    ) -> Result<Option<GeneratedExecutionControl>, ExecutionError> {
        let Some(plan) =
            self.p9_x86_64_generated_handoff_owner_post_call_reentry_plan(handoff, code_block)?
        else {
            return Ok(None);
        };
        let (entry_kind, current_tier) = self.generated_resume_entry_context(handoff.resume.owner);
        let dispatch = P6EmittedNativeDispatch {
            code_block_id: handoff.resume.owner,
            expected_frame: handoff.resume.frame,
            entry_kind,
            current_tier,
            bytecode_snapshot: plan
                .readiness
                .bytecode_snapshot
                .ok_or(ExecutionError::BaselineGeneratedExecutionRejected)?,
            readiness: &plan.readiness,
            descriptor: &plan.descriptor,
            allow_interpreter_fallback: false,
        };
        match self.execute_generated_js_direct_call_transaction_with_return_mode(
            handoff.clone(),
            code_block,
            host,
            config,
            GeneratedJsDirectCallReturnMode::OwnerPostCallReentry(&plan.proof),
        ) {
            GeneratedJsDirectCallTransactionResult::Outcome(outcome) => {
                let resume = GeneratedSingleDispatchResume::from_js_call(handoff);
                Ok(Some(self.finish_generated_single_dispatch_handoff_control(
                    resume, outcome,
                )))
            }
            GeneratedJsDirectCallTransactionResult::P9OwnerPostCallReentry(reentry) => {
                let execution = self
                    .execute_p6_x86_64_emitted_semantic_native_invocation_in_current_region(
                        code_block,
                        dispatch,
                        P6X86_64CallableNativeInvocation::P9OwnerPostCallReentry(reentry),
                        host,
                        config,
                    );
                let completion = match execution {
                    BaselineNativeEntryVmExecution::Native(completion)
                    | BaselineNativeEntryVmExecution::InterpreterFallback(completion) => completion,
                    BaselineNativeEntryVmExecution::DeferredRootedInterpreterFallback {
                        completion,
                        roots,
                    } => match self.cleanup_baseline_native_entry_deferred_roots(roots) {
                        Ok(()) => completion,
                        Err(error) => ExecutionCompletion::Failed(error),
                    },
                    BaselineNativeEntryVmExecution::P9OwnerPostCallReentry(_) => {
                        ExecutionCompletion::Failed(
                            ExecutionError::BaselineGeneratedExecutionRejected,
                        )
                    }
                    BaselineNativeEntryVmExecution::P6SideExitReentry(_) => {
                        ExecutionCompletion::Failed(
                            ExecutionError::BaselineGeneratedExecutionRejected,
                        )
                    }
                };
                Ok(Some(GeneratedExecutionControl::complete(completion)))
            }
        }
    }

    fn execute_generated_runtime_helper_handoff_in_current_region<H: DispatchHost>(
        &mut self,
        handoff: BaselineGeneratedRuntimeHelperHandoff,
        code_block: &CodeBlock,
        host: &mut H,
        config: DispatchConfig,
    ) -> ExecutionCompletion {
        let control = self
            .execute_generated_runtime_helper_handoff_control(handoff, code_block, host, config);
        self.drive_generated_execution_control(control, code_block, host, config)
    }

    fn execute_generated_runtime_helper_handoff_control<H: DispatchHost>(
        &mut self,
        handoff: BaselineGeneratedRuntimeHelperHandoff,
        code_block: &CodeBlock,
        host: &mut H,
        _config: DispatchConfig,
    ) -> GeneratedExecutionControl {
        let outcome = self
            .dispatch_generated_runtime_helper_handoff_in_current_region(handoff, code_block, host);
        self.finish_generated_single_dispatch_handoff_control(
            GeneratedSingleDispatchResume::from_runtime_helper(handoff),
            outcome,
        )
    }

    fn dispatch_generated_js_call_handoff_in_current_region<H: DispatchHost>(
        &mut self,
        handoff: BaselineGeneratedJsCallHandoff,
        code_block: &CodeBlock,
        host: &mut H,
        config: DispatchConfig,
    ) -> SingleDispatchOutcome {
        if !matches!(
            handoff.resume.opcode,
            CoreOpcode::Call | CoreOpcode::CallWithThis | CoreOpcode::Construct
        ) {
            return SingleDispatchOutcome::Failed(
                ExecutionError::BaselineGeneratedExecutionRejected,
            );
        }
        if handoff.direct_call.is_some() {
            if !matches!(
                handoff.resume.opcode,
                CoreOpcode::Call | CoreOpcode::CallWithThis
            ) {
                return SingleDispatchOutcome::Failed(
                    ExecutionError::BaselineGeneratedExecutionRejected,
                );
            }
            return self
                .execute_generated_js_direct_call_transaction(handoff, code_block, host, config);
        }
        let validation = match handoff.resume.opcode {
            CoreOpcode::Call | CoreOpcode::CallWithThis => {
                self.validate_generated_js_call_handoff_continuation(&handoff, code_block)
            }
            CoreOpcode::Construct => {
                if handoff.direct_call.is_some() {
                    Err(ExecutionError::BaselineGeneratedExecutionRejected)
                } else {
                    self.validate_generated_js_construct_handoff_continuation(&handoff, code_block)
                }
            }
            _ => Err(ExecutionError::BaselineGeneratedExecutionRejected),
        };
        if let Err(error) = validation {
            return SingleDispatchOutcome::Failed(error);
        }
        let bytecode_snapshot =
            match BaselineBytecodeEligibilityProof::fingerprint_code_block_snapshot(code_block) {
                Ok(bytecode_snapshot) => bytecode_snapshot,
                Err(_) => {
                    return SingleDispatchOutcome::Failed(
                        ExecutionError::BaselineGeneratedExecutionRejected,
                    )
                }
            };
        self.execute_generated_js_call_single_dispatch_exit_transaction(
            handoff,
            bytecode_snapshot,
            code_block,
            host,
            config,
        )
    }

    fn execute_generated_js_call_single_dispatch_exit_transaction<H: DispatchHost>(
        &mut self,
        handoff: BaselineGeneratedJsCallHandoff,
        bytecode_snapshot: BaselineBytecodeSnapshotFingerprint,
        code_block: &CodeBlock,
        host: &mut H,
        config: DispatchConfig,
    ) -> SingleDispatchOutcome {
        let transaction = GeneratedSingleDispatchExitTransaction::from_js_call(&handoff);
        if !transaction.requires_no_gc_exit_reentry {
            return SingleDispatchOutcome::Failed(ExecutionError::GcBoundaryViolation);
        }
        let suspended = match self.suspend_no_gc_execution_region() {
            Ok(suspended) => suspended,
            Err(_) => return SingleDispatchOutcome::Failed(ExecutionError::GcBoundaryViolation),
        };
        let mut active_register_roots = Vec::new();
        let mut active_frame_roots = Vec::new();
        if let Err(error) = self.sync_generated_direct_call_deferred_nonlocal_roots(
            transaction.resume.frame,
            host,
            &mut active_register_roots,
            &mut active_frame_roots,
        ) {
            let cleanup = cleanup_targeted_root_sets(
                &mut self.heap,
                &mut active_register_roots,
                &mut active_frame_roots,
            );
            return self.resume_generated_single_dispatch_no_gc(
                suspended,
                SingleDispatchOutcome::Failed(cleanup.err().unwrap_or(error)),
            );
        }
        let exception_snapshot = self.exceptions.clone();
        let outcome = execute_single_dispatch_deferring_ordinary_calls(
            InterpreterExecutionState {
                stack: &mut self.execution,
                registers: &mut self.registers,
                exceptions: &mut self.exceptions,
                heap: &mut self.heap,
            },
            SingleDispatchRequest::new(
                transaction.resume.owner,
                transaction.resume.frame,
                transaction.resume.bytecode_index,
            ),
            code_block,
            host,
        );
        let observation =
            match self.drain_generated_js_call_observation(&handoff, bytecode_snapshot, host) {
                Ok(observation) => observation,
                Err(error) => {
                    let error = self
                        .restore_exception_snapshot_and_sync_roots(exception_snapshot)
                        .err()
                        .unwrap_or(error);
                    let cleanup = cleanup_targeted_root_sets(
                        &mut self.heap,
                        &mut active_register_roots,
                        &mut active_frame_roots,
                    );
                    return self.resume_generated_single_dispatch_no_gc(
                        suspended,
                        SingleDispatchOutcome::Failed(cleanup.err().unwrap_or(error)),
                    );
                }
            };

        match outcome {
            SingleDispatchOutcome::OrdinaryBytecodeCall(request) => {
                let outcome = match self.resume_no_gc_execution_region(suspended) {
                    Ok(_) => self.execute_ordinary_bytecode_call_request_as_single_dispatch_in_current_region(
                        *request,
                        transaction.resume.owner,
                        code_block,
                        host,
                        config,
                    ),
                    Err(_) => SingleDispatchOutcome::Failed(ExecutionError::GcBoundaryViolation),
                };
                let observation = Self::retarget_call_observation_outcome(observation, &outcome);
                if let Err(error) = self.record_call_observation_and_metadata(observation) {
                    let error = self
                        .restore_exception_snapshot_and_sync_roots(exception_snapshot)
                        .err()
                        .unwrap_or(error);
                    let cleanup = cleanup_targeted_root_sets(
                        &mut self.heap,
                        &mut active_register_roots,
                        &mut active_frame_roots,
                    );
                    return SingleDispatchOutcome::Failed(cleanup.err().unwrap_or(error));
                }
                let outcome = self.normalize_generated_single_dispatch_outcome(
                    transaction.may_throw,
                    exception_snapshot,
                    outcome,
                );
                match cleanup_targeted_root_sets(
                    &mut self.heap,
                    &mut active_register_roots,
                    &mut active_frame_roots,
                ) {
                    Ok(()) => outcome,
                    Err(error) => SingleDispatchOutcome::Failed(error),
                }
            }
            SingleDispatchOutcome::OrdinaryBytecodeConstruct(request) => {
                let outcome = match self.resume_no_gc_execution_region(suspended) {
                    Ok(_) => self
                        .execute_ordinary_bytecode_construct_request_as_single_dispatch_in_current_region(
                            *request,
                            transaction.resume.owner,
                            code_block,
                            host,
                            config,
                        ),
                    Err(_) => SingleDispatchOutcome::Failed(ExecutionError::GcBoundaryViolation),
                };
                let observation = Self::retarget_call_observation_outcome(observation, &outcome);
                if let Err(error) = self.record_call_observation_and_metadata(observation) {
                    let error = self
                        .restore_exception_snapshot_and_sync_roots(exception_snapshot)
                        .err()
                        .unwrap_or(error);
                    let cleanup = cleanup_targeted_root_sets(
                        &mut self.heap,
                        &mut active_register_roots,
                        &mut active_frame_roots,
                    );
                    return SingleDispatchOutcome::Failed(cleanup.err().unwrap_or(error));
                }
                let outcome = self.normalize_generated_single_dispatch_outcome(
                    transaction.may_throw,
                    exception_snapshot,
                    outcome,
                );
                match cleanup_targeted_root_sets(
                    &mut self.heap,
                    &mut active_register_roots,
                    &mut active_frame_roots,
                ) {
                    Ok(()) => outcome,
                    Err(error) => SingleDispatchOutcome::Failed(error),
                }
            }
            SingleDispatchOutcome::FunctionValueCall(request) => {
                let outcome = match self.resume_no_gc_execution_region(suspended) {
                    Ok(_) => self
                        .execute_function_value_call_request_as_single_dispatch_in_current_region(
                            *request,
                            transaction.resume.owner,
                            code_block,
                            host,
                            config,
                        ),
                    Err(_) => SingleDispatchOutcome::Failed(ExecutionError::GcBoundaryViolation),
                };
                let observation = Self::retarget_call_observation_outcome(observation, &outcome);
                if let Err(error) = self.record_call_observation_and_metadata(observation) {
                    let error = self
                        .restore_exception_snapshot_and_sync_roots(exception_snapshot)
                        .err()
                        .unwrap_or(error);
                    let cleanup = cleanup_targeted_root_sets(
                        &mut self.heap,
                        &mut active_register_roots,
                        &mut active_frame_roots,
                    );
                    return SingleDispatchOutcome::Failed(cleanup.err().unwrap_or(error));
                }
                let outcome = self.normalize_generated_single_dispatch_outcome(
                    transaction.may_throw,
                    exception_snapshot,
                    outcome,
                );
                match cleanup_targeted_root_sets(
                    &mut self.heap,
                    &mut active_register_roots,
                    &mut active_frame_roots,
                ) {
                    Ok(()) => outcome,
                    Err(error) => SingleDispatchOutcome::Failed(error),
                }
            }
            outcome => {
                if let Err(error) = self.record_call_observation_and_metadata(observation) {
                    let error = self
                        .restore_exception_snapshot_and_sync_roots(exception_snapshot)
                        .err()
                        .unwrap_or(error);
                    let cleanup = cleanup_targeted_root_sets(
                        &mut self.heap,
                        &mut active_register_roots,
                        &mut active_frame_roots,
                    );
                    return self.resume_generated_single_dispatch_no_gc(
                        suspended,
                        SingleDispatchOutcome::Failed(cleanup.err().unwrap_or(error)),
                    );
                }
                let outcome = self.normalize_generated_single_dispatch_outcome(
                    transaction.may_throw,
                    exception_snapshot,
                    outcome,
                );
                let outcome = match cleanup_targeted_root_sets(
                    &mut self.heap,
                    &mut active_register_roots,
                    &mut active_frame_roots,
                ) {
                    Ok(()) => outcome,
                    Err(error) => SingleDispatchOutcome::Failed(error),
                };
                self.resume_generated_single_dispatch_no_gc(suspended, outcome)
            }
        }
    }

    fn drain_generated_js_call_observation<H: DispatchHost>(
        &mut self,
        handoff: &BaselineGeneratedJsCallHandoff,
        bytecode_snapshot: BaselineBytecodeSnapshotFingerprint,
        host: &mut H,
    ) -> Result<Option<VmCallObservationRequest>, ExecutionError> {
        let Some(descriptor) = host.drain_call_observation(
            &mut self.heap,
            CallObservationDrainRequest {
                owner: handoff.resume.owner,
                frame: handoff.resume.frame,
                bytecode_index: handoff.resume.bytecode_index,
                opcode: handoff.resume.opcode,
            },
        )?
        else {
            return Ok(None);
        };

        Ok(Some(VmCallObservationRequest {
            owner: handoff.resume.owner,
            frame: Some(handoff.resume.frame),
            bytecode_index: handoff.resume.bytecode_index,
            opcode: handoff.resume.opcode,
            bytecode_snapshot,
            descriptor,
        }))
    }

    fn drain_ordinary_bytecode_call_observation<H: DispatchHost>(
        &mut self,
        continuation: &CallReturnContinuation,
        caller_code_block: &CodeBlock,
        host: &mut H,
    ) -> Result<Option<VmCallObservationRequest>, ExecutionError> {
        let bytecode_snapshot =
            match BaselineBytecodeEligibilityProof::fingerprint_code_block_snapshot(
                caller_code_block,
            ) {
                Ok(bytecode_snapshot) => bytecode_snapshot,
                Err(_) => return Ok(None),
            };
        let opcode = continuation.kind.opcode();
        let Some(descriptor) = host.drain_call_observation(
            &mut self.heap,
            CallObservationDrainRequest {
                owner: continuation.owner,
                frame: continuation.caller_frame,
                bytecode_index: continuation.call_bytecode_index,
                opcode,
            },
        )?
        else {
            return Ok(None);
        };

        Ok(Some(VmCallObservationRequest {
            owner: continuation.owner,
            frame: Some(continuation.caller_frame),
            bytecode_index: continuation.call_bytecode_index,
            opcode,
            bytecode_snapshot,
            descriptor,
        }))
    }

    fn drain_ordinary_bytecode_construct_observation<H: DispatchHost>(
        &mut self,
        continuation: &ConstructReturnContinuation,
        caller_code_block: &CodeBlock,
        host: &mut H,
    ) -> Result<Option<VmCallObservationRequest>, ExecutionError> {
        let bytecode_snapshot =
            match BaselineBytecodeEligibilityProof::fingerprint_code_block_snapshot(
                caller_code_block,
            ) {
                Ok(bytecode_snapshot) => bytecode_snapshot,
                Err(_) => return Ok(None),
            };
        let opcode = CoreOpcode::Construct;
        let Some(descriptor) = host.drain_call_observation(
            &mut self.heap,
            CallObservationDrainRequest {
                owner: continuation.owner,
                frame: continuation.caller_frame,
                bytecode_index: continuation.construct_bytecode_index,
                opcode,
            },
        )?
        else {
            return Ok(None);
        };

        Ok(Some(VmCallObservationRequest {
            owner: continuation.owner,
            frame: Some(continuation.caller_frame),
            bytecode_index: continuation.construct_bytecode_index,
            opcode,
            bytecode_snapshot,
            descriptor,
        }))
    }

    fn record_call_observation_and_metadata(
        &mut self,
        observation: Option<VmCallObservationRequest>,
    ) -> Result<(), ExecutionError> {
        let Some(observation) = observation else {
            return Ok(());
        };
        if self.call_observation_target_already_has_call_link_metadata(&observation) {
            return Ok(());
        }
        let observation_record = self
            .tiering
            .record_call_observation(observation)
            .map_err(|_| ExecutionError::BaselineGeneratedExecutionRejected)?;
        self.record_metadata_only_call_link_boundary_validation_for_observation(
            observation_record.ordinal,
        );
        Ok(())
    }

    fn call_observation_target_already_has_call_link_metadata(
        &self,
        observation: &VmCallObservationRequest,
    ) -> bool {
        if observation.descriptor.outcome != CallObservationOutcome::Returned {
            return false;
        }
        let Some(executable) = observation.descriptor.target_executable else {
            return false;
        };
        let Some(callee) = observation.descriptor.callee_object else {
            return false;
        };
        let Some(target_code_block) = observation.descriptor.target_code_block else {
            return false;
        };
        let Some(slot) = self
            .code_blocks
            .call_link_inline_cache_slot_for_owner(observation.owner, observation.bytecode_index)
        else {
            return false;
        };
        if self.call_link_inline_cache_has_active_attachment_for_target(
            observation.owner,
            observation.bytecode_snapshot,
            observation.bytecode_index,
            slot,
            executable,
            callee,
            target_code_block,
        ) {
            return true;
        }
        self.tiering
            .call_link_attachment_plan_records()
            .iter()
            .any(|record| {
                record.owner == observation.owner
                    && record.bytecode_snapshot == observation.bytecode_snapshot
                    && record.bytecode_index == observation.bytecode_index
                    && record.opcode == observation.opcode
                    && record.lifecycle == VmCallLinkAttachmentPlanLifecycle::MetadataOnly
                    && matches!(
                        &record.outcome,
                        VmCallLinkAttachmentPlanOutcome::Planned { plan }
                            if plan.slot == slot
                                && plan.target.executable == executable
                                && plan.target.callee == callee
                                && plan.target.target_code_block == target_code_block
                    )
            })
    }

    fn retarget_call_observation_outcome(
        observation: Option<VmCallObservationRequest>,
        outcome: &SingleDispatchOutcome,
    ) -> Option<VmCallObservationRequest> {
        observation.map(|mut observation| {
            observation.descriptor.outcome =
                Self::call_observation_outcome_for_single_dispatch(outcome);
            observation
        })
    }

    fn call_observation_outcome_for_single_dispatch(
        outcome: &SingleDispatchOutcome,
    ) -> CallObservationOutcome {
        match outcome {
            SingleDispatchOutcome::Continue(_)
            | SingleDispatchOutcome::Jump(_)
            | SingleDispatchOutcome::Return(_) => CallObservationOutcome::Returned,
            SingleDispatchOutcome::Threw(_) => CallObservationOutcome::Threw,
            SingleDispatchOutcome::OrdinaryBytecodeCall(_)
            | SingleDispatchOutcome::OrdinaryBytecodeConstruct(_)
            | SingleDispatchOutcome::FunctionValueCall(_)
            | SingleDispatchOutcome::EvalRequest(_)
            | SingleDispatchOutcome::Suspended(_)
            | SingleDispatchOutcome::Failed(_) => CallObservationOutcome::FailedOrOpaque,
        }
    }

    fn record_generated_direct_call_transaction(
        &mut self,
        continuation: CallReturnContinuation,
        target_code_block: CodeBlockId,
        argument_count_including_this: u32,
        route: VmGeneratedDirectCallTransactionRoute,
        outcome: VmGeneratedDirectCallTransactionOutcome,
    ) {
        self.tiering.record_generated_direct_call_transaction(
            VmGeneratedDirectCallTransactionRequest {
                caller: continuation.owner,
                call_bytecode_index: continuation.call_bytecode_index,
                callee: continuation.callee_object,
                target_code_block,
                argument_count_including_this,
                route,
                outcome,
            },
        );
    }

    fn record_generated_direct_call_callee_fallback(
        &mut self,
        continuation: CallReturnContinuation,
        target_code_block: CodeBlockId,
        argument_count_including_this: u32,
        preferred_route: Option<VmGeneratedDirectCallTransactionRoute>,
        generated_entry_miss: VmGeneratedDirectCallGeneratedEntryMissReason,
        native_entry_miss: VmGeneratedDirectCallNativeEntryMissReason,
    ) {
        self.tiering.record_generated_direct_call_callee_fallback(
            VmGeneratedDirectCallCalleeFallbackRequest {
                caller: continuation.owner,
                call_bytecode_index: continuation.call_bytecode_index,
                callee: continuation.callee_object,
                target_code_block,
                argument_count_including_this,
                preferred_route,
                generated_entry_miss,
                native_entry_miss,
            },
        );
    }

    fn record_generated_direct_call_route_opportunity(
        &mut self,
        continuation: CallReturnContinuation,
        target_code_block: CodeBlockId,
        argument_count_including_this: u32,
        selected_route: VmGeneratedDirectCallTransactionRoute,
        preferred_route: Option<VmGeneratedDirectCallTransactionRoute>,
        native_entry_miss: VmGeneratedDirectCallNativeEntryMissReason,
    ) {
        self.tiering.record_generated_direct_call_route_opportunity(
            VmGeneratedDirectCallRouteOpportunityRequest {
                caller: continuation.owner,
                call_bytecode_index: continuation.call_bytecode_index,
                callee: continuation.callee_object,
                target_code_block,
                argument_count_including_this,
                selected_route,
                preferred_route,
                native_entry_miss,
            },
        );
    }

    fn generated_direct_call_generated_entry_miss_reason(
        &self,
        code_block_id: CodeBlockId,
        code_block: &CodeBlock,
        expected_frame: CallFrameId,
    ) -> VmGeneratedDirectCallGeneratedEntryMissReason {
        let Some(artifact) = self
            .tiering
            .baseline_generated_code_artifact_ref_for(code_block_id)
        else {
            return VmGeneratedDirectCallGeneratedEntryMissReason::MissingArtifact;
        };
        if artifact.validate().is_err() {
            return VmGeneratedDirectCallGeneratedEntryMissReason::InvalidArtifact;
        }
        if artifact.owner != code_block_id {
            return VmGeneratedDirectCallGeneratedEntryMissReason::OwnerMismatch;
        }
        let expected_snapshot = artifact.eligibility_proof.bytecode_snapshot_fingerprint();
        let Ok(actual_snapshot) =
            BaselineBytecodeEligibilityProof::fingerprint_code_block_snapshot(code_block)
        else {
            return VmGeneratedDirectCallGeneratedEntryMissReason::SnapshotMismatch;
        };
        if actual_snapshot != expected_snapshot {
            return VmGeneratedDirectCallGeneratedEntryMissReason::SnapshotMismatch;
        }
        let Some(active_frame) = self.execution.top_frame() else {
            return VmGeneratedDirectCallGeneratedEntryMissReason::FrameMismatch;
        };
        if active_frame.id != expected_frame || active_frame.code_block != Some(code_block_id) {
            return VmGeneratedDirectCallGeneratedEntryMissReason::FrameMismatch;
        }
        VmGeneratedDirectCallGeneratedEntryMissReason::Ready
    }

    fn generated_direct_call_native_entry_miss_reason(
        &self,
        code_block_id: CodeBlockId,
        code_block: &CodeBlock,
        expected_frame: CallFrameId,
    ) -> VmGeneratedDirectCallNativeEntryMissReason {
        let Some(gate) = self
            .tiering
            .baseline_native_entry_gate_for_owner(code_block_id)
        else {
            // Oversized-file exception: generated direct-call telemetry lives in
            // the VM core today. C++ linkFor() prepares the callee executable
            // before publishing an entrypoint; after Rust attempts that
            // preparation, a generated fallback should report the concrete
            // native materialization failure rather than the pre-attempt
            // MissingGate state.
            if let Some(reason) = self
                .tiering
                .baseline_entry_auto_materializations()
                .iter()
                .rev()
                .find(|record| record.owner == code_block_id)
                .and_then(|record| match record.native {
                    BaselineEntryAutoNativeMaterializationOutcome::Failed {
                        reason,
                        generated_fallback_allowed,
                    } => Some(
                        VmGeneratedDirectCallNativeEntryMissReason::NativeMaterializationFailed {
                            reason,
                            generated_fallback_allowed,
                        },
                    ),
                    _ => None,
                })
            {
                return reason;
            }
            return VmGeneratedDirectCallNativeEntryMissReason::MissingGate;
        };
        if gate.outcome != BaselineEntryGateOutcome::NativeEntryReady {
            return VmGeneratedDirectCallNativeEntryMissReason::GateNotReady {
                outcome: gate.outcome,
            };
        }
        let Some(readiness) = self.tiering.baseline_native_entry_readiness_for_gate(&gate) else {
            return VmGeneratedDirectCallNativeEntryMissReason::MissingReadiness;
        };
        if readiness.execution_policy != BaselineNativeEntryExecutionPolicy::Enabled
            || readiness.outcome != BaselineNativeEntryReadinessOutcome::Ready
        {
            return VmGeneratedDirectCallNativeEntryMissReason::ReadinessNotReady;
        }
        let Some(callable) = readiness.callable else {
            return VmGeneratedDirectCallNativeEntryMissReason::MissingCallable;
        };
        if !self.can_execute_baseline_native_entry_kind(callable.kind()) {
            // Historical telemetry name: this path was introduced for x86_64
            // semantic bytes on arm64. It now gates any non-executable native
            // callable kind, while ARM64 direct-call continuation binding stays
            // disabled until the full PC-metadata backend is ported.
            return VmGeneratedDirectCallNativeEntryMissReason::HostBlockedX86_64;
        }
        let Some(descriptor) = readiness.descriptor else {
            return VmGeneratedDirectCallNativeEntryMissReason::MissingDescriptor;
        };
        let Some(artifact) = gate.native_artifact else {
            return VmGeneratedDirectCallNativeEntryMissReason::MissingNativeArtifact;
        };
        if artifact.owner != code_block_id
            || descriptor.owner != code_block_id
            || descriptor.artifact_id != artifact.id
            || descriptor.native_symbol != artifact.native_code
            || descriptor.machine_code != artifact.machine_code
            || descriptor.machine_range != artifact.machine_code.range
            || descriptor.entrypoint != artifact.entrypoint
            || descriptor.baseline_abi_proof != artifact.baseline_abi_proof
            || callable.validate_for_descriptor(&descriptor).is_err()
        {
            return VmGeneratedDirectCallNativeEntryMissReason::MetadataMismatch;
        }
        let Some(readiness_snapshot) = readiness.bytecode_snapshot else {
            return VmGeneratedDirectCallNativeEntryMissReason::SnapshotMissing;
        };
        let Ok(actual_snapshot) =
            BaselineBytecodeEligibilityProof::fingerprint_code_block_snapshot(code_block)
        else {
            return VmGeneratedDirectCallNativeEntryMissReason::SnapshotMismatch;
        };
        if actual_snapshot != readiness_snapshot {
            return VmGeneratedDirectCallNativeEntryMissReason::SnapshotMismatch;
        }
        let Some(active_frame) = self.execution.top_frame() else {
            return VmGeneratedDirectCallNativeEntryMissReason::FrameMismatch;
        };
        if active_frame.id != expected_frame || active_frame.code_block != Some(code_block_id) {
            return VmGeneratedDirectCallNativeEntryMissReason::FrameMismatch;
        }
        let Some((scope, call_frame)) = self.baseline_native_entry_launch_metadata(
            code_block_id,
            code_block,
            crate::interpreter::ExecutionEntryKind::Function,
        ) else {
            return VmGeneratedDirectCallNativeEntryMissReason::MissingLaunchMetadata;
        };
        let Ok(launch_descriptor) =
            VmEntryLaunchDescriptor::baseline_native_entry(scope, call_frame, gate, readiness)
        else {
            return VmGeneratedDirectCallNativeEntryMissReason::InvalidLaunchDescriptor;
        };
        match launch_descriptor.dispatch {
            VmEntryDispatchSelection::BaselineNative(
                BaselineNativeDispatchTokenSelection::NormalEntry { token },
            ) if token == callable.token() => VmGeneratedDirectCallNativeEntryMissReason::Ready,
            _ => VmGeneratedDirectCallNativeEntryMissReason::DispatchSelectionMismatch,
        }
    }

    fn generated_direct_call_transaction_outcome(
        outcome: &SingleDispatchOutcome,
    ) -> VmGeneratedDirectCallTransactionOutcome {
        match outcome {
            SingleDispatchOutcome::Continue(_) => VmGeneratedDirectCallTransactionOutcome::Continue,
            SingleDispatchOutcome::Jump(_) => VmGeneratedDirectCallTransactionOutcome::Jump,
            SingleDispatchOutcome::Return(_) => VmGeneratedDirectCallTransactionOutcome::Return,
            SingleDispatchOutcome::Threw(_) => VmGeneratedDirectCallTransactionOutcome::Threw,
            SingleDispatchOutcome::OrdinaryBytecodeCall(_) => {
                VmGeneratedDirectCallTransactionOutcome::OrdinaryBytecodeCall
            }
            SingleDispatchOutcome::OrdinaryBytecodeConstruct(_) => {
                VmGeneratedDirectCallTransactionOutcome::OrdinaryBytecodeConstruct
            }
            SingleDispatchOutcome::FunctionValueCall(_) => {
                VmGeneratedDirectCallTransactionOutcome::FunctionValueCall
            }
            // An eval deferral never originates from a generated direct call; if
            // one did, it is an unexpected outcome for this accounting path.
            SingleDispatchOutcome::EvalRequest(_) => {
                VmGeneratedDirectCallTransactionOutcome::Failed
            }
            SingleDispatchOutcome::Suspended(_) => {
                VmGeneratedDirectCallTransactionOutcome::Suspended
            }
            SingleDispatchOutcome::Failed(_) => VmGeneratedDirectCallTransactionOutcome::Failed,
        }
    }

    fn generated_js_direct_call_rootless_generated_entry_proof(
        &mut self,
        validation: &GeneratedJsDirectCallValidation,
    ) -> Result<
        GeneratedDirectCallRootlessGeneratedEntryProof,
        VmGeneratedDirectCallRootlessRejectionReason,
    > {
        if validation.preferred_route != Some(VmGeneratedDirectCallTransactionRoute::NativeEntry) {
            if let Some(kind) =
                self.generated_direct_call_native_entry_kind(validation.target_code_block_id)
            {
                // C++ CallLinkInfo's fast path jumps to the prepared target
                // entrypoint. Once Rust has a sealed callable native entry, the
                // generated re-interpreter artifact is not the faithful
                // equivalent of that target entrypoint.
                return Err(
                    VmGeneratedDirectCallRootlessRejectionReason::PreferredRouteNotGeneratedEntry {
                        native_entry_kind: Some(kind),
                    },
                );
            }
        }
        if validation.hot_slot_hit
            && validation.preferred_route
                != Some(VmGeneratedDirectCallTransactionRoute::GeneratedEntry)
        {
            return Err(
                VmGeneratedDirectCallRootlessRejectionReason::PreferredRouteNotGeneratedEntry {
                    native_entry_kind: self
                        .generated_direct_call_native_entry_kind(validation.target_code_block_id),
                },
            );
        }
        // C++ Baseline CallLinkInfo's monomorphic fast path calls the linked
        // target entry after linkFor() has prepared the callee; it does not
        // require a second VM-owned hot-slot hit. A full Rust sidecar handoff is
        // already a validated monomorphic call-link observation, so the
        // generated artifact/snapshot/effect checks below are the rootless
        // admission proof when no cached hot slot exists yet.
        if let Some(cache) = validation.rootless_generated_entry_proof {
            if cache.epoch == self.generated_direct_call_rootless_proof_epoch()
                && cache.target_code_block_id == validation.target_code_block_id
            {
                if let Some(artifact) = self
                    .tiering
                    .baseline_generated_code_artifact_ref_for(validation.target_code_block_id)
                {
                    let expected_snapshot =
                        artifact.eligibility_proof.bytecode_snapshot_fingerprint();
                    if artifact.id == cache.artifact_id
                        && artifact.owner == validation.target_code_block_id
                        && artifact.validate().is_ok()
                        && artifact.runtime_helper_plan().is_none()
                        && expected_snapshot == cache.bytecode_snapshot
                    {
                        self.tiering
                            .record_generated_direct_call_rootless_generated_entry_proof_cache_hit(
                            );
                        return Ok(cache.proof);
                    }
                }
            }
        }
        let Some(artifact) = self
            .tiering
            .baseline_generated_code_artifact_ref_for(validation.target_code_block_id)
        else {
            // C++ CallLinkInfo::linkFor() prepares a missing JS callee
            // executable from the rooted call slow path before returning the
            // entrypoint. Rootless dispatch is only the already-prepared fast
            // path, so absence of the generated artifact must fall through to
            // Rust's rooted direct-call slow path rather than generating here.
            return Err(VmGeneratedDirectCallRootlessRejectionReason::MissingGeneratedArtifact);
        };
        if artifact.validate().is_err() || artifact.owner != validation.target_code_block_id {
            return Err(VmGeneratedDirectCallRootlessRejectionReason::InvalidGeneratedArtifact);
        }
        if artifact.runtime_helper_plan().is_some() {
            return Err(VmGeneratedDirectCallRootlessRejectionReason::RuntimeHelperPlan);
        }
        let expected_snapshot = artifact.eligibility_proof.bytecode_snapshot_fingerprint();
        let Ok(actual_snapshot) = BaselineBytecodeEligibilityProof::fingerprint_code_block_snapshot(
            &validation.target_code_block,
        ) else {
            return Err(VmGeneratedDirectCallRootlessRejectionReason::SnapshotMismatch);
        };
        if actual_snapshot != expected_snapshot {
            return Err(VmGeneratedDirectCallRootlessRejectionReason::SnapshotMismatch);
        }
        let contract = artifact.eligibility_proof.generated_effect_contract();
        if !contract.permits_no_heap_allocation_no_runtime_call()
            || contract.summary.may_throw
            || contract.summary.writes_heap
            || contract.touches_gc_roots
        {
            return Err(VmGeneratedDirectCallRootlessRejectionReason::EffectContract);
        }
        let js_call_native_exit_plan =
            derive_baseline_generated_js_call_native_exit_plan_from_code_block(
                &validation.target_code_block,
                artifact.owner,
            )
            .ok()
            .and_then(|derivation| derivation.metadata)
            .filter(|metadata| metadata.site_count() > 0);
        let proof =
            if artifact.property_handoff_plan().is_some() || js_call_native_exit_plan.is_some() {
                GeneratedDirectCallRootlessGeneratedEntryProof::DeferredGeneratedExitRooting
            } else {
                GeneratedDirectCallRootlessGeneratedEntryProof::StrictLocalLeaf
            };
        Self::validate_rootless_generated_direct_call_body(
            &validation.target_code_block,
            &artifact,
            js_call_native_exit_plan.as_ref(),
            proof,
        )?;
        self.remember_generated_direct_call_hot_slot_rootless_generated_entry_proof(
            validation,
            artifact.id,
            expected_snapshot,
            proof,
        );
        Ok(proof)
    }

    fn generated_js_direct_call_rootless_emitted_native_entry_proof(
        &mut self,
        validation: &GeneratedJsDirectCallValidation,
    ) -> Result<
        GeneratedDirectCallRootlessGeneratedEntryProof,
        VmGeneratedDirectCallRootlessRejectionReason,
    > {
        if !validation.hot_slot_hit {
            return Err(VmGeneratedDirectCallRootlessRejectionReason::HotSlotMiss);
        }
        if validation.preferred_route != Some(VmGeneratedDirectCallTransactionRoute::NativeEntry) {
            return Err(
                VmGeneratedDirectCallRootlessRejectionReason::PreferredRouteNotGeneratedEntry {
                    native_entry_kind: self
                        .generated_direct_call_native_entry_kind(validation.target_code_block_id),
                },
            );
        }

        let gate = self
            .tiering
            .baseline_native_entry_gate_for_owner(validation.target_code_block_id)
            .ok_or(VmGeneratedDirectCallRootlessRejectionReason::MissingGeneratedArtifact)?;
        if gate.outcome != BaselineEntryGateOutcome::NativeEntryReady {
            return Err(VmGeneratedDirectCallRootlessRejectionReason::InvalidGeneratedArtifact);
        }
        let readiness = self
            .tiering
            .baseline_native_entry_readiness_for_gate(&gate)
            .ok_or(VmGeneratedDirectCallRootlessRejectionReason::InvalidGeneratedArtifact)?;
        if readiness.execution_policy != BaselineNativeEntryExecutionPolicy::Enabled
            || readiness.outcome != BaselineNativeEntryReadinessOutcome::Ready
        {
            return Err(VmGeneratedDirectCallRootlessRejectionReason::InvalidGeneratedArtifact);
        }
        let callable = readiness
            .callable
            .ok_or(VmGeneratedDirectCallRootlessRejectionReason::InvalidGeneratedArtifact)?;
        if callable.kind() != BaselineNativeEntryCallableKind::P6X86_64EmittedSemanticCAbiEntry {
            return Err(VmGeneratedDirectCallRootlessRejectionReason::EffectContract);
        }
        if !self.can_execute_p6_x86_64_emitted_native_entry() {
            return Err(VmGeneratedDirectCallRootlessRejectionReason::InvalidGeneratedArtifact);
        }
        let descriptor = readiness
            .descriptor
            .ok_or(VmGeneratedDirectCallRootlessRejectionReason::InvalidGeneratedArtifact)?;
        let artifact = gate
            .native_artifact
            .ok_or(VmGeneratedDirectCallRootlessRejectionReason::MissingGeneratedArtifact)?;
        if artifact.owner != validation.target_code_block_id
            || descriptor.owner != validation.target_code_block_id
            || descriptor.artifact_id != artifact.id
            || descriptor.native_symbol != artifact.native_code
            || descriptor.machine_code != artifact.machine_code
            || descriptor.machine_range != artifact.machine_code.range
            || descriptor.entrypoint != artifact.entrypoint
            || descriptor.baseline_abi_proof != artifact.baseline_abi_proof
            || callable.validate_for_descriptor(&descriptor).is_err()
        {
            return Err(VmGeneratedDirectCallRootlessRejectionReason::InvalidGeneratedArtifact);
        }
        let readiness_snapshot = readiness
            .bytecode_snapshot
            .ok_or(VmGeneratedDirectCallRootlessRejectionReason::SnapshotMismatch)?;
        let Ok(actual_snapshot) = BaselineBytecodeEligibilityProof::fingerprint_code_block_snapshot(
            &validation.target_code_block,
        ) else {
            return Err(VmGeneratedDirectCallRootlessRejectionReason::SnapshotMismatch);
        };
        if actual_snapshot != readiness_snapshot {
            return Err(VmGeneratedDirectCallRootlessRejectionReason::SnapshotMismatch);
        }
        if self
            .platform_residency_index_for_native_entry(readiness, &descriptor)
            .is_none()
        {
            return Err(VmGeneratedDirectCallRootlessRejectionReason::InvalidGeneratedArtifact);
        }

        let body_capability = readiness
            .body_capability
            .ok_or(VmGeneratedDirectCallRootlessRejectionReason::EffectContract)?;
        let opcode_subset = body_capability.supported_opcode_subset;
        let contract = body_capability.effect_contract;
        if contract.opcode_subset != opcode_subset
            || !contract.permits_no_heap_allocation_no_runtime_call()
            || contract.summary.may_throw
            || contract.summary.writes_heap
            || contract.touches_gc_roots
        {
            return Err(VmGeneratedDirectCallRootlessRejectionReason::EffectContract);
        }
        let table = self
            .p6_x86_64_callable_retained_return_tables
            .iter()
            .rev()
            .find(|table| {
                table.matches_native_entry_metadata(
                    validation.target_code_block_id,
                    readiness,
                    &descriptor,
                    actual_snapshot,
                )
            })
            .ok_or(VmGeneratedDirectCallRootlessRejectionReason::InvalidGeneratedArtifact)?;
        if !self.rootless_emitted_native_entry_property_increment_store_readiness_allowed(
            &validation.target_code_block,
            table,
        ) {
            let rejection_records =
                Self::rootless_emitted_native_entry_retained_side_exit_rejection_records(
                    &validation.target_code_block,
                    table,
                );
            for (bytecode_index, opcode, reason) in rejection_records {
                self.tiering
                    .record_generated_direct_call_rootless_native_entry_retained_side_exit(
                        validation.target_code_block_id,
                        bytecode_index,
                        opcode,
                        reason,
                    );
            }
            return Err(VmGeneratedDirectCallRootlessRejectionReason::RetainedSideExit);
        }
        let side_exit_proof = match Self::rootless_emitted_native_entry_retained_side_exit_proof(
            &validation.target_code_block,
            table,
        ) {
            Some(proof) => proof,
            None => {
                let rejection_records =
                    Self::rootless_emitted_native_entry_retained_side_exit_rejection_records(
                        &validation.target_code_block,
                        table,
                    );
                for (bytecode_index, opcode, reason) in rejection_records {
                    self.tiering
                        .record_generated_direct_call_rootless_native_entry_retained_side_exit(
                            validation.target_code_block_id,
                            bytecode_index,
                            opcode,
                            reason,
                        );
                }
                return Err(VmGeneratedDirectCallRootlessRejectionReason::RetainedSideExit);
            }
        };
        if !table.loop_backedge_sites.is_empty() {
            return Err(VmGeneratedDirectCallRootlessRejectionReason::RetainedLoopBackedgeExit);
        }
        if !Self::rootless_emitted_native_entry_retained_runtime_helper_exit_plan_allowed(
            &validation.target_code_block,
            validation.target_code_block_id,
            actual_snapshot,
            table,
        ) {
            return Err(VmGeneratedDirectCallRootlessRejectionReason::RetainedRuntimeHelperExit);
        }
        for site in &table.property_exit_sites {
            if site.site.owner != validation.target_code_block_id
                || !site.site.requires_no_gc_exit_reentry
                || !site.site.may_throw
                || validate_baseline_generated_property_handoff_site_metadata(&site.site).is_err()
                || validate_baseline_generated_property_handoff_site_against_current_code_block(
                    &validation.target_code_block,
                    validation.target_code_block_id,
                    &site.site,
                )
                .is_err()
            {
                return Err(VmGeneratedDirectCallRootlessRejectionReason::InvalidGeneratedArtifact);
            }
        }
        for site in &table.js_call_exit_sites {
            if site.owner != validation.target_code_block_id
                || site.encoded_payload.low_tag()
                    != P9_X86_64_BASELINE_JS_CALL_NATIVE_EXIT_RETURN_PAYLOAD_LOW_TAG
                || !site.requires_no_gc_exit_reentry
                || !site.may_throw
                || !matches!(
                    site.opcode,
                    CoreOpcode::Call | CoreOpcode::CallWithThis | CoreOpcode::Construct
                )
            {
                return Err(VmGeneratedDirectCallRootlessRejectionReason::RetainedJsCallExit);
            }
            let plan_site = site.as_plan_site();
            if validate_baseline_generated_js_call_native_exit_site_metadata(&plan_site).is_err()
                || validate_baseline_generated_js_call_native_exit_site_against_code_block(
                    &validation.target_code_block,
                    validation.target_code_block_id,
                    &plan_site,
                )
                .is_err()
            {
                return Err(VmGeneratedDirectCallRootlessRejectionReason::InvalidGeneratedArtifact);
            }
        }
        let retained_js_call_native_exit_plan = if table.js_call_exit_sites.is_empty() {
            None
        } else {
            Some(
                BaselineGeneratedJsCallNativeExitPlanMetadata::new(
                    actual_snapshot,
                    table
                        .js_call_exit_sites
                        .iter()
                        .map(P9X86_64CallableJsCallNativeExitReturnSite::as_plan_site)
                        .collect(),
                )
                .map_err(|_| {
                    VmGeneratedDirectCallRootlessRejectionReason::InvalidGeneratedArtifact
                })?,
            )
        };
        let derived_js_call_native_exit_plan =
            derive_baseline_generated_js_call_native_exit_plan_from_code_block(
                &validation.target_code_block,
                validation.target_code_block_id,
            )
            .map_err(|_| VmGeneratedDirectCallRootlessRejectionReason::InvalidGeneratedArtifact)?
            .metadata;
        if retained_js_call_native_exit_plan != derived_js_call_native_exit_plan {
            return Err(VmGeneratedDirectCallRootlessRejectionReason::InvalidGeneratedArtifact);
        }
        Self::validate_rootless_emitted_native_entry_body(
            &validation.target_code_block,
            opcode_subset,
            table,
        )?;

        if !table.runtime_helper_exit_sites.is_empty()
            || !table.property_exit_sites.is_empty()
            || !table.js_call_exit_sites.is_empty()
        {
            Ok(GeneratedDirectCallRootlessGeneratedEntryProof::DeferredGeneratedExitRooting)
        } else if let Some(proof) = side_exit_proof {
            Ok(proof)
        } else {
            Ok(GeneratedDirectCallRootlessGeneratedEntryProof::StrictLocalLeaf)
        }
    }

    fn generated_direct_call_native_entry_kind(
        &self,
        code_block_id: CodeBlockId,
    ) -> Option<BaselineNativeEntryCallableKind> {
        let gate = self
            .tiering
            .baseline_native_entry_gate_for_owner(code_block_id)?;
        let readiness = self
            .tiering
            .baseline_native_entry_readiness_for_gate(&gate)?;
        let kind = readiness.callable.map(|callable| callable.kind())?;
        if !self.can_execute_baseline_native_entry_kind(kind) {
            return None;
        }
        Some(kind)
    }

    fn validate_rootless_emitted_native_entry_body(
        code_block: &CodeBlock,
        opcode_subset: BaselineSupportedOpcodeSubset,
        retained_return_table: &P6X86_64CallableRetainedReturnTable,
    ) -> Result<(), VmGeneratedDirectCallRootlessRejectionReason> {
        let mut saw_return = false;
        for (ordinal, instruction) in code_block
            .unlinked()
            .instructions()
            .decoded_instructions()
            .enumerate()
        {
            let Ok(instruction) = instruction else {
                return Err(VmGeneratedDirectCallRootlessRejectionReason::InvalidBodyInstruction);
            };
            let Some(opcode) = CoreOpcode::from_opcode(instruction.opcode) else {
                return Err(VmGeneratedDirectCallRootlessRejectionReason::InvalidBodyInstruction);
            };
            if !instruction.bytecode_index.is_valid()
                || instruction.bytecode_index != BytecodeIndex::from_offset(ordinal as u32)
            {
                return Err(VmGeneratedDirectCallRootlessRejectionReason::InvalidBodyBytecodeIndex);
            }
            if !opcode_subset.supports(opcode)
                && !Self::rootless_emitted_native_entry_runtime_helper_exit_site_allowed(
                    instruction.bytecode_index,
                    opcode,
                    retained_return_table,
                )
                && !Self::rootless_emitted_native_entry_property_exit_site_allowed(
                    instruction.bytecode_index,
                    opcode,
                    retained_return_table,
                )
                && !Self::rootless_emitted_native_entry_js_call_exit_site_allowed(
                    instruction.bytecode_index,
                    opcode,
                    retained_return_table,
                )
            {
                return Err(
                    VmGeneratedDirectCallRootlessRejectionReason::UnsupportedBodyOpcode { opcode },
                );
            }
            saw_return |= opcode == CoreOpcode::Return;
        }
        if saw_return {
            Ok(())
        } else {
            Err(VmGeneratedDirectCallRootlessRejectionReason::MissingReturn)
        }
    }

    fn rootless_emitted_native_entry_retained_runtime_helper_exit_plan_allowed(
        code_block: &CodeBlock,
        owner: CodeBlockId,
        bytecode_snapshot: BaselineBytecodeSnapshotFingerprint,
        retained_return_table: &P6X86_64CallableRetainedReturnTable,
    ) -> bool {
        if retained_return_table.runtime_helper_exit_sites.is_empty() {
            return true;
        }

        let Ok(derivation) =
            derive_baseline_generated_runtime_helper_plan_from_code_block(code_block, owner)
        else {
            return false;
        };
        let Some(metadata) = derivation.metadata else {
            return false;
        };
        if metadata.bytecode_snapshot() != bytecode_snapshot
            || metadata.proof_count() != retained_return_table.runtime_helper_exit_sites.len()
            || !baseline_generated_runtime_helper_plan_is_native_exit_eligible(&metadata)
            || validate_baseline_generated_runtime_helper_plan_against_code_block(
                code_block, owner, &metadata,
            )
            .is_err()
        {
            return false;
        }

        retained_return_table
            .runtime_helper_exit_sites
            .iter()
            .enumerate()
            .all(|(ordinal, site)| {
                metadata
                    .proof_for_bytecode_index(site.bytecode_index)
                    .map(|proof| {
                        Self::rootless_emitted_native_entry_runtime_helper_exit_site_allowed_with_proof(
                            ordinal, site, proof,
                        )
                    })
                    .unwrap_or(false)
            })
    }

    fn rootless_emitted_native_entry_runtime_helper_exit_site_allowed_with_proof(
        ordinal: usize,
        site: &P6X86_64CallableRuntimeHelperNativeExitReturnSite,
        proof: &BaselineGeneratedRuntimeBoundaryProof,
    ) -> bool {
        let Ok(site_index) = u32::try_from(ordinal) else {
            return false;
        };
        let Some(payload_index) = P6_X86_64_BASELINE_RUNTIME_HELPER_NATIVE_EXIT_PAYLOAD_INDEX_BASE
            .checked_add(site_index)
        else {
            return false;
        };
        let Some(root_map) = proof.root_map else {
            return false;
        };

        site.bytecode_index.is_valid()
            && site.encoded_payload == P6X86_64BaselineSideExitReturnPayload::encode(payload_index)
            && site.opcode == proof.contract.opcode
            && site.safepoint == proof.safepoint
            && site.root_map == root_map
            && site.root_count == proof.root_count
            && site.requires_no_gc_exit_reentry == proof.no_gc_exit_reentry
            && site.may_throw == proof.may_throw
            && proof.contract.effects.calls_runtime_helper
            && proof.contract.effects.touches_gc_roots
            && proof.contract.requirements.complete_safepoint_root_map
            && proof.contract.requirements.no_gc_exit_reentry
            && proof.no_gc_exit_reentry
            && proof.may_throw == proof.contract.effects.may_throw
    }

    fn rootless_emitted_native_entry_runtime_helper_exit_site_allowed(
        bytecode_index: BytecodeIndex,
        opcode: CoreOpcode,
        retained_return_table: &P6X86_64CallableRetainedReturnTable,
    ) -> bool {
        retained_return_table
            .runtime_helper_exit_sites
            .iter()
            .any(|site| {
                site.bytecode_index == bytecode_index
                    && site.opcode == opcode
                    && site.requires_no_gc_exit_reentry
                    && site.may_throw
                    && site.encoded_payload.side_exit_index()
                        >= P6_X86_64_BASELINE_RUNTIME_HELPER_NATIVE_EXIT_PAYLOAD_INDEX_BASE
            })
    }

    fn rootless_emitted_native_entry_property_exit_site_allowed(
        bytecode_index: BytecodeIndex,
        opcode: CoreOpcode,
        retained_return_table: &P6X86_64CallableRetainedReturnTable,
    ) -> bool {
        retained_return_table
            .property_exit_sites
            .iter()
            .any(|site| {
                site.site.bytecode_index == bytecode_index
                    && site.site.opcode == opcode
                    && site.site.requires_no_gc_exit_reentry
                    && site.site.may_throw
                    && matches!(
                        opcode,
                        CoreOpcode::GetByName
                            | CoreOpcode::GetGlobalObjectProperty
                            | CoreOpcode::GetByValue
                            | CoreOpcode::PutByName
                            | CoreOpcode::PutGlobalObjectProperty
                            | CoreOpcode::PutByValue
                    )
            })
    }

    fn rootless_emitted_native_entry_js_call_exit_site_allowed(
        bytecode_index: BytecodeIndex,
        opcode: CoreOpcode,
        retained_return_table: &P6X86_64CallableRetainedReturnTable,
    ) -> bool {
        retained_return_table.js_call_exit_sites.iter().any(|site| {
            site.bytecode_index == bytecode_index
                && site.opcode == opcode
                && site.requires_no_gc_exit_reentry
                && site.may_throw
                && site.encoded_payload.low_tag()
                    == P9_X86_64_BASELINE_JS_CALL_NATIVE_EXIT_RETURN_PAYLOAD_LOW_TAG
                && matches!(
                    opcode,
                    CoreOpcode::Call | CoreOpcode::CallWithThis | CoreOpcode::Construct
                )
        })
    }

    fn rootless_emitted_native_entry_property_increment_store_readiness_allowed(
        &self,
        code_block: &CodeBlock,
        retained_return_table: &P6X86_64CallableRetainedReturnTable,
    ) -> bool {
        let to_number_increment_put_sites = retained_return_table
            .side_exit_sites
            .iter()
            .filter(|site| {
                site.reason == P6X86_64BaselineSelectedSideExitReason::UnsupportedToNumberOperand
            })
            .filter_map(|side_exit| {
                Self::rootless_emitted_native_entry_property_increment_put_exit_for_to_number_side_exit(
                    code_block,
                    retained_return_table,
                    side_exit,
                )
            })
            .collect::<Vec<_>>();
        if to_number_increment_put_sites.is_empty() {
            return !retained_return_table.side_exit_sites.iter().any(|site| {
                site.reason == P6X86_64BaselineSelectedSideExitReason::UnsupportedToNumberOperand
            });
        }

        to_number_increment_put_sites.iter().all(|put_exit| {
            let PropertyCacheKey::Key(key) = put_exit.site.property_key else {
                return false;
            };
            self.tiering
                .generated_property_store_mutation_readiness_records()
                .iter()
                .any(|readiness| {
                    readiness.owner == retained_return_table.owner
                        && readiness.bytecode_snapshot == retained_return_table.bytecode_snapshot
                        && readiness.bytecode_index == put_exit.site.bytecode_index
                        && readiness.slot == put_exit.site.slot
                        && readiness.key == CacheKey::Property(key)
                        && readiness.plan_kind == PropertyStoreAccessCasePlanKind::DataOnlyReplace
                        && matches!(
                            readiness.outcome,
                            VmGeneratedPropertyStoreMutationReadinessOutcome::Accepted { .. }
                        )
                })
        })
    }

    fn rootless_emitted_native_entry_retained_side_exit_proof(
        code_block: &CodeBlock,
        retained_return_table: &P6X86_64CallableRetainedReturnTable,
    ) -> Option<Option<GeneratedDirectCallRootlessGeneratedEntryProof>> {
        if retained_return_table.side_exit_sites.is_empty() {
            return Some(None);
        }
        let all_allowed = retained_return_table
            .side_exit_sites
            .iter()
            .enumerate()
            .all(|(ordinal, site)| {
                Self::rootless_emitted_native_entry_retained_side_exit_site_allowed(
                    code_block, ordinal, site,
                ) || Self::rootless_emitted_native_entry_property_increment_side_exit_site_allowed(
                    code_block,
                    retained_return_table,
                    ordinal,
                    site,
                )
            });
        if !all_allowed {
            return None;
        }
        let may_call_or_throw = retained_return_table.side_exit_sites.iter().any(|site| {
            matches!(
                site.reason,
                P6X86_64BaselineSelectedSideExitReason::NonInt32Operand
                    | P6X86_64BaselineSelectedSideExitReason::UnsupportedToNumberOperand
            )
        });
        Some(Some(if may_call_or_throw {
            GeneratedDirectCallRootlessGeneratedEntryProof::DeferredThrowingSideExitRooting
        } else {
            GeneratedDirectCallRootlessGeneratedEntryProof::DeferredNonThrowingExitRooting
        }))
    }

    fn rootless_emitted_native_entry_retained_side_exit_rejection_records(
        code_block: &CodeBlock,
        retained_return_table: &P6X86_64CallableRetainedReturnTable,
    ) -> Vec<(
        BytecodeIndex,
        Option<CoreOpcode>,
        P6X86_64BaselineSelectedSideExitReason,
    )> {
        retained_return_table
            .side_exit_sites
            .iter()
            .map(|site| {
                let opcode = code_block
                    .decoded_instruction_at(site.bytecode_index)
                    .ok()
                    .and_then(|instruction| CoreOpcode::from_opcode(instruction.opcode));
                (site.bytecode_index, opcode, site.reason)
            })
            .collect()
    }

    fn rootless_emitted_native_entry_retained_side_exit_site_allowed(
        code_block: &CodeBlock,
        ordinal: usize,
        site: &P6X86_64CallableSideExitReturnSite,
    ) -> bool {
        site.side_exit_index as usize == ordinal
            && site.encoded_payload
                == P6X86_64BaselineSideExitReturnPayload::encode(site.side_exit_index)
            && Self::rootless_emitted_native_entry_side_exit_reason_allowed(code_block, site)
    }

    fn rootless_emitted_native_entry_property_increment_side_exit_site_allowed(
        code_block: &CodeBlock,
        retained_return_table: &P6X86_64CallableRetainedReturnTable,
        ordinal: usize,
        side_exit: &P6X86_64CallableSideExitReturnSite,
    ) -> bool {
        side_exit.side_exit_index as usize == ordinal
            && side_exit.encoded_payload
                == P6X86_64BaselineSideExitReturnPayload::encode(side_exit.side_exit_index)
            && matches!(
                side_exit.reason,
                P6X86_64BaselineSelectedSideExitReason::UnsupportedToNumberOperand
                    | P6X86_64BaselineSelectedSideExitReason::NonInt32Operand
                    | P6X86_64BaselineSelectedSideExitReason::Overflow
            )
            && side_exit.resume_bytecode_index.is_some()
            && side_exit.resume_entry_offset.is_some()
            && retained_return_table
                .property_exit_sites
                .iter()
                .any(|property_exit| {
                    Self::rootless_emitted_native_entry_property_increment_shape_covers_side_exit(
                        code_block,
                        retained_return_table,
                        property_exit,
                        side_exit,
                    )
                })
    }

    fn rootless_emitted_native_entry_property_increment_shape_covers_side_exit(
        code_block: &CodeBlock,
        retained_return_table: &P6X86_64CallableRetainedReturnTable,
        get_exit: &P10X86_64CallablePropertyNativeExitReturnSite,
        side_exit: &P6X86_64CallableSideExitReturnSite,
    ) -> bool {
        if get_exit.site.opcode != CoreOpcode::GetByName
            || get_exit.site.owner != retained_return_table.owner
            || !get_exit.site.requires_no_gc_exit_reentry
            || !get_exit.site.may_throw
            || validate_baseline_generated_property_handoff_site_metadata(&get_exit.site).is_err()
        {
            return false;
        }
        let PropertyCacheKey::Key(get_key) = get_exit.site.property_key else {
            return false;
        };
        let Ok(get_instruction) = code_block.decoded_instruction_at(get_exit.site.bytecode_index)
        else {
            return false;
        };
        if CoreOpcode::from_opcode(get_instruction.opcode) != Some(CoreOpcode::GetByName) {
            return false;
        }
        let Ok(get_destination) = get_instruction.register_operand(0) else {
            return false;
        };
        let Ok(get_base) = get_instruction.register_operand(1) else {
            return false;
        };
        let Some(get_identifier) =
            identifier_index_operand_for_rootless_increment(get_instruction, 2)
        else {
            return false;
        };

        let mut cursor = get_instruction.bytecode_index.offset().saturating_add(1);
        let Some(to_number) = decoded_core_instruction_at_offset_for_rootless_increment(
            code_block,
            cursor,
            CoreOpcode::ToNumber,
        ) else {
            return false;
        };
        let Ok(to_number_destination) = to_number.register_operand(0) else {
            return false;
        };
        if to_number.register_operand(1).ok() != Some(get_destination) {
            return false;
        }
        cursor = cursor.saturating_add(1);

        if let Some(move_instruction) = decoded_core_instruction_at_offset_for_rootless_increment(
            code_block,
            cursor,
            CoreOpcode::Move,
        ) {
            if move_instruction.register_operand(1).ok() != Some(to_number_destination)
                || move_instruction.register_operand(0).is_err()
            {
                return false;
            }
            cursor = cursor.saturating_add(1);
        }

        let Some(load_one) = decoded_core_instruction_at_offset_for_rootless_increment(
            code_block,
            cursor,
            CoreOpcode::LoadInt32,
        ) else {
            return false;
        };
        let Ok(one_destination) = load_one.register_operand(0) else {
            return false;
        };
        if load_one.signed_immediate_operand(1).ok() != Some(1) {
            return false;
        }
        cursor = cursor.saturating_add(1);

        let Some(add) = decoded_core_instruction_at_offset_for_rootless_increment(
            code_block,
            cursor,
            CoreOpcode::AddInt32,
        ) else {
            return false;
        };
        let Ok(add_destination) = add.register_operand(0) else {
            return false;
        };
        if add.register_operand(1).ok() != Some(to_number_destination)
            || add.register_operand(2).ok() != Some(one_destination)
        {
            return false;
        }
        cursor = cursor.saturating_add(1);

        let Some(put) = decoded_core_instruction_at_offset_for_rootless_increment(
            code_block,
            cursor,
            CoreOpcode::PutByName,
        ) else {
            return false;
        };
        if put.register_operand(0).ok() != Some(get_base)
            || identifier_index_operand_for_rootless_increment(put, 1) != Some(get_identifier)
            || put.register_operand(2).ok() != Some(add_destination)
        {
            return false;
        }
        let put_exit_matches = retained_return_table
            .property_exit_sites
            .iter()
            .any(|put_exit| {
                put_exit.site.owner == retained_return_table.owner
                    && put_exit.site.bytecode_index == put.bytecode_index
                    && put_exit.site.opcode == CoreOpcode::PutByName
                    && put_exit.site.requires_no_gc_exit_reentry
                    && put_exit.site.may_throw
                    && put_exit.site.property_key == PropertyCacheKey::Key(get_key)
                    && validate_baseline_generated_property_handoff_site_metadata(&put_exit.site)
                        .is_ok()
            });
        if !put_exit_matches {
            return false;
        }

        match side_exit.reason {
            P6X86_64BaselineSelectedSideExitReason::UnsupportedToNumberOperand => {
                side_exit.bytecode_index == to_number.bytecode_index
                    && side_exit.resume_bytecode_index
                        == next_code_block_bytecode_index(code_block, to_number.bytecode_index)
                            .ok()
                            .flatten()
            }
            P6X86_64BaselineSelectedSideExitReason::NonInt32Operand
            | P6X86_64BaselineSelectedSideExitReason::Overflow => {
                side_exit.bytecode_index == add.bytecode_index
                    && side_exit.resume_bytecode_index
                        == next_code_block_bytecode_index(code_block, add.bytecode_index)
                            .ok()
                            .flatten()
            }
            _ => false,
        }
    }

    fn rootless_emitted_native_entry_property_increment_put_exit_for_to_number_side_exit(
        code_block: &CodeBlock,
        retained_return_table: &P6X86_64CallableRetainedReturnTable,
        side_exit: &P6X86_64CallableSideExitReturnSite,
    ) -> Option<P10X86_64CallablePropertyNativeExitReturnSite> {
        if side_exit.reason != P6X86_64BaselineSelectedSideExitReason::UnsupportedToNumberOperand {
            return None;
        }
        let get_bytecode_index =
            BytecodeIndex::from_offset(side_exit.bytecode_index.offset().checked_sub(1)?);
        let get_exit = retained_return_table
            .property_exit_sites
            .iter()
            .find(|site| {
                site.site.bytecode_index == get_bytecode_index
                    && site.site.opcode == CoreOpcode::GetByName
            })?;
        if !Self::rootless_emitted_native_entry_property_increment_shape_covers_side_exit(
            code_block,
            retained_return_table,
            get_exit,
            side_exit,
        ) {
            return None;
        }

        let get_instruction = code_block.decoded_instruction_at(get_bytecode_index).ok()?;
        let mut cursor = get_instruction.bytecode_index.offset().checked_add(2)?;
        if decoded_core_instruction_at_offset_for_rootless_increment(
            code_block,
            cursor,
            CoreOpcode::Move,
        )
        .is_some()
        {
            cursor = cursor.checked_add(1)?;
        }
        cursor = cursor.checked_add(2)?;
        let put = decoded_core_instruction_at_offset_for_rootless_increment(
            code_block,
            cursor,
            CoreOpcode::PutByName,
        )?;
        retained_return_table
            .property_exit_sites
            .iter()
            .copied()
            .find(|site| site.site.bytecode_index == put.bytecode_index)
    }

    fn rootless_emitted_native_entry_side_exit_reason_allowed(
        code_block: &CodeBlock,
        site: &P6X86_64CallableSideExitReturnSite,
    ) -> bool {
        if !site.bytecode_index.is_valid() || site.bytecode_index.checkpoint() != Checkpoint::NONE {
            return false;
        }
        let Ok(instruction) = code_block.decoded_instruction_at(site.bytecode_index) else {
            return false;
        };
        if instruction.bytecode_index != site.bytecode_index {
            return false;
        }
        let Some(opcode) = CoreOpcode::from_opcode(instruction.opcode) else {
            return false;
        };
        match site.reason {
            P6X86_64BaselineSelectedSideExitReason::UnsupportedTruthinessOperand => {
                Self::rootless_emitted_native_entry_truthiness_side_exit_site_allowed_with_instruction(
                    code_block,
                    site,
                    &instruction,
                )
            }
            P6X86_64BaselineSelectedSideExitReason::UnsupportedToNumberOperand => false,
            P6X86_64BaselineSelectedSideExitReason::UnsupportedStrictEqualityOperand => false,
            P6X86_64BaselineSelectedSideExitReason::Overflow => {
                matches!(
                    opcode,
                    CoreOpcode::AddInt32 | CoreOpcode::SubInt32 | CoreOpcode::MulInt32
                ) && instruction.register_operand(0).is_ok()
                    && instruction.register_operand(1).is_ok()
                    && instruction.register_operand(2).is_ok()
            }
            P6X86_64BaselineSelectedSideExitReason::NegativeZero => {
                opcode == CoreOpcode::MulInt32
                    && instruction.register_operand(0).is_ok()
                    && instruction.register_operand(1).is_ok()
                    && instruction.register_operand(2).is_ok()
            }
            P6X86_64BaselineSelectedSideExitReason::NonInt32Operand => {
                Self::rootless_emitted_native_entry_non_int32_side_exit_site_allowed_with_instruction(
                    opcode,
                    &instruction,
                )
            }
        }
    }

    fn rootless_emitted_native_entry_non_int32_side_exit_site_allowed_with_instruction(
        opcode: CoreOpcode,
        instruction: &DecodedInstruction,
    ) -> bool {
        matches!(
            opcode,
            CoreOpcode::AddInt32
                | CoreOpcode::SubInt32
                | CoreOpcode::MulInt32
                | CoreOpcode::BitAndInt32
                | CoreOpcode::BitOrInt32
                | CoreOpcode::BitXorInt32
                | CoreOpcode::RightShiftInt32
                | CoreOpcode::Equal
                | CoreOpcode::NotEqual
                | CoreOpcode::LessThanInt32
                | CoreOpcode::LessEqualInt32
                | CoreOpcode::GreaterThanInt32
                | CoreOpcode::GreaterEqualInt32
        ) && instruction.register_operand(0).is_ok()
            && instruction.register_operand(1).is_ok()
            && instruction.register_operand(2).is_ok()
    }

    #[cfg(test)]
    fn rootless_emitted_native_entry_truthiness_side_exit_site_allowed(
        code_block: &CodeBlock,
        site: &P6X86_64CallableSideExitReturnSite,
    ) -> bool {
        if !site.bytecode_index.is_valid() || site.bytecode_index.checkpoint() != Checkpoint::NONE {
            return false;
        }
        let Ok(instruction) = code_block.decoded_instruction_at(site.bytecode_index) else {
            return false;
        };
        if instruction.bytecode_index != site.bytecode_index {
            return false;
        }
        Self::rootless_emitted_native_entry_truthiness_side_exit_site_allowed_with_instruction(
            code_block,
            site,
            &instruction,
        )
    }

    fn rootless_emitted_native_entry_truthiness_side_exit_site_allowed_with_instruction(
        code_block: &CodeBlock,
        site: &P6X86_64CallableSideExitReturnSite,
        instruction: &DecodedInstruction,
    ) -> bool {
        if site.reason != P6X86_64BaselineSelectedSideExitReason::UnsupportedTruthinessOperand
            || CoreOpcode::from_opcode(instruction.opcode) != Some(CoreOpcode::JumpIfFalse)
            || instruction.register_operand(0).is_err()
        {
            return false;
        }
        let Ok(target) = instruction.bytecode_index_operand(1) else {
            return false;
        };
        target.is_valid()
            && target.checkpoint() == Checkpoint::NONE
            && target != site.bytecode_index
            && code_block.decoded_instruction_at(target).is_ok()
    }

    fn validate_rootless_generated_direct_call_body(
        code_block: &CodeBlock,
        artifact: &BaselineGeneratedCodeArtifact,
        js_call_native_exit_plan: Option<&BaselineGeneratedJsCallNativeExitPlanMetadata>,
        proof: GeneratedDirectCallRootlessGeneratedEntryProof,
    ) -> Result<(), VmGeneratedDirectCallRootlessRejectionReason> {
        let mut saw_return = false;
        for (ordinal, instruction) in code_block
            .unlinked()
            .instructions()
            .decoded_instructions()
            .enumerate()
        {
            let Ok(instruction) = instruction else {
                return Err(VmGeneratedDirectCallRootlessRejectionReason::InvalidBodyInstruction);
            };
            let Some(opcode) = CoreOpcode::from_opcode(instruction.opcode) else {
                return Err(VmGeneratedDirectCallRootlessRejectionReason::InvalidBodyInstruction);
            };
            if !instruction.bytecode_index.is_valid()
                || instruction.bytecode_index != BytecodeIndex::from_offset(ordinal as u32)
            {
                return Err(VmGeneratedDirectCallRootlessRejectionReason::InvalidBodyBytecodeIndex);
            }
            if !Self::rootless_generated_direct_call_opcode_allowed(
                instruction.bytecode_index,
                opcode,
                artifact,
                js_call_native_exit_plan,
                proof,
            ) {
                return Err(
                    VmGeneratedDirectCallRootlessRejectionReason::UnsupportedBodyOpcode { opcode },
                );
            }
            saw_return |= opcode == CoreOpcode::Return;
        }
        if saw_return {
            Ok(())
        } else {
            Err(VmGeneratedDirectCallRootlessRejectionReason::MissingReturn)
        }
    }

    fn rootless_generated_direct_call_opcode_allowed(
        bytecode_index: BytecodeIndex,
        opcode: CoreOpcode,
        artifact: &BaselineGeneratedCodeArtifact,
        js_call_native_exit_plan: Option<&BaselineGeneratedJsCallNativeExitPlanMetadata>,
        proof: GeneratedDirectCallRootlessGeneratedEntryProof,
    ) -> bool {
        match proof {
            GeneratedDirectCallRootlessGeneratedEntryProof::StrictLocalLeaf
            | GeneratedDirectCallRootlessGeneratedEntryProof::DeferredNonThrowingExitRooting => {
                Self::rootless_generated_direct_call_leaf_opcode(opcode)
            }
            GeneratedDirectCallRootlessGeneratedEntryProof::DeferredThrowingSideExitRooting
            | GeneratedDirectCallRootlessGeneratedEntryProof::DeferredGeneratedExitRooting => {
                artifact.eligibility_proof.opcode_subset().supports(opcode)
                    || Self::rootless_generated_direct_call_property_exit_site_allowed(
                        bytecode_index,
                        opcode,
                        artifact,
                    )
                    || Self::rootless_generated_direct_call_js_call_exit_site_allowed(
                        bytecode_index,
                        opcode,
                        artifact,
                        js_call_native_exit_plan,
                    )
            }
        }
    }

    fn rootless_generated_direct_call_js_call_exit_site_allowed(
        bytecode_index: BytecodeIndex,
        opcode: CoreOpcode,
        artifact: &BaselineGeneratedCodeArtifact,
        js_call_native_exit_plan: Option<&BaselineGeneratedJsCallNativeExitPlanMetadata>,
    ) -> bool {
        let Some(js_call_native_exit_plan) = js_call_native_exit_plan else {
            return false;
        };
        if js_call_native_exit_plan.bytecode_snapshot()
            != artifact.eligibility_proof.bytecode_snapshot_fingerprint()
        {
            return false;
        }
        let Some(site) = js_call_native_exit_plan.site_for_bytecode_index(bytecode_index) else {
            return false;
        };
        site.owner == artifact.owner
            && site.bytecode_index == bytecode_index
            && site.opcode == opcode
            && site.requires_no_gc_exit_reentry
            && site.may_throw
            && matches!(
                opcode,
                CoreOpcode::Call | CoreOpcode::CallWithThis | CoreOpcode::Construct
            )
    }

    fn rootless_generated_direct_call_property_exit_site_allowed(
        bytecode_index: BytecodeIndex,
        opcode: CoreOpcode,
        artifact: &BaselineGeneratedCodeArtifact,
    ) -> bool {
        let Some(property_plan) = artifact.property_handoff_plan() else {
            return false;
        };
        let Ok(Some(site)) = property_plan.site_for_bytecode_index(bytecode_index) else {
            return false;
        };
        site.owner == artifact.owner
            && site.bytecode_index == bytecode_index
            && site.opcode == opcode
            && site.requires_no_gc_exit_reentry
            && matches!(
                opcode,
                CoreOpcode::GetByName
                    | CoreOpcode::GetGlobalObjectProperty
                    | CoreOpcode::GetLength
                    | CoreOpcode::GetByValue
                    | CoreOpcode::PutByName
                    | CoreOpcode::PutGlobalObjectProperty
                    | CoreOpcode::PutByValue
            )
    }

    const fn rootless_generated_direct_call_leaf_opcode(opcode: CoreOpcode) -> bool {
        matches!(
            opcode,
            CoreOpcode::LoadUndefined
                | CoreOpcode::LoadNull
                | CoreOpcode::LoadBool
                | CoreOpcode::LoadInt32
                | CoreOpcode::LoadDouble
                | CoreOpcode::Move
                | CoreOpcode::LoadCallee
                | CoreOpcode::Void
                | CoreOpcode::Return
        )
    }

    fn normalize_rootless_generated_direct_call_outcome(
        &mut self,
        proof: GeneratedDirectCallRootlessGeneratedEntryProof,
        exception_snapshot: ExceptionState,
        outcome: SingleDispatchOutcome,
    ) -> SingleDispatchOutcome {
        match outcome {
            SingleDispatchOutcome::Threw(pending) if proof.allows_throw() => {
                SingleDispatchOutcome::Threw(pending)
            }
            SingleDispatchOutcome::Threw(_)
            | SingleDispatchOutcome::OrdinaryBytecodeCall(_)
            | SingleDispatchOutcome::OrdinaryBytecodeConstruct(_)
            | SingleDispatchOutcome::FunctionValueCall(_)
            | SingleDispatchOutcome::Suspended(_) => {
                match self.restore_exception_snapshot_and_sync_roots(exception_snapshot) {
                    Ok(()) => SingleDispatchOutcome::Failed(
                        ExecutionError::BaselineGeneratedExecutionRejected,
                    ),
                    Err(error) => SingleDispatchOutcome::Failed(error),
                }
            }
            outcome => outcome,
        }
    }

    fn execute_nested_callee_code_block<H: DispatchHost>(
        &mut self,
        code_block_id: CodeBlockId,
        code_block: &CodeBlock,
        host: &mut H,
        config: DispatchConfig,
    ) -> ExecutionCompletion {
        self.execute_code_block_with_entry_kind(
            code_block_id,
            code_block,
            host,
            config,
            crate::interpreter::ExecutionEntryKind::Function,
        )
    }

    fn execute_generated_direct_construct_callee_code_block<H: DispatchHost>(
        &mut self,
        code_block_id: CodeBlockId,
        code_block: &CodeBlock,
        expected_frame: CallFrameId,
        host: &mut H,
        config: DispatchConfig,
    ) -> ExecutionCompletion {
        self.try_execute_generated_direct_construct_callee_with_generated_entry(
            code_block_id,
            code_block,
            expected_frame,
            host,
            config,
        )
        .or_else(|| {
            self.try_execute_generated_direct_construct_callee_with_native_entry(
                code_block_id,
                code_block,
                expected_frame,
                host,
                config,
            )
        })
        .unwrap_or_else(|| {
            self.execute_nested_construct_code_block(code_block_id, code_block, host, config)
        })
    }

    fn try_execute_generated_direct_construct_callee_with_generated_entry<H: DispatchHost>(
        &mut self,
        code_block_id: CodeBlockId,
        code_block: &CodeBlock,
        expected_frame: CallFrameId,
        host: &mut H,
        config: DispatchConfig,
    ) -> Option<ExecutionCompletion> {
        if !self.config.baseline_generated_execution_enabled() {
            return None;
        }
        let artifact = self
            .tiering
            .baseline_generated_code_artifact_for(code_block_id)?;
        if artifact.validate().is_err() || artifact.owner != code_block_id {
            return None;
        }
        let expected_snapshot = artifact.eligibility_proof.bytecode_snapshot_fingerprint();
        let actual_snapshot =
            BaselineBytecodeEligibilityProof::fingerprint_code_block_snapshot(code_block).ok()?;
        if actual_snapshot != expected_snapshot {
            return None;
        }
        let active_frame = self.execution.top_frame()?;
        if active_frame.id != expected_frame || active_frame.code_block != Some(code_block_id) {
            return None;
        }

        let region = self.enter_no_gc_execution_region();
        let completion = self.execute_baseline_generated_code_in_current_region_with_entry_context(
            code_block_id,
            code_block,
            Some(expected_frame),
            crate::interpreter::ExecutionEntryKind::Construct,
            JitType::Baseline,
            code_block_id,
            crate::interpreter::ExecutionEntryKind::Construct,
            JitType::Baseline,
            host,
            config,
            BaselineGeneratedExecutionValidation::Full,
        );
        let completion = self.drain_nested_callee_completion_in_current_region(
            completion,
            code_block_id,
            code_block,
            host,
            config,
        );
        Some(self.leave_no_gc_region_with_completion(region, completion))
    }

    fn try_execute_generated_direct_construct_callee_with_native_entry<H: DispatchHost>(
        &mut self,
        code_block_id: CodeBlockId,
        code_block: &CodeBlock,
        expected_frame: CallFrameId,
        host: &mut H,
        config: DispatchConfig,
    ) -> Option<ExecutionCompletion> {
        let gate = self
            .tiering
            .baseline_native_entry_gate_for_owner(code_block_id)?;
        if gate.outcome != BaselineEntryGateOutcome::NativeEntryReady {
            return None;
        }
        let active_frame = self.execution.top_frame()?;
        if active_frame.id != expected_frame || active_frame.code_block != Some(code_block_id) {
            return None;
        }

        let region = self.enter_no_gc_execution_region();
        let execution = self.try_execute_baseline_native_entry_shim_for_gate_in_current_region(
            code_block_id,
            code_block,
            Some(expected_frame),
            crate::interpreter::ExecutionEntryKind::Construct,
            JitType::Baseline,
            &gate,
            host,
            config,
            true,
        );
        let Some(execution) = execution else {
            return match self.leave_no_gc_execution_region(region) {
                Ok(_) => None,
                Err(_) => Some(ExecutionCompletion::Failed(
                    ExecutionError::GcBoundaryViolation,
                )),
            };
        };
        let completion = match execution {
            BaselineNativeEntryVmExecution::Native(completion)
            | BaselineNativeEntryVmExecution::InterpreterFallback(completion) => completion,
            BaselineNativeEntryVmExecution::DeferredRootedInterpreterFallback {
                completion,
                roots,
            } => {
                let completion = self.drain_nested_callee_completion_in_current_region(
                    completion,
                    code_block_id,
                    code_block,
                    host,
                    config,
                );
                let completion = match self.cleanup_baseline_native_entry_deferred_roots(roots) {
                    Ok(()) => completion,
                    Err(error) => ExecutionCompletion::Failed(error),
                };
                return Some(self.leave_no_gc_region_with_completion(region, completion));
            }
            BaselineNativeEntryVmExecution::P9OwnerPostCallReentry(_) => {
                ExecutionCompletion::Failed(ExecutionError::BaselineGeneratedExecutionRejected)
            }
            BaselineNativeEntryVmExecution::P6SideExitReentry(_) => {
                ExecutionCompletion::Failed(ExecutionError::BaselineGeneratedExecutionRejected)
            }
        };
        let completion = self.drain_nested_callee_completion_in_current_region(
            completion,
            code_block_id,
            code_block,
            host,
            config,
        );
        Some(self.leave_no_gc_region_with_completion(region, completion))
    }

    fn drain_nested_callee_completion_in_current_region<H: DispatchHost>(
        &mut self,
        mut completion: ExecutionCompletion,
        code_block_id: CodeBlockId,
        code_block: &CodeBlock,
        host: &mut H,
        config: DispatchConfig,
    ) -> ExecutionCompletion {
        loop {
            completion = match completion {
                ExecutionCompletion::OrdinaryBytecodeCall(request) => self
                    .execute_ordinary_bytecode_call_request_in_current_region(
                        *request,
                        code_block_id,
                        code_block,
                        host,
                        config,
                    ),
                ExecutionCompletion::OrdinaryBytecodeConstruct(request) => self
                    .execute_ordinary_bytecode_construct_request_in_current_region(
                        *request,
                        code_block_id,
                        code_block,
                        host,
                        config,
                    ),
                ExecutionCompletion::FunctionValueCall(request) => self
                    .execute_function_value_call_request_in_current_region(
                        *request,
                        code_block_id,
                        code_block,
                        host,
                        config,
                    ),
                done => return done,
            };
        }
    }

    fn execute_nested_construct_code_block<H: DispatchHost>(
        &mut self,
        code_block_id: CodeBlockId,
        code_block: &CodeBlock,
        host: &mut H,
        config: DispatchConfig,
    ) -> ExecutionCompletion {
        self.execute_code_block_with_entry_kind(
            code_block_id,
            code_block,
            host,
            config,
            crate::interpreter::ExecutionEntryKind::Construct,
        )
    }

    fn execute_ordinary_bytecode_call_request_in_current_region<H: DispatchHost>(
        &mut self,
        request: OrdinaryBytecodeCallRequest,
        caller_code_block_id: CodeBlockId,
        caller_code_block: &CodeBlock,
        host: &mut H,
        config: DispatchConfig,
    ) -> ExecutionCompletion {
        let resume_owner = request.continuation.owner;
        let resume_frame = request.continuation.caller_frame;
        let outcome = self
            .execute_ordinary_bytecode_call_request_as_single_dispatch_in_current_region(
                request,
                caller_code_block_id,
                caller_code_block,
                host,
                config,
            );
        self.finish_single_dispatch_resume_in_current_region(
            resume_owner,
            resume_frame,
            outcome,
            caller_code_block,
            host,
            config,
        )
    }

    fn execute_ordinary_bytecode_call_request_as_single_dispatch_in_current_region<
        H: DispatchHost,
    >(
        &mut self,
        request: OrdinaryBytecodeCallRequest,
        caller_code_block_id: CodeBlockId,
        caller_code_block: &CodeBlock,
        host: &mut H,
        config: DispatchConfig,
    ) -> SingleDispatchOutcome {
        if request.continuation.owner != caller_code_block_id {
            return SingleDispatchOutcome::Failed(ExecutionError::CodeBlockMismatch {
                expected: request.continuation.owner,
                actual: Some(caller_code_block_id),
            });
        }
        if request.continuation.callee_frame.is_some() {
            return SingleDispatchOutcome::Failed(ExecutionError::InvalidCallContinuation);
        }

        if let Some(direct_call) = self.authorized_ordinary_bytecode_call_link_direct_dispatch(
            &request,
            caller_code_block,
            host,
        ) {
            if let Some(target_code_block) = self
                .validate_ordinary_bytecode_call_link_direct_dispatch_target(&request, &direct_call)
            {
                if let Err(error) = self.drain_ordinary_bytecode_call_observation(
                    &request.continuation,
                    caller_code_block,
                    host,
                ) {
                    return SingleDispatchOutcome::Failed(error);
                }
                return self
                    .execute_ordinary_bytecode_call_link_direct_dispatch_as_single_dispatch(
                        request,
                        direct_call,
                        caller_code_block,
                        target_code_block,
                        host,
                        config,
                    );
            }
        }

        let observation = match self.drain_ordinary_bytecode_call_observation(
            &request.continuation,
            caller_code_block,
            host,
        ) {
            Ok(observation) => observation,
            Err(error) => return SingleDispatchOutcome::Failed(error),
        };
        let target_validation = self.validate_ordinary_bytecode_call_registered_target(&request);
        self.record_ordinary_bytecode_call_registered_target_validation(
            &request,
            &target_validation,
        );
        let outcome = match target_validation {
            Ok(target_code_block) => self
                .execute_vm_owned_ordinary_bytecode_call_request_as_single_dispatch(
                    request,
                    caller_code_block,
                    target_code_block,
                    host,
                    config,
                ),
            Err(_) => self.execute_direct_ordinary_bytecode_call_request_as_single_dispatch(
                request,
                caller_code_block,
                host,
                config,
            ),
        };
        let observation = Self::retarget_call_observation_outcome(observation, &outcome);
        if let Err(error) = self.record_call_observation_and_metadata(observation) {
            return SingleDispatchOutcome::Failed(error);
        }
        outcome
    }

    fn authorized_ordinary_bytecode_call_link_direct_dispatch<H: DispatchHost>(
        &mut self,
        request: &OrdinaryBytecodeCallRequest,
        caller_code_block: &CodeBlock,
        host: &mut H,
    ) -> Option<BaselineGeneratedJsDirectCall> {
        let opcode = request.continuation.kind.opcode();
        if !matches!(opcode, CoreOpcode::Call | CoreOpcode::CallWithThis) {
            return None;
        }
        let callee_value = request.continuation.callee_value?;
        let bytecode_snapshot =
            BaselineBytecodeEligibilityProof::fingerprint_code_block_snapshot(caller_code_block)
                .ok()?;
        let candidate_table = self
            .generated_call_link_candidate_table_for_owner_cached(
                request.continuation.owner,
                bytecode_snapshot,
            )
            .ok()?;
        let candidates = candidate_table
            .candidates_for_bytecode_index(request.continuation.call_bytecode_index.offset())
            .cloned()
            .collect::<Vec<GeneratedCallLinkCandidate>>();
        if candidates.is_empty() {
            return None;
        }

        let this_value = request.argument_values.first().copied()?;
        let this_object = this_value
            .as_cell()
            .and_then(|cell| self.heap.cell_for_payload(cell.pointer_payload_bits()))
            .map(ObjectId);
        let argument_count_including_this = request.continuation.argument_count_including_this;
        let mut direct_calls = Vec::new();

        for candidate in candidates {
            let probe = GeneratedCallLinkProbeRequest::new(
                &candidate,
                request.continuation.owner,
                opcode,
                request.continuation.call_bytecode_index.offset(),
                argument_count_including_this,
                callee_value,
                callee_value.kind(),
                request.continuation.callee_object,
                this_value,
                this_value.kind(),
                this_object,
            );
            let GeneratedCallLinkProbeResult::DirectCall(authorization) =
                DispatchHost::probe_generated_call_link(host, &mut self.heap, probe)
            else {
                continue;
            };
            let callee_object = request.continuation.callee_object?;
            if authorization != GeneratedCallLinkDirectCall::from_candidate(&candidate)
                || authorization.target_code_block != request.target_code_block_id
                || authorization.target_callee != callee_object
            {
                continue;
            }

            direct_calls.push(BaselineGeneratedJsDirectCall {
                candidate,
                authorization,
                callee_value,
                callee_object,
                this_value,
                this_object,
                argument_count_including_this,
                setup_payload: None,
            });
        }

        match direct_calls.len() {
            1 => direct_calls.pop(),
            _ => None,
        }
    }

    fn validate_ordinary_bytecode_call_link_direct_dispatch_target(
        &self,
        request: &OrdinaryBytecodeCallRequest,
        direct_call: &BaselineGeneratedJsDirectCall,
    ) -> Option<Rc<CodeBlock>> {
        let target_code_block = self.validate_ordinary_bytecode_call_vm_target(request)?;
        let executable = target_code_block.link_context().owner_executable?;
        if direct_call.authorization.target_executable != executable
            || direct_call.authorization.target_code_block != request.target_code_block_id
            || direct_call.authorization.target_callee != direct_call.callee_object
            || direct_call.candidate.target.executable != executable
            || direct_call.candidate.target.target_code_block != request.target_code_block_id
            || direct_call.candidate.target.callee != direct_call.callee_object
            || direct_call.candidate.target.specialization != CodeSpecialization::Call
            || direct_call.candidate.opcode != request.continuation.kind.opcode()
            || direct_call.candidate.bytecode_index
                != request.continuation.call_bytecode_index.offset()
            || direct_call.candidate.direct_call_status
                != GeneratedCallLinkDirectCallStatus::Authorized
        {
            return None;
        }

        let mut unsupported_blockers = direct_call.candidate.remaining_blockers;
        unsupported_blockers.remove(CallLinkReadinessBlocker::MayCallJsBoundary);
        if !unsupported_blockers.is_empty() {
            return None;
        }

        Some(target_code_block)
    }

    fn validate_ordinary_bytecode_call_vm_target(
        &self,
        request: &OrdinaryBytecodeCallRequest,
    ) -> Option<Rc<CodeBlock>> {
        let registered = self
            .validate_ordinary_bytecode_call_registered_target(request)
            .ok()?;
        let executable = registered.link_context().owner_executable?;
        let callee = request.continuation.callee_object?;
        self.validate_call_link_metadata_target(executable, request.target_code_block_id, callee)
            .ok()?;
        Some(registered)
    }

    fn validate_ordinary_bytecode_call_registered_target(
        &self,
        request: &OrdinaryBytecodeCallRequest,
    ) -> Result<Rc<CodeBlock>, VmOwnedCallTargetValidationRejection> {
        self.validate_registered_vm_owned_call_target(
            request.target_code_block_id,
            &request.target_code_block,
            CodeSpecialization::Call,
        )
    }

    fn record_ordinary_bytecode_call_registered_target_validation(
        &mut self,
        request: &OrdinaryBytecodeCallRequest,
        result: &Result<Rc<CodeBlock>, VmOwnedCallTargetValidationRejection>,
    ) {
        self.tiering
            .record_vm_owned_call_target_validation(VmOwnedCallTargetValidationRequest {
                owner: request.continuation.owner,
                frame: Some(request.continuation.caller_frame),
                bytecode_index: request.continuation.call_bytecode_index,
                opcode: request.continuation.kind.opcode(),
                target_code_block: request.target_code_block_id,
                expected_specialization: CodeSpecialization::Call,
                outcome: vm_owned_call_target_validation_outcome(result),
            });
    }

