fn metadata_only_call_link_boundary_for_descriptor(
    descriptor_record: &VmCallLinkDescriptorRecord,
) -> CallBoundaryMetadata {
    CallBoundaryMetadata {
        id: CallBoundaryId(CALL_LINK_BOUNDARY_ID_BASE.saturating_add(descriptor_record.ordinal)),
        owner: Some(descriptor_record.owner),
        abi: EntryAbi::LlIntCompatible,
        entry_kind: EntrypointKind::InterpreterThunk,
        native_symbol: None,
        arguments: vec![
            AbiValue::JsValue;
            usize::from(
                descriptor_record
                    .descriptor
                    .max_argument_count_including_this
            )
        ],
        returns: vec![AbiValue::JsValue],
        registers: Vec::new(),
        frame_slots: Vec::new(),
        requires_vm_entry_scope: true,
        may_call_js: true,
        may_throw: true,
    }
}

fn call_link_inline_cache_clear_request_for_candidate(
    candidate: &CodeBlockRegistryAttachedCallLinkInlineCacheCandidate,
) -> VmCallLinkInlineCacheClearRequest {
    VmCallLinkInlineCacheClearRequest {
        owner: candidate.owner,
        bytecode_index: candidate.bytecode_index,
        bytecode_snapshot: candidate.bytecode_snapshot,
        slot: candidate.slot,
        attachment_ordinal: candidate.attachment_ordinal,
        attachment_plan_ordinal: candidate.attachment_plan_ordinal,
        install_recheck_ordinal: candidate.install_recheck_ordinal,
        boundary_validation_ordinal: candidate.boundary_validation_ordinal,
        descriptor_ordinal: candidate.descriptor_ordinal,
        observation_ordinal: candidate.observation_ordinal,
        readiness_ordinal: candidate.readiness_ordinal,
        target: candidate.target.clone(),
    }
}

fn generated_baseline_fallback_record(
    fallback: BaselineGeneratedFallback,
) -> GeneratedBaselineFallbackRecord {
    GeneratedBaselineFallbackRecord {
        bytecode_index: fallback.reason.bytecode_index,
        opcode: generated_baseline_fallback_opcode(fallback.reason.opcode),
        cause: generated_baseline_fallback_cause(fallback.reason.cause),
    }
}

fn p6_core_opcode_at_bytecode_index(
    code_block: &CodeBlock,
    bytecode_index: BytecodeIndex,
) -> Option<CoreOpcode> {
    let instructions = code_block.unlinked().instructions();
    if !instructions.typed_placeholder().is_empty() {
        return instructions
            .typed_placeholder()
            .iter()
            .enumerate()
            .find_map(|(offset, instruction)| {
                let offset = u32::try_from(offset).ok()?;
                let instruction_bytecode_index = instruction
                    .bytecode_index
                    .unwrap_or_else(|| BytecodeIndex::from_offset(offset));
                (instruction_bytecode_index == bytecode_index)
                    .then(|| CoreOpcode::from_opcode(instruction.opcode))
                    .flatten()
            });
    }
    instructions
        .declarations()
        .iter()
        .enumerate()
        .find_map(|(offset, instruction)| {
            let offset = u32::try_from(offset).ok()?;
            let instruction_bytecode_index = instruction
                .bytecode_index
                .unwrap_or_else(|| BytecodeIndex::from_offset(offset));
            (instruction_bytecode_index == bytecode_index)
                .then(|| CoreOpcode::from_opcode(instruction.opcode))
                .flatten()
        })
}

fn decoded_core_instruction_at_offset_for_rootless_increment(
    code_block: &CodeBlock,
    offset: u32,
    opcode: CoreOpcode,
) -> Option<DecodedInstruction<'_>> {
    let instruction = code_block
        .decoded_instruction_at(BytecodeIndex::from_offset(offset))
        .ok()?;
    (CoreOpcode::from_opcode(instruction.opcode) == Some(opcode)).then_some(instruction)
}

fn identifier_index_operand_for_rootless_increment(
    instruction: DecodedInstruction<'_>,
    index: usize,
) -> Option<u32> {
    match instruction.operand(index).ok()? {
        Operand::IdentifierIndex(identifier_index) => Some(identifier_index),
        _ => None,
    }
}

fn p6_native_strict_equality_side_exit_value_kind(kind: crate::value::ValueKind) -> bool {
    matches!(
        kind,
        crate::value::ValueKind::Cell
            | crate::value::ValueKind::Double
            | crate::value::ValueKind::Unknown
    )
}

fn p14_branch_kind_for_opcode(opcode: CoreOpcode) -> Option<P6X86_64BaselineBytecodeBranchKind> {
    match opcode {
        CoreOpcode::Jump => Some(P6X86_64BaselineBytecodeBranchKind::UnconditionalJump),
        CoreOpcode::JumpIfNotNullish => {
            Some(P6X86_64BaselineBytecodeBranchKind::JumpIfNotNullishTaken)
        }
        CoreOpcode::JumpIfFalse => Some(P6X86_64BaselineBytecodeBranchKind::JumpIfFalseTaken),
        _ => None,
    }
}

fn p14_allocation_relative_entry_offset_for_loop_backedge(
    dispatch: &P6EmittedNativeDispatch<'_>,
    site: P14X86_64CallableLoopBackedgeSafepointReturnSite,
) -> Result<u32, ExecutionError> {
    p6_allocation_relative_entry_offset_for_side_exit_resume(
        dispatch,
        site.target_instruction_offset,
    )
}

fn p6_allocation_relative_entry_offset_for_side_exit_resume(
    dispatch: &P6EmittedNativeDispatch<'_>,
    image_entry_offset: u32,
) -> Result<u32, ExecutionError> {
    let range = dispatch.descriptor.machine_range;
    let end_offset = range
        .end_offset()
        .ok_or(ExecutionError::BaselineGeneratedExecutionRejected)?;
    let entry_offset = range
        .start_offset
        .checked_add(image_entry_offset)
        .ok_or(ExecutionError::BaselineGeneratedExecutionRejected)?;
    if image_entry_offset >= range.size_bytes
        || entry_offset < range.start_offset
        || entry_offset >= end_offset
    {
        return Err(ExecutionError::BaselineGeneratedExecutionRejected);
    }
    Ok(entry_offset)
}

fn p6_x86_64_semantic_native_entry_opcode_subset_for_code_block(
    code_block: &CodeBlock,
) -> BaselineSupportedOpcodeSubset {
    let opcodes = code_block
        .unlinked()
        .instructions()
        .decoded_instructions()
        .filter_map(Result::ok)
        .filter_map(|instruction| CoreOpcode::from_opcode(instruction.opcode))
        .collect::<Vec<_>>();
    let has_emitted_native_int32_bitwise = opcodes.iter().any(|opcode| {
        matches!(
            opcode,
            CoreOpcode::BitAndInt32
                | CoreOpcode::BitOrInt32
                | CoreOpcode::BitXorInt32
                | CoreOpcode::RightShiftInt32
        )
    });
    let has_equal_not_equal = opcodes
        .iter()
        .any(|opcode| matches!(opcode, CoreOpcode::Equal | CoreOpcode::NotEqual));
    let has_relational = opcodes.iter().any(|opcode| {
        matches!(
            opcode,
            CoreOpcode::LessThanInt32
                | CoreOpcode::LessEqualInt32
                | CoreOpcode::GreaterThanInt32
                | CoreOpcode::GreaterEqualInt32
        )
    });
    let has_to_number = opcodes
        .iter()
        .any(|opcode| matches!(opcode, CoreOpcode::ToNumber));
    let has_strict_equality = opcodes
        .iter()
        .any(|opcode| matches!(opcode, CoreOpcode::StrictEqual | CoreOpcode::StrictNotEqual));
    let branch_opcodes = opcodes
        .iter()
        .copied()
        .filter(|opcode| {
            matches!(
                opcode,
                CoreOpcode::Jump | CoreOpcode::JumpIfNotNullish | CoreOpcode::JumpIfFalse
            )
        })
        .collect::<Vec<_>>();
    if has_strict_equality
        && opcodes
            .iter()
            .copied()
            .all(p6_x86_64_semantic_native_entry_supports_primitive_boolean_lowering)
    {
        return BaselineSupportedOpcodeSubset::P6ConstantsMovesReturnInt32ArithmeticBitwiseRelationalJumpsPrimitiveTruthinessPrimitiveBoolean;
    }
    if branch_opcodes
        .iter()
        .any(|opcode| matches!(opcode, CoreOpcode::JumpIfFalse))
    {
        if has_to_number {
            BaselineSupportedOpcodeSubset::P8bConstantsMovesReturnInt32ArithmeticBitAndOrNoCallLooseEqualityRelationalPrimitiveToNumberBranchNullishFalse
        } else if has_relational && has_equal_not_equal {
            BaselineSupportedOpcodeSubset::P8bConstantsMovesReturnInt32ArithmeticBitAndOrNoCallLooseEqualityRelationalBranchNullishFalse
        } else if has_relational {
            BaselineSupportedOpcodeSubset::P8bConstantsMovesReturnInt32ArithmeticBitAndOrEqualityRelationalBranchNullishFalse
        } else if has_equal_not_equal {
            BaselineSupportedOpcodeSubset::P8bConstantsMovesReturnInt32ArithmeticBitAndOrNoCallLooseEqualityBranchNullishFalse
        } else if has_emitted_native_int32_bitwise {
            BaselineSupportedOpcodeSubset::P8bConstantsMovesReturnInt32ArithmeticBitAndOrBranchNullishFalse
        } else {
            BaselineSupportedOpcodeSubset::P8bConstantsMovesReturnInt32ArithmeticBranchNullishFalse
        }
    } else if !branch_opcodes.is_empty() {
        if has_to_number {
            BaselineSupportedOpcodeSubset::P8aConstantsMovesReturnInt32ArithmeticBitAndOrNoCallLooseEqualityRelationalPrimitiveToNumberBranchNullish
        } else if has_relational && has_equal_not_equal {
            BaselineSupportedOpcodeSubset::P8aConstantsMovesReturnInt32ArithmeticBitAndOrNoCallLooseEqualityRelationalBranchNullish
        } else if has_relational {
            BaselineSupportedOpcodeSubset::P8aConstantsMovesReturnInt32ArithmeticBitAndOrEqualityRelationalBranchNullish
        } else if has_equal_not_equal {
            BaselineSupportedOpcodeSubset::P8aConstantsMovesReturnInt32ArithmeticBitAndOrNoCallLooseEqualityBranchNullish
        } else if has_emitted_native_int32_bitwise {
            BaselineSupportedOpcodeSubset::P8aConstantsMovesReturnInt32ArithmeticBitAndOrBranchNullish
        } else {
            BaselineSupportedOpcodeSubset::P8aConstantsMovesReturnInt32ArithmeticBranchNullish
        }
    } else if has_to_number {
        BaselineSupportedOpcodeSubset::P6ConstantsMovesReturnInt32ArithmeticBitAndOrNoCallLooseEqualityRelationalPrimitiveToNumber
    } else if has_relational && has_equal_not_equal {
        BaselineSupportedOpcodeSubset::P6ConstantsMovesReturnInt32ArithmeticBitAndOrNoCallLooseEqualityRelational
    } else if has_relational {
        BaselineSupportedOpcodeSubset::P6ConstantsMovesReturnInt32ArithmeticBitAndOrEqualityRelational
    } else if has_equal_not_equal {
        BaselineSupportedOpcodeSubset::P6ConstantsMovesReturnInt32ArithmeticBitAndOrNoCallLooseEquality
    } else if has_emitted_native_int32_bitwise {
        BaselineSupportedOpcodeSubset::P6ConstantsMovesReturnInt32ArithmeticBitAndOr
    } else {
        BaselineSupportedOpcodeSubset::P6ConstantsMovesReturnInt32Arithmetic
    }
}

fn p6_x86_64_semantic_native_entry_supports_primitive_boolean_lowering(opcode: CoreOpcode) -> bool {
    matches!(
        opcode,
        CoreOpcode::LoadUndefined
            | CoreOpcode::LoadNull
            | CoreOpcode::LoadBool
            | CoreOpcode::LoadInt32
            | CoreOpcode::LoadCallee
            | CoreOpcode::Move
            | CoreOpcode::Return
            | CoreOpcode::AddInt32
            | CoreOpcode::SubInt32
            | CoreOpcode::MulInt32
            | CoreOpcode::BitAndInt32
            | CoreOpcode::BitOrInt32
            | CoreOpcode::BitXorInt32
            | CoreOpcode::RightShiftInt32
            | CoreOpcode::LessThanInt32
            | CoreOpcode::LessEqualInt32
            | CoreOpcode::GreaterThanInt32
            | CoreOpcode::GreaterEqualInt32
            | CoreOpcode::Jump
            | CoreOpcode::JumpIfNotNullish
            | CoreOpcode::JumpIfFalse
            | CoreOpcode::StrictEqual
            | CoreOpcode::StrictNotEqual
    )
}

fn p6_code_block_uses_load_callee(code_block: &CodeBlock) -> bool {
    code_block
        .unlinked()
        .instructions()
        .decoded_instructions()
        .filter_map(Result::ok)
        .any(|instruction| {
            CoreOpcode::from_opcode(instruction.opcode) == Some(CoreOpcode::LoadCallee)
        })
}

fn p14_x86_64_backedge_safepoint_authorities_for_code_block(
    owner: CodeBlockId,
    bytecode_snapshot: BaselineBytecodeSnapshotFingerprint,
    code_block: &CodeBlock,
) -> Vec<P14X86_64BaselineBackedgeSafepointAuthority> {
    code_block
        .unlinked()
        .instructions()
        .decoded_instructions()
        .filter_map(Result::ok)
        .filter_map(|instruction| {
            let opcode = CoreOpcode::from_opcode(instruction.opcode)?;
            let (target_operand_index, kind) = match opcode {
                CoreOpcode::Jump => (0, P6X86_64BaselineBytecodeBranchKind::UnconditionalJump),
                CoreOpcode::JumpIfNotNullish => {
                    (1, P6X86_64BaselineBytecodeBranchKind::JumpIfNotNullishTaken)
                }
                CoreOpcode::JumpIfFalse => {
                    (1, P6X86_64BaselineBytecodeBranchKind::JumpIfFalseTaken)
                }
                _ => return None,
            };
            let target = instruction
                .bytecode_index_operand(target_operand_index)
                .ok()?;
            (target < instruction.bytecode_index).then_some(
                P14X86_64BaselineBackedgeSafepointAuthority {
                    owner,
                    bytecode_snapshot,
                    source_bytecode_index: instruction.bytecode_index,
                    target_bytecode_index: target,
                    opcode,
                    kind,
                },
            )
        })
        .collect()
}

fn next_code_block_bytecode_index(
    code_block: &CodeBlock,
    bytecode_index: BytecodeIndex,
) -> Result<Option<BytecodeIndex>, ExecutionError> {
    let next = BytecodeIndex::from_offset(bytecode_index.offset().saturating_add(1));
    match code_block.decoded_instruction_at(next) {
        Ok(instruction) => Ok(Some(instruction.bytecode_index)),
        Err(crate::bytecode::InstructionDecodeError::MissingInstruction { .. }) => Ok(None),
        Err(_) => Err(ExecutionError::BaselineGeneratedExecutionRejected),
    }
}

fn validate_generated_js_construct_continuation_shape(
    continuation: &BaselineGeneratedJsConstructContinuation,
    owner: CodeBlockId,
    frame: CallFrameId,
    bytecode_index: BytecodeIndex,
) -> Result<(), ExecutionError> {
    if continuation.owner != owner
        || continuation.caller_frame != frame
        || continuation.construct_bytecode_index != bytecode_index
    {
        return Err(ExecutionError::BaselineGeneratedExecutionRejected);
    }
    if continuation.argument_count_including_this == 0 {
        return Err(ExecutionError::BaselineGeneratedExecutionRejected);
    }
    Ok(())
}

fn generated_baseline_fallback_opcode(
    opcode: BaselineGeneratedFallbackOpcode,
) -> GeneratedBaselineFallbackOpcode {
    match opcode {
        BaselineGeneratedFallbackOpcode::Core(opcode) => {
            GeneratedBaselineFallbackOpcode::Core(opcode)
        }
        BaselineGeneratedFallbackOpcode::NonCore(opcode) => {
            GeneratedBaselineFallbackOpcode::NonCore(opcode)
        }
    }
}

fn generated_baseline_fallback_cause(
    cause: BaselineGeneratedFallbackCause,
) -> GeneratedBaselineFallbackCause {
    match cause {
        BaselineGeneratedFallbackCause::UnsupportedOpcode => {
            GeneratedBaselineFallbackCause::UnsupportedOpcode
        }
        BaselineGeneratedFallbackCause::NonInt32Operand {
            operand_index,
            register,
        } => GeneratedBaselineFallbackCause::NonInt32Operand {
            operand_index,
            register,
        },
        BaselineGeneratedFallbackCause::NonNumberOperand {
            operand_index,
            register,
            value_kind,
        } => GeneratedBaselineFallbackCause::NonNumberOperand {
            operand_index,
            register,
            value_kind,
        },
        BaselineGeneratedFallbackCause::UnsupportedPrimitiveNumericCoercionOperand {
            operand_index,
            register,
            value_kind,
        } => GeneratedBaselineFallbackCause::UnsupportedPrimitiveNumericCoercionOperand {
            operand_index,
            register,
            value_kind,
        },
        BaselineGeneratedFallbackCause::UnsupportedTruthinessOperand {
            operand_index,
            register,
            value_kind,
        } => GeneratedBaselineFallbackCause::UnsupportedTruthinessOperand {
            operand_index,
            register,
            value_kind,
        },
        BaselineGeneratedFallbackCause::UnsupportedStrictEqualityOperand {
            operand_index,
            register,
            value_kind,
        } => GeneratedBaselineFallbackCause::UnsupportedStrictEqualityOperand {
            operand_index,
            register,
            value_kind,
        },
        BaselineGeneratedFallbackCause::Int32Overflow => {
            GeneratedBaselineFallbackCause::Int32Overflow
        }
        BaselineGeneratedFallbackCause::OperandAccess { error } => {
            GeneratedBaselineFallbackCause::OperandAccess { error }
        }
        BaselineGeneratedFallbackCause::BadImmediate {
            operand_index,
            error,
        } => GeneratedBaselineFallbackCause::BadImmediate {
            operand_index,
            error,
        },
        BaselineGeneratedFallbackCause::RegisterRead { register, error } => {
            GeneratedBaselineFallbackCause::RegisterRead {
                register,
                error: generated_baseline_register_fallback_cause(error),
            }
        }
        BaselineGeneratedFallbackCause::RegisterWrite { register, error } => {
            GeneratedBaselineFallbackCause::RegisterWrite {
                register,
                error: generated_baseline_register_fallback_cause(error),
            }
        }
        BaselineGeneratedFallbackCause::BadReturnRegister { register, error } => {
            GeneratedBaselineFallbackCause::BadReturnRegister {
                register,
                error: generated_baseline_register_fallback_cause(error),
            }
        }
    }
}

fn generated_baseline_register_fallback_cause(
    cause: BaselineGeneratedRegisterFallbackCause,
) -> GeneratedBaselineRegisterFallbackCause {
    match cause {
        BaselineGeneratedRegisterFallbackCause::InvalidRegister => {
            GeneratedBaselineRegisterFallbackCause::InvalidRegister
        }
        BaselineGeneratedRegisterFallbackCause::CannotWriteConstant => {
            GeneratedBaselineRegisterFallbackCause::CannotWriteConstant
        }
        BaselineGeneratedRegisterFallbackCause::CannotAddressHeaderAsValue => {
            GeneratedBaselineRegisterFallbackCause::CannotAddressHeaderAsValue
        }
        BaselineGeneratedRegisterFallbackCause::MissingConstantPool => {
            GeneratedBaselineRegisterFallbackCause::MissingConstantPool
        }
        BaselineGeneratedRegisterFallbackCause::DeferredConstant => {
            GeneratedBaselineRegisterFallbackCause::DeferredConstant
        }
        BaselineGeneratedRegisterFallbackCause::RegisterOutOfBounds => {
            GeneratedBaselineRegisterFallbackCause::RegisterOutOfBounds
        }
    }
}

fn inline_cache_count(code_block: &CodeBlock) -> u32 {
    let table = code_block.side_tables().inline_caches();
    table
        .property_accesses
        .len()
        .saturating_add(table.calls.len())
        .saturating_add(table.structure_stubs.len())
        .saturating_add(table.iteration_modes.len())
        .try_into()
        .unwrap_or(u32::MAX)
}

fn reserved_structure_stub_access_case_ref(
    transaction: &VmStructureStubRepatchTransactionRecord,
) -> Option<AccessCaseRef> {
    if transaction.lifecycle != VmStructureStubRepatchTransactionLifecycle::Reserved {
        return None;
    }
    if !matches!(
        transaction.outcome,
        tiering::VmStructureStubRepatchTransactionOutcome::Reserved
    ) {
        return None;
    }
    transaction
        .stub
        .as_ref()
        .map(|stub| AccessCaseRef(stub.id.0))
}

fn structure_stub_access_case_link_request(
    candidate: &VmStructureStubPropertyInlineCacheCandidate,
    access_case_ref: AccessCaseRef,
) -> Option<StructureStubAccessCaseLinkRequest> {
    let CacheKey::Property(key) = candidate.key else {
        return None;
    };

    Some(StructureStubAccessCaseLinkRequest {
        structure_stub_index: candidate.structure_stub_index,
        bytecode_index: candidate.bytecode_index,
        slot: candidate.slot.0 as usize,
        key,
        attachment_kind: candidate.kind.bytecode_attachment_kind(),
        base_structure: candidate.base_structure,
        holder_structure: candidate.holder_structure,
        new_structure: candidate.new_structure,
        offset: candidate
            .offset
            .map(|offset| crate::bytecode::ic::PropertyOffset(offset.raw())),
        access_case_ref,
    })
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
enum GlobalRootAppliedMutation {
    Registered(RootRecord),
    Retargeted(TargetedRootRecord),
}

fn rollback_global_root_mutations(heap: &mut Heap, applied: Vec<GlobalRootAppliedMutation>) {
    for mutation in applied.into_iter().rev() {
        match mutation {
            GlobalRootAppliedMutation::Registered(root) => {
                let _ = heap
                    .unregister_targeted_root(root, RootSetMutationAuthority::ExplicitRootRegistry);
            }
            GlobalRootAppliedMutation::Retargeted(record) => {
                let _ = heap
                    .retarget_targeted_root(record, RootSetMutationAuthority::ExplicitRootRegistry);
            }
        }
    }
}

#[derive(Clone, Debug, Default, Eq, PartialEq)]
pub struct VmGcExecutionState {
    no_gc_regions: Vec<VmNoGcRegion>,
    suspended_no_gc_regions: Vec<VmNoGcRegionId>,
    next_no_gc_region: u64,
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub struct VmCollectionCompletionRecord {
    pub kind: crate::gc::CollectionKind,
    pub heap_phase_before: crate::gc::GcPhase,
    pub heap_phase_after: crate::gc::GcPhase,
    pub property_load_megamorphic_cache_aging:
        Option<tiering::VmPropertyLoadMegamorphicCacheAgingRecord>,
}

impl VmGcExecutionState {
    pub fn no_gc_scope_depth(&self) -> u32 {
        self.no_gc_regions.len().try_into().unwrap_or(u32::MAX)
    }

    pub fn enter_no_gc_region(&mut self, heap_scope: NoGcScopeDepth) -> VmNoGcRegion {
        self.next_no_gc_region = self.next_no_gc_region.saturating_add(1);
        let region = VmNoGcRegion {
            id: VmNoGcRegionId(self.next_no_gc_region),
            depth: self.no_gc_scope_depth().saturating_add(1),
            contract: NoGcScope::new().contract(),
            heap_scope,
        };
        self.no_gc_regions.push(region);
        region
    }

    pub fn validate_leave_no_gc_region(
        &self,
        region: VmNoGcRegion,
    ) -> Result<VmNoGcRegion, VmGcIntegrationError> {
        let Some(active) = self.no_gc_regions.last().copied() else {
            return Err(VmGcIntegrationError::NoActiveNoGcRegion);
        };
        if active.id != region.id {
            return Err(VmGcIntegrationError::NoGcRegionMismatch {
                expected: active.id,
                actual: region.id,
            });
        }
        let actual_depth = self.no_gc_scope_depth();
        if actual_depth != active.depth {
            return Err(VmGcIntegrationError::NoGcRegionDepthMismatch {
                expected: active.depth,
                actual: actual_depth,
            });
        }
        Ok(active)
    }

    pub fn leave_no_gc_region(
        &mut self,
        region: VmNoGcRegion,
    ) -> Result<VmNoGcRegion, VmGcIntegrationError> {
        let active = self.validate_leave_no_gc_region(region)?;
        self.no_gc_regions.pop();
        Ok(active)
    }

    pub fn validate_suspend_no_gc_region(&self) -> Result<VmNoGcRegion, VmGcIntegrationError> {
        let Some(active) = self.no_gc_regions.last().copied() else {
            return Err(VmGcIntegrationError::NoActiveNoGcRegion);
        };
        let actual_depth = self.no_gc_scope_depth();
        if actual_depth != active.depth {
            return Err(VmGcIntegrationError::NoGcRegionDepthMismatch {
                expected: active.depth,
                actual: actual_depth,
            });
        }
        Ok(active)
    }

    pub fn suspend_no_gc_region(&mut self) -> Result<VmSuspendedNoGcRegion, VmGcIntegrationError> {
        let active = self.validate_suspend_no_gc_region()?;
        self.no_gc_regions.pop();
        let expected_depth = active.depth.saturating_sub(1);
        let actual_depth = self.no_gc_scope_depth();
        if actual_depth != expected_depth {
            self.no_gc_regions.push(active);
            return Err(VmGcIntegrationError::NoGcRegionDepthMismatch {
                expected: expected_depth,
                actual: actual_depth,
            });
        }
        self.suspended_no_gc_regions.push(active.id);
        Ok(VmSuspendedNoGcRegion {
            region: active,
            restore_depth: active.depth,
            restore_heap_scope_depth: active.heap_scope.depth,
        })
    }

    pub fn validate_resume_no_gc_region(
        &self,
        suspended: VmSuspendedNoGcRegion,
    ) -> Result<(), VmGcIntegrationError> {
        let Some(expected) = self.suspended_no_gc_regions.last().copied() else {
            return Err(VmGcIntegrationError::NoSuspendedNoGcRegion);
        };
        if expected != suspended.region.id {
            return Err(VmGcIntegrationError::NoGcRegionMismatch {
                expected,
                actual: suspended.region.id,
            });
        }
        let expected_depth = suspended.restore_depth.saturating_sub(1);
        let actual_depth = self.no_gc_scope_depth();
        if actual_depth != expected_depth {
            return Err(VmGcIntegrationError::NoGcRegionDepthMismatch {
                expected: expected_depth,
                actual: actual_depth,
            });
        }
        if suspended.region.depth != suspended.restore_depth {
            return Err(VmGcIntegrationError::NoGcRegionDepthMismatch {
                expected: suspended.restore_depth,
                actual: suspended.region.depth,
            });
        }
        if suspended.region.heap_scope.depth != suspended.restore_heap_scope_depth {
            return Err(VmGcIntegrationError::NoGcRegionDepthMismatch {
                expected: suspended.restore_heap_scope_depth,
                actual: suspended.region.heap_scope.depth,
            });
        }
        Ok(())
    }

    pub fn resume_no_gc_region(
        &mut self,
        suspended: VmSuspendedNoGcRegion,
    ) -> Result<VmNoGcRegion, VmGcIntegrationError> {
        self.validate_resume_no_gc_region(suspended)?;
        self.suspended_no_gc_regions.pop();
        self.no_gc_regions.push(suspended.region);
        Ok(suspended.region)
    }

    pub fn abandon_suspended_no_gc_region(
        &mut self,
        suspended: VmSuspendedNoGcRegion,
    ) -> Result<(), VmGcIntegrationError> {
        let Some(expected) = self.suspended_no_gc_regions.last().copied() else {
            return Err(VmGcIntegrationError::NoSuspendedNoGcRegion);
        };
        if expected != suspended.region.id {
            return Err(VmGcIntegrationError::NoGcRegionMismatch {
                expected,
                actual: suspended.region.id,
            });
        }
        let expected_depth = suspended.restore_depth.saturating_sub(1);
        let actual_depth = self.no_gc_scope_depth();
        if actual_depth != expected_depth {
            return Err(VmGcIntegrationError::NoGcRegionDepthMismatch {
                expected: expected_depth,
                actual: actual_depth,
            });
        }
        self.suspended_no_gc_regions.pop();
        Ok(())
    }

    pub fn evaluate_heap_operation(
        &self,
        phase: crate::gc::GcPhase,
        operation: HeapSemanticOperation,
    ) -> Result<crate::gc::HeapSemanticGrant, HeapSemanticError> {
        evaluate_heap_semantics(
            HeapStateDescriptor {
                phase,
                no_gc_scope_depth: self.no_gc_scope_depth(),
                ..HeapStateDescriptor::default()
            },
            HeapMutationAuthority::Mutator,
            operation,
        )
    }
}

#[derive(Clone, Copy, Debug, Default, Eq, Hash, PartialEq)]
#[repr(transparent)]
pub struct VmNoGcRegionId(pub u64);

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub struct VmNoGcRegion {
    pub id: VmNoGcRegionId,
    pub depth: u32,
    pub contract: NoGcScopeContract,
    heap_scope: NoGcScopeDepth,
}

impl VmNoGcRegion {
    pub fn heap_scope(&self) -> NoGcScopeDepth {
        self.heap_scope
    }
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub struct VmSuspendedNoGcRegion {
    region: VmNoGcRegion,
    restore_depth: u32,
    restore_heap_scope_depth: u32,
}

impl VmSuspendedNoGcRegion {
    pub fn region(&self) -> VmNoGcRegion {
        self.region
    }

    pub fn restore_depth(&self) -> u32 {
        self.restore_depth
    }

    pub fn restore_heap_scope_depth(&self) -> u32 {
        self.restore_heap_scope_depth
    }

    fn with_heap_scope(mut self, heap_scope: NoGcScopeDepth) -> Self {
        self.region.heap_scope = heap_scope;
        self
    }
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub enum VmGcIntegrationError {
    NoActiveNoGcRegion,
    NoSuspendedNoGcRegion,
    NoGcRegionMismatch {
        expected: VmNoGcRegionId,
        actual: VmNoGcRegionId,
    },
    NoGcRegionDepthMismatch {
        expected: u32,
        actual: u32,
    },
}

#[derive(Clone, Debug, Eq, PartialEq)]
pub struct VmHeapSnapshotHook {
    pub builder: HeapSnapshotBuilder,
    pub statistics: HeapStatistics,
    pub entry_roots: Vec<RootRecord>,
    pub execution_roots: Vec<RootRecord>,
    pub exception_roots: Vec<RootRecord>,
    pub global_roots: Vec<TargetedRootRecord>,
    pub active_entry_depth: usize,
    pub active_frame_depth: usize,
    pub no_gc_scope_depth: u32,
}

/// Explicit proof that the mutator may allocate or inspect GC cells.
pub struct HeapAccessToken<'vm> {
    heap: &'vm mut Heap,
}

impl<'vm> HeapAccessToken<'vm> {
    pub fn heap(&self) -> &Heap {
        self.heap
    }

    pub fn heap_mut(&mut self) -> &mut Heap {
        self.heap
    }
}

