    fn assert_host_supported_baseline_source_execution_path(
        vm: &Vm,
        execution_path: TierEntryExecutionPath,
    ) {
        if vm.can_execute_p6_x86_64_emitted_native_entry() {
            assert_eq!(
                execution_path,
                TierEntryExecutionPath::NativeCode(JitType::Baseline)
            );
        } else {
            assert!(
                matches!(
                    execution_path,
                    TierEntryExecutionPath::Interpreter
                        | TierEntryExecutionPath::NativeCode(JitType::Baseline)
                        | TierEntryExecutionPath::GeneratedCode(JitType::Baseline)
                ),
                "unsupported x86_64 emitted entries should either stay on the interpreter path, use a platform-independent native shim, or use generated fallback residency, got {execution_path:?}"
            );
        }
    }

    fn source(text: &str) -> SourceCode {
        let provider = Arc::new(SourceProvider::new(
            SourceOrigin::default(),
            SourceText::Latin1(text.as_bytes().to_vec()),
        ));
        SourceCode::new(
            provider,
            SourceSpan::new(SourcePosition(0), SourcePosition(text.len() as u32)),
        )
    }

    fn js_string_literal(text: &str) -> String {
        let mut literal = String::from("'");
        for character in text.chars() {
            match character {
                '\\' => literal.push_str("\\\\"),
                '\'' => literal.push_str("\\'"),
                '\n' => literal.push_str("\\n"),
                '\r' => literal.push_str("\\r"),
                '\t' => literal.push_str("\\t"),
                _ => literal.push(character),
            }
        }
        literal.push('\'');
        literal
    }

    fn compiler_produced_program_code_block(text: &str, session: u64) -> CodeBlock {
        let source = source(text);
        let mut arena = ParserArena::new();
        let parsed = Parser::with_mode(
            &mut arena,
            AstBuilder::default(),
            &source,
            crate::syntax::ParseMode::Program,
        )
        .parse()
        .unwrap();
        let input = bytecompiler_input_from_parsed_ast(
            BytecompilerSessionId(session),
            source.clone(),
            &parsed,
            &arena,
        )
        .unwrap();
        let plan = emit_unlinked_code_from_parsed_ast(&input, &arena).unwrap();
        let unlinked = plan.unlinked_code.unwrap();
        assert!(unlinked
            .side_tables()
            .root_maps
            .iter()
            .all(|root_map| root_map.owner.is_none()));

        CodeBlock::from_unlinked(unlinked, LinkContext::default())
            .with_entrypoints(CodeBlockEntrypoints {
                interpreter: Some(InterpreterEntrySlot(0)),
                ..CodeBlockEntrypoints::default()
            })
            .with_lifecycle(CodeBlockLifecycleState::LinkedInterpreter)
    }

    fn register_compiler_produced_program_code_block_with_executable(
        vm: &mut Vm,
        text: &str,
        session: u64,
    ) -> (CodeBlockId, CodeBlock) {
        let source = source(text);
        let mut arena = ParserArena::new();
        let parsed = Parser::with_mode(
            &mut arena,
            AstBuilder::default(),
            &source,
            crate::syntax::ParseMode::Program,
        )
        .parse()
        .unwrap();
        let input = bytecompiler_input_from_parsed_ast(
            BytecompilerSessionId(session),
            source.clone(),
            &parsed,
            &arena,
        )
        .unwrap();
        let mut plan = emit_unlinked_code_from_parsed_ast(&input, &arena).unwrap();
        let unlinked = plan.unlinked_code.take().expect("program code block");
        let shared_unlinked = Arc::new(unlinked);
        let executable = vm.allocate_executable_cell().unwrap();
        let owner = vm.allocate_code_block_cell().unwrap();
        let code_block = CodeBlock::from_shared_unlinked(
            shared_unlinked.clone(),
            LinkContext {
                owner_executable: Some(executable),
                specialization: CodeSpecialization::None,
                ..LinkContext::default()
            },
        )
        .with_entrypoints(CodeBlockEntrypoints {
            interpreter: Some(InterpreterEntrySlot(0)),
            ..CodeBlockEntrypoints::default()
        })
        .with_lifecycle(CodeBlockLifecycleState::LinkedInterpreter)
        .with_root_map_owner(owner);
        vm.executables
            .register_script(executable, ScriptExecutableKind::Program, shared_unlinked)
            .expect("source executable registration");
        vm.code_blocks.register(owner, code_block.clone());
        let install = vm.executables.install_script_code(
            executable,
            owner,
            CodeSpecialization::None,
            &code_block,
        );
        assert!(
            !matches!(install.outcome, ExecutableInstallOutcome::Rejected(_)),
            "source executable install failed: {install:?}"
        );
        (owner, code_block)
    }

    fn assert_compiler_produced_helper_install(
        source_text: &str,
        session: u64,
        code_id: u64,
        expected_opcode: CoreOpcode,
        expected_root_count: usize,
    ) {
        let mut vm = Vm::new(VmConfig::interpreter_only());
        let owner = vm.allocate_code_block_cell().unwrap();
        let code_block = compiler_produced_program_code_block(source_text, session);
        vm.code_blocks.register(owner, code_block);
        let registered = vm
            .code_blocks
            .get(owner)
            .expect("registered compiler code block")
            .code_block();
        assert!(registered
            .side_tables()
            .root_maps
            .iter()
            .all(|root_map| root_map.owner == Some(owner)));

        let artifact = vm
            .install_baseline_generated_code_artifact(
                owner,
                JitCodeId(code_id),
                BaselineGeneratedCodeBodyId(code_id.saturating_add(100)),
                BaselineInstallDependencyPolicy::Allow,
            )
            .unwrap();
        let plan = artifact
            .runtime_helper_plan()
            .expect("artifact should own compiler-derived helper metadata");
        let proof = plan.proof_at(0).expect("helper proof");

        assert_eq!(plan.proof_count(), 1);
        assert_eq!(proof.proof.contract.opcode, expected_opcode);
        assert_eq!(proof.proof.root_count, expected_root_count);
        assert_eq!(artifact.owner, owner);
    }

    fn baseline_artifact(owner: CodeBlockId, id: u64) -> JitCodeArtifact {
        let code = JitCodeId(id);
        let native_code = NativeCodeId(id as u32 + 100);
        let allocation = ExecutableAllocationId(id + 200);
        JitCodeArtifact {
            id: code,
            tier: JitType::Baseline,
            origin: CodeOrigin {
                kind: CodeOriginKind::BaselineCodeBlock,
                owner: Some(owner),
                executable: None,
                bytecode_index: Some(0),
            },
            ownership: CodeOwnership::CodeBlockOwned,
            native_code: Some(native_code),
            machine_code: Some(MachineCodeHandle {
                allocation,
                owner: MachineCodeOwnership::CodeBlock(owner),
                range: MachineCodeRange {
                    allocation,
                    start_offset: 0,
                    size_bytes: 64,
                },
                symbol: Some(native_code),
                protection: ExecutableMemoryProtection::Executable,
                lifecycle: ExecutableAllocationLifecycle::LinkedExecutable,
                mutation_authority: ExecutableMutationAuthority::LinkBuffer,
            }),
            entrypoint: Entrypoint {
                kind: EntrypointKind::GeneratedCode,
                abi: EntryAbi::GeneratedCode,
                code: Some(code),
                boundary: None,
            },
            patchpoints: Vec::new(),
            dependencies: Vec::new(),
            byproducts: Vec::new(),
            disassembly: None,
            liveness: CodeLiveness::Live,
            finalization_authority: CodeFinalizationAuthority::MainThread,
        }
    }

    fn p6_semantic_install_request(
        owner: CodeBlockId,
        id: u64,
    ) -> P6X86_64SemanticBaselineNativeEntryInstallRequest {
        P6X86_64SemanticBaselineNativeEntryInstallRequest {
            owner,
            code_id: JitCodeId(id),
            native_code: NativeCodeId(id as u32 + 1_000),
            allocation: ExecutableAllocationId(id + 2_000),
            slot: JitCodeSlot(id.try_into().expect("test JIT slot id")),
        }
    }

