    fn p8a_jump_if_not_nullish_code_block(source: CoreOpcode) -> CodeBlock {
        let source_instruction = match source {
            CoreOpcode::LoadUndefined => typed_core_instruction_with_operands(
                0,
                CoreOpcode::LoadUndefined,
                vec![Operand::Register(local(0))],
            ),
            CoreOpcode::LoadNull => typed_core_instruction_with_operands(
                0,
                CoreOpcode::LoadNull,
                vec![Operand::Register(local(0))],
            ),
            CoreOpcode::LoadBool => typed_core_instruction_with_operands(
                0,
                CoreOpcode::LoadBool,
                vec![Operand::Register(local(0)), Operand::UnsignedImmediate(0)],
            ),
            CoreOpcode::LoadInt32 => typed_core_instruction_with_operands(
                0,
                CoreOpcode::LoadInt32,
                vec![Operand::Register(local(0)), Operand::SignedImmediate(7)],
            ),
            _ => unreachable!("unsupported P8a test source"),
        };
        linked_p6_test_code_block(vec![
            source_instruction,
            typed_core_instruction_with_operands(
                1,
                CoreOpcode::JumpIfNotNullish,
                vec![
                    Operand::Register(local(0)),
                    Operand::BytecodeIndex(BytecodeIndex::from_offset(4)),
                ],
            ),
            typed_core_instruction_with_operands(
                2,
                CoreOpcode::LoadInt32,
                vec![Operand::Register(local(1)), Operand::SignedImmediate(11)],
            ),
            typed_core_instruction_with_operands(
                3,
                CoreOpcode::Return,
                vec![Operand::Register(local(1))],
            ),
            typed_core_instruction_with_operands(
                4,
                CoreOpcode::LoadInt32,
                vec![Operand::Register(local(1)), Operand::SignedImmediate(42)],
            ),
            typed_core_instruction_with_operands(
                5,
                CoreOpcode::Return,
                vec![Operand::Register(local(1))],
            ),
        ])
    }

    #[derive(Clone, Copy, Debug, Eq, PartialEq)]
    enum P8bTruthinessSource {
        Undefined,
        Null,
        Bool(bool),
        Int32(i32),
    }

    fn p8b_jump_if_false_code_block(source: P8bTruthinessSource) -> CodeBlock {
        let source_instruction = match source {
            P8bTruthinessSource::Undefined => typed_core_instruction_with_operands(
                0,
                CoreOpcode::LoadUndefined,
                vec![Operand::Register(local(0))],
            ),
            P8bTruthinessSource::Null => typed_core_instruction_with_operands(
                0,
                CoreOpcode::LoadNull,
                vec![Operand::Register(local(0))],
            ),
            P8bTruthinessSource::Bool(value) => typed_core_instruction_with_operands(
                0,
                CoreOpcode::LoadBool,
                vec![
                    Operand::Register(local(0)),
                    Operand::UnsignedImmediate(value as u32),
                ],
            ),
            P8bTruthinessSource::Int32(value) => typed_core_instruction_with_operands(
                0,
                CoreOpcode::LoadInt32,
                vec![Operand::Register(local(0)), Operand::SignedImmediate(value)],
            ),
        };
        linked_p6_test_code_block(vec![
            source_instruction,
            typed_core_instruction_with_operands(
                1,
                CoreOpcode::JumpIfFalse,
                vec![
                    Operand::Register(local(0)),
                    Operand::BytecodeIndex(BytecodeIndex::from_offset(4)),
                ],
            ),
            typed_core_instruction_with_operands(
                2,
                CoreOpcode::LoadInt32,
                vec![Operand::Register(local(1)), Operand::SignedImmediate(11)],
            ),
            typed_core_instruction_with_operands(
                3,
                CoreOpcode::Return,
                vec![Operand::Register(local(1))],
            ),
            typed_core_instruction_with_operands(
                4,
                CoreOpcode::LoadInt32,
                vec![Operand::Register(local(1)), Operand::SignedImmediate(42)],
            ),
            typed_core_instruction_with_operands(
                5,
                CoreOpcode::Return,
                vec![Operand::Register(local(1))],
            ),
        ])
    }

