    #[derive(Clone, Copy, Debug, Eq, PartialEq)]
    struct P6SemanticInstallSideEffectCounts {
        materializations: usize,
        platform_residencies: usize,
        installs: usize,
        readiness: usize,
        provenance: usize,
    }

    fn p6_semantic_install_side_effect_counts(vm: &Vm) -> P6SemanticInstallSideEffectCounts {
        P6SemanticInstallSideEffectCounts {
            materializations: vm
                .tiering_integration()
                .baseline_executable_materializations()
                .len(),
            platform_residencies: vm.baseline_platform_executable_residencies.len(),
            installs: vm.tiering_integration().baseline_install_records().len(),
            readiness: vm
                .tiering_integration()
                .baseline_native_entry_readiness_records()
                .len(),
            provenance: vm
                .tiering_integration()
                .baseline_machine_code_emission_provenance_records()
                .len(),
        }
    }

    fn baseline_native_entry_callable_kind_for_owner(
        vm: &Vm,
        owner: CodeBlockId,
    ) -> Option<BaselineNativeEntryCallableKind> {
        let gate = vm.tiering.baseline_native_entry_gate_for_owner(owner)?;
        let readiness = vm.tiering.baseline_native_entry_readiness_for_gate(&gate)?;
        readiness.callable.map(|callable| callable.kind())
    }

    fn baseline_native_entry_for_owner_is_host_callable(vm: &Vm, owner: CodeBlockId) -> bool {
        baseline_native_entry_callable_kind_for_owner(vm, owner)
            .map(|kind| vm.can_execute_baseline_native_entry_kind(kind))
            .unwrap_or(false)
    }

    fn assert_p6_semantic_install_rejected_without_side_effects(
        vm: &Vm,
        owner: CodeBlockId,
        slot: JitCodeSlot,
        before: P6SemanticInstallSideEffectCounts,
    ) {
        assert_eq!(p6_semantic_install_side_effect_counts(vm), before);
        let registered = vm
            .code_blocks
            .get(owner)
            .expect("registered code block after rejected P6 semantic install")
            .code_block();
        assert_ne!(registered.entrypoints().baseline_jit(), Some(slot));
    }

    #[cfg(all(unix, target_arch = "x86_64"))]
    fn assert_p6_callable_emitted_readiness(
        record: &P6X86_64SemanticBaselineNativeEntryInstallRecord,
    ) -> u64 {
        let enabled_readiness = record
            .enabled_readiness
            .as_ref()
            .expect("callable install records enabled readiness");
        assert_eq!(
            enabled_readiness.callable.map(|callable| callable.kind()),
            Some(BaselineNativeEntryCallableKind::P6X86_64EmittedSemanticCAbiEntry)
        );
        assert_ne!(
            enabled_readiness.callable.map(|callable| callable.kind()),
            Some(BaselineNativeEntryCallableKind::P6PureBaselineNativeEntryShim)
        );
        enabled_readiness.ordinal
    }

    #[cfg(all(unix, any(target_arch = "x86_64", target_arch = "aarch64")))]
    fn assert_latest_p6_callable_native_completion(
        vm: &Vm,
        owner: CodeBlockId,
        readiness_ordinal: u64,
        launch_descriptor_count_before: usize,
    ) {
        let entry_decision = vm
            .tiering_integration()
            .entry_decisions()
            .last()
            .expect("P6 callable native entry decision");
        assert_eq!(entry_decision.owner, owner);
        assert_eq!(
            entry_decision.decision,
            TierEntryDecision::EnterNative {
                tier: JitType::Baseline
            }
        );
        assert_eq!(
            entry_decision
                .baseline_entry_gate
                .as_ref()
                .map(|gate| gate.outcome),
            Some(super::tiering::BaselineEntryGateOutcome::NativeEntryReady)
        );
        assert_eq!(
            entry_decision
                .baseline_entry_gate
                .as_ref()
                .and_then(|gate| gate.native_entry_readiness_ordinal),
            Some(readiness_ordinal)
        );
        assert_eq!(
            entry_decision.execution_path,
            TierEntryExecutionPath::NativeCode(JitType::Baseline)
        );
        assert_eq!(
            vm.tiering_integration()
                .diagnostics()
                .last()
                .expect("P6 callable native diagnostic")
                .execution_path,
            TierEntryExecutionPath::NativeCode(JitType::Baseline)
        );
        assert_eq!(
            vm.entry_state().launch_descriptors().len(),
            launch_descriptor_count_before + 1
        );
        assert_eq!(
            vm.entry_state()
                .launch_descriptors()
                .last()
                .expect("P6 callable launch descriptor")
                .readiness_ordinal,
            readiness_ordinal
        );
    }

