    #[cfg(all(unix, target_arch = "x86_64"))]
    fn assert_p6_callable_side_exit_stub(
        record: &P6X86_64SemanticBaselineNativeEntryInstallRecord,
        bytecode_index: BytecodeIndex,
        reason: P6X86_64BaselineSelectedSideExitReason,
    ) {
        let stub = record
            .semantic_emission
            .side_exit_return_stubs
            .iter()
            .find(|stub| stub.bytecode_index == bytecode_index && stub.reason == reason)
            .expect("P6 callable side-exit return stub");
        assert_eq!(
            P6X86_64BaselineSideExitReturnPayload::decode(stub.encoded_payload.raw_bits())
                .map(P6X86_64BaselineSideExitReturnPayload::side_exit_index),
            Some(stub.side_exit_index)
        );
    }

    #[cfg(all(unix, target_arch = "x86_64"))]
    fn assert_latest_p6_callable_side_exit_fallback(
        vm: &Vm,
        owner: CodeBlockId,
        fallback_count_before: usize,
        bytecode_index: BytecodeIndex,
        opcode: CoreOpcode,
        generated_cause: Option<GeneratedBaselineFallbackCause>,
    ) {
        assert_eq!(
            vm.tiering_integration().fallback_records().len(),
            fallback_count_before + 1
        );
        let fallback = vm
            .tiering_integration()
            .fallback_records()
            .last()
            .expect("P6 callable side-exit fallback telemetry");
        assert_eq!(fallback.owner, owner);
        assert_eq!(fallback.result.bytecode_index, Some(bytecode_index));
        assert!(fallback.frame.is_some());
        assert_eq!(fallback.result.attempted_tier, JitType::Baseline);
        assert_eq!(
            fallback.result.target,
            TierFallbackTarget::ReturnToInterpreter
        );
        assert_eq!(
            fallback.result.resume,
            TierFallbackResumeKind::ContinueInInterpreter
        );
        assert_eq!(
            fallback.generated_baseline,
            generated_cause.map(|cause| GeneratedBaselineFallbackRecord {
                bytecode_index,
                opcode: GeneratedBaselineFallbackOpcode::Core(opcode),
                cause,
            })
        );
        assert_eq!(fallback.boundary.no_gc_scope_depth, 1);
    }

    fn baseline_link_finalization(artifact: &JitCodeArtifact) -> LinkBufferFinalizationRecord {
        let machine_code = artifact
            .machine_code
            .expect("baseline artifact machine-code descriptor");
        let buffer = AssemblerBufferDescriptor::builder(AssemblerBufferId(artifact.id.0))
            .architecture(AssemblerArchitecture::X86_64)
            .lifecycle(AssemblerBufferLifecycle::FrozenForLink)
            .capacity(machine_code.range.size_bytes, machine_code.range.size_bytes)
            .build()
            .expect("frozen assembler buffer descriptor");
        let allocation = ExecutableAllocationRecord::from_request(
            ExecutableAllocationRequest::allocated_writable(
                machine_code.allocation,
                machine_code.owner,
                machine_code.range.size_bytes,
            ),
        );
        let layout = plan_link_buffer_layout(
            &buffer,
            LinkBufferProfile::Baseline,
            Some(machine_code.allocation),
        )
        .expect("baseline link-buffer layout");
        let image = describe_assembler_byte_image(
            &buffer,
            AssemblerByteImageId(artifact.id.0),
            AssemblerByteImageDigest(0xfeed),
        )
        .expect("assembler byte image");
        let copy_link = record_link_buffer_copy_link(LinkBufferCopyLinkRequest {
            source: &buffer,
            source_image: &image,
            layout: &layout,
            allocation: &allocation,
            code_id: artifact.id,
            owner: machine_code.owner,
        });
        assert_eq!(copy_link.outcome, LinkBufferCopyLinkOutcome::Accepted);
        let record = finalize_link_buffer(LinkBufferFinalizationRequest {
            copy_link: &copy_link,
            code_id: artifact.id,
            owner: machine_code.owner,
            symbol: machine_code.symbol,
        });
        assert_eq!(record.outcome, LinkBufferFinalizationOutcome::Accepted);
        record
    }

    fn baseline_link_finalization_with_byte_evidence(
        artifact: &JitCodeArtifact,
    ) -> LinkBufferFinalizationRecord {
        baseline_link_finalization_with_byte_evidence_and_linked_bytes(artifact).0
    }

    fn baseline_link_finalization_with_byte_evidence_and_linked_bytes(
        artifact: &JitCodeArtifact,
    ) -> (LinkBufferFinalizationRecord, Vec<u8>) {
        let machine_code = artifact
            .machine_code
            .expect("baseline artifact machine-code descriptor");
        let buffer = AssemblerBufferDescriptor::builder(AssemblerBufferId(artifact.id.0))
            .architecture(AssemblerArchitecture::X86_64)
            .lifecycle(AssemblerBufferLifecycle::FrozenForLink)
            .capacity(machine_code.range.size_bytes, machine_code.range.size_bytes)
            .build()
            .expect("frozen assembler buffer descriptor");
        let allocation = ExecutableAllocationRecord::from_request(
            ExecutableAllocationRequest::allocated_writable(
                machine_code.allocation,
                machine_code.owner,
                machine_code.range.size_bytes,
            ),
        );
        let layout = plan_link_buffer_layout(
            &buffer,
            LinkBufferProfile::Baseline,
            Some(machine_code.allocation),
        )
        .expect("baseline link-buffer layout");
        let bytes: Vec<u8> = (0..machine_code.range.size_bytes)
            .map(|index| (index as u8).wrapping_mul(5).wrapping_add(1))
            .collect();
        let image =
            freeze_assembler_byte_image(&buffer, AssemblerByteImageId(artifact.id.0), bytes)
                .expect("assembler byte image");
        let linked_image = link_assembler_byte_image(&image, &layout).expect("linked byte image");
        let copy_link =
            record_link_buffer_copy_link_with_linked_image(LinkBufferLinkedCopyLinkRequest {
                source: &buffer,
                source_image: &image,
                linked_image: &linked_image,
                layout: &layout,
                allocation: &allocation,
                code_id: artifact.id,
                owner: machine_code.owner,
            });
        assert_eq!(copy_link.outcome, LinkBufferCopyLinkOutcome::Accepted);
        let record = finalize_link_buffer(LinkBufferFinalizationRequest {
            copy_link: &copy_link,
            code_id: artifact.id,
            owner: machine_code.owner,
            symbol: machine_code.symbol,
        });
        assert_eq!(record.outcome, LinkBufferFinalizationOutcome::Accepted);
        assert!(record.byte_copy_evidence.is_some());
        (record, linked_image.bytes().to_vec())
    }

    fn baseline_executable_residency(
        link_finalization: &LinkBufferFinalizationRecord,
    ) -> ExecutableMemoryResidencyRecord {
        let allocation_ledger = ExecutableAllocationRecord::from_request(
            ExecutableAllocationRequest::allocated_writable(
                link_finalization.allocation,
                link_finalization.owner,
                link_finalization.allocation_range.size_bytes,
            ),
        );
        let allocation = record_executable_memory_allocation(ExecutableMemoryAllocationRequest {
            ordinal: ExecutableMemoryOperationOrdinal(1),
            allocation: allocation_ledger,
            mapped_range: ExecutableMemoryMappedRange {
                allocation: link_finalization.allocation,
                start_offset: 0,
                byte_len: 4096,
                page_size: ExecutableMemoryPageSize(4096),
            },
        });
        assert_eq!(
            allocation.outcome,
            ExecutableMemoryResidencyOutcome::Accepted
        );

        let transition = record_executable_memory_protection_transition(
            ExecutableMemoryProtectionTransitionRequest {
                ordinal: ExecutableMemoryOperationOrdinal(2),
                allocation: allocation.clone(),
                transition: JitPermissionTransition::RwToRx,
                start_protection: ExecutableMemoryProtection::Writable,
                start_lifecycle: ExecutableAllocationLifecycle::AllocatedWritable,
                end_protection: ExecutableMemoryProtection::Executable,
                end_lifecycle: ExecutableAllocationLifecycle::LinkedExecutable,
                mutation_authority: ExecutableMutationAuthority::LinkBuffer,
            },
        );
        assert_eq!(
            transition.outcome,
            ExecutableMemoryResidencyOutcome::Accepted
        );

        let cache_flush = record_instruction_cache_flush(InstructionCacheFlushRequest {
            ordinal: ExecutableMemoryOperationOrdinal(3),
            transition: transition.clone(),
            code_id: link_finalization.code_id,
            owner: link_finalization.owner,
            allocation: link_finalization.allocation,
            range: link_finalization.allocation_range,
        });
        assert_eq!(
            cache_flush.outcome,
            ExecutableMemoryResidencyOutcome::Accepted
        );

        let residency = record_executable_memory_residency(ExecutableMemoryResidencyRequest {
            link_finalization,
            allocation: &allocation,
            protection_transition: &transition,
            instruction_cache_flush: Some(&cache_flush),
        });
        assert_eq!(
            residency.outcome,
            ExecutableMemoryResidencyOutcome::Accepted
        );
        residency
    }

    fn baseline_executable_residency_with_byte_evidence(
        link_finalization: &LinkBufferFinalizationRecord,
    ) -> ExecutableMemoryResidencyRecord {
        let allocation_ledger = ExecutableAllocationRecord::from_request(
            ExecutableAllocationRequest::allocated_writable(
                link_finalization.allocation,
                link_finalization.owner,
                link_finalization.allocation_range.size_bytes,
            ),
        );
        let allocation = record_executable_memory_allocation(ExecutableMemoryAllocationRequest {
            ordinal: ExecutableMemoryOperationOrdinal(1),
            allocation: allocation_ledger,
            mapped_range: ExecutableMemoryMappedRange {
                allocation: link_finalization.allocation,
                start_offset: 0,
                byte_len: 4096,
                page_size: ExecutableMemoryPageSize(4096),
            },
        });
        assert_eq!(
            allocation.outcome,
            ExecutableMemoryResidencyOutcome::Accepted
        );

        let evidence = link_finalization
            .byte_copy_evidence
            .as_ref()
            .expect("link finalization byte evidence");
        let byte_copy = record_executable_memory_byte_copy(ExecutableMemoryByteCopyRequest {
            ordinal: ExecutableMemoryOperationOrdinal(2),
            allocation: &allocation,
            link_finalization,
            copied_range: link_finalization.allocation_range,
            copied_byte_len: evidence.output_byte_len,
            copied_digest: evidence.output_digest,
        });
        assert_eq!(
            byte_copy.outcome,
            ExecutableMemoryResidencyOutcome::Accepted
        );

        let transition = record_executable_memory_protection_transition(
            ExecutableMemoryProtectionTransitionRequest {
                ordinal: ExecutableMemoryOperationOrdinal(3),
                allocation: allocation.clone(),
                transition: JitPermissionTransition::RwToRx,
                start_protection: ExecutableMemoryProtection::Writable,
                start_lifecycle: ExecutableAllocationLifecycle::AllocatedWritable,
                end_protection: ExecutableMemoryProtection::Executable,
                end_lifecycle: ExecutableAllocationLifecycle::LinkedExecutable,
                mutation_authority: ExecutableMutationAuthority::LinkBuffer,
            },
        );
        assert_eq!(
            transition.outcome,
            ExecutableMemoryResidencyOutcome::Accepted
        );

        let cache_flush = record_instruction_cache_flush(InstructionCacheFlushRequest {
            ordinal: ExecutableMemoryOperationOrdinal(4),
            transition: transition.clone(),
            code_id: link_finalization.code_id,
            owner: link_finalization.owner,
            allocation: link_finalization.allocation,
            range: link_finalization.allocation_range,
        });
        assert_eq!(
            cache_flush.outcome,
            ExecutableMemoryResidencyOutcome::Accepted
        );

        let residency = record_executable_memory_residency_with_byte_copy(
            ExecutableMemoryByteResidencyRequest {
                ordinal: ExecutableMemoryOperationOrdinal(5),
                link_finalization,
                allocation: &allocation,
                byte_copy: &byte_copy,
                protection_transition: &transition,
                instruction_cache_flush: Some(&cache_flush),
            },
        );
        assert_eq!(
            residency.outcome,
            ExecutableMemoryResidencyOutcome::Accepted
        );
        residency
    }

    fn install_enabled_native_entry(
        vm: &mut Vm,
        owner: CodeBlockId,
        artifact_id: u64,
    ) -> BaselineNativeEntryReadinessRecord {
        let artifact = baseline_artifact(owner, artifact_id);
        let link_finalization = baseline_link_finalization_with_byte_evidence(&artifact);
        let executable_residency =
            baseline_executable_residency_with_byte_evidence(&link_finalization);
        let materialization = vm.materialize_baseline_executable_artifact(
            owner,
            &artifact,
            &link_finalization,
            &executable_residency,
        );
        assert_eq!(
            materialization.outcome,
            BaselineExecutableMaterializationOutcome::Accepted
        );
        let install_record = vm.install_baseline_artifact(
            owner,
            artifact,
            Some(&materialization),
            JitCodeSlot(artifact_id.try_into().expect("test JIT slot id")),
            BaselineInstallDependencyPolicy::Allow,
        );
        assert_eq!(
            install_record.outcome,
            BaselineInstallOutcome::InstalledButEntryDisabled
        );
        let descriptor = install_record
            .artifact
            .expect("installed native artifact")
            .validate_native_entry_descriptor()
            .expect("native entry descriptor");
        vm.tiering
            .record_baseline_native_entry_readiness(BaselineNativeEntryReadinessRequest {
                owner,
                materialization: &materialization,
                install: &install_record,
                execution_policy: BaselineNativeEntryExecutionPolicy::Enabled,
                callable: Some(
                    BaselineNativeEntryCallableAuthority::new_p6_pure_baseline_native_entry_shim(
                        descriptor,
                    ),
                ),
            })
    }

    #[cfg(unix)]
    fn install_enabled_platform_native_entry(
        vm: &mut Vm,
        owner: CodeBlockId,
        artifact_id: u64,
    ) -> BaselineNativeEntryReadinessRecord {
        let artifact = baseline_artifact(owner, artifact_id);
        let (link_finalization, linked_bytes) =
            baseline_link_finalization_with_byte_evidence_and_linked_bytes(&artifact);
        let materialization = vm
            .materialize_baseline_platform_executable_artifact(
                owner,
                &artifact,
                &link_finalization,
                &linked_bytes,
            )
            .expect("platform-backed executable materialization");
        assert_eq!(
            materialization.outcome,
            BaselineExecutableMaterializationOutcome::Accepted
        );
        let install_record = vm.install_baseline_artifact(
            owner,
            artifact,
            Some(&materialization),
            JitCodeSlot(artifact_id.try_into().expect("test JIT slot id")),
            BaselineInstallDependencyPolicy::Allow,
        );
        assert_eq!(
            install_record.outcome,
            BaselineInstallOutcome::InstalledButEntryDisabled
        );
        let descriptor = install_record
            .artifact
            .expect("installed native artifact")
            .validate_native_entry_descriptor()
            .expect("native entry descriptor");
        vm.tiering
            .record_baseline_native_entry_readiness(BaselineNativeEntryReadinessRequest {
                owner,
                materialization: &materialization,
                install: &install_record,
                execution_policy: BaselineNativeEntryExecutionPolicy::Enabled,
                callable: Some(
                    BaselineNativeEntryCallableAuthority::new_p6_pure_baseline_native_entry_shim(
                        descriptor,
                    ),
                ),
            })
    }

    fn linked_interpreter_test_code_block(lifecycle: CodeBlockLifecycleState) -> CodeBlock {
        linked_interpreter_test_code_block_with_opcodes(
            lifecycle,
            &[CoreOpcode::LoadInt32, CoreOpcode::Return],
        )
    }

    fn linked_interpreter_test_code_block_with_opcodes(
        lifecycle: CodeBlockLifecycleState,
        opcodes: &[CoreOpcode],
    ) -> CodeBlock {
        CodeBlock::from_unlinked(
            UnlinkedCodeBlock::new(
                CodeKind::Function,
                PackedInstructionStream::from_typed_placeholder(
                    opcodes
                        .iter()
                        .enumerate()
                        .map(|(offset, opcode)| typed_core_instruction(offset as u32, *opcode))
                        .collect(),
                ),
            )
            .with_frame(RegisterFrameShape {
                num_parameters_including_this: 1,
                num_vars: 1,
                num_callee_locals: 0,
                num_temporaries: 0,
                special: Default::default(),
            }),
            LinkContext::default(),
        )
        .with_entrypoints(CodeBlockEntrypoints {
            interpreter: Some(InterpreterEntrySlot(0)),
            ..CodeBlockEntrypoints::default()
        })
        .with_lifecycle(lifecycle)
    }

    fn typed_core_instruction(offset: u32, opcode: CoreOpcode) -> TypedInstruction {
        typed_core_instruction_with_operands(offset, opcode, Vec::new())
    }

    fn typed_core_instruction_with_operands(
        offset: u32,
        opcode: CoreOpcode,
        operands: Vec<Operand>,
    ) -> TypedInstruction {
        TypedInstruction {
            opcode: opcode.opcode(),
            width: OperandWidth::Narrow,
            operands,
            schema: None,
            bytecode_index: Some(BytecodeIndex::from_offset(offset)),
        }
    }

    fn typed_load_double_instruction(
        offset: u32,
        destination: VirtualRegister,
        value: f64,
    ) -> TypedInstruction {
        let bits = value.to_bits();
        typed_core_instruction_with_operands(
            offset,
            CoreOpcode::LoadDouble,
            vec![
                Operand::Register(destination),
                Operand::UnsignedImmediate((bits & u64::from(u32::MAX)) as u32),
                Operand::UnsignedImmediate((bits >> 32) as u32),
            ],
        )
    }

    fn local(index: u32) -> VirtualRegister {
        VirtualRegister::local(index)
    }

    fn argument_including_this(index: u32) -> VirtualRegister {
        VirtualRegister::argument_including_this(index, ThisArgumentOffset(5))
    }

    fn linked_p6_test_code_block(instructions: Vec<TypedInstruction>) -> CodeBlock {
        linked_p6_test_code_block_with_parameters(instructions, 1)
    }

    fn linked_p6_test_code_block_with_parameters(
        instructions: Vec<TypedInstruction>,
        num_parameters_including_this: u32,
    ) -> CodeBlock {
        linked_p6_test_code_block_with_parameters_and_string_literals(
            instructions,
            num_parameters_including_this,
            Vec::new(),
        )
    }

    fn linked_p6_test_code_block_with_parameters_and_string_literals(
        instructions: Vec<TypedInstruction>,
        num_parameters_including_this: u32,
        string_literals: Vec<(u32, String)>,
    ) -> CodeBlock {
        CodeBlock::from_unlinked(
            UnlinkedCodeBlock::new(
                CodeKind::Program,
                PackedInstructionStream::from_typed_placeholder(instructions),
            )
            .with_frame(RegisterFrameShape {
                num_parameters_including_this,
                num_vars: 8,
                num_callee_locals: 0,
                num_temporaries: 0,
                special: Default::default(),
            })
            .with_string_literals(string_literals),
            LinkContext::default(),
        )
        .with_entrypoints(CodeBlockEntrypoints {
            interpreter: Some(InterpreterEntrySlot(0)),
            ..CodeBlockEntrypoints::default()
        })
        .with_lifecycle(CodeBlockLifecycleState::LinkedInterpreter)
    }

    fn register_test_code_block(vm: &mut Vm, code_block: CodeBlock) -> CodeBlockId {
        let owner = vm.allocate_code_block_cell().unwrap();
        vm.code_blocks.register(owner, code_block);
        owner
    }

    fn register_vm_owned_function_code_block(
        vm: &mut Vm,
        code_block: CodeBlock,
    ) -> (CodeBlockId, CodeBlock) {
        let executable = vm.allocate_executable_cell().unwrap();
        let owner = vm.allocate_code_block_cell().unwrap();
        let shared_unlinked = code_block.shared_unlinked().clone();
        let function_code_block = CodeBlock::from_shared_unlinked(
            shared_unlinked.clone(),
            LinkContext {
                owner_executable: Some(executable),
                specialization: CodeSpecialization::Call,
                ..LinkContext::default()
            },
        )
        .with_entrypoints(CodeBlockEntrypoints {
            interpreter: Some(InterpreterEntrySlot(0)),
            ..CodeBlockEntrypoints::default()
        })
        .with_lifecycle(CodeBlockLifecycleState::LinkedInterpreter);
        vm.executables
            .register_function(executable, shared_unlinked)
            .expect("function executable registration");
        vm.code_blocks.register(owner, function_code_block.clone());
        let install = vm.executables.install_function_code(
            executable,
            owner,
            CodeSpecialization::Call,
            &function_code_block,
        );
        assert!(
            !matches!(install.outcome, ExecutableInstallOutcome::Rejected(_)),
            "function executable install failed: {install:?}"
        );
        let registered = vm
            .code_blocks
            .get(owner)
            .expect("registered function code block")
            .code_block()
            .clone();
        (owner, registered)
    }

    fn construct_code_block_for_executable(
        code_block: &CodeBlock,
        executable: crate::runtime::ExecutableId,
    ) -> CodeBlock {
        CodeBlock::from_shared_unlinked(
            code_block.shared_unlinked().clone(),
            LinkContext {
                owner_executable: Some(executable),
                specialization: CodeSpecialization::Construct,
                ..LinkContext::default()
            },
        )
        .with_entrypoints(CodeBlockEntrypoints {
            interpreter: Some(InterpreterEntrySlot(0)),
            ..CodeBlockEntrypoints::default()
        })
        .with_lifecycle(CodeBlockLifecycleState::LinkedInterpreter)
    }

    fn ordinary_call_to_function_index_code_block(opcode: CoreOpcode) -> CodeBlock {
        match opcode {
            CoreOpcode::Call => linked_p6_test_code_block(vec![
                typed_core_instruction_with_operands(
                    0,
                    CoreOpcode::LoadFunction,
                    vec![
                        Operand::Register(local(0)),
                        Operand::UnsignedImmediate(0),
                        Operand::UnsignedImmediate(0),
                    ],
                ),
                typed_core_instruction_with_operands(
                    1,
                    CoreOpcode::Call,
                    vec![
                        Operand::Register(local(1)),
                        Operand::Register(local(0)),
                        Operand::UnsignedImmediate(0),
                    ],
                ),
                typed_core_instruction_with_operands(
                    2,
                    CoreOpcode::Return,
                    vec![Operand::Register(local(1))],
                ),
            ]),
            CoreOpcode::CallWithThis => linked_p6_test_code_block(vec![
                typed_core_instruction_with_operands(
                    0,
                    CoreOpcode::LoadFunction,
                    vec![
                        Operand::Register(local(0)),
                        Operand::UnsignedImmediate(0),
                        Operand::UnsignedImmediate(0),
                    ],
                ),
                typed_core_instruction_with_operands(
                    1,
                    CoreOpcode::LoadInt32,
                    vec![Operand::Register(local(2)), Operand::SignedImmediate(99)],
                ),
                typed_core_instruction_with_operands(
                    2,
                    CoreOpcode::CallWithThis,
                    vec![
                        Operand::Register(local(1)),
                        Operand::Register(local(0)),
                        Operand::Register(local(2)),
                        Operand::UnsignedImmediate(0),
                    ],
                ),
                typed_core_instruction_with_operands(
                    3,
                    CoreOpcode::Return,
                    vec![Operand::Register(local(1))],
                ),
            ]),
            _ => panic!("unsupported ordinary call opcode {opcode:?}"),
        }
    }

