    const P17_SET_IDENTIFIER: u32 = 90_004;
    const P17_VALUE_IDENTIFIER: u32 = 90_010;

    fn p17_function_value_identifier_texts() -> HashMap<u32, String> {
        HashMap::from([
            (P17_CALL_IDENTIFIER, "call".to_string()),
            (P17_APPLY_IDENTIFIER, "apply".to_string()),
            (P17_GET_IDENTIFIER, "get".to_string()),
            (P17_SET_IDENTIFIER, "set".to_string()),
            (P17_VALUE_IDENTIFIER, "p".to_string()),
            (PROPERTY_HANDOFF_KEY, "p".to_string()),
        ])
    }

