    fn execute_registered_code_block_with_host<H: DispatchHost>(
        vm: &mut Vm,
        owner: CodeBlockId,
        code_block: &CodeBlock,
        host: &mut H,
    ) -> ExecutionCompletion {
        execute_registered_code_block_with_host_config(
            vm,
            owner,
            code_block,
            host,
            DispatchConfig::default(),
            Vec::new(),
        )
    }

    fn execute_registered_code_block_with_host_config<H: DispatchHost>(
        vm: &mut Vm,
        owner: CodeBlockId,
        code_block: &CodeBlock,
        host: &mut H,
        config: DispatchConfig,
        argument_values_including_this: Vec<RuntimeValue>,
    ) -> ExecutionCompletion {
        execute_registered_code_block_with_host_and_arguments_config(
            vm,
            owner,
            code_block,
            host,
            config,
            argument_values_including_this,
        )
    }

    fn execute_registered_code_block_with_host_and_arguments<H: DispatchHost>(
        vm: &mut Vm,
        owner: CodeBlockId,
        code_block: &CodeBlock,
        host: &mut H,
        argument_values_including_this: Vec<RuntimeValue>,
    ) -> ExecutionCompletion {
        execute_registered_code_block_with_host_config(
            vm,
            owner,
            code_block,
            host,
            DispatchConfig::default(),
            argument_values_including_this,
        )
    }

    fn execute_registered_code_block_with_host_and_arguments_config<H: DispatchHost>(
        vm: &mut Vm,
        owner: CodeBlockId,
        code_block: &CodeBlock,
        host: &mut H,
        config: DispatchConfig,
        argument_values_including_this: Vec<RuntimeValue>,
    ) -> ExecutionCompletion {
        let global_object = vm.allocate_global_object_cell().unwrap();
        vm.record_source_global_object(global_object).unwrap();
        let entry = vm
            .execution
            .enter(ExecutionEntryRecord::Program(ProgramExecutionEntry {
                code_block: owner,
                global_object,
                this_value: RuntimeValue::undefined(),
            }));
        let frame = vm
            .execution
            .push_frame(
                &mut vm.registers,
                FramePushRequest {
                    code_block: Some(owner),
                    callee: None,
                    callee_value: None,
                    lexical_scope: None,
                    shape: code_block.unlinked().frame(),
                    argument_count_including_this: argument_values_including_this
                        .len()
                        .max(1)
                        .try_into()
                        .unwrap_or(u32::MAX),
                    argument_values: argument_values_including_this,
                    start_bytecode_index: Some(BytecodeIndex::from_offset(0)),
                    return_bytecode_index: None,
                },
            )
            .unwrap();

        let completion = vm.execute_code_block(owner, code_block, host, config);

        if vm.execution.frame(frame).is_some() {
            vm.execution.pop_frame(&mut vm.registers, frame).unwrap();
        }
        vm.execution.leave(entry).unwrap();
        completion
    }

