    fn record_property_store_plan_for_attachment_at_bytecode_index_with_base_structure_and_value(
        vm: &mut Vm,
        owner: CodeBlockId,
        bytecode_snapshot: crate::jit::plan::BaselineBytecodeSnapshotFingerprint,
        bytecode_index: BytecodeIndex,
        slot: InlineCacheSlotId,
        base_structure: StructureId,
        stored_value: RuntimeValue,
        outcome: PropertyStoreObservationOutcome,
    ) -> VmPropertyStoreAccessCasePlanRecord {
        let descriptor = PropertyStoreObservationDescriptor {
            owner,
            frame: CallFrameId(1),
            slot,
            bytecode_index: bytecode_index.offset(),
            cache_kind: InlineCacheKind::PropertyStore,
            fallback: InlineCacheFallbackSemantics::SlowPathLookup,
            key: property_attachment_key(),
            base_object: Some(ObjectId(CellId(710))),
            base_structure_before: Some(base_structure),
            base_structure_after: Some(match outcome {
                PropertyStoreObservationOutcome::CreatedProperty => StructureId(712),
                _ => base_structure,
            }),
            offset_after: Some(PropertyOffset::new(0)),
            stored_value,
            outcome,
            may_call_js: false,
            cacheability: PropertyCacheability::Disallowed,
            can_use_put_by_id_megamorphic: true,
            write_barrier_count: 1,
            last_write_barrier: Some(crate::gc::BarrierRequirementOutcome::Required(
                crate::gc::BarrierAction::MarkingBarrier,
            )),
            cold_miss_handoff: crate::jit::InlineCacheMissHandoffDescriptor {
                owner,
                slot,
                bytecode_index: bytecode_index.offset(),
                cache_kind: InlineCacheKind::PropertyStore,
                miss_kind: InlineCacheMissKind::Cold,
                fallback: InlineCacheFallbackSemantics::SlowPathLookup,
                boundary: None,
                call_link: None,
                preserves_operand_registers: true,
            },
        };
        vm.tiering_integration_mut()
            .record_property_store_observation(VmPropertyStoreObservationRequest {
                owner,
                frame: Some(CallFrameId(1)),
                bytecode_index,
                bytecode_snapshot,
                descriptor: descriptor.clone(),
            })
            .expect("property store warmup observation for attachment");
        vm.tiering_integration_mut()
            .record_property_store_observation(VmPropertyStoreObservationRequest {
                owner,
                frame: Some(CallFrameId(1)),
                bytecode_index,
                bytecode_snapshot,
                descriptor,
            })
            .expect("property store observation for attachment");
        vm.tiering_integration()
            .property_store_access_case_plans()
            .last()
            .expect("property store plan for attachment")
            .clone()
    }

    fn load_attachment_request(
        plan: &VmPropertyLoadAccessCasePlanRecord,
    ) -> VmPropertyInlineCacheAttachmentRequest {
        VmPropertyInlineCacheAttachmentRequest {
            owner: plan.owner,
            bytecode_index: plan.bytecode_index,
            bytecode_snapshot: plan.bytecode_snapshot,
            slot: plan.plan.slot,
            kind: VmPropertyInlineCacheAttachmentKind::OwnDataLoad,
            source_plan_ordinal: plan.ordinal,
            store_install_recheck_ordinal: None,
            store_readiness_ordinal: None,
            guarded_materialization_ordinal: None,
            guarded_dependency_ordinals: Vec::new(),
            guarded_binding_set_ids: Vec::new(),
            requested_stub_mode: PropertyInlineCacheStubMode::MetadataOnly,
            key: plan.plan.key,
            base_structure: plan.plan.access_case.base_structure.unwrap(),
            holder_structure: None,
            new_structure: plan.plan.access_case.new_structure,
            offset: plan.plan.access_case.offset,
        }
    }

    fn store_attachment_request(
        plan: &VmPropertyStoreAccessCasePlanRecord,
        recheck_ordinal: u64,
        readiness_ordinal: u64,
    ) -> VmPropertyInlineCacheAttachmentRequest {
        VmPropertyInlineCacheAttachmentRequest {
            owner: plan.owner,
            bytecode_index: plan.bytecode_index,
            bytecode_snapshot: plan.bytecode_snapshot,
            slot: plan.plan.slot,
            kind: match plan.plan.plan_kind {
                PropertyStoreAccessCasePlanKind::DataOnlyReplace => {
                    VmPropertyInlineCacheAttachmentKind::StoreReplace
                }
                PropertyStoreAccessCasePlanKind::DataOnlyTransition => {
                    VmPropertyInlineCacheAttachmentKind::StoreTransition
                }
                PropertyStoreAccessCasePlanKind::DataOnlyIndexedStore => {
                    unreachable!("indexed store plan has no bytecode IC attachment kind")
                }
                PropertyStoreAccessCasePlanKind::Unsupported => unreachable!("test plan"),
            },
            source_plan_ordinal: plan.ordinal,
            store_install_recheck_ordinal: Some(recheck_ordinal),
            store_readiness_ordinal: Some(readiness_ordinal),
            guarded_materialization_ordinal: None,
            guarded_dependency_ordinals: Vec::new(),
            guarded_binding_set_ids: Vec::new(),
            requested_stub_mode: PropertyInlineCacheStubMode::MetadataOnly,
            key: plan.plan.key,
            base_structure: plan.plan.access_case.base_structure.unwrap(),
            holder_structure: None,
            new_structure: plan.plan.access_case.new_structure,
            offset: plan.plan.access_case.offset,
        }
    }

    fn production_store_attachment_for_plan(
        vm: &Vm,
        plan: &VmPropertyStoreAccessCasePlanRecord,
        expected_kind: VmPropertyInlineCacheAttachmentKind,
    ) -> VmPropertyInlineCacheAttachmentRecord {
        let recheck = vm
            .tiering_integration()
            .property_store_access_case_install_rechecks()
            .iter()
            .find(|recheck| recheck.store_plan_ordinal == plan.ordinal)
            .expect("production store install recheck");
        assert!(matches!(
            recheck.outcome,
            VmPropertyStoreAccessCaseInstallRecheckOutcome::Accepted { .. }
        ));

        let readiness = vm
            .tiering_integration()
            .generated_property_store_mutation_readiness_records()
            .iter()
            .find(|readiness| readiness.store_plan_ordinal == plan.ordinal)
            .expect("production generated store readiness");
        assert_eq!(readiness.install_recheck_ordinal, recheck.ordinal);
        assert!(matches!(
            readiness.outcome,
            VmGeneratedPropertyStoreMutationReadinessOutcome::Accepted { .. }
        ));
        let observation = vm
            .tiering_integration()
            .property_store_observations()
            .iter()
            .find(|observation| observation.ordinal == plan.observation_ordinal)
            .expect("source store observation");
        assert_eq!(
            readiness.stored_value_kind,
            observation.descriptor.stored_value.kind()
        );

        let attachment = vm
            .tiering_integration()
            .property_inline_cache_attachment_records()
            .iter()
            .find(|attachment| attachment.source_plan_ordinal == plan.ordinal)
            .expect("production store attachment");
        assert_eq!(attachment.kind, expected_kind);
        assert_eq!(
            attachment.store_install_recheck_ordinal,
            Some(recheck.ordinal)
        );
        assert_eq!(attachment.store_readiness_ordinal, Some(readiness.ordinal));
        assert!(matches!(
            attachment.outcome,
            VmPropertyInlineCacheAttachmentOutcome::Accepted { .. }
        ));
        attachment.clone()
    }

    fn guarded_attachment_request(
        vm: &Vm,
        guard_plan: &VmPropertyLoadGuardPlanRecord,
        materialization: &VmPropertyLoadGuardWatchpointMaterializationRecord,
    ) -> VmPropertyInlineCacheAttachmentRequest {
        let projection = vm
            .tiering_integration()
            .project_property_load_guarded_candidates(
                super::tiering::VmPropertyLoadGuardedCandidateProjectionRequest {
                    owner: guard_plan.owner,
                    bytecode_snapshot: guard_plan.bytecode_snapshot,
                    bytecode_index: Some(guard_plan.bytecode_index),
                },
            );
        let record = projection
            .candidates
            .iter()
            .find(|record| record.materialization_ordinal == materialization.ordinal)
            .expect("guarded candidate for materialization");
        let binding_set_ids = materialization
            .bindings
            .iter()
            .map(|binding| binding.set_id)
            .collect::<Vec<_>>();

        match &record.candidate {
            VmPropertyLoadGuardedCandidate::PrototypeData {
                key,
                base_structure,
                holder_structure,
                offset,
                ..
            } => VmPropertyInlineCacheAttachmentRequest {
                owner: guard_plan.owner,
                bytecode_index: guard_plan.bytecode_index,
                bytecode_snapshot: guard_plan.bytecode_snapshot,
                slot: guard_plan.plan.slot,
                kind: VmPropertyInlineCacheAttachmentKind::GuardedPrototypeDataLoad,
                source_plan_ordinal: guard_plan.ordinal,
                store_install_recheck_ordinal: None,
                store_readiness_ordinal: None,
                guarded_materialization_ordinal: Some(materialization.ordinal),
                guarded_dependency_ordinals: materialization.dependency_ordinals.clone(),
                guarded_binding_set_ids: binding_set_ids,
                requested_stub_mode: PropertyInlineCacheStubMode::MetadataOnly,
                key: *key,
                base_structure: *base_structure,
                holder_structure: Some(*holder_structure),
                new_structure: None,
                offset: Some(*offset),
            },
            VmPropertyLoadGuardedCandidate::NegativeLookup {
                key,
                base_structure,
                ..
            } => VmPropertyInlineCacheAttachmentRequest {
                owner: guard_plan.owner,
                bytecode_index: guard_plan.bytecode_index,
                bytecode_snapshot: guard_plan.bytecode_snapshot,
                slot: guard_plan.plan.slot,
                kind: VmPropertyInlineCacheAttachmentKind::GuardedNegativeLookup,
                source_plan_ordinal: guard_plan.ordinal,
                store_install_recheck_ordinal: None,
                store_readiness_ordinal: None,
                guarded_materialization_ordinal: Some(materialization.ordinal),
                guarded_dependency_ordinals: materialization.dependency_ordinals.clone(),
                guarded_binding_set_ids: binding_set_ids,
                requested_stub_mode: PropertyInlineCacheStubMode::MetadataOnly,
                key: *key,
                base_structure: *base_structure,
                holder_structure: None,
                new_structure: None,
                offset: None,
            },
        }
    }

