    fn assert_pending_watchpoint_dispatch_cleared_attachment(
        vm: &Vm,
        dispatch_count_before: usize,
        invalidation_count_before: usize,
        clear_count_before: usize,
        attachment_ordinal: u64,
        materialization_ordinal: u64,
    ) {
        let dispatches = vm
            .tiering_integration()
            .property_load_guard_watchpoint_event_dispatches();
        assert_eq!(dispatches.len(), dispatch_count_before + 1);
        let dispatch = dispatches.last().expect("watchpoint event dispatch");
        assert_eq!(
            dispatch.materialization_ordinals,
            vec![materialization_ordinal]
        );
        assert_eq!(
            dispatch.outcome,
            VmPropertyLoadGuardWatchpointEventDispatchOutcome::Accepted {
                invalidation_count: 1
            }
        );
        assert_eq!(dispatch.invalidation_ordinals.len(), 1);

        let invalidations = vm
            .tiering_integration()
            .property_load_guard_watchpoint_invalidations();
        assert_eq!(invalidations.len(), invalidation_count_before + 1);
        let invalidation = invalidations.last().expect("watchpoint invalidation");
        assert_eq!(invalidation.ordinal, dispatch.invalidation_ordinals[0]);
        assert_eq!(
            invalidation.materialization_ordinal,
            materialization_ordinal
        );
        assert!(matches!(
            invalidation.outcome,
            super::tiering::VmPropertyLoadGuardWatchpointInvalidationOutcome::Accepted { .. }
        ));

        let clears = vm
            .tiering_integration()
            .property_inline_cache_clear_records();
        assert_eq!(clears.len(), clear_count_before + 1);
        let clear = clears.last().expect("property inline cache clear");
        assert_eq!(clear.attachment_ordinal, attachment_ordinal);
        assert_eq!(
            clear.guarded_materialization_ordinal,
            Some(materialization_ordinal)
        );
        assert_eq!(
            clear.triggering_invalidation_ordinal,
            Some(invalidation.ordinal)
        );
        assert_eq!(
            clear.triggering_event_dispatch_ordinal,
            Some(dispatch.ordinal)
        );
        assert!(matches!(
            clear.outcome,
            VmPropertyInlineCacheClearOutcome::Accepted { .. }
        ));

        let attachment = vm
            .tiering_integration()
            .property_inline_cache_attachment_records()
            .iter()
            .find(|record| record.ordinal == attachment_ordinal)
            .expect("cleared attachment record");
        assert_eq!(
            attachment.lifecycle,
            VmPropertyInlineCacheAttachmentLifecycle::Cleared {
                clear_ordinal: clear.ordinal,
                invalidation_ordinal: Some(invalidation.ordinal),
                event_dispatch_ordinal: Some(dispatch.ordinal),
            }
        );
    }

