    fn attached_guarded_candidate_for_owner(
        vm: &Vm,
        owner: CodeBlockId,
        bytecode_snapshot: crate::jit::plan::BaselineBytecodeSnapshotFingerprint,
    ) -> crate::jit::PropertyLoadGuardedCandidate {
        let attached = vm
            .code_blocks
            .attached_property_inline_cache_candidates_for_owner(
                owner,
                bytecode_snapshot,
                vm.tiering_integration()
                    .property_inline_cache_attachment_records(),
            );
        let table = vm
            .tiering_integration()
            .property_load_guarded_candidate_table_for_owner_with_attached(
                owner,
                bytecode_snapshot,
                &attached,
            )
            .expect("attached guarded candidate table");
        assert_eq!(table.len(), 1);
        table.candidates()[0].clone()
    }

    fn assert_descriptor_only_structure_stub_repatch_transaction(
        record: &VmStructureStubRepatchTransactionRecord,
    ) {
        assert_eq!(
            record.outcome,
            VmStructureStubRepatchTransactionOutcome::Reserved
        );
        assert_eq!(
            record.lifecycle,
            VmStructureStubRepatchTransactionLifecycle::Reserved
        );

        let artifact = record.artifact.as_ref().expect("descriptor artifact");
        assert_eq!(artifact.id, record.code_id);
        assert_eq!(artifact.origin.kind, CodeOriginKind::InlineCacheStub);
        assert_eq!(artifact.origin.owner, Some(record.owner));
        assert_eq!(
            artifact.origin.bytecode_index,
            Some(record.bytecode_index.offset())
        );
        assert_eq!(artifact.liveness, CodeLiveness::Unallocated);
        assert!(artifact.native_code.is_none());
        assert!(artifact.machine_code.is_none());
        assert_eq!(artifact.entrypoint.kind, EntrypointKind::None);
        assert_eq!(artifact.entrypoint.code, None);
        assert_eq!(artifact.patchpoints.len(), 1);
        assert_eq!(
            artifact.patchpoints[0].kind,
            PatchpointKind::InlineCacheData
        );
        artifact
            .validate()
            .expect("descriptor-only structure-stub artifact validates");

        let patch_plan = record.patch_plan.as_ref().expect("reserved patch plan");
        assert_eq!(patch_plan.owner, record.owner);
        assert_eq!(
            patch_plan.required_protection,
            ExecutableMemoryProtection::Unallocated
        );
        assert_eq!(patch_plan.records.len(), 1);
        assert_eq!(patch_plan.records[0].code, record.code_id);
        assert_eq!(patch_plan.records[0].state, CodePatchState::Reserved);
        assert!(patch_plan.records[0].range.is_none());
        patch_plan
            .validate()
            .expect("descriptor-only structure-stub patch plan validates");
    }

    fn install_explicit_structure_stub_descriptor_for_generated_property_load(
        vm: &mut Vm,
        host: &mut RecordingCoreHost,
        object: RuntimeValue,
        generated_code_id: u64,
    ) -> (
        CodeBlock,
        CodeBlockId,
        BaselineGeneratedCodeArtifact,
        VmPropertyLoadAccessCasePlanRecord,
        VmPropertyInlineCacheAttachmentRecord,
        VmStructureStubRepatchTransactionRecord,
        VmStructureStubAccessCaseLinkRecord,
    ) {
        let code_block = generated_property_get_by_name_return_consumed_code_block();
        let owner = vm.allocate_code_block_cell().expect("code block cell");

        let first = execute_registered_code_block_with_host_and_arguments(
            vm,
            owner,
            &code_block,
            host,
            vec![RuntimeValue::undefined(), object],
        );
        assert_eq!(
            first,
            ExecutionCompletion::Returned(RuntimeValue::from_i32(42))
        );
        let bytecode_snapshot =
            BaselineBytecodeEligibilityProof::fingerprint_code_block_snapshot(&code_block)
                .expect("generated property-load code block snapshot");
        let observation = host
            .drain_property_load_observation(
                &mut vm.heap,
                PropertyLoadObservationDrainRequest {
                    owner,
                    frame: CallFrameId(3),
                    bytecode_index: BytecodeIndex::from_offset(1),
                    opcode: CoreOpcode::GetByName,
                    slot: InlineCacheSlotId(0),
                    cache_kind: InlineCacheKind::PropertyLoad,
                    fallback: InlineCacheFallbackSemantics::SlowPathLookup,
                    property_key: PropertyCacheKey::Key(PropertyKey::from_identifier(
                        Identifier::from_atom(AtomId::from_table_slot(PROPERTY_HANDOFF_KEY)),
                    )),
                    cold_miss_handoff: crate::jit::InlineCacheMissHandoffDescriptor {
                        owner,
                        slot: InlineCacheSlotId(0),
                        bytecode_index: 1,
                        cache_kind: InlineCacheKind::PropertyLoad,
                        miss_kind: InlineCacheMissKind::Cold,
                        fallback: InlineCacheFallbackSemantics::SlowPathLookup,
                        boundary: None,
                        call_link: None,
                        preserves_operand_registers: true,
                    },
                },
            )
            .expect("drain generated property-load observation")
            .expect("generated property-load observation");
        vm.tiering_integration_mut()
            .record_property_load_observation(VmPropertyLoadObservationRequest {
                owner,
                frame: None,
                bytecode_index: BytecodeIndex::from_offset(1),
                bytecode_snapshot,
                descriptor: observation.clone(),
            })
            .expect("record generated property-load warmup observation");
        vm.tiering_integration_mut()
            .record_property_load_observation(VmPropertyLoadObservationRequest {
                owner,
                frame: None,
                bytecode_index: BytecodeIndex::from_offset(1),
                bytecode_snapshot,
                descriptor: observation,
            })
            .expect("record generated property-load observation");
        let plan = vm
            .tiering_integration()
            .property_load_access_case_plans()
            .last()
            .expect("generated property-load plan")
            .clone();
        assert_eq!(
            plan.lifecycle,
            VmPropertyLoadAccessCasePlanLifecycle::Active
        );
        assert_eq!(plan.bytecode_index, BytecodeIndex::from_offset(1));

        vm.code_blocks.register(owner, code_block.clone());
        let artifact = install_typed_baseline_for_test(vm, owner, generated_code_id);
        assert_eq!(
            artifact.eligibility_proof.bytecode_snapshot_fingerprint(),
            bytecode_snapshot
        );

        let mut request = load_attachment_request(&plan);
        request.requested_stub_mode = PropertyInlineCacheStubMode::StructureStub;
        let attachment = vm.attach_property_inline_cache_case(request);
        assert!(matches!(
            attachment.outcome,
            VmPropertyInlineCacheAttachmentOutcome::Accepted { .. }
        ));
        assert_eq!(
            attachment.requested_stub_mode,
            PropertyInlineCacheStubMode::StructureStub
        );
        assert_eq!(
            vm.tiering_integration()
                .property_load_access_case_plans()
                .iter()
                .find(|record| record.ordinal == plan.ordinal)
                .expect("attached generated property-load plan")
                .lifecycle,
            VmPropertyLoadAccessCasePlanLifecycle::Attached {
                attachment_ordinal: attachment.ordinal,
            }
        );

        vm.reserve_descriptor_only_structure_stub_repatch_transactions_at_safepoint(
            owner,
            &code_block,
        );
        let transaction = vm
            .tiering_integration()
            .structure_stub_repatch_transactions()
            .iter()
            .find(|record| record.attachment_ordinal == attachment.ordinal)
            .expect("reserved structure-stub transaction")
            .clone();
        let link = vm
            .tiering_integration()
            .structure_stub_access_case_link_records()
            .iter()
            .find(|record| record.transaction_ordinal == transaction.ordinal)
            .expect("active structure-stub access-case link")
            .clone();
        assert_descriptor_only_structure_stub_repatch_transaction(&transaction);
        assert_eq!(
            link.lifecycle,
            VmStructureStubAccessCaseLinkLifecycle::Active
        );

        (
            code_block,
            owner,
            artifact,
            plan,
            attachment,
            transaction,
            link,
        )
    }

    #[test]
    fn vm_property_inline_cache_attachment_load_success_records_metadata_only_transaction() {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let code_block = property_ic_load_code_block();
        let bytecode_snapshot =
            BaselineBytecodeEligibilityProof::fingerprint_code_block_snapshot(&code_block)
                .expect("load code block snapshot");
        let owner = register_test_code_block(&mut vm, code_block);
        let _artifact = install_typed_baseline_for_test(&mut vm, owner, 2101);
        let generated_artifacts_before = vm
            .tiering_integration()
            .baseline_generated_code_artifacts()
            .to_vec();
        let plan = record_property_load_plan_for_attachment(&mut vm, owner, bytecode_snapshot);
        let request = load_attachment_request(&plan);

        let record = vm.attach_property_inline_cache_case(request.clone());

        let VmPropertyInlineCacheAttachmentOutcome::Accepted { outcome } = record.outcome else {
            panic!("expected accepted load attachment, got {record:?}");
        };
        assert_eq!(
            outcome.attachment_kind,
            crate::bytecode::ic::PropertyInlineCacheAttachmentKind::GetByNameOwnDataLoad
        );
        assert_eq!(outcome.dispatch, PropertyInlineCacheDispatch::Handler);
        assert_eq!(outcome.stub_mode, PropertyInlineCacheStubMode::MetadataOnly);
        assert_eq!(outcome.structure_stub_index, None);
        assert_eq!(
            record.requested_stub_mode,
            PropertyInlineCacheStubMode::MetadataOnly
        );
        assert!(record.code_block_error.is_none());
        assert_eq!(record.code_block_outcome, Some(outcome));
        assert_eq!(
            vm.tiering_integration().property_load_access_case_plans()[0].lifecycle,
            VmPropertyLoadAccessCasePlanLifecycle::Attached {
                attachment_ordinal: record.ordinal,
            }
        );
        let registered = vm.code_blocks.get(owner).expect("registered code block");
        // Clone the cache element so no `Ref` borrow of `vm`'s registry is held across
        // the later `&mut vm` mutation (the table now lives behind a `RefCell`).
        let cache = registered
            .code_block()
            .side_tables()
            .inline_caches()
            .property_accesses[0]
            .clone();
        assert_eq!(cache.dispatch, PropertyInlineCacheDispatch::Handler);
        assert_eq!(
            cache
                .get_by_id
                .as_ref()
                .and_then(|metadata| metadata.structure),
            Some(plan.plan.access_case.base_structure.unwrap())
        );
        assert_eq!(
            cache
                .get_by_id
                .as_ref()
                .and_then(|metadata| metadata.cached_offset),
            plan.plan
                .access_case
                .offset
                .map(|offset| crate::bytecode::ic::PropertyOffset(offset.raw()))
        );
        assert_eq!(
            vm.tiering_integration().baseline_generated_code_artifacts(),
            generated_artifacts_before.as_slice()
        );
        assert!(vm
            .tiering_integration()
            .baseline_generated_code_invalidations()
            .is_empty());
        assert!(vm
            .tiering_integration()
            .structure_stub_repatch_transactions()
            .is_empty());

        let duplicate = vm.attach_property_inline_cache_case(request);
        assert!(matches!(
            duplicate.outcome,
            VmPropertyInlineCacheAttachmentOutcome::Rejected {
                reason: VmPropertyInlineCacheAttachmentRejectionReason::LoadPlanNotActive { .. }
            }
        ));
        assert_eq!(duplicate.code_block_outcome, None);
        assert_eq!(
            vm.tiering_integration()
                .property_inline_cache_attachment_records()
                .len(),
            2
        );
    }

    #[test]
    fn vm_property_inline_cache_attachment_load_success_records_structure_stub_request() {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let code_block = property_ic_load_code_block();
        let bytecode_snapshot =
            BaselineBytecodeEligibilityProof::fingerprint_code_block_snapshot(&code_block)
                .expect("load code block snapshot");
        let owner = register_test_code_block(&mut vm, code_block);
        let _artifact = install_typed_baseline_for_test(&mut vm, owner, 2102);
        let generated_artifacts_before = vm
            .tiering_integration()
            .baseline_generated_code_artifacts()
            .to_vec();
        let plan = record_property_load_plan_for_attachment(&mut vm, owner, bytecode_snapshot);
        let mut request = load_attachment_request(&plan);
        request.requested_stub_mode = PropertyInlineCacheStubMode::StructureStub;

        let record = vm.attach_property_inline_cache_case(request);

        let VmPropertyInlineCacheAttachmentOutcome::Accepted { outcome } = record.outcome else {
            panic!("expected accepted structure-stub load attachment, got {record:?}");
        };
        assert_eq!(
            record.requested_stub_mode,
            PropertyInlineCacheStubMode::StructureStub
        );
        assert_eq!(
            outcome.stub_mode,
            PropertyInlineCacheStubMode::StructureStub
        );
        assert_eq!(outcome.structure_stub_index, Some(0));
        assert_eq!(record.code_block_outcome, Some(outcome));

        let registered = vm.code_blocks.get(owner).expect("registered code block");
        let side_tables = registered
            .code_block()
            .side_tables()
            .inline_caches()
            .clone();
        assert_eq!(side_tables.structure_stubs.len(), 1);
        let stub = &side_tables.structure_stubs[0];
        assert_eq!(stub.bytecode_index, plan.bytecode_index);
        assert_eq!(stub.inline_cache_slot, plan.plan.slot.0 as usize);
        assert_eq!(
            stub.attachment_kind,
            crate::bytecode::ic::PropertyInlineCacheAttachmentKind::GetByNameOwnDataLoad
        );
        assert_eq!(
            vm.tiering_integration().property_load_access_case_plans()[0].lifecycle,
            VmPropertyLoadAccessCasePlanLifecycle::Attached {
                attachment_ordinal: record.ordinal,
            }
        );
        assert_eq!(
            vm.tiering_integration().baseline_generated_code_artifacts(),
            generated_artifacts_before.as_slice()
        );
        assert!(vm
            .tiering_integration()
            .baseline_generated_code_invalidations()
            .is_empty());
        assert!(vm
            .tiering_integration()
            .structure_stub_repatch_transactions()
            .is_empty());
    }

    #[test]
    fn vm_structure_stub_safepoint_reserves_descriptor_only_repatch_transaction_for_explicit_own_data_load(
    ) {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let code_block = property_ic_load_code_block();
        let bytecode_snapshot =
            BaselineBytecodeEligibilityProof::fingerprint_code_block_snapshot(&code_block)
                .expect("load code block snapshot");
        let owner = register_test_code_block(&mut vm, code_block.clone());
        let artifact = install_typed_baseline_for_test(&mut vm, owner, 2103);
        let generated_artifacts_before = vm
            .tiering_integration()
            .baseline_generated_code_artifacts()
            .to_vec();
        let plan = record_property_load_plan_for_attachment(&mut vm, owner, bytecode_snapshot);
        let mut request = load_attachment_request(&plan);
        request.requested_stub_mode = PropertyInlineCacheStubMode::StructureStub;
        let attachment = vm.attach_property_inline_cache_case(request);
        assert!(matches!(
            attachment.outcome,
            VmPropertyInlineCacheAttachmentOutcome::Accepted { .. }
        ));

        vm.reserve_descriptor_only_structure_stub_repatch_transactions_at_safepoint(
            owner,
            &code_block,
        );

        let transactions = vm
            .tiering_integration()
            .structure_stub_repatch_transactions();
        assert_eq!(transactions.len(), 1);
        let transaction = &transactions[0];
        assert_eq!(transaction.owner, owner);
        assert_eq!(transaction.bytecode_snapshot, bytecode_snapshot);
        assert_eq!(transaction.slot, plan.plan.slot);
        assert_eq!(transaction.attachment_ordinal, attachment.ordinal);
        assert_eq!(transaction.source_plan_ordinal, plan.ordinal);
        assert_eq!(transaction.structure_stub_index, 0);
        assert_eq!(transaction.key, plan.plan.key);
        assert_eq!(
            transaction.base_structure,
            plan.plan.access_case.base_structure.unwrap()
        );
        assert_eq!(transaction.holder_structure, None);
        assert_eq!(transaction.new_structure, None);
        assert_eq!(transaction.offset, plan.plan.access_case.offset);
        assert_ne!(transaction.code_id, artifact.id);
        assert_descriptor_only_structure_stub_repatch_transaction(transaction);
        let expected_access_case_ref =
            reserved_structure_stub_access_case_ref(transaction).expect("reserved stub ref");
        let link_records = vm
            .tiering_integration()
            .structure_stub_access_case_link_records();
        assert_eq!(link_records.len(), 1);
        let link = &link_records[0];
        assert_eq!(link.owner, owner);
        assert_eq!(link.bytecode_snapshot, bytecode_snapshot);
        assert_eq!(link.bytecode_index, transaction.bytecode_index);
        assert_eq!(link.slot, transaction.slot);
        assert_eq!(link.attachment_ordinal, attachment.ordinal);
        assert_eq!(link.source_plan_ordinal, plan.ordinal);
        assert_eq!(link.structure_stub_index, 0);
        assert_eq!(link.transaction_ordinal, transaction.ordinal);
        assert_eq!(link.access_case_ref, expected_access_case_ref);
        assert_eq!(link.key, transaction.key);
        assert_eq!(link.base_structure, transaction.base_structure);
        assert_eq!(link.holder_structure, None);
        assert_eq!(link.new_structure, None);
        assert_eq!(link.offset, transaction.offset);
        assert_eq!(
            link.lifecycle,
            VmStructureStubAccessCaseLinkLifecycle::Active
        );
        let VmStructureStubAccessCaseLinkOutcome::Accepted { outcome } = &link.outcome else {
            panic!("expected accepted structure-stub access-case link, got {link:?}");
        };
        assert!(outcome.inserted);
        assert_eq!(outcome.access_case_ref, expected_access_case_ref);
        assert_eq!(outcome.access_case_count, 1);
        let registered = vm.code_blocks.get(owner).expect("registered code block");
        assert_eq!(
            registered
                .code_block()
                .side_tables()
                .inline_caches()
                .structure_stubs[0]
                .access_cases,
            vec![expected_access_case_ref]
        );
        assert_eq!(
            vm.tiering_integration().baseline_generated_code_artifacts(),
            generated_artifacts_before.as_slice()
        );
    }

