    #[test]
    fn vm_structure_stub_access_case_link_rejection_does_not_mutate_code_block_access_cases() {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let code_block = property_ic_load_code_block();
        let bytecode_snapshot =
            BaselineBytecodeEligibilityProof::fingerprint_code_block_snapshot(&code_block)
                .expect("load code block snapshot");
        let owner = register_test_code_block(&mut vm, code_block);
        install_typed_baseline_for_test(&mut vm, owner, 2105);
        let plan = record_property_load_plan_for_attachment(&mut vm, owner, bytecode_snapshot);
        let mut request = load_attachment_request(&plan);
        request.requested_stub_mode = PropertyInlineCacheStubMode::StructureStub;
        let attachment = vm.attach_property_inline_cache_case(request);
        assert!(matches!(
            attachment.outcome,
            VmPropertyInlineCacheAttachmentOutcome::Accepted { .. }
        ));

        let candidate = vm
            .code_blocks
            .structure_stub_property_inline_cache_candidates_for_owner(
                owner,
                bytecode_snapshot,
                vm.tiering_integration()
                    .property_inline_cache_attachment_records(),
            )
            .pop()
            .expect("structure-stub candidate");
        let code_id = vm.tiering.allocate_structure_stub_repatch_code_id();
        let transaction = vm.tiering.record_structure_stub_repatch_transaction(
            VmStructureStubRepatchTransactionRequest {
                candidate: candidate.clone(),
                code_id,
            },
        );
        assert_eq!(
            transaction.outcome,
            VmStructureStubRepatchTransactionOutcome::Reserved
        );
        let access_case_ref =
            reserved_structure_stub_access_case_ref(&transaction).expect("reserved stub ref");

        let registered = vm
            .code_blocks
            .code_block_mut_for_test(owner)
            .expect("registered code block");
        let side_tables = registered.side_tables().clone();
        side_tables.inline_caches_mut().structure_stubs[0].offset =
            Some(crate::bytecode::ic::PropertyOffset(99));
        *registered = registered.clone().with_side_tables(side_tables);

        let link = vm
            .link_reserved_structure_stub_access_case_for_candidate(candidate.clone(), &transaction)
            .expect("rejected access-case link record");

        assert_eq!(link.access_case_ref, access_case_ref);
        assert_eq!(
            link.outcome,
            VmStructureStubAccessCaseLinkOutcome::Rejected {
                reason: VmStructureStubAccessCaseLinkRejectionReason::CodeBlockLinkError {
                    error: StructureStubAccessCaseLinkError::StructureStubMetadataMismatch {
                        index: 0,
                        field: StructureStubMetadataMismatchField::Offset,
                    },
                },
            }
        );
        assert_eq!(
            link.lifecycle,
            VmStructureStubAccessCaseLinkLifecycle::Rejected
        );
        assert!(vm
            .code_blocks
            .get(owner)
            .expect("registered code block")
            .code_block()
            .side_tables()
            .inline_caches()
            .structure_stubs[0]
            .access_cases
            .is_empty());
        assert!(vm
            .link_reserved_structure_stub_access_case_for_candidate(candidate, &transaction)
            .is_none());
        assert_eq!(
            vm.tiering_integration()
                .structure_stub_access_case_link_records(),
            std::slice::from_ref(&link)
        );
    }

    #[test]
    fn vm_property_inline_cache_clear_retires_structure_stub_transaction_and_link() {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let code_block = property_ic_load_code_block();
        let bytecode_snapshot =
            BaselineBytecodeEligibilityProof::fingerprint_code_block_snapshot(&code_block)
                .expect("load code block snapshot");
        let owner = register_test_code_block(&mut vm, code_block.clone());
        install_typed_baseline_for_test(&mut vm, owner, 2106);
        let plan = record_property_load_plan_for_attachment(&mut vm, owner, bytecode_snapshot);
        let mut request = load_attachment_request(&plan);
        request.requested_stub_mode = PropertyInlineCacheStubMode::StructureStub;
        let attachment = vm.attach_property_inline_cache_case(request);
        assert!(matches!(
            attachment.outcome,
            VmPropertyInlineCacheAttachmentOutcome::Accepted { .. }
        ));

        vm.reserve_descriptor_only_structure_stub_repatch_transactions_at_safepoint(
            owner,
            &code_block,
        );
        let transaction_before = vm
            .tiering_integration()
            .structure_stub_repatch_transactions()[0]
            .clone();
        let link_before = vm
            .tiering_integration()
            .structure_stub_access_case_link_records()[0]
            .clone();
        assert_eq!(
            transaction_before.lifecycle,
            VmStructureStubRepatchTransactionLifecycle::Reserved
        );
        assert_eq!(
            link_before.lifecycle,
            VmStructureStubAccessCaseLinkLifecycle::Active
        );
        assert_eq!(
            vm.tiering_integration().property_load_access_case_plans()[0].lifecycle,
            VmPropertyLoadAccessCasePlanLifecycle::Attached {
                attachment_ordinal: attachment.ordinal,
            }
        );
        assert_eq!(
            vm.code_blocks
                .get(owner)
                .expect("registered code block")
                .code_block()
                .side_tables()
                .inline_caches()
                .structure_stubs[0]
                .access_cases,
            vec![link_before.access_case_ref]
        );

        let mut stale = unguarded_clear_request(&attachment);
        stale.bytecode_snapshot =
            BaselineBytecodeEligibilityProof::fingerprint_code_block_snapshot(
                &property_ic_store_code_block(),
            )
            .expect("stale snapshot source");
        let rejected = vm.clear_property_inline_cache_case(stale);
        assert_eq!(
            rejected.outcome,
            VmPropertyInlineCacheClearOutcome::Rejected {
                reason: VmPropertyInlineCacheClearRejectionReason::AttachmentProvenanceMismatch {
                    field: VmPropertyInlineCacheClearProvenanceMismatchField::BytecodeSnapshot,
                },
            }
        );
        assert_eq!(
            vm.tiering_integration()
                .structure_stub_repatch_transactions()[0]
                .lifecycle,
            VmStructureStubRepatchTransactionLifecycle::Reserved
        );
        assert_eq!(
            vm.tiering_integration()
                .structure_stub_access_case_link_records()[0]
                .lifecycle,
            VmStructureStubAccessCaseLinkLifecycle::Active
        );
        assert_eq!(
            vm.tiering_integration().property_load_access_case_plans()[0].lifecycle,
            VmPropertyLoadAccessCasePlanLifecycle::Attached {
                attachment_ordinal: attachment.ordinal,
            }
        );

        let clear_request = unguarded_clear_request(&attachment);
        let accepted = vm.clear_property_inline_cache_case(clear_request.clone());
        assert!(matches!(
            accepted.outcome,
            VmPropertyInlineCacheClearOutcome::Accepted { .. }
        ));
        assert_eq!(
            vm.tiering_integration()
                .property_inline_cache_attachment_records()
                .iter()
                .find(|record| record.ordinal == attachment.ordinal)
                .expect("cleared attachment")
                .lifecycle,
            VmPropertyInlineCacheAttachmentLifecycle::Cleared {
                clear_ordinal: accepted.ordinal,
                invalidation_ordinal: None,
                event_dispatch_ordinal: None,
            }
        );
        assert_eq!(
            vm.tiering_integration()
                .structure_stub_repatch_transactions()[0]
                .lifecycle,
            VmStructureStubRepatchTransactionLifecycle::Retired {
                clear_ordinal: accepted.ordinal,
            }
        );
        assert_eq!(
            vm.tiering_integration()
                .structure_stub_access_case_link_records()[0]
                .lifecycle,
            VmStructureStubAccessCaseLinkLifecycle::Retired {
                clear_ordinal: accepted.ordinal,
            }
        );
        assert_eq!(
            vm.tiering_integration().property_load_access_case_plans()[0].lifecycle,
            VmPropertyLoadAccessCasePlanLifecycle::RetiredByStructureStubClear {
                clear_ordinal: accepted.ordinal,
                attachment_ordinal: attachment.ordinal,
            }
        );
        let cache = vm
            .code_blocks
            .get(owner)
            .expect("registered code block")
            .code_block()
            .side_tables()
            .inline_caches()
            .clone();
        assert_eq!(
            cache.property_accesses[0].state,
            crate::bytecode::ic::InlineCacheState::Unset
        );
        assert_eq!(
            cache.property_accesses[0].dispatch,
            PropertyInlineCacheDispatch::Unlinked
        );
        assert_eq!(
            cache.structure_stubs[0].cache_state,
            crate::bytecode::ic::InlineCacheState::Unset
        );
        assert!(cache.structure_stubs[0].access_cases.is_empty());

        let retired_transaction = vm
            .tiering_integration()
            .structure_stub_repatch_transactions()[0]
            .clone();
        let retired_link = vm
            .tiering_integration()
            .structure_stub_access_case_link_records()[0]
            .clone();
        let repeated = vm.clear_property_inline_cache_case(clear_request);
        assert!(matches!(
            repeated.outcome,
            VmPropertyInlineCacheClearOutcome::Rejected {
                reason: VmPropertyInlineCacheClearRejectionReason::AttachmentNotActive {
                    lifecycle: VmPropertyInlineCacheAttachmentLifecycle::Cleared { .. },
                },
            }
        ));
        assert_eq!(
            vm.tiering_integration()
                .structure_stub_repatch_transactions(),
            std::slice::from_ref(&retired_transaction)
        );
        assert_eq!(
            vm.tiering_integration()
                .structure_stub_access_case_link_records(),
            std::slice::from_ref(&retired_link)
        );
        assert_eq!(
            vm.tiering_integration().property_load_access_case_plans()[0].lifecycle,
            VmPropertyLoadAccessCasePlanLifecycle::RetiredByStructureStubClear {
                clear_ordinal: accepted.ordinal,
                attachment_ordinal: attachment.ordinal,
            }
        );
    }

