    #[test]
    fn vm_property_inline_cache_attachment_guarded_prototype_data_success_after_live_watchpoint_materialization(
    ) {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let mut host = RecordingCoreHost::with_function_blocks(Vec::new());
        let (object, _) = create_prototype_data_property_object_for_test(&mut vm, &mut host);
        host.clear_observations();

        let code_block = generated_property_get_by_name_return_consumed_code_block();
        let owner = register_test_code_block(&mut vm, code_block.clone());
        let artifact = install_typed_baseline_for_test(&mut vm, owner, 2140);
        let bytecode_snapshot = artifact.eligibility_proof.bytecode_snapshot_fingerprint();

        let first = execute_registered_code_block_with_host_and_arguments(
            &mut vm,
            owner,
            &code_block,
            &mut host,
            vec![RuntimeValue::undefined(), object],
        );
        assert_eq!(
            first,
            ExecutionCompletion::Returned(RuntimeValue::from_i32(42))
        );
        let guard_plan = vm.tiering_integration().property_load_guard_plans()[0].clone();
        let materialization = accepted_guarded_materialization_for_plan(&vm, &guard_plan);
        let record = accepted_guarded_attachment_for_plan(&vm, &guard_plan);

        let VmPropertyInlineCacheAttachmentOutcome::Accepted { outcome } = record.outcome else {
            panic!("expected accepted guarded prototype attachment, got {record:?}");
        };
        assert_eq!(
            outcome.attachment_kind,
            crate::bytecode::ic::PropertyInlineCacheAttachmentKind::GetByNamePrototypeDataLoad
        );
        assert_eq!(
            outcome.stub_mode,
            crate::bytecode::ic::PropertyInlineCacheStubMode::MetadataOnly
        );
        assert_eq!(outcome.structure_stub_index, None);
        assert_eq!(record.code_block_outcome, Some(outcome));
        assert_eq!(
            vm.tiering_integration().property_load_guard_plans()[0].lifecycle,
            VmPropertyLoadGuardPlanLifecycle::Attached {
                attachment_ordinal: record.ordinal,
            }
        );
        let cache = vm
            .code_blocks
            .get(owner)
            .expect("registered code block")
            .code_block()
            .side_tables()
            .inline_caches()
            .property_accesses[0]
            .clone();
        let get_by_id = cache.get_by_id.expect("get metadata");
        assert_eq!(get_by_id.mode, GetByIdMode::ProtoLoad);
        assert_eq!(
            get_by_id.structure,
            Some(guard_plan.plan.descriptor.base_structure)
        );
        assert_eq!(get_by_id.holder_structure, record.holder_structure);
        assert_eq!(
            get_by_id.cached_offset,
            record
                .offset
                .map(|offset| crate::bytecode::ic::PropertyOffset(offset.raw()))
        );

        let binding = materialization.bindings[0].clone();
        host.set_identifier_data_property_for_test(object, 777, RuntimeValue::from_i32(1))
            .expect("shape transition");
        let dispatches = vm.drain_property_load_guard_watchpoint_events_for_test(&mut host);
        assert_eq!(dispatches.len(), 1);
        assert_eq!(
            dispatches[0].outcome,
            VmPropertyLoadGuardWatchpointEventDispatchOutcome::Accepted {
                invalidation_count: 1
            }
        );
        let clear_record = vm
            .tiering_integration()
            .property_inline_cache_clear_records()
            .last()
            .expect("guarded IC clear record");
        assert_eq!(clear_record.attachment_ordinal, record.ordinal);
        assert_eq!(
            clear_record.triggering_event_dispatch_ordinal,
            Some(dispatches[0].ordinal)
        );
        assert!(matches!(
            clear_record.outcome,
            VmPropertyInlineCacheClearOutcome::Accepted { .. }
        ));
        let invalidation = vm
            .tiering_integration()
            .property_load_guard_watchpoint_invalidations()
            .last()
            .expect("watchpoint invalidation");
        assert_eq!(
            clear_record.triggering_invalidation_ordinal,
            Some(invalidation.ordinal)
        );
        let fired_generation = match &invalidation.outcome {
            super::tiering::VmPropertyLoadGuardWatchpointInvalidationOutcome::Accepted {
                fired_generation,
                ..
            } => *fired_generation,
            _ => panic!("expected accepted invalidation, got {invalidation:?}"),
        };
        assert_eq!(
            vm.tiering_integration()
                .property_load_guard_watchpoint_materializations()[0]
                .lifecycle,
            VmPropertyLoadGuardWatchpointMaterializationLifecycle::Invalidated {
                invalidation_ordinal: invalidation.ordinal,
                dependency_ordinal: binding.dependency_ordinal,
                set_id: binding.set_id,
                generation: fired_generation,
            }
        );
        assert_eq!(
            vm.tiering_integration().property_load_guard_plans()[0].lifecycle,
            VmPropertyLoadGuardPlanLifecycle::Retired {
                invalidation_ordinal: invalidation.ordinal,
                dependency_ordinal: binding.dependency_ordinal,
                set_id: binding.set_id,
                generation: fired_generation,
            }
        );
        assert_eq!(
            vm.tiering_integration()
                .property_inline_cache_attachment_records()[0]
                .lifecycle,
            VmPropertyInlineCacheAttachmentLifecycle::Cleared {
                clear_ordinal: clear_record.ordinal,
                invalidation_ordinal: Some(invalidation.ordinal),
                event_dispatch_ordinal: Some(dispatches[0].ordinal),
            }
        );
        let cache = &vm
            .code_blocks
            .get(owner)
            .expect("registered code block")
            .code_block()
            .side_tables()
            .inline_caches()
            .property_accesses[0];
        assert_eq!(cache.state, crate::bytecode::ic::InlineCacheState::Unset);
        assert_eq!(cache.dispatch, PropertyInlineCacheDispatch::Unlinked);
        assert_eq!(
            cache.get_by_id.expect("cleared get metadata").mode,
            GetByIdMode::Unset
        );
        assert!(vm
            .tiering_integration()
            .property_load_guarded_candidate_table_for_owner(owner, bytecode_snapshot)
            .expect("invalidated guarded candidate table")
            .is_empty());
    }

