    #[test]
    fn vm_property_inline_cache_watchpoint_dispatch_clears_only_matching_guarded_attachment() {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let mut host = RecordingCoreHost::with_function_blocks(Vec::new());
        let (object, _) = create_prototype_data_property_object_for_test(&mut vm, &mut host);
        host.clear_observations();

        let code_block = generated_property_get_by_name_return_consumed_code_block();
        let owner = register_test_code_block(&mut vm, code_block.clone());
        install_typed_baseline_for_test(&mut vm, owner, 2143);
        let first = execute_registered_code_block_with_host_and_arguments(
            &mut vm,
            owner,
            &code_block,
            &mut host,
            vec![RuntimeValue::undefined(), object],
        );
        assert_eq!(
            first,
            ExecutionCompletion::Returned(RuntimeValue::from_i32(42))
        );
        let guard_plan = vm.tiering_integration().property_load_guard_plans()[0].clone();
        let _materialization = accepted_guarded_materialization_for_plan(&vm, &guard_plan);
        let matching_attachment = accepted_guarded_attachment_for_plan(&vm, &guard_plan);

        let unrelated_object = host.create_null_prototype_object_for_test();
        host.clear_observations();
        let unrelated_code_block = generated_property_get_by_name_throwing_code_block();
        let unrelated_owner = register_test_code_block(&mut vm, unrelated_code_block.clone());
        install_typed_baseline_for_test(&mut vm, unrelated_owner, 2144);
        let unrelated_first = execute_registered_code_block_with_host_and_arguments(
            &mut vm,
            unrelated_owner,
            &unrelated_code_block,
            &mut host,
            vec![RuntimeValue::undefined(), unrelated_object],
        );
        assert_eq!(
            unrelated_first,
            ExecutionCompletion::Returned(RuntimeValue::undefined())
        );
        let unrelated_guard_plan = vm
            .tiering_integration()
            .property_load_guard_plans()
            .last()
            .expect("unrelated guard plan")
            .clone();
        let _unrelated_materialization =
            accepted_guarded_materialization_for_plan(&vm, &unrelated_guard_plan);
        let unrelated_attachment = accepted_guarded_attachment_for_plan(&vm, &unrelated_guard_plan);

        let load_code_block = property_ic_load_code_block();
        let load_snapshot =
            BaselineBytecodeEligibilityProof::fingerprint_code_block_snapshot(&load_code_block)
                .expect("load code block snapshot");
        let load_owner = register_test_code_block(&mut vm, load_code_block);
        let load_plan =
            record_property_load_plan_for_attachment(&mut vm, load_owner, load_snapshot);
        let load_attachment =
            vm.attach_property_inline_cache_case(load_attachment_request(&load_plan));
        assert!(matches!(
            load_attachment.outcome,
            VmPropertyInlineCacheAttachmentOutcome::Accepted { .. }
        ));

        let store_code_block = property_ic_store_code_block();
        let store_snapshot =
            BaselineBytecodeEligibilityProof::fingerprint_code_block_snapshot(&store_code_block)
                .expect("store code block snapshot");
        let store_owner = register_test_code_block(&mut vm, store_code_block);
        let store_plan = record_property_store_plan_for_attachment(
            &mut vm,
            store_owner,
            store_snapshot,
            PropertyStoreObservationOutcome::OwnDataStore,
        );
        let (recheck_ordinal, readiness_ordinal) =
            record_store_recheck_and_readiness_for_test(&mut vm, &store_plan, ValueKind::Int32);
        let store_attachment = vm.attach_property_inline_cache_case(store_attachment_request(
            &store_plan,
            recheck_ordinal,
            readiness_ordinal,
        ));
        assert!(matches!(
            store_attachment.outcome,
            VmPropertyInlineCacheAttachmentOutcome::Accepted { .. }
        ));

        host.set_identifier_data_property_for_test(object, 777, RuntimeValue::from_i32(1))
            .expect("matching shape transition");
        let dispatches = vm.drain_property_load_guard_watchpoint_events_for_test(&mut host);

        assert_eq!(dispatches.len(), 1);
        assert_eq!(
            dispatches[0].outcome,
            VmPropertyLoadGuardWatchpointEventDispatchOutcome::Accepted {
                invalidation_count: 1,
            }
        );
        assert_eq!(
            vm.tiering_integration()
                .property_inline_cache_clear_records()
                .len(),
            1
        );
        assert_eq!(
            vm.tiering_integration()
                .property_inline_cache_clear_records()[0]
                .attachment_ordinal,
            matching_attachment.ordinal
        );

        let attachment_lifecycle = |vm: &Vm, ordinal| {
            vm.tiering_integration()
                .property_inline_cache_attachment_records()
                .iter()
                .find(|record| record.ordinal == ordinal)
                .expect("attachment record")
                .lifecycle
        };
        assert!(matches!(
            attachment_lifecycle(&vm, matching_attachment.ordinal),
            VmPropertyInlineCacheAttachmentLifecycle::Cleared { .. }
        ));
        assert_eq!(
            attachment_lifecycle(&vm, unrelated_attachment.ordinal),
            VmPropertyInlineCacheAttachmentLifecycle::Active
        );
        assert_eq!(
            attachment_lifecycle(&vm, load_attachment.ordinal),
            VmPropertyInlineCacheAttachmentLifecycle::Active
        );
        assert_eq!(
            attachment_lifecycle(&vm, store_attachment.ordinal),
            VmPropertyInlineCacheAttachmentLifecycle::Active
        );

        let cache_state = |vm: &Vm, owner| {
            let cache = &vm
                .code_blocks
                .get(owner)
                .expect("registered code block")
                .code_block()
                .side_tables()
                .inline_caches()
                .property_accesses[0];
            (cache.state, cache.dispatch)
        };
        assert_eq!(
            cache_state(&vm, owner),
            (
                crate::bytecode::ic::InlineCacheState::Unset,
                PropertyInlineCacheDispatch::Unlinked,
            )
        );
        assert_eq!(
            cache_state(&vm, unrelated_owner),
            (
                crate::bytecode::ic::InlineCacheState::Monomorphic,
                PropertyInlineCacheDispatch::Handler,
            )
        );
        assert_eq!(
            cache_state(&vm, load_owner),
            (
                crate::bytecode::ic::InlineCacheState::Monomorphic,
                PropertyInlineCacheDispatch::Handler,
            )
        );
        assert_eq!(
            cache_state(&vm, store_owner),
            (
                crate::bytecode::ic::InlineCacheState::Monomorphic,
                PropertyInlineCacheDispatch::Handler,
            )
        );
    }

    #[test]
    fn vm_property_inline_cache_clear_records_rejected_stale_already_cleared_and_mismatched_provenance(
    ) {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let mut host = RecordingCoreHost::with_function_blocks(Vec::new());
        let (object, _) = create_prototype_data_property_object_for_test(&mut vm, &mut host);
        host.clear_observations();
        host.suppress_structure_transition_watchpoint_materialization();

        let code_block = generated_property_get_by_name_return_consumed_code_block();
        let owner = register_test_code_block(&mut vm, code_block.clone());
        install_typed_baseline_for_test(&mut vm, owner, 2145);
        let first = execute_registered_code_block_with_host_and_arguments(
            &mut vm,
            owner,
            &code_block,
            &mut host,
            vec![RuntimeValue::undefined(), object],
        );
        assert_eq!(
            first,
            ExecutionCompletion::Returned(RuntimeValue::from_i32(42))
        );
        host.allow_structure_transition_watchpoint_materialization();
        let guard_plan = vm.tiering_integration().property_load_guard_plans()[0].clone();
        let materialization = vm
            .materialize_property_load_guard_watchpoints_from_host_for_test(&mut host, &guard_plan)
            .expect("live watchpoint materialization")
            .expect("accepted live watchpoint recheck");
        let attachment = vm.attach_property_inline_cache_case(guarded_attachment_request(
            &vm,
            &guard_plan,
            &materialization,
        ));
        assert!(matches!(
            &attachment.outcome,
            VmPropertyInlineCacheAttachmentOutcome::Accepted { .. }
        ));
        let attachment_record = vm
            .tiering_integration()
            .property_inline_cache_attachment_records()[0]
            .clone();

        let binding = materialization.bindings[0].clone();
        let dispatch = vm
            .tiering_integration_mut()
            .record_property_load_guard_watchpoint_event_dispatch(watchpoint_fire_event_for_test(
                &binding,
            ));
        assert!(matches!(
            dispatch.outcome,
            VmPropertyLoadGuardWatchpointEventDispatchOutcome::Accepted { .. }
        ));
        let invalidation = vm
            .tiering_integration()
            .property_load_guard_watchpoint_invalidations()
            .last()
            .expect("accepted invalidation")
            .clone();
        let before = vm
            .code_blocks
            .get(owner)
            .expect("registered code block")
            .code_block()
            .side_tables()
            .inline_caches()
            .clone();

        let base_request = guarded_clear_request(
            &attachment_record,
            invalidation.ordinal,
            Some(dispatch.ordinal),
        );

        let mut stale_snapshot = base_request.clone();
        stale_snapshot.bytecode_snapshot =
            BaselineBytecodeEligibilityProof::fingerprint_code_block_snapshot(
                &property_ic_store_code_block(),
            )
            .expect("stale snapshot source");
        let stale = vm.clear_property_inline_cache_case(stale_snapshot);
        assert_eq!(
            stale.outcome,
            VmPropertyInlineCacheClearOutcome::Rejected {
                reason: VmPropertyInlineCacheClearRejectionReason::AttachmentProvenanceMismatch {
                    field: VmPropertyInlineCacheClearProvenanceMismatchField::BytecodeSnapshot,
                },
            }
        );
        assert_eq!(
            &*vm.code_blocks
                .get(owner)
                .expect("registered code block")
                .code_block()
                .side_tables()
                .inline_caches(),
            &before
        );

        let mut mismatched_materialization = base_request.clone();
        mismatched_materialization.guarded_materialization_ordinal = Some(u64::MAX);
        let mismatched = vm.clear_property_inline_cache_case(mismatched_materialization);
        assert_eq!(
            mismatched.outcome,
            VmPropertyInlineCacheClearOutcome::Rejected {
                reason:
                    VmPropertyInlineCacheClearRejectionReason::AttachmentProvenanceMismatch {
                        field:
                            VmPropertyInlineCacheClearProvenanceMismatchField::GuardedMaterializationOrdinal,
                    },
            }
        );
        assert_eq!(
            &*vm.code_blocks
                .get(owner)
                .expect("registered code block")
                .code_block()
                .side_tables()
                .inline_caches(),
            &before
        );

        let accepted = vm.clear_property_inline_cache_case(base_request.clone());
        assert!(matches!(
            accepted.outcome,
            VmPropertyInlineCacheClearOutcome::Accepted { .. }
        ));
        let already_cleared = vm.clear_property_inline_cache_case(base_request);
        assert!(matches!(
            already_cleared.outcome,
            VmPropertyInlineCacheClearOutcome::Rejected {
                reason: VmPropertyInlineCacheClearRejectionReason::AttachmentNotActive {
                    lifecycle: VmPropertyInlineCacheAttachmentLifecycle::Cleared { .. },
                },
            }
        ));
        assert_eq!(
            vm.tiering_integration()
                .property_inline_cache_clear_records()
                .len(),
            4
        );
    }

    #[test]
    fn vm_property_inline_cache_attachment_rejects_stale_retired_and_materialization_mismatched_guarded_requests_without_mutating_code_block(
    ) {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let mut host = RecordingCoreHost::with_function_blocks(Vec::new());
        let (object, _) = create_prototype_data_property_object_for_test(&mut vm, &mut host);
        host.clear_observations();
        host.suppress_structure_transition_watchpoint_materialization();

        let code_block = generated_property_get_by_name_return_consumed_code_block();
        let owner = register_test_code_block(&mut vm, code_block.clone());
        let _artifact = install_typed_baseline_for_test(&mut vm, owner, 2142);
        let first = execute_registered_code_block_with_host_and_arguments(
            &mut vm,
            owner,
            &code_block,
            &mut host,
            vec![RuntimeValue::undefined(), object],
        );
        assert_eq!(
            first,
            ExecutionCompletion::Returned(RuntimeValue::from_i32(42))
        );
        host.allow_structure_transition_watchpoint_materialization();
        let guard_plan = vm.tiering_integration().property_load_guard_plans()[0].clone();
        let materialization = vm
            .materialize_property_load_guard_watchpoints_from_host_for_test(&mut host, &guard_plan)
            .expect("live watchpoint materialization")
            .expect("accepted live watchpoint recheck");
        let request = guarded_attachment_request(&vm, &guard_plan, &materialization);
        let before = vm
            .code_blocks
            .get(owner)
            .expect("registered code block")
            .code_block()
            .side_tables()
            .inline_caches()
            .clone();

        let mut stale = request.clone();
        stale.bytecode_snapshot =
            BaselineBytecodeEligibilityProof::fingerprint_code_block_snapshot(
                &property_ic_store_code_block(),
            )
            .expect("stale snapshot source");
        let stale_record = vm.attach_property_inline_cache_case(stale);
        assert!(matches!(
            stale_record.outcome,
            VmPropertyInlineCacheAttachmentOutcome::Rejected {
                reason: VmPropertyInlineCacheAttachmentRejectionReason::BytecodeSnapshotMismatch,
            }
        ));
        assert_eq!(
            &*vm.code_blocks
                .get(owner)
                .expect("registered code block")
                .code_block()
                .side_tables()
                .inline_caches(),
            &before
        );

        let mut mismatched_materialization = request.clone();
        mismatched_materialization.guarded_materialization_ordinal = Some(u64::MAX);
        let mismatched_record = vm.attach_property_inline_cache_case(mismatched_materialization);
        assert_eq!(
            mismatched_record.outcome,
            VmPropertyInlineCacheAttachmentOutcome::Rejected {
                reason:
                    VmPropertyInlineCacheAttachmentRejectionReason::GuardedMaterializationMissing,
            }
        );
        assert_eq!(
            &*vm.code_blocks
                .get(owner)
                .expect("registered code block")
                .code_block()
                .side_tables()
                .inline_caches(),
            &before
        );

        let binding = materialization.bindings[0].clone();
        host.set_identifier_data_property_for_test(object, 778, RuntimeValue::from_i32(2))
            .expect("shape transition");
        let dispatches = vm.drain_property_load_guard_watchpoint_events_for_test(&mut host);
        assert_eq!(dispatches.len(), 1);

        let retired_record = vm.attach_property_inline_cache_case(request);
        assert!(matches!(
            retired_record.outcome,
            VmPropertyInlineCacheAttachmentOutcome::Rejected {
                reason: VmPropertyInlineCacheAttachmentRejectionReason::GuardPlanNotActive {
                    lifecycle: VmPropertyLoadGuardPlanLifecycle::Retired { .. },
                },
            }
        ));
        assert!(
            vm.tiering_integration()
                .property_load_guard_watchpoint_materializations()[0]
                .lifecycle
                != VmPropertyLoadGuardWatchpointMaterializationLifecycle::Active
        );
        assert_eq!(
            &*vm.code_blocks
                .get(owner)
                .expect("registered code block")
                .code_block()
                .side_tables()
                .inline_caches(),
            &before
        );
        assert_eq!(
            vm.tiering_integration()
                .property_load_guard_watchpoint_invalidations()
                .last()
                .and_then(|record| {
                    match &record.outcome {
                    super::tiering::VmPropertyLoadGuardWatchpointInvalidationOutcome::Accepted {
                        dependency_ordinal,
                        ..
                    } => Some(*dependency_ordinal),
                    _ => None,
                }
                }),
            Some(binding.dependency_ordinal)
        );
    }

    #[test]
    fn vm_property_inline_cache_attachment_rejects_dead_owner_before_code_block_mutation() {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let code_block = property_ic_load_code_block();
        let bytecode_snapshot =
            BaselineBytecodeEligibilityProof::fingerprint_code_block_snapshot(&code_block)
                .expect("load code block snapshot");
        let dead_owner = CodeBlockId(CellId(99_001));
        vm.code_blocks.register(dead_owner, code_block);
        let plan = record_property_load_plan_for_attachment(&mut vm, dead_owner, bytecode_snapshot);

        let record = vm.attach_property_inline_cache_case(load_attachment_request(&plan));

        assert_eq!(
            record.outcome,
            VmPropertyInlineCacheAttachmentOutcome::Rejected {
                reason: VmPropertyInlineCacheAttachmentRejectionReason::OwnerNotLive,
            }
        );
        let cache = &vm
            .code_blocks
            .get(dead_owner)
            .expect("registered dead-owner code block")
            .code_block()
            .side_tables()
            .inline_caches()
            .property_accesses[0];
        assert_eq!(cache.dispatch, PropertyInlineCacheDispatch::Unlinked);
    }

    #[test]
    fn vm_property_inline_cache_attachment_rejects_stale_missing_and_store_unready_requests() {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let code_block = property_ic_load_code_block();
        let bytecode_snapshot =
            BaselineBytecodeEligibilityProof::fingerprint_code_block_snapshot(&code_block)
                .expect("load code block snapshot");
        let owner = register_test_code_block(&mut vm, code_block);
        let plan = record_property_load_plan_for_attachment(&mut vm, owner, bytecode_snapshot);

        let mut stale = load_attachment_request(&plan);
        stale.bytecode_snapshot =
            BaselineBytecodeEligibilityProof::fingerprint_code_block_snapshot(
                &property_ic_store_code_block(),
            )
            .expect("stale snapshot source");
        let stale_record = vm.attach_property_inline_cache_case(stale);
        assert!(matches!(
            stale_record.outcome,
            VmPropertyInlineCacheAttachmentOutcome::Rejected {
                reason: VmPropertyInlineCacheAttachmentRejectionReason::BytecodeSnapshotMismatch,
            }
        ));

        let mut missing = load_attachment_request(&plan);
        missing.source_plan_ordinal = u64::MAX;
        let missing_record = vm.attach_property_inline_cache_case(missing);
        assert_eq!(
            missing_record.outcome,
            VmPropertyInlineCacheAttachmentOutcome::Rejected {
                reason: VmPropertyInlineCacheAttachmentRejectionReason::PlanMissing,
            }
        );

        let unregistered_owner = vm.allocate_code_block_cell().unwrap();
        let unregistered_snapshot =
            BaselineBytecodeEligibilityProof::fingerprint_code_block_snapshot(
                &property_ic_load_code_block(),
            )
            .expect("unregistered load code block snapshot");
        let unregistered_plan = record_property_load_plan_for_attachment(
            &mut vm,
            unregistered_owner,
            unregistered_snapshot,
        );
        let unregistered_record =
            vm.attach_property_inline_cache_case(load_attachment_request(&unregistered_plan));
        assert_eq!(
            unregistered_record.outcome,
            VmPropertyInlineCacheAttachmentOutcome::Rejected {
                reason: VmPropertyInlineCacheAttachmentRejectionReason::CodeBlockNotRegistered,
            }
        );

        let store_code_block = property_ic_store_code_block();
        let store_snapshot =
            BaselineBytecodeEligibilityProof::fingerprint_code_block_snapshot(&store_code_block)
                .expect("store code block snapshot");
        let store_owner = register_test_code_block(&mut vm, store_code_block);
        let store_plan = record_property_store_plan_for_attachment(
            &mut vm,
            store_owner,
            store_snapshot,
            PropertyStoreObservationOutcome::OwnDataStore,
        );
        let missing_recheck =
            vm.attach_property_inline_cache_case(VmPropertyInlineCacheAttachmentRequest {
                store_install_recheck_ordinal: None,
                store_readiness_ordinal: None,
                ..store_attachment_request(&store_plan, 1, 2)
            });
        assert_eq!(
            missing_recheck.outcome,
            VmPropertyInlineCacheAttachmentOutcome::Rejected {
                reason: VmPropertyInlineCacheAttachmentRejectionReason::StoreInstallRecheckMissing,
            }
        );

        let accepted_recheck = vm
            .tiering_integration_mut()
            .record_property_store_access_case_install_recheck(
                VmPropertyStoreAccessCaseInstallRecheckRequest {
                    owner: store_plan.owner,
                    slot: store_plan.plan.slot,
                    bytecode_index: store_plan.bytecode_index,
                    bytecode_snapshot: store_plan.bytecode_snapshot,
                    store_plan_ordinal: store_plan.ordinal,
                },
            );
        assert!(matches!(
            accepted_recheck.outcome,
            VmPropertyStoreAccessCaseInstallRecheckOutcome::Accepted { .. }
        ));
        let missing_readiness_record = vm.attach_property_inline_cache_case(
            store_attachment_request(&store_plan, accepted_recheck.ordinal, u64::MAX),
        );
        assert!(matches!(
            missing_readiness_record.outcome,
            VmPropertyInlineCacheAttachmentOutcome::Rejected {
                reason: VmPropertyInlineCacheAttachmentRejectionReason::StoreReadinessMissing,
            }
        ));
    }

    #[test]
    fn vm_property_inline_cache_attachment_records_code_block_error_without_attaching_plan() {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let no_ic_code_block =
            linked_interpreter_test_code_block(CodeBlockLifecycleState::LinkedInterpreter);
        let bytecode_snapshot =
            BaselineBytecodeEligibilityProof::fingerprint_code_block_snapshot(&no_ic_code_block)
                .expect("no-ic code block snapshot");
        let owner = register_test_code_block(&mut vm, no_ic_code_block);
        let plan = record_property_load_plan_for_attachment(&mut vm, owner, bytecode_snapshot);

        let record = vm.attach_property_inline_cache_case(load_attachment_request(&plan));

        assert!(matches!(
            record.outcome,
            VmPropertyInlineCacheAttachmentOutcome::Rejected {
                reason: VmPropertyInlineCacheAttachmentRejectionReason::CodeBlockAttachmentError {
                    error: crate::bytecode::ic::PropertyInlineCacheAttachmentError::InvalidSlot {
                        slot: 0,
                        len: 0
                    }
                }
            }
        ));
        assert!(record.code_block_outcome.is_none());
        assert_eq!(
            record.code_block_error,
            Some(
                crate::bytecode::ic::PropertyInlineCacheAttachmentError::InvalidSlot {
                    slot: 0,
                    len: 0,
                }
            )
        );
        assert_eq!(
            vm.tiering_integration().property_load_access_case_plans()[0].lifecycle,
            VmPropertyLoadAccessCasePlanLifecycle::Active
        );
    }

    #[test]
    fn jit_baseline_source_does_not_import_code_block_mutation_authority() {
        let source = include_str!("../jit/baseline.rs");
        for forbidden in [
            "use crate::bytecode::CodeBlockMutationAuthority",
            "use crate::bytecode::{CodeBlockMutationAuthority",
            "CodeBlockMutationAuthority::VmMainThread",
        ] {
            assert!(
                !source.contains(forbidden),
                "unexpected baseline CodeBlock mutation authority use: {forbidden}"
            );
        }
    }

