    #[cfg(all(unix, target_arch = "x86_64"))]
    fn install_real_p10_retained_property_native_exit_for_owner_with_opcode_at_index(
        vm: &mut Vm,
        id: u64,
        owner: CodeBlockId,
        code_block: CodeBlock,
        expected_opcode: CoreOpcode,
        expected_site_index: usize,
        expected_site_count: usize,
    ) -> RealP10RetainedPropertyNativeExitFixture {
        let record = vm
            .install_p6_x86_64_callable_semantic_baseline_native_entry(p6_semantic_install_request(
                owner, id,
            ))
            .expect("accepted real P10 callable property native exit");
        let readiness = record
            .enabled_readiness
            .clone()
            .expect("P10 callable install should publish enabled readiness");
        let descriptor = readiness.descriptor.expect("enabled descriptor");
        assert!(
            record
                .semantic_emission
                .runtime_helper_native_exit_stubs
                .is_empty(),
            "P10 property exit must not be encoded as a runtime-helper native exit"
        );
        assert!(
            record
                .semantic_emission
                .js_call_native_exit_stubs
                .is_empty(),
            "P10 property exit must not be encoded as a JS-call native exit"
        );
        assert_eq!(
            record.semantic_emission.property_native_exit_stubs.len(),
            expected_site_count
        );
        let property_stub = record
            .semantic_emission
            .property_native_exit_stubs
            .get(expected_site_index)
            .expect("real emitted P10 property native-exit stub");
        assert_eq!(property_stub.site.opcode, expected_opcode);
        let instruction = code_block
            .decoded_instruction_at(property_stub.bytecode_index)
            .expect("P10 property native-exit instruction");
        assert_eq!(
            CoreOpcode::from_opcode(instruction.opcode),
            Some(expected_opcode)
        );
        match expected_opcode {
            CoreOpcode::GetByName => {
                let destination = instruction
                    .register_operand(0)
                    .expect("P10 GetByName destination operand");
                let base = instruction
                    .register_operand(1)
                    .expect("P10 GetByName base operand");
                assert_eq!(
                    property_stub.operands,
                    P10X86_64BaselinePropertyNativeExitOperands::GetByName { destination, base }
                );
            }
            CoreOpcode::GetGlobalObjectProperty => {
                let destination = instruction
                    .register_operand(0)
                    .expect("P10 GetGlobalObjectProperty destination operand");
                assert_eq!(
                    property_stub.operands,
                    P10X86_64BaselinePropertyNativeExitOperands::GetGlobalObjectProperty {
                        destination
                    }
                );
            }
            CoreOpcode::PutByName => {
                let base = instruction
                    .register_operand(0)
                    .expect("P10 PutByName base operand");
                let value = instruction
                    .register_operand(2)
                    .expect("P10 PutByName value operand");
                assert_eq!(
                    property_stub.operands,
                    P10X86_64BaselinePropertyNativeExitOperands::PutByName { base, value }
                );
            }
            CoreOpcode::PutGlobalObjectProperty => {
                let value = instruction
                    .register_operand(1)
                    .expect("P10 PutGlobalObjectProperty value operand");
                assert_eq!(
                    property_stub.operands,
                    P10X86_64BaselinePropertyNativeExitOperands::PutGlobalObjectProperty { value }
                );
            }
            CoreOpcode::GetByValue => {
                let destination = instruction
                    .register_operand(0)
                    .expect("P10 GetByValue destination operand");
                let base = instruction
                    .register_operand(1)
                    .expect("P10 GetByValue base operand");
                let property = instruction
                    .register_operand(2)
                    .expect("P10 GetByValue property operand");
                assert_eq!(
                    property_stub.operands,
                    P10X86_64BaselinePropertyNativeExitOperands::GetByValue {
                        destination,
                        base,
                        property,
                    }
                );
            }
            CoreOpcode::PutByValue => {
                let base = instruction
                    .register_operand(0)
                    .expect("P10 PutByValue base operand");
                let property = instruction
                    .register_operand(1)
                    .expect("P10 PutByValue property operand");
                let value = instruction
                    .register_operand(2)
                    .expect("P10 PutByValue value operand");
                assert_eq!(
                    property_stub.operands,
                    P10X86_64BaselinePropertyNativeExitOperands::PutByValue {
                        base,
                        property,
                        value,
                    }
                );
            }
            CoreOpcode::InById => {
                let destination = instruction
                    .register_operand(0)
                    .expect("P10 InById destination operand");
                let base = instruction
                    .register_operand(1)
                    .expect("P10 InById base operand");
                assert_eq!(
                    property_stub.operands,
                    P10X86_64BaselinePropertyNativeExitOperands::InById { destination, base }
                );
            }
            CoreOpcode::InByVal => {
                let destination = instruction
                    .register_operand(0)
                    .expect("P10 InByVal destination operand");
                let base = instruction
                    .register_operand(1)
                    .expect("P10 InByVal base operand");
                let property = instruction
                    .register_operand(2)
                    .expect("P10 InByVal property operand");
                assert_eq!(
                    property_stub.operands,
                    P10X86_64BaselinePropertyNativeExitOperands::InByVal {
                        destination,
                        base,
                        property,
                    }
                );
            }
            _ => unreachable!("unsupported real P10 property native-exit opcode"),
        }
        assert!(property_stub.site.requires_no_gc_exit_reentry);
        assert!(property_stub.site.may_throw);
        assert_eq!(
            property_stub.encoded_payload.low_tag(),
            P10_X86_64_BASELINE_PROPERTY_NATIVE_EXIT_RETURN_PAYLOAD_LOW_TAG
        );
        let property_payload = property_stub.encoded_payload;

        let table = vm
            .p6_x86_64_callable_retained_return_tables
            .iter()
            .find(|table| table.owner == owner && table.readiness_ordinal == readiness.ordinal)
            .expect("real retained P10 native-exit table");
        assert_eq!(
            table.bytecode_snapshot,
            readiness.bytecode_snapshot.unwrap()
        );
        assert_eq!(table.descriptor, descriptor);
        assert!(table.runtime_helper_exit_sites.is_empty());
        assert!(table.js_call_exit_sites.is_empty());
        assert_eq!(table.property_exit_sites.len(), expected_site_count);
        let table_site = table
            .property_exit_sites
            .get(expected_site_index)
            .expect("selected retained P10 property native-exit table site");
        assert_eq!(table_site.encoded_payload, property_payload);
        assert_eq!(table_site.operands, property_stub.operands);

        RealP10RetainedPropertyNativeExitFixture {
            owner,
            code_block,
            readiness,
            property_payload,
        }
    }

    // Reset the registry-held resident DataIC record (site 0) back to SENTINEL so the
    // next entry takes the slow-path/sidecar exit, even though FIX 1 admitted the
    // argument-base GetByName to the resident fast path. Reads the REGISTRY instance
    // (the one r13 addresses + the writeback mutates), not a clone.
    #[cfg(all(unix, target_arch = "x86_64"))]
    fn reset_real_p10_self_load_data_ic_record_to_sentinel(
        vm: &mut Vm,
        fixture: &RealP10RetainedPropertyNativeExitFixture,
    ) {
        let resident = vm
            .code_block_for_diagnostics(fixture.owner)
            .expect("registered resident code block");
        assert!(
            resident.reset_self_load_data_ic_record_to_sentinel(0),
            "resident self-load DataIC record 0 must exist to reset"
        );
    }

    #[cfg(all(unix, target_arch = "x86_64"))]
    fn mutate_real_p10_retained_property_native_exit_site(
        vm: &mut Vm,
        fixture: &RealP10RetainedPropertyNativeExitFixture,
        mutate: impl FnOnce(&mut P10X86_64CallablePropertyNativeExitReturnSite),
    ) {
        let table = vm
            .p6_x86_64_callable_retained_return_tables
            .iter_mut()
            .find(|table| {
                table.owner == fixture.owner && table.readiness_ordinal == fixture.readiness.ordinal
            })
            .expect("real retained P10 native-exit table");
        let site = table
            .property_exit_sites
            .iter_mut()
            .find(|site| site.encoded_payload == fixture.property_payload)
            .expect("real property native-exit site");
        mutate(site);
    }

