    #[cfg(all(unix, target_arch = "x86_64"))]
    fn install_real_p6_retained_runtime_helper_native_exit(
        vm: &mut Vm,
        id: u64,
        make_code_block: impl FnOnce(CodeBlockId) -> CodeBlock,
        opcode: CoreOpcode,
        root_count: usize,
    ) -> RealP6RetainedRuntimeHelperNativeExitFixture {
        let owner = vm.allocate_code_block_cell().unwrap();
        let code_block = make_code_block(owner);
        vm.code_blocks.register(owner, code_block.clone());
        let record = vm
            .install_p6_x86_64_callable_semantic_baseline_native_entry(p6_semantic_install_request(
                owner, id,
            ))
            .expect("accepted real P6 callable helper native exit");
        let readiness = record
            .enabled_readiness
            .clone()
            .expect("callable helper install should publish enabled readiness");
        let descriptor = readiness.descriptor.expect("enabled descriptor");
        assert!(
            record.semantic_emission.side_exit_return_stubs.is_empty(),
            "runtime helper exit must not be encoded as an arithmetic side exit"
        );
        let helper_stub = record
            .semantic_emission
            .runtime_helper_native_exit_stubs
            .first()
            .expect("real emitted helper native-exit stub");
        assert_eq!(helper_stub.bytecode_index, BytecodeIndex::from_offset(0));
        assert_eq!(helper_stub.opcode, opcode);
        assert_eq!(helper_stub.safepoint, CompilerSafepointId(1));
        assert_eq!(helper_stub.root_map, BytecodeRootMapId(42));
        assert_eq!(helper_stub.root_count, root_count);
        assert!(helper_stub.requires_no_gc_exit_reentry);
        assert!(helper_stub.may_throw);
        let helper_payload = helper_stub.encoded_payload;

        let table = vm
            .p6_x86_64_callable_retained_return_tables
            .iter()
            .find(|table| table.owner == owner && table.readiness_ordinal == readiness.ordinal)
            .expect("real retained P6 native-exit table");
        assert_eq!(
            table.bytecode_snapshot,
            readiness.bytecode_snapshot.unwrap()
        );
        assert!(table.side_exit_sites.is_empty());
        assert_eq!(table.runtime_helper_exit_sites.len(), 1);
        assert_eq!(
            table.runtime_helper_exit_sites[0].encoded_payload,
            helper_payload
        );

        RealP6RetainedRuntimeHelperNativeExitFixture {
            owner,
            code_block,
            readiness,
            descriptor,
            helper_payload,
        }
    }

