    #[cfg(all(unix, target_arch = "x86_64"))]
    fn install_synthetic_p6_retained_new_object_runtime_helper_native_exit(
        vm: &mut Vm,
        payload_index: u32,
    ) -> SyntheticP6RetainedRuntimeHelperNativeExitFixture {
        let owner = register_test_code_block(vm, p6_int32_arithmetic_code_block());
        let record =
            vm.install_p6_x86_64_callable_semantic_baseline_native_entry(
                p6_semantic_install_request(owner, 1_300 + u64::from(payload_index)),
            )
            .expect("accepted P6 callable semantic install for synthetic retained helper table");
        let mut readiness = record
            .enabled_readiness
            .clone()
            .expect("callable P6 install should publish enabled readiness");
        let descriptor = readiness.descriptor.expect("enabled descriptor");
        let arithmetic_payload = record
            .semantic_emission
            .side_exit_return_stubs
            .first()
            .expect("arithmetic retained side-exit payload")
            .encoded_payload;
        let code_block = runtime_helper_new_object_code_block_with_root_map(owner);
        let bytecode_snapshot =
            BaselineBytecodeEligibilityProof::fingerprint_code_block_snapshot(&code_block)
                .expect("synthetic helper snapshot");
        *vm.code_blocks
            .code_block_mut_for_test(owner)
            .expect("registered helper owner") = code_block.clone();
        readiness.bytecode_snapshot = Some(bytecode_snapshot);
        let helper_payload = P6X86_64BaselineSideExitReturnPayload::encode(payload_index);
        let table = vm
            .p6_x86_64_callable_retained_return_tables
            .iter_mut()
            .find(|table| table.owner == owner && table.readiness_ordinal == readiness.ordinal)
            .expect("retained P6 native-exit table");
        table.bytecode_snapshot = bytecode_snapshot;
        table.runtime_helper_exit_sites.clear();
        table
            .runtime_helper_exit_sites
            .push(P6X86_64CallableRuntimeHelperNativeExitReturnSite {
                bytecode_index: BytecodeIndex::from_offset(0),
                opcode: CoreOpcode::NewObject,
                safepoint: CompilerSafepointId(1),
                root_map: BytecodeRootMapId(42),
                root_count: 1,
                requires_no_gc_exit_reentry: true,
                may_throw: true,
                encoded_payload: helper_payload,
            });

        SyntheticP6RetainedRuntimeHelperNativeExitFixture {
            owner,
            code_block,
            readiness,
            descriptor,
            helper_payload,
            arithmetic_payload,
        }
    }

