    #[derive(Clone, Debug, Eq, PartialEq)]
    struct HeapMutationSnapshot {
        allocation_record_count: usize,
        targeted_roots: Vec<TargetedRootRecord>,
        no_gc_scope_depth: u32,
        heap_no_gc_scope_depth: u32,
    }

    impl HeapMutationSnapshot {
        fn capture(vm: &Vm) -> Self {
            Self {
                allocation_record_count: vm.heap().allocation_records().len(),
                targeted_roots: vm.heap().targeted_roots().records().to_vec(),
                no_gc_scope_depth: vm.gc_execution_state().no_gc_scope_depth(),
                heap_no_gc_scope_depth: vm.heap().no_gc_scope_depth(),
            }
        }

        fn assert_heap_and_targeted_roots_unchanged(&self, vm: &Vm) {
            assert_eq!(
                vm.heap().allocation_records().len(),
                self.allocation_record_count,
                "heap allocation record count changed across generated boundary"
            );
            assert_eq!(
                vm.heap().targeted_roots().records(),
                self.targeted_roots.as_slice(),
                "targeted root records changed across generated boundary"
            );
        }

        fn assert_no_gc_scope_depth(&self, expected: u32) {
            assert_eq!(self.no_gc_scope_depth, expected);
            assert_eq!(self.heap_no_gc_scope_depth, expected);
        }

        fn assert_current_no_gc_scope_depth(&self, vm: &Vm, expected: u32) {
            assert_eq!(
                vm.gc_execution_state().no_gc_scope_depth(),
                expected,
                "expected current no-GC depth {expected} after snapshot depth {}",
                self.no_gc_scope_depth
            );
            assert_eq!(
                vm.heap().no_gc_scope_depth(),
                expected,
                "expected current heap no-GC depth {expected} after snapshot depth {}",
                self.heap_no_gc_scope_depth
            );
        }

        fn assert_latest_generated_fallback_boundary_no_gc_depth(&self, vm: &Vm, expected: u32) {
            let fallback = vm
                .tiering_integration()
                .fallback_records()
                .last()
                .expect("generated fallback record");
            assert_eq!(fallback.boundary.no_gc_scope_depth, expected);
            assert_eq!(
                fallback.boundary.no_gc_scope_depth,
                self.no_gc_scope_depth.saturating_add(1)
            );
        }
    }

    fn assert_latest_generated_entry_evidence(
        vm: &Vm,
        owner: CodeBlockId,
        artifact: BaselineGeneratedCodeArtifact,
    ) {
        let entry_decision = vm
            .tiering_integration()
            .entry_decisions()
            .iter()
            .rev()
            .find(|decision| decision.owner == owner)
            .expect("generated entry decision");
        assert_eq!(
            entry_decision.decision,
            TierEntryDecision::EnterOptimized {
                tier: JitType::Baseline
            }
        );
        assert_eq!(
            entry_decision.execution_path,
            TierEntryExecutionPath::GeneratedCode(JitType::Baseline)
        );
        assert_eq!(
            entry_decision
                .baseline_entry_gate
                .as_ref()
                .and_then(|gate| gate.generated_artifact.clone()),
            Some(artifact)
        );

        let diagnostic = vm
            .tiering_integration()
            .diagnostics()
            .iter()
            .rev()
            .find(|diagnostic| diagnostic.owner == owner)
            .expect("generated completion diagnostic");
        assert_eq!(diagnostic.owner, owner);
        assert_eq!(
            diagnostic.execution_path,
            TierEntryExecutionPath::GeneratedCode(JitType::Baseline)
        );
    }

    fn assert_latest_generated_entry_invalidated(
        vm: &Vm,
        owner: CodeBlockId,
        artifact: BaselineGeneratedCodeArtifact,
    ) {
        let entry_decision = vm
            .tiering_integration()
            .entry_decisions()
            .last()
            .expect("generated entry decision");
        assert_eq!(entry_decision.owner, owner);
        assert_eq!(
            entry_decision.decision,
            TierEntryDecision::FallbackToInterpreter {
                attempted_tier: JitType::Baseline,
                reason: TierEntryFallbackReason::Tier(TierFallbackReason::UnsupportedTier),
            }
        );
        assert_eq!(
            entry_decision.execution_path,
            TierEntryExecutionPath::Interpreter
        );
        let gate = entry_decision
            .baseline_entry_gate
            .as_ref()
            .expect("invalidated generated artifact gate");
        assert_eq!(
            gate.outcome,
            super::tiering::BaselineEntryGateOutcome::InvalidatedGeneratedArtifact
        );
        assert_eq!(gate.generated_artifact.as_ref(), Some(&artifact));

        let diagnostic = vm
            .tiering_integration()
            .diagnostics()
            .last()
            .expect("interpreter completion diagnostic after invalidated generated entry");
        assert_eq!(diagnostic.owner, owner);
        assert_eq!(
            diagnostic.execution_path,
            TierEntryExecutionPath::Interpreter
        );
    }

    fn assert_latest_generated_fallback(
        vm: &Vm,
        owner: CodeBlockId,
        fallback_count_before: usize,
        bytecode_index: BytecodeIndex,
        opcode: CoreOpcode,
        cause: GeneratedBaselineFallbackCause,
    ) {
        assert_eq!(
            vm.tiering_integration().fallback_records().len(),
            fallback_count_before + 1
        );
        let fallback = vm
            .tiering_integration()
            .fallback_records()
            .last()
            .expect("generated fallback record");
        assert_eq!(fallback.owner, owner);
        assert_eq!(fallback.result.bytecode_index, Some(bytecode_index));
        assert!(fallback.frame.is_some());
        assert_eq!(fallback.result.attempted_tier, JitType::Baseline);
        assert_eq!(
            fallback.result.target,
            TierFallbackTarget::ReturnToInterpreter
        );
        assert_eq!(
            fallback.result.resume,
            TierFallbackResumeKind::ContinueInInterpreter
        );
        assert_eq!(
            fallback.generated_baseline,
            Some(GeneratedBaselineFallbackRecord {
                bytecode_index,
                opcode: GeneratedBaselineFallbackOpcode::Core(opcode),
                cause,
            })
        );
        assert_eq!(fallback.boundary.no_gc_scope_depth, 1);
    }

    fn api_opaque_handle(address: usize) -> ApiOpaqueHandle {
        let raw = NonNull::new(address as *mut c_void).unwrap();
        unsafe { ApiOpaqueHandle::from_raw(raw) }
    }

    fn api_context_group(address: usize) -> ApiContextGroup {
        unsafe { ApiContextGroup::from_opaque(api_opaque_handle(address)) }
    }

    fn api_value_ref(address: usize) -> ApiValueRef {
        unsafe { ApiValueRef::from_opaque(api_opaque_handle(address)) }
    }

    fn api_protection_owner() -> ApiProtectionOwner {
        ApiProtectionOwner::new(api_context_group(0x1000))
    }

    fn api_protected_value(slot: ApiProtectionSlot) -> ProtectedValue {
        ProtectedValue::with_slot(api_protection_owner(), api_value_ref(0x2000), slot)
    }

    #[repr(transparent)]
    struct TestStringCell(String);

    #[repr(transparent)]
    struct TestObjectCell(u8);

    fn heap_bound_object_value(
        heap: &mut Heap,
    ) -> (Pin<Box<TestObjectCell>>, RuntimeValue, CellId) {
        let metadata = static_cell_metadata_registry()
            .metadata_for_type(CellType::Object)
            .map(|descriptor| descriptor.metadata)
            .expect("object metadata");
        let allocation = heap
            .allocate_record(HeapAllocationRequest {
                heap: heap.id(),
                subspace: "object",
                metadata,
                byte_size: std::mem::size_of::<TestObjectCell>().max(1),
                mode: AllocationMode::Normal,
                may_trigger_collection: false,
            })
            .expect("object allocation");
        let object = Box::pin(TestObjectCell(0));
        let ptr = NonNull::from(object.as_ref().get_ref());
        // SAFETY: The pinned test cell is kept alive by the test while the value is used.
        let value = RuntimeValue::from_cell(unsafe { GcRef::from_non_null(ptr) });
        let payload = value.as_cell().expect("cell value").pointer_payload_bits();
        heap.bind_cell_payload(allocation.cell, payload)
            .expect("payload binding");
        heap.publish_cell(allocation.cell)
            .expect("publish object cell");
        (object, value, allocation.cell)
    }

    fn heap_bound_string_value(
        heap: &mut Heap,
        text: &str,
    ) -> (Pin<Box<TestStringCell>>, RuntimeValue, CellId) {
        let metadata = static_cell_metadata_registry()
            .metadata_for_type(CellType::String)
            .map(|descriptor| descriptor.metadata)
            .expect("string metadata");
        let allocation = heap
            .allocate_record(HeapAllocationRequest {
                heap: heap.id(),
                subspace: "auxiliary",
                metadata,
                byte_size: std::mem::size_of::<String>().max(1),
                mode: AllocationMode::Normal,
                may_trigger_collection: false,
            })
            .expect("string allocation");
        let string = Box::pin(TestStringCell(text.to_owned()));
        let ptr = NonNull::from(string.as_ref().get_ref());
        // SAFETY: The pinned test cell is kept alive by the test while the value is used.
        let value = RuntimeValue::from_cell(unsafe { GcRef::from_non_null(ptr) });
        let payload = value.as_cell().expect("cell value").pointer_payload_bits();
        heap.bind_cell_payload(allocation.cell, payload)
            .expect("payload binding");
        heap.publish_cell(allocation.cell)
            .expect("publish string cell");
        (string, value, allocation.cell)
    }

    fn heap_cell_for_value(vm: &Vm, value: RuntimeValue) -> CellId {
        let payload = value
            .as_cell()
            .expect("value should be a heap cell")
            .pointer_payload_bits();
        vm.heap()
            .cell_for_payload(payload)
            .expect("cell should be bound to the heap")
    }

    fn assert_heap_published_cell_type(
        vm: &Vm,
        value: RuntimeValue,
        cell_type: CellType,
    ) -> CellId {
        let cell = heap_cell_for_value(vm, value);
        let allocation = vm
            .heap()
            .allocation_records()
            .iter()
            .find(|record| record.response.cell == cell)
            .expect("allocation record");
        assert_eq!(allocation.response.metadata.type_info.cell_type, cell_type);
        assert!(allocation.published);
        cell
    }

