    #[test]
    fn collecting_heap_operation_is_allowed_while_no_gc_region_suspended() {
        let mut vm = Vm::new(VmConfig::default());
        let region = vm.enter_no_gc_execution_region();
        assert_vm_and_heap_no_gc_scope_depth(&vm, 1);

        assert_eq!(
            vm.evaluate_heap_operation(HeapSemanticOperation::Allocate {
                may_trigger_collection: true
            }),
            Err(HeapSemanticError::NoGcScopeActive(
                HeapSemanticOperation::Allocate {
                    may_trigger_collection: true
                }
            ))
        );

        let suspended = vm.suspend_no_gc_execution_region().unwrap();
        assert_vm_and_heap_no_gc_scope_depth(&vm, 0);
        assert!(vm
            .evaluate_heap_operation(HeapSemanticOperation::Allocate {
                may_trigger_collection: true
            })
            .is_ok());
        assert!(vm
            .heap
            .queue_collection(crate::gc::CollectionRequest {
                kind: crate::gc::CollectionKind::Full,
                ..crate::gc::CollectionRequest::default()
            })
            .is_ok());

        assert_eq!(vm.resume_no_gc_execution_region(suspended), Ok(region));
        assert_vm_and_heap_no_gc_scope_depth(&vm, 1);
        assert_eq!(
            vm.evaluate_heap_operation(HeapSemanticOperation::Allocate {
                may_trigger_collection: true
            }),
            Err(HeapSemanticError::NoGcScopeActive(
                HeapSemanticOperation::Allocate {
                    may_trigger_collection: true
                }
            ))
        );
        vm.leave_no_gc_execution_region(region).unwrap();
        assert_vm_and_heap_no_gc_scope_depth(&vm, 0);
    }

    #[test]
    fn vm_collection_completion_ages_property_load_megamorphic_cache() {
        let mut vm = Vm::new(VmConfig::default());
        let epoch_before = vm
            .tiering_integration()
            .property_load_megamorphic_cache_epoch();

        let completion = vm.finalize_completed_collection(crate::gc::CollectionKind::Eden);
        let record = completion
            .property_load_megamorphic_cache_aging
            .expect("eden completion ages megamorphic cache");

        assert_eq!(completion.kind, crate::gc::CollectionKind::Eden);
        assert_eq!(completion.heap_phase_after, crate::gc::GcPhase::NotRunning);
        assert_eq!(
            record.trigger,
            super::tiering::VmPropertyLoadMegamorphicCacheAgingTrigger::CollectionCompletion {
                kind: crate::gc::CollectionKind::Eden
            }
        );
        assert!(!record.full_collection);
        assert_eq!(record.epoch_before, epoch_before);
        assert_ne!(
            vm.tiering_integration()
                .property_load_megamorphic_cache_epoch(),
            epoch_before
        );
        assert_eq!(
            vm.tiering_integration()
                .property_load_megamorphic_cache_aging_records(),
            &[record]
        );
    }

    #[test]
    fn vm_heap_collection_completion_finalizes_and_ages_property_load_megamorphic_cache() {
        let mut vm = Vm::new(VmConfig::default());
        vm.heap.enter_phase(
            crate::gc::GcPhase::End,
            crate::gc::MutatorState::Collecting,
            crate::gc::GcConductor::Collector,
        );
        let epoch_before = vm
            .tiering_integration()
            .property_load_megamorphic_cache_epoch();

        let completion = vm.finalize_completed_collection(crate::gc::CollectionKind::Full);
        let aging = completion
            .property_load_megamorphic_cache_aging
            .expect("full collection completion ages megamorphic cache");

        assert_eq!(completion.kind, crate::gc::CollectionKind::Full);
        assert_eq!(completion.heap_phase_before, crate::gc::GcPhase::End);
        assert_eq!(completion.heap_phase_after, crate::gc::GcPhase::NotRunning);
        assert_eq!(vm.heap.phase(), crate::gc::GcPhase::NotRunning);
        assert_eq!(
            aging.trigger,
            super::tiering::VmPropertyLoadMegamorphicCacheAgingTrigger::CollectionCompletion {
                kind: crate::gc::CollectionKind::Full
            }
        );
        assert!(aging.full_collection);
        assert_eq!(aging.epoch_before, epoch_before);
        assert_ne!(
            vm.tiering_integration()
                .property_load_megamorphic_cache_epoch(),
            epoch_before
        );
        assert_eq!(
            vm.tiering_integration()
                .property_load_megamorphic_cache_aging_records(),
            &[aging]
        );
    }

    #[test]
    fn vm_structure_chain_invalidation_event_ages_property_load_megamorphic_cache() {
        let mut vm = Vm::new(VmConfig::default());
        let mut host = CoreOpcodeDispatchHost::new();
        let object = host.allocate_null_prototype_object_for_test();
        let old_structure = host
            .generated_property_sidecar_base_structure(object)
            .expect("object structure");
        let epoch_before = vm
            .tiering_integration()
            .property_load_megamorphic_cache_epoch();

        host.set_identifier_data_property_for_test(object, 77, RuntimeValue::from_i32(1))
            .expect("shape transition");
        assert!(host.has_pending_structure_chain_invalidation_events());

        let records = vm.drain_pending_property_load_structure_chain_invalidations(&mut host);

        assert_eq!(records.len(), 1);
        assert_eq!(
            records[0].0,
            StructureChainInvalidationEvent { old_structure }
        );
        assert_eq!(
            records[0].1.trigger,
            super::tiering::VmPropertyLoadMegamorphicCacheAgingTrigger::StructureChainInvalidation
        );
        assert_eq!(records[0].1.epoch_before, epoch_before);
        assert_ne!(
            vm.tiering_integration()
                .property_load_megamorphic_cache_epoch(),
            epoch_before
        );
        assert!(!host.has_pending_structure_chain_invalidation_events());
    }

    #[test]
    fn vm_structure_chain_invalidation_ages_once_when_watchpoint_event_also_fires() {
        let mut vm = Vm::new(VmConfig::default());
        let mut host = CoreOpcodeDispatchHost::new();
        let object = host.allocate_null_prototype_object_for_test();
        let old_structure = host
            .generated_property_sidecar_base_structure(object)
            .expect("object structure");
        host.start_structure_transition_watchpoints(&[StructureTransitionWatchpointRequest {
            set: crate::jit::WatchpointSetId(901),
            structure: old_structure,
        }])
        .expect("watchpoint start");

        host.set_identifier_data_property_for_test(object, 78, RuntimeValue::from_i32(2))
            .expect("shape transition");
        let dispatches = vm.drain_pending_property_load_runtime_invalidations(&mut host);

        assert_eq!(dispatches.len(), 1);
        assert_eq!(
            vm.tiering_integration()
                .property_load_megamorphic_cache_aging_records()
                .len(),
            1
        );
        assert!(matches!(
            dispatches[0].outcome,
            super::tiering::VmPropertyLoadGuardWatchpointEventDispatchOutcome::Rejected { .. }
        ));
    }

    #[test]
    fn heap_snapshot_hook_reports_vm_execution_roots() {
        let mut vm = Vm::new(VmConfig::default());
        let code_block = CodeBlockId(CellId(31));
        vm.execution
            .enter(crate::interpreter::ExecutionEntryRecord::Program(
                ProgramExecutionEntry {
                    code_block,
                    global_object: GlobalObjectId(ObjectId(CellId(32))),
                    this_value: RuntimeValue::undefined(),
                },
            ));
        vm.execution
            .push_frame(
                &mut vm.registers,
                FramePushRequest {
                    code_block: Some(code_block),
                    callee: Some(ObjectId(CellId(33))),
                    callee_value: None,
                    lexical_scope: None,
                    shape: RegisterFrameShape {
                        num_parameters_including_this: 1,
                        num_vars: 1,
                        num_callee_locals: 0,
                        num_temporaries: 0,
                        special: Default::default(),
                    },
                    argument_count_including_this: 1,
                    argument_values: vec![RuntimeValue::from_i32(4)],
                    start_bytecode_index: Some(BytecodeIndex::from_offset(0)),
                    return_bytecode_index: None,
                },
            )
            .unwrap();

        let hook = vm.heap_snapshot_hook();

        assert_eq!(hook.statistics.heap, vm.heap().id());
        assert_eq!(hook.active_frame_depth, 1);
        assert!(hook.execution_roots.len() >= 3);
        assert!(hook
            .execution_roots
            .iter()
            .all(|root| root.heap == vm.heap().id()));
    }

    #[test]
    fn vm_execution_records_tier_fallback_roots_and_diagnostics() {
        struct ReturnHost;
        impl DispatchHost for ReturnHost {
            fn dispatch_instruction(
                &mut self,
                _state: &mut DispatchState<'_>,
                _instruction: DispatchInstruction<'_>,
            ) -> DispatchOutcome {
                DispatchOutcome::Return(RuntimeValue::from_i32(17))
            }
        }

        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let code_block_id = CodeBlockId(CellId(41));
        let block = CodeBlock::from_unlinked(
            UnlinkedCodeBlock::new(
                CodeKind::Function,
                PackedInstructionStream::from_typed_placeholder(vec![TypedInstruction {
                    opcode: Opcode::Reserved,
                    width: OperandWidth::Narrow,
                    operands: Vec::new(),
                    schema: None,
                    bytecode_index: Some(BytecodeIndex::from_offset(0)),
                }]),
            )
            .with_frame(RegisterFrameShape {
                num_parameters_including_this: 1,
                num_vars: 1,
                num_callee_locals: 0,
                num_temporaries: 0,
                special: Default::default(),
            }),
            LinkContext::default(),
        );
        vm.execution
            .enter(crate::interpreter::ExecutionEntryRecord::Program(
                ProgramExecutionEntry {
                    code_block: code_block_id,
                    global_object: GlobalObjectId(ObjectId(CellId(42))),
                    this_value: RuntimeValue::undefined(),
                },
            ));
        vm.execution
            .push_frame(
                &mut vm.registers,
                FramePushRequest {
                    code_block: Some(code_block_id),
                    callee: Some(ObjectId(CellId(43))),
                    callee_value: None,
                    lexical_scope: None,
                    shape: block.unlinked().frame(),
                    argument_count_including_this: 1,
                    argument_values: vec![RuntimeValue::from_i32(5)],
                    start_bytecode_index: Some(BytecodeIndex::from_offset(0)),
                    return_bytecode_index: None,
                },
            )
            .unwrap();

        let completion = vm.execute_code_block(
            code_block_id,
            &block,
            &mut ReturnHost,
            DispatchConfig::default(),
        );

        assert_eq!(
            completion,
            ExecutionCompletion::Returned(RuntimeValue::from_i32(17))
        );
        assert_eq!(
            vm.tiering_integration().entry_decisions()[0].requested_tier,
            Some(JitType::Baseline)
        );
        assert_eq!(
            vm.tiering_integration().entry_decisions()[0].execution_path,
            TierEntryExecutionPath::Interpreter
        );
        assert_eq!(
            vm.tiering_integration().fallback_records()[0].result.reason,
            TierFallbackReason::UnsupportedTier
        );
        assert_eq!(
            vm.tiering_integration().fallback_records()[0]
                .boundary
                .no_gc_scope_depth,
            1
        );
        assert!(!vm.tiering_integration().fallback_records()[0]
            .boundary
            .roots
            .is_empty());
        assert_eq!(
            vm.tiering_integration().diagnostics()[0].completion,
            CompletionDiagnostic::Returned
        );
        assert_eq!(
            vm.tiering_integration().diagnostics()[0].execution_path,
            TierEntryExecutionPath::Interpreter
        );
    }

