    // C++ JSC JSValue::putToPrimitive (runtime/JSCJSValue.cpp:217): a property
    // PUT on a primitive base is NOT fatal. In sloppy mode (Octane), with no
    // prototype setter, it is a SILENT NO-OP — definePropertyOnReceiver
    // (JSObject.cpp:983) cannot CreateDataProperty on a non-object receiver and
    // returns false without storing. These prove JSC behavior (not accidental
    // Rust behavior): the put does not throw, no property is created, and the
    // assignment expression still evaluates to the RHS value.
    #[test]
    fn vm_put_to_primitive_number_base_is_sloppy_no_op() {
        let mut vm = Vm::new(VmConfig::default());
        // `(5).foo = 1` does not throw; the assignment expression evaluates to
        // the RHS value 1 (putToPrimitive returns, the bytecode result is the
        // stored value, not a property read).
        assert_eq!(
            vm.execute_source(source("(5).foo = 1;")).unwrap(),
            ExecutionCompletion::Returned(RuntimeValue::from_i32(1))
        );
        // Afterward `(5).foo` is undefined: nothing was stored on the primitive
        // and Number.prototype has no `foo`.
        let mut vm = Vm::new(VmConfig::default());
        assert_eq!(
            vm.execute_source(source("(5).foo = 1; (5).foo;")).unwrap(),
            ExecutionCompletion::Returned(RuntimeValue::undefined())
        );
    }

    #[test]
    fn vm_put_to_primitive_string_length_is_sloppy_no_op() {
        let mut vm = Vm::new(VmConfig::default());
        // gbemu's residual blocker: `s.length = 99` on a string. putToPrimitive
        // (JSCJSValue.cpp:223) treats String length as read-only — a sloppy
        // no-op — so it does not throw and `s.length` stays 1.
        assert_eq!(
            vm.execute_source(source("var s = \"x\"; s.length = 99; s.length;"))
                .unwrap(),
            ExecutionCompletion::Returned(RuntimeValue::from_i32(1))
        );
    }

    #[test]
    fn vm_put_to_primitive_string_and_boolean_bases_do_not_throw() {
        // `"a".foo = 1` and `true.x = 1` are sloppy no-ops via String.prototype
        // / Boolean.prototype synthesis, not fatal ExpectedObject failures. The
        // assignment expression evaluates to the RHS value.
        let mut vm = Vm::new(VmConfig::default());
        assert_eq!(
            vm.execute_source(source("\"a\".foo = 1;")).unwrap(),
            ExecutionCompletion::Returned(RuntimeValue::from_i32(1))
        );
        let mut vm = Vm::new(VmConfig::default());
        assert_eq!(
            vm.execute_source(source("true.x = 1;")).unwrap(),
            ExecutionCompletion::Returned(RuntimeValue::from_i32(1))
        );
    }

    #[test]
    fn vm_put_on_object_base_still_stores() {
        // Object-base puts are unchanged by the put-to-primitive path: a normal
        // own data property is created and reads back.
        let mut vm = Vm::new(VmConfig::default());
        assert_eq!(
            vm.execute_source(source("var o = {}; o.x = 3; o.x;"))
                .unwrap(),
            ExecutionCompletion::Returned(RuntimeValue::from_i32(3))
        );
    }

    // C++ JSC RegExpPrototype::finishCreation (runtime/RegExpPrototype.cpp:81-90)
    // installs the RegExp.prototype accessor getters this engine previously
    // omitted, so `/re/.source` returned undefined and jQuery/Sizzle's
    // `new RegExp(o.match[r].source + ...)` threw on undefined.replace. These
    // prove the JSC-derived getter behavior, not accidental Rust behavior.
    #[test]
    fn vm_regexp_prototype_source_getter_returns_pattern_string() {
        // regExpProtoGetterSource (RegExpPrototype.cpp:459) returns the escaped
        // pattern as a string for a RegExpObject receiver.
        let mut vm = Vm::new(VmConfig::default());
        assert_eq!(
            vm.execute_source(source("/abc/.source === \"abc\";"))
                .unwrap(),
            ExecutionCompletion::Returned(RuntimeValue::from_bool(true))
        );
        let mut vm = Vm::new(VmConfig::default());
        assert_eq!(
            vm.execute_source(source("typeof /x/.source === \"string\";"))
                .unwrap(),
            ExecutionCompletion::Returned(RuntimeValue::from_bool(true))
        );
    }

    #[test]
    fn vm_regexp_prototype_boolean_getters_read_flag_bits() {
        // regExpProtoGetterGlobal/IgnoreCase (RegExpPrototype.cpp:314/346) return
        // the receiver's flag bit; absent flags read false.
        let mut vm = Vm::new(VmConfig::default());
        assert_eq!(
            vm.execute_source(source("/x/g.global === true && /x/.global === false;"))
                .unwrap(),
            ExecutionCompletion::Returned(RuntimeValue::from_bool(true))
        );
        let mut vm = Vm::new(VmConfig::default());
        assert_eq!(
            vm.execute_source(source("/x/i.ignoreCase === true;"))
                .unwrap(),
            ExecutionCompletion::Returned(RuntimeValue::from_bool(true))
        );
    }

    #[test]
    fn vm_regexp_prototype_flags_getter_is_canonical_order() {
        // regExpProtoGetterFlags (RegExpPrototype.cpp:443) reassembles the flag
        // string in Yarr::flagsString canonical order (d,g,i,m,s,u,v,y), NOT the
        // order the flags were written in the literal.
        let mut vm = Vm::new(VmConfig::default());
        assert_eq!(
            vm.execute_source(source("/x/gi.flags === \"gi\";"))
                .unwrap(),
            ExecutionCompletion::Returned(RuntimeValue::from_bool(true))
        );
        let mut vm = Vm::new(VmConfig::default());
        assert_eq!(
            vm.execute_source(source("/x/ig.flags === \"gi\";"))
                .unwrap(),
            ExecutionCompletion::Returned(RuntimeValue::from_bool(true))
        );
    }

    #[test]
    fn vm_regexp_prototype_object_getters_use_special_case_values() {
        // The %RegExp.prototype% receiver returns "(?:)" for source
        // (RegExpPrototype.cpp:455), "" for flags, and undefined for the boolean
        // getters (e.g. :310), rather than throwing.
        let mut vm = Vm::new(VmConfig::default());
        assert_eq!(
            vm.execute_source(source("RegExp.prototype.source === \"(?:)\";"))
                .unwrap(),
            ExecutionCompletion::Returned(RuntimeValue::from_bool(true))
        );
        let mut vm = Vm::new(VmConfig::default());
        assert_eq!(
            vm.execute_source(source("RegExp.prototype.flags === \"\";"))
                .unwrap(),
            ExecutionCompletion::Returned(RuntimeValue::from_bool(true))
        );
        let mut vm = Vm::new(VmConfig::default());
        assert_eq!(
            vm.execute_source(source("RegExp.prototype.global === undefined;"))
                .unwrap(),
            ExecutionCompletion::Returned(RuntimeValue::from_bool(true))
        );
    }

    #[test]
    fn vm_regexp_prototype_getter_on_wrong_receiver_throws_type_error() {
        // regExpProtoGetterSource (RegExpPrototype.cpp:456): a non-RegExp,
        // non-%RegExp.prototype% receiver throws a catchable TypeError. The
        // try/catch swallows it and the program completes normally with `true`.
        let mut vm = Vm::new(VmConfig::default());
        assert_eq!(
            vm.execute_source(source(
                "var t=false; \
                 try { Object.getOwnPropertyDescriptor(RegExp.prototype,\"source\").get.call({}); } \
                 catch (e) { t = (e instanceof TypeError); } \
                 t;"
            ))
            .unwrap(),
            ExecutionCompletion::Returned(RuntimeValue::from_bool(true))
        );
    }

    #[test]
    fn vm_regexp_prototype_flags_getter_accepts_any_object() {
        // regExpProtoGetterFlags (RegExpPrototype.cpp:437-440) does an
        // isObject-only check, unlike source/boolean getters: a plain (non-RegExp)
        // object receiver yields "" (every flag reads falsy), it does NOT throw.
        let mut vm = Vm::new(VmConfig::default());
        assert_eq!(
            vm.execute_source(source(
                "Object.getOwnPropertyDescriptor(RegExp.prototype,\"flags\").get.call({}) === \"\";"
            ))
            .unwrap(),
            ExecutionCompletion::Returned(RuntimeValue::from_bool(true))
        );
        // A non-object receiver still throws a catchable TypeError (:437-438).
        let mut vm = Vm::new(VmConfig::default());
        assert_eq!(
            vm.execute_source(source(
                "var t=false; \
                 try { Object.getOwnPropertyDescriptor(RegExp.prototype,\"flags\").get.call(5); } \
                 catch (e) { t = (e instanceof TypeError); } \
                 t;"
            ))
            .unwrap(),
            ExecutionCompletion::Returned(RuntimeValue::from_bool(true))
        );
    }

    #[test]
    fn vm_regexp_source_unblocks_sizzle_reconstruction() {
        // jQuery 1.7.2 / Sizzle's `new RegExp(expr.source + suffix, flags)`
        // pattern: reading `.source` off a RegExp and rebuilding. Previously
        // `.source` was undefined and this threw.
        let mut vm = Vm::new(VmConfig::default());
        assert_eq!(
            vm.execute_source(source(
                "var r = /ab/g; var n = new RegExp(r.source + \"c\", \"i\"); \
                 n.source === \"abc\" && n.flags === \"i\";"
            ))
            .unwrap(),
            ExecutionCompletion::Returned(RuntimeValue::from_bool(true))
        );
    }

    // C++ JSC globalFuncEval (runtime/JSGlobalObjectFunctions.cpp:450) ->
    // Interpreter::executeEval (interpreter/Interpreter.cpp:1436). INDIRECT
    // (global) eval. These prove JSC behavior: a string arg is compiled and its
    // completion value returned; a non-string arg is returned unchanged; eval
    // bound to a local and called still runs indirect eval; eval-body global var
    // declarations become global bindings; a concatenated program string returns
    // its completion value.
    #[test]
    fn vm_indirect_eval_compiles_and_returns_string_completion_value() {
        let mut vm = Vm::new(VmConfig::default());
        // globalFuncEval :458/:517 -> executeEval: "1+2" compiles to an Eval
        // CodeBlock whose completion value is the last expression (3).
        assert_eq!(
            vm.execute_source(source("eval(\"1+2\");")).unwrap(),
            ExecutionCompletion::Returned(RuntimeValue::from_i32(3))
        );
    }

    #[test]
    fn vm_indirect_eval_returns_non_string_argument_unchanged() {
        let mut vm = Vm::new(VmConfig::default());
        // globalFuncEval :477-478: a non-string argument is returned unchanged
        // (no compilation). `eval(o) === o` for an object `o`.
        assert_eq!(
            vm.execute_source(source("var o = {}; eval(o) === o;"))
                .unwrap(),
            ExecutionCompletion::Returned(RuntimeValue::from_bool(true))
        );
        // A number argument is likewise returned unchanged.
        let mut vm = Vm::new(VmConfig::default());
        assert_eq!(
            vm.execute_source(source("eval(41);")).unwrap(),
            ExecutionCompletion::Returned(RuntimeValue::from_i32(41))
        );
    }

    #[test]
    fn vm_indirect_eval_through_local_alias_runs_and_declares_global_var() {
        let mut vm = Vm::new(VmConfig::default());
        // `var e = eval; e("var x = 41; x + 1")` is INDIRECT eval (the callee is
        // not the syntactic `eval` identifier). It runs at global scope, declares
        // global `var x`, and returns the completion value 42 (executeEval global
        // var hoisting, Interpreter.cpp:1513-1577).
        assert_eq!(
            vm.execute_source(source("var e = eval; e(\"var x = 41; x + 1\");"))
                .unwrap(),
            ExecutionCompletion::Returned(RuntimeValue::from_i32(42))
        );
    }

    #[test]
    fn vm_indirect_eval_declared_global_var_is_visible_after_eval() {
        let mut vm = Vm::new(VmConfig::default());
        // The global `var gg` declared inside the eval body is a global binding;
        // a subsequent top-level reference resolves it.
        assert_eq!(
            vm.execute_source(source("eval(\"var gg = 7;\"); gg + 1;"))
                .unwrap(),
            ExecutionCompletion::Returned(RuntimeValue::from_i32(8))
        );
    }

    #[test]
    fn vm_indirect_eval_concatenated_program_returns_completion_value() {
        let mut vm = Vm::new(VmConfig::default());
        // A multi-statement program string: the last evaluated expression
        // statement is the eval completion value (the IIFE result, 9).
        assert_eq!(
            vm.execute_source(source(
                "eval(\"var a = 4; (function(){ return a + 5; })();\");"
            ))
            .unwrap(),
            ExecutionCompletion::Returned(RuntimeValue::from_i32(9))
        );
    }

    #[test]
    fn vm_indirect_eval_empty_string_returns_undefined() {
        let mut vm = Vm::new(VmConfig::default());
        // An empty program has an undefined completion value (executeEval's
        // initial completion register, emit_load_undefined for Eval mode).
        assert_eq!(
            vm.execute_source(source("eval(\"\");")).unwrap(),
            ExecutionCompletion::Returned(RuntimeValue::undefined())
        );
    }

