    #[test]
    fn vm_execute_source_publishes_top_level_code_block_and_global_object_cells() {
        let mut vm = Vm::new(VmConfig::baseline_allowed());

        let completion = vm.execute_source(source("42;")).unwrap();

        assert_eq!(
            completion,
            ExecutionCompletion::Returned(RuntimeValue::from_i32(42))
        );
        let diagnostic_owner = vm.tiering_integration().diagnostics()[0].owner;
        assert!(vm.code_block_owner_is_live(diagnostic_owner));
        let registered_code_block = vm
            .code_blocks
            .get(diagnostic_owner)
            .expect("registered source code block")
            .code_block();
        assert_eq!(
            registered_code_block.lifecycle(),
            CodeBlockLifecycleState::BaselineInstalled
        );
        assert!(registered_code_block.entrypoints().interpreter.is_some());
        assert!(registered_code_block.entrypoints().baseline_jit().is_some());
        let executable = registered_code_block
            .link_context()
            .owner_executable
            .expect("source code block owner executable");
        assert_eq!(
            vm.executable_registry()
                .executable_for_code_block(diagnostic_owner),
            Some(executable)
        );
        let executable_record = vm
            .executable_registry()
            .script(executable)
            .expect("registered source executable");
        assert_eq!(
            executable_record
                .installed_code()
                .map(|installed| installed.code_block),
            Some(diagnostic_owner)
        );
        assert_eq!(
            executable_record
                .executable()
                .base
                .entrypoints
                .call
                .interpreter,
            Some(crate::bytecode::InterpreterEntrypointSlot(0))
        );
        assert_eq!(
            vm.executable_registry().install_records().len(),
            1,
            "source execution should install top-level executable code once"
        );
        let executable_allocation = vm
            .heap()
            .allocation_records()
            .iter()
            .find(|record| record.response.cell == executable.0)
            .expect("source executable heap allocation");
        assert_eq!(
            executable_allocation.response.metadata.type_info.cell_type,
            CellType::Executable
        );
        assert_eq!(executable_allocation.request.subspace, "auxiliary");
        assert!(executable_allocation.published);
        let allocation = vm
            .heap()
            .allocation_records()
            .iter()
            .find(|record| record.response.cell == diagnostic_owner.0)
            .expect("source code block heap allocation");
        assert_eq!(
            allocation.response.metadata.type_info.cell_type,
            CellType::CodeBlock
        );
        assert_eq!(
            allocation.request.metadata.type_info.cell_type,
            CellType::CodeBlock
        );
        assert_eq!(allocation.request.subspace, "auxiliary");
        assert!(allocation.published);

        let global_allocation = vm
            .heap()
            .allocation_records()
            .iter()
            .find(|record| record.response.metadata.type_info.cell_type == CellType::GlobalObject)
            .expect("source global object heap allocation");
        assert_eq!(
            global_allocation.request.metadata.type_info.cell_type,
            CellType::GlobalObject
        );
        assert_eq!(global_allocation.request.subspace, "object");
        assert!(global_allocation.published);
        assert_ne!(global_allocation.response.cell, diagnostic_owner.0);

        assert!(vm.tiering_integration().fallback_records().is_empty());
        assert_host_supported_baseline_source_execution_path(
            &vm,
            vm.tiering_integration().diagnostics()[0].execution_path,
        );
    }

    #[test]
    fn vm_execute_source_registers_nested_function_executable_and_owned_call_code() {
        let mut vm = Vm::new(VmConfig::baseline_allowed());

        let completion = vm
            .execute_source(source("function add(a, b) { return a + b; } add(20, 22);"))
            .unwrap();

        assert_eq!(
            completion,
            ExecutionCompletion::Returned(RuntimeValue::from_i32(42))
        );
        let function_records = vm
            .executable_registry()
            .function_records()
            .collect::<Vec<_>>();
        let [function_record] = function_records.as_slice() else {
            assert_eq!(
                function_records.len(),
                1,
                "expected exactly one nested function executable"
            );
            return;
        };
        let function_executable = function_record
            .executable()
            .script
            .base
            .identity
            .expect("function executable identity");
        let installed = function_record
            .installed_call_code()
            .expect("installed function call code");
        assert_eq!(installed.specialization, CodeSpecialization::Call);
        assert_ne!(installed.code_block, CodeBlockId(CellId(50_000)));
        assert_eq!(
            vm.executable_registry()
                .executable_for_code_block(installed.code_block),
            Some(function_executable)
        );
        let registered = vm
            .code_blocks
            .get(installed.code_block)
            .expect("registered function call code block")
            .code_block();
        assert_eq!(
            registered.link_context().owner_executable,
            Some(function_executable)
        );
        assert_eq!(
            registered.link_context().specialization,
            CodeSpecialization::Call
        );
        assert_eq!(
            registered.lifecycle(),
            CodeBlockLifecycleState::BaselineInstalled
        );
        assert_eq!(
            function_record
                .executable()
                .script
                .base
                .entrypoints
                .call
                .interpreter,
            Some(crate::bytecode::InterpreterEntrypointSlot(0))
        );
        let installed_construct = function_record
            .installed_construct_code()
            .expect("installed function construct code");
        assert_eq!(
            installed_construct.specialization,
            CodeSpecialization::Construct
        );
        assert_ne!(installed_construct.code_block, installed.code_block);
        assert_eq!(
            vm.executable_registry()
                .executable_for_code_block(installed_construct.code_block),
            Some(function_executable)
        );
        let registered_construct = vm
            .code_blocks
            .get(installed_construct.code_block)
            .expect("registered function construct code block")
            .code_block();
        assert_eq!(
            registered_construct.link_context().owner_executable,
            Some(function_executable)
        );
        assert_eq!(
            registered_construct.link_context().specialization,
            CodeSpecialization::Construct
        );
        assert_eq!(
            registered_construct.lifecycle(),
            CodeBlockLifecycleState::LinkedInterpreter
        );
        assert!(function_record.executable().construct_code.is_some());

        let executable_allocation = vm
            .heap()
            .allocation_records()
            .iter()
            .find(|record| record.response.cell == function_executable.0)
            .expect("function executable heap allocation");
        assert_eq!(
            executable_allocation.response.metadata.type_info.cell_type,
            CellType::Executable
        );
        assert!(executable_allocation.published);

        let code_block_allocation = vm
            .heap()
            .allocation_records()
            .iter()
            .find(|record| record.response.cell == installed.code_block.0)
            .expect("function code block heap allocation");
        assert_eq!(
            code_block_allocation.response.metadata.type_info.cell_type,
            CellType::CodeBlock
        );
        assert!(code_block_allocation.published);

        let construct_code_block_allocation = vm
            .heap()
            .allocation_records()
            .iter()
            .find(|record| record.response.cell == installed_construct.code_block.0)
            .expect("function construct code block heap allocation");
        assert_eq!(
            construct_code_block_allocation
                .response
                .metadata
                .type_info
                .cell_type,
            CellType::CodeBlock
        );
        assert!(construct_code_block_allocation.published);
    }

