    #[test]
    fn vm_baseline_install_updates_live_source_code_block() {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let (owner, _) =
            register_compiler_produced_program_code_block_with_executable(&mut vm, "42;", 31);
        let slot = JitCodeSlot(31);
        let artifact = baseline_artifact(owner, 31);
        let link_finalization = baseline_link_finalization(&artifact);
        let executable_residency = baseline_executable_residency(&link_finalization);
        let materialization = vm.materialize_baseline_executable_artifact(
            owner,
            &artifact,
            &link_finalization,
            &executable_residency,
        );
        assert_eq!(
            materialization.outcome,
            BaselineExecutableMaterializationOutcome::Accepted
        );

        let record = vm.install_baseline_artifact(
            owner,
            artifact,
            Some(&materialization),
            slot,
            BaselineInstallDependencyPolicy::Allow,
        );

        assert_eq!(
            record.outcome,
            BaselineInstallOutcome::InstalledButEntryDisabled
        );
        assert!(!record.generated_code_entry_enabled);
        assert_eq!(record.artifact.map(|artifact| artifact.owner), Some(owner));
        assert_eq!(
            record.eligibility_proof.map(|proof| proof.owner()),
            Some(owner)
        );
        let registered = vm
            .code_blocks
            .get(owner)
            .expect("registered source code block")
            .code_block();
        assert_eq!(registered.entrypoints().baseline_jit(), Some(slot));
        assert_eq!(
            registered.lifecycle(),
            CodeBlockLifecycleState::BaselineInstalled
        );
        assert_eq!(
            registered.tier_state().current_tier(),
            crate::bytecode::ExecutionTier::BaselineJit
        );
    }

