    #[test]
    fn vm_install_baseline_generated_artifact_derives_owner_continuation_map_from_current_code_block(
    ) {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let code_block = owner_continuation_vm_call_code_block(CoreOpcode::Call);
        let owner = register_test_code_block(&mut vm, code_block);

        let artifact = vm
            .install_baseline_generated_code_artifact(
                owner,
                JitCodeId(46),
                BaselineGeneratedCodeBodyId(146),
                BaselineInstallDependencyPolicy::Allow,
            )
            .unwrap();
        let owner_map = artifact
            .owner_continuation_map()
            .expect("owner continuation map");

        assert_eq!(owner_map.label_count(), 3);
        assert_eq!(owner_map.call_site_count(), 1);
        let site = owner_map
            .call_site_for_bytecode_index(BytecodeIndex::from_offset(1))
            .expect("call continuation site");
        assert_eq!(site.owner, owner);
        assert_eq!(site.opcode, CoreOpcode::Call);
        assert_eq!(site.destination, local(1));
        assert_eq!(site.argument_count_including_this, 1);
        assert_eq!(
            site.resume_bytecode_index,
            Some(BytecodeIndex::from_offset(2))
        );
    }

    #[test]
    fn vm_generated_owner_continuation_map_rederived_after_code_block_snapshot_change() {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let first_code_block = owner_continuation_vm_call_code_block(CoreOpcode::Call);
        let owner = register_test_code_block(&mut vm, first_code_block);

        let first_artifact = vm
            .install_baseline_generated_code_artifact(
                owner,
                JitCodeId(47),
                BaselineGeneratedCodeBodyId(147),
                BaselineInstallDependencyPolicy::Allow,
            )
            .unwrap();
        let first_map = first_artifact
            .owner_continuation_map()
            .expect("first owner continuation map")
            .clone();

        let second_code_block = owner_continuation_vm_call_code_block(CoreOpcode::CallWithThis);
        *vm.code_blocks
            .code_block_mut_for_test(owner)
            .expect("registered mutable code block") = second_code_block;

        let second_artifact = vm
            .install_baseline_generated_code_artifact(
                owner,
                JitCodeId(48),
                BaselineGeneratedCodeBodyId(148),
                BaselineInstallDependencyPolicy::Allow,
            )
            .unwrap();
        let second_map = second_artifact
            .owner_continuation_map()
            .expect("second owner continuation map");

        assert_ne!(
            first_map.bytecode_snapshot(),
            second_map.bytecode_snapshot()
        );
        assert_eq!(second_map.call_site_count(), 1);
        let site = second_map
            .call_site_for_bytecode_index(BytecodeIndex::from_offset(2))
            .expect("call-with-this continuation site");
        assert_eq!(site.opcode, CoreOpcode::CallWithThis);
        assert_eq!(
            site.resume_bytecode_index,
            Some(BytecodeIndex::from_offset(3))
        );
    }

