    #[test]
    fn vm_typed_baseline_generated_entry_matches_interpreter_for_p6_constant_return_sources() {
        let cases = [
            (
                "undefined return",
                "undefined;",
                ExecutionCompletion::Returned(RuntimeValue::undefined()),
                &[CoreOpcode::LoadUndefined, CoreOpcode::Return][..],
            ),
            (
                "null return",
                "null;",
                ExecutionCompletion::Returned(RuntimeValue::null()),
                &[CoreOpcode::LoadNull, CoreOpcode::Return][..],
            ),
            (
                "true return",
                "true;",
                ExecutionCompletion::Returned(RuntimeValue::from_bool(true)),
                &[CoreOpcode::LoadBool, CoreOpcode::Return][..],
            ),
            (
                "false return",
                "false;",
                ExecutionCompletion::Returned(RuntimeValue::from_bool(false)),
                &[CoreOpcode::LoadBool, CoreOpcode::Return][..],
            ),
            (
                "int32 return",
                "7;",
                ExecutionCompletion::Returned(RuntimeValue::from_i32(7)),
                &[CoreOpcode::LoadInt32, CoreOpcode::Return][..],
            ),
        ];

        for (case_index, (name, text, expected, expected_opcodes)) in cases.iter().enumerate() {
            let mut interpreter_vm = Vm::new(VmConfig::interpreter_only());
            let interpreter_completion = interpreter_vm.execute_source(source(text)).unwrap();
            assert_eq!(&interpreter_completion, expected, "{name}");

            let mut vm = Vm::new(VmConfig::baseline_allowed());
            assert_eq!(
                vm.execute_source(source(text)).unwrap(),
                interpreter_completion
            );
            let owner = vm.tiering_integration().diagnostics()[0].owner;
            let code_block = vm
                .code_blocks
                .get(owner)
                .expect("registered source code block")
                .code_block()
                .clone();
            assert_code_block_contains_core_opcodes(&code_block, expected_opcodes);
            let fallback_count_before = vm.tiering_integration().fallback_records().len();
            let artifact = install_typed_baseline_for_test(&mut vm, owner, 150 + case_index as u64);
            let mut host = InterpreterDispatchMustNotRun;

            let completion =
                execute_registered_code_block_with_host(&mut vm, owner, &code_block, &mut host);

            assert_eq!(&completion, expected, "{name}");
            assert_eq!(
                vm.tiering_integration().fallback_records().len(),
                fallback_count_before,
                "{name}"
            );
            assert_latest_generated_entry_evidence(&vm, owner, artifact);
            assert_eq!(
                vm.tiering_integration()
                    .diagnostics()
                    .last()
                    .expect("generated completion diagnostic")
                    .completion,
                CompletionDiagnostic::Returned,
                "{name}"
            );
        }
    }

