    #[test]
    fn vm_typed_baseline_generated_entry_matches_interpreter_for_p6_unary_minus_primitive_coercion_source(
    ) {
        let cases = [
            ("-true;", Some(RuntimeValue::from_i32(-1)), 191, false),
            ("-null;", Some(RuntimeValue::from_double(-0.0)), 192, false),
            ("-void 0;", None, 193, true),
        ];

        for (text, expected, id, expects_void) in cases {
            let mut interpreter_vm = Vm::new(VmConfig::interpreter_only());
            let expected_completion = interpreter_vm.execute_source(source(text)).unwrap();
            if let Some(expected) = expected {
                assert_eq!(
                    expected_completion,
                    ExecutionCompletion::Returned(expected),
                    "{text}"
                );
            } else {
                assert!(
                    completion_returned_double_nan(&expected_completion),
                    "{text}"
                );
            }

            let mut vm = Vm::new(VmConfig::baseline_allowed());
            let first_completion = vm.execute_source(source(text)).unwrap();
            if let Some(expected) = expected {
                assert_eq!(
                    first_completion,
                    ExecutionCompletion::Returned(expected),
                    "{text}"
                );
            } else {
                assert!(completion_returned_double_nan(&first_completion), "{text}");
            }
            let owner = vm.tiering_integration().diagnostics()[0].owner;
            let code_block = vm
                .code_blocks
                .get(owner)
                .expect("registered source code block")
                .code_block()
                .clone();
            assert_code_block_contains_core_opcodes(
                &code_block,
                &[CoreOpcode::NegateNumber, CoreOpcode::Return],
            );
            if expects_void {
                assert_code_block_contains_core_opcodes(&code_block, &[CoreOpcode::Void]);
            }
            let fallback_count_before = vm.tiering_integration().fallback_records().len();
            let artifact = install_typed_baseline_for_test(&mut vm, owner, id);
            let mut host = InterpreterDispatchMustNotRun;

            let completion =
                execute_registered_code_block_with_host(&mut vm, owner, &code_block, &mut host);

            if let Some(expected) = expected {
                assert_eq!(
                    completion,
                    ExecutionCompletion::Returned(expected),
                    "{text}"
                );
            } else {
                assert!(completion_returned_double_nan(&completion), "{text}");
            }
            assert_eq!(
                vm.tiering_integration().fallback_records().len(),
                fallback_count_before,
                "{text}"
            );
            assert_latest_generated_entry_evidence(&vm, owner, artifact);
        }
    }

