    #[test]
    fn vm_typed_baseline_generated_success_does_not_allocate_heap_or_mutate_roots() {
        let code_block = linked_p6_test_code_block(vec![
            typed_core_instruction_with_operands(
                0,
                CoreOpcode::LoadInt32,
                vec![Operand::Register(local(0)), Operand::SignedImmediate(6)],
            ),
            typed_core_instruction_with_operands(
                1,
                CoreOpcode::LoadInt32,
                vec![Operand::Register(local(1)), Operand::SignedImmediate(7)],
            ),
            typed_core_instruction_with_operands(
                2,
                CoreOpcode::MulInt32,
                vec![
                    Operand::Register(local(2)),
                    Operand::Register(local(0)),
                    Operand::Register(local(1)),
                ],
            ),
            typed_load_double_instruction(3, local(3), 1.5),
            typed_core_instruction_with_operands(
                4,
                CoreOpcode::AddInt32,
                vec![
                    Operand::Register(local(4)),
                    Operand::Register(local(2)),
                    Operand::Register(local(3)),
                ],
            ),
            typed_core_instruction_with_operands(
                5,
                CoreOpcode::LoadInt32,
                vec![Operand::Register(local(5)), Operand::SignedImmediate(2)],
            ),
            typed_core_instruction_with_operands(
                6,
                CoreOpcode::BitOrInt32,
                vec![
                    Operand::Register(local(6)),
                    Operand::Register(local(3)),
                    Operand::Register(local(5)),
                ],
            ),
            typed_core_instruction_with_operands(
                7,
                CoreOpcode::GreaterThanInt32,
                vec![
                    Operand::Register(local(7)),
                    Operand::Register(local(4)),
                    Operand::Register(local(6)),
                ],
            ),
            typed_core_instruction_with_operands(
                8,
                CoreOpcode::Return,
                vec![Operand::Register(local(7))],
            ),
        ]);
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let owner = register_test_code_block(&mut vm, code_block.clone());
        install_typed_baseline_for_test(&mut vm, owner, 171);
        let global_object = vm.allocate_global_object_cell().unwrap();
        vm.record_source_global_object(global_object).unwrap();
        let entry = vm
            .execution
            .enter(ExecutionEntryRecord::Program(ProgramExecutionEntry {
                code_block: owner,
                global_object,
                this_value: RuntimeValue::undefined(),
            }));
        let frame = vm
            .execution
            .push_frame(
                &mut vm.registers,
                FramePushRequest {
                    code_block: Some(owner),
                    callee: None,
                    callee_value: None,
                    lexical_scope: None,
                    shape: code_block.unlinked().frame(),
                    argument_count_including_this: 1,
                    argument_values: Vec::new(),
                    start_bytecode_index: Some(BytecodeIndex::from_offset(0)),
                    return_bytecode_index: None,
                },
            )
            .unwrap();
        let boundary_snapshot = HeapMutationSnapshot::capture(&vm);
        boundary_snapshot.assert_no_gc_scope_depth(0);

        let completion = vm.execute_code_block(
            owner,
            &code_block,
            &mut InterpreterDispatchMustNotRun,
            DispatchConfig::default(),
        );

        assert_eq!(
            completion,
            ExecutionCompletion::Returned(RuntimeValue::from_bool(true))
        );
        assert_no_gc_execution_depth_observed(&vm, VmNoGcExecutionPathForTest::GeneratedEntry, 1);
        boundary_snapshot.assert_heap_and_targeted_roots_unchanged(&vm);
        boundary_snapshot.assert_current_no_gc_scope_depth(&vm, 0);
        // C++ JSC divergence (removed assertion): register/stack stores are not
        // barriered in C++ (op_mov -> storeValue, no barrier), so there is no
        // per-write handoff to accumulate. The faithful invariant this test now
        // proves is that a successful generated entry mutates neither the heap
        // nor the targeted root set (asserted above).
        if vm.execution.frame(frame).is_some() {
            vm.execution.pop_frame(&mut vm.registers, frame).unwrap();
        }
        vm.execution.leave(entry).unwrap();
    }

