    #[test]
    fn vm_generated_runtime_helper_execute_code_block_dispatches_installed_typeof() {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let (object, object_value, object_cell) = heap_bound_object_value(&mut vm.heap);
        let (owner, code_block) = register_runtime_helper_type_of_code_block_with_root_map(&mut vm);
        let artifact = vm
            .install_baseline_generated_code_artifact(
                owner,
                JitCodeId(910),
                BaselineGeneratedCodeBodyId(1010),
                BaselineInstallDependencyPolicy::Allow,
            )
            .unwrap();
        let fallback_count_before = vm.tiering_integration().fallback_records().len();
        let (_other_object, other_value, other_cell) = heap_bound_object_value(&mut vm.heap);
        let mut host = RecordingCoreHost::with_function_blocks_and_strings(
            Vec::new(),
            HashMap::from([(1, "object".to_owned()), (2, "string".to_owned())]),
        );

        let (completion, boundary_snapshot) =
            execute_registered_code_block_with_boundary_snapshot_and_arguments(
                &mut vm,
                owner,
                &code_block,
                &mut host,
                vec![other_value, object_value],
            );

        let object_type = if let ExecutionCompletion::Returned(value) = completion {
            value
        } else {
            unreachable!("expected returned typeof string, got {completion:?}");
        };
        assert_heap_published_cell_type(&vm, object_type, CellType::String);
        assert!(vm.heap().allocation_records().len() > boundary_snapshot.allocation_record_count);
        assert_eq!(
            vm.heap().targeted_roots().records(),
            boundary_snapshot.targeted_roots.as_slice()
        );
        assert!(host.dispatch_roots[0]
            .iter()
            .any(|record| record.target == object_cell));
        assert!(!host.dispatch_roots[0]
            .iter()
            .any(|record| record.target == other_cell));
        assert!(!vm
            .heap()
            .targeted_roots()
            .records()
            .iter()
            .any(|record| record.target == object_cell));
        boundary_snapshot.assert_no_gc_scope_depth(0);
        boundary_snapshot.assert_current_no_gc_scope_depth(&vm, 0);
        assert_eq!(
            vm.tiering_integration().fallback_records().len(),
            fallback_count_before,
            "runtime-helper handoff should not be recorded as a generated fallback"
        );
        assert_latest_generated_entry_evidence(&vm, owner, artifact);
        let generated_artifact = vm
            .tiering_integration()
            .entry_decisions()
            .last()
            .and_then(|record| record.baseline_entry_gate.as_ref())
            .and_then(|gate| gate.generated_artifact.clone())
            .expect("generated artifact evidence");
        let (helper_opcode, helper_root_count) = generated_artifact
            .runtime_helper_plan()
            .and_then(|plan| {
                plan.proof_at(0)
                    .map(|proof| (proof.proof.contract.opcode, proof.proof.root_count))
            })
            .expect("typeof helper proof");
        assert_eq!(helper_opcode, CoreOpcode::TypeOf);
        assert_eq!(helper_root_count, 2);
        assert_runtime_string_equals(&mut vm, &mut host, object_type, 1, "object");

        let fallback_count_before_repeat = vm.tiering_integration().fallback_records().len();
        let repeated = execute_registered_code_block_with_host_and_arguments(
            &mut vm,
            owner,
            &code_block,
            &mut host,
            vec![RuntimeValue::undefined(), object_value],
        );
        assert_eq!(repeated, ExecutionCompletion::Returned(object_type));
        assert_eq!(
            vm.tiering_integration().fallback_records().len(),
            fallback_count_before_repeat,
            "runtime-helper handoff should not be recorded as a generated fallback"
        );

        let fallback_count_before_string_type = vm.tiering_integration().fallback_records().len();
        let (string_completion, string_boundary_snapshot) =
            execute_registered_code_block_with_boundary_snapshot_and_arguments(
                &mut vm,
                owner,
                &code_block,
                &mut host,
                vec![RuntimeValue::undefined(), object_type],
            );
        let string_type = if let ExecutionCompletion::Returned(value) = string_completion {
            value
        } else {
            unreachable!("expected returned typeof string, got {string_completion:?}");
        };
        assert_heap_published_cell_type(&vm, string_type, CellType::String);
        assert_eq!(
            vm.heap().targeted_roots().records(),
            string_boundary_snapshot.targeted_roots.as_slice()
        );
        string_boundary_snapshot.assert_current_no_gc_scope_depth(&vm, 0);
        assert_eq!(
            vm.tiering_integration().fallback_records().len(),
            fallback_count_before_string_type,
            "runtime-helper handoff should not be recorded as a generated fallback"
        );
        assert_runtime_string_equals(&mut vm, &mut host, string_type, 2, "string");
        drop(object);
    }

    #[test]
    fn vm_generated_runtime_helper_typeof_handoff_roots_heap_throw_and_cleans_helper_roots() {
        struct ThrowingTypeOfHost {
            core: CoreOpcodeDispatchHost,
            thrown: RuntimeValue,
            dispatches: Vec<(CallFrameId, BytecodeIndex, Option<CoreOpcode>)>,
            dispatch_roots: Vec<Vec<TargetedRootRecord>>,
        }

        impl DispatchHost for ThrowingTypeOfHost {
            fn targeted_register_roots(
                &mut self,
                heap: &mut Heap,
                snapshot: &ExecutionRootSnapshot,
            ) -> Result<Vec<TargetedRootRecord>, ExecutionError> {
                self.core.targeted_register_roots(heap, snapshot)
            }

            fn dispatch_instruction(
                &mut self,
                state: &mut DispatchState<'_>,
                instruction: DispatchInstruction<'_>,
            ) -> DispatchOutcome {
                self.dispatches.push((
                    instruction.frame,
                    instruction.bytecode_index,
                    CoreOpcode::from_opcode(instruction.opcode),
                ));
                self.dispatch_roots
                    .push(state.heap.targeted_roots().records().to_vec());
                DispatchOutcome::Throw(self.thrown)
            }
        }

        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let (_thrown_string, thrown, thrown_cell) =
            heap_bound_string_value(&mut vm.heap, "generated helper throw");
        let (_object, object_value, object_cell) = heap_bound_object_value(&mut vm.heap);
        let (owner, code_block) = register_runtime_helper_type_of_code_block_with_root_map(&mut vm);
        let artifact = vm
            .install_baseline_generated_code_artifact(
                owner,
                JitCodeId(921),
                BaselineGeneratedCodeBodyId(1021),
                BaselineInstallDependencyPolicy::Allow,
            )
            .unwrap();
        let helper_proof = artifact
            .runtime_helper_plan()
            .and_then(|plan| plan.proof_at(0).copied())
            .expect("typeof helper proof");
        assert_eq!(helper_proof.proof.contract.opcode, CoreOpcode::TypeOf);
        assert!(helper_proof.proof.may_throw);
        assert_eq!(
            helper_proof.proof.may_throw,
            helper_proof.proof.contract.effects.may_throw
        );
        let fallback_count_before = vm.tiering_integration().fallback_records().len();
        let mut host = ThrowingTypeOfHost {
            core: CoreOpcodeDispatchHost::new(),
            thrown,
            dispatches: Vec::new(),
            dispatch_roots: Vec::new(),
        };

        let (completion, boundary_snapshot) =
            execute_registered_code_block_with_boundary_snapshot_and_arguments(
                &mut vm,
                owner,
                &code_block,
                &mut host,
                vec![RuntimeValue::undefined(), object_value],
            );

        let pending = if let ExecutionCompletion::Threw(pending) = completion {
            pending
        } else {
            unreachable!("expected helper throw, got {completion:?}");
        };
        assert_eq!(pending.value, thrown);
        assert_eq!(vm.exception_state().pending(), Some(pending));
        assert_eq!(
            host.dispatches,
            vec![(
                vm.exception_state()
                    .unwind_state()
                    .origin_frame()
                    .expect("throw origin frame"),
                BytecodeIndex::from_offset(0),
                Some(CoreOpcode::TypeOf)
            )]
        );
        assert_eq!(
            vm.exception_state().unwind_state().popped_frames(),
            &[host.dispatches[0].0]
        );
        assert!(host.dispatch_roots[0]
            .iter()
            .any(|record| record.target == object_cell));
        assert!(!vm
            .heap()
            .targeted_roots()
            .records()
            .iter()
            .any(|record| record.target == object_cell));

        let exception_plan = vm
            .exception_state()
            .targeted_root_plan(vm.heap())
            .expect("exception targeted root plan");
        assert_eq!(exception_plan.records().len(), 3);
        assert!(exception_plan
            .records()
            .iter()
            .all(|record| record.target == thrown_cell));
        assert_eq!(exception_targeted_roots(&vm), exception_plan.records());
        let non_exception_roots = vm
            .heap()
            .targeted_roots()
            .records()
            .iter()
            .copied()
            .filter(|record| !exception_plan.records().contains(record))
            .collect::<Vec<_>>();
        assert_eq!(non_exception_roots, boundary_snapshot.targeted_roots);
        boundary_snapshot.assert_no_gc_scope_depth(0);
        boundary_snapshot.assert_current_no_gc_scope_depth(&vm, 0);
        assert_eq!(
            vm.tiering_integration().fallback_records().len(),
            fallback_count_before,
            "runtime-helper handoff should not be recorded as a generated fallback"
        );
        assert_latest_generated_entry_evidence(&vm, owner, artifact);
    }

    #[test]
    fn vm_generated_runtime_helper_typeof_failure_cleans_helper_roots_and_restores_no_gc() {
        struct FailingTypeOfHost {
            core: CoreOpcodeDispatchHost,
            dispatches: Vec<(CallFrameId, BytecodeIndex, Option<CoreOpcode>)>,
            dispatch_roots: Vec<Vec<TargetedRootRecord>>,
            dispatch_heap_no_gc_depths: Vec<u32>,
        }

        impl DispatchHost for FailingTypeOfHost {
            fn targeted_register_roots(
                &mut self,
                heap: &mut Heap,
                snapshot: &ExecutionRootSnapshot,
            ) -> Result<Vec<TargetedRootRecord>, ExecutionError> {
                self.core.targeted_register_roots(heap, snapshot)
            }

            fn dispatch_instruction(
                &mut self,
                state: &mut DispatchState<'_>,
                instruction: DispatchInstruction<'_>,
            ) -> DispatchOutcome {
                self.dispatches.push((
                    instruction.frame,
                    instruction.bytecode_index,
                    CoreOpcode::from_opcode(instruction.opcode),
                ));
                self.dispatch_heap_no_gc_depths
                    .push(state.heap.no_gc_scope_depth());
                self.dispatch_roots
                    .push(state.heap.targeted_roots().records().to_vec());
                DispatchOutcome::Fail(ExecutionError::ExpectedObject)
            }
        }

        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let (_object, object_value, object_cell) = heap_bound_object_value(&mut vm.heap);
        let (owner, code_block) = register_runtime_helper_type_of_code_block_with_root_map(&mut vm);
        let artifact = vm
            .install_baseline_generated_code_artifact(
                owner,
                JitCodeId(922),
                BaselineGeneratedCodeBodyId(1022),
                BaselineInstallDependencyPolicy::Allow,
            )
            .unwrap();
        let mut host = FailingTypeOfHost {
            core: CoreOpcodeDispatchHost::new(),
            dispatches: Vec::new(),
            dispatch_roots: Vec::new(),
            dispatch_heap_no_gc_depths: Vec::new(),
        };

        let (completion, boundary_snapshot) =
            execute_registered_code_block_with_boundary_snapshot_and_arguments(
                &mut vm,
                owner,
                &code_block,
                &mut host,
                vec![RuntimeValue::undefined(), object_value],
            );

        assert_eq!(
            completion,
            ExecutionCompletion::Failed(ExecutionError::ExpectedObject)
        );
        assert_eq!(
            host.dispatches
                .first()
                .map(|(_, index, opcode)| (*index, *opcode)),
            Some((BytecodeIndex::from_offset(0), Some(CoreOpcode::TypeOf)))
        );
        assert_eq!(host.dispatch_heap_no_gc_depths, vec![0]);
        assert!(host.dispatch_roots[0]
            .iter()
            .any(|record| record.target == object_cell));
        assert!(!vm
            .heap()
            .targeted_roots()
            .records()
            .iter()
            .any(|record| record.target == object_cell));
        boundary_snapshot.assert_no_gc_scope_depth(0);
        boundary_snapshot.assert_current_no_gc_scope_depth(&vm, 0);
        assert_latest_generated_entry_evidence(&vm, owner, artifact);
    }

    #[test]
    fn vm_generated_runtime_helper_single_dispatch_disallowed_throw_restores_exception_and_no_gc() {
        struct ThrowingHost {
            thrown: RuntimeValue,
            dispatch_roots: Vec<Vec<TargetedRootRecord>>,
            dispatch_heap_no_gc_depths: Vec<u32>,
        }

        impl DispatchHost for ThrowingHost {
            fn dispatch_instruction(
                &mut self,
                state: &mut DispatchState<'_>,
                _instruction: DispatchInstruction<'_>,
            ) -> DispatchOutcome {
                self.dispatch_heap_no_gc_depths
                    .push(state.heap.no_gc_scope_depth());
                self.dispatch_roots
                    .push(state.heap.targeted_roots().records().to_vec());
                DispatchOutcome::Throw(self.thrown)
            }
        }

        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let (_thrown_string, thrown, thrown_cell) =
            heap_bound_string_value(&mut vm.heap, "disallowed helper throw");
        let (owner, code_block) =
            register_runtime_helper_new_object_code_block_with_root_map(&mut vm);
        let (entry, frame) = enter_runtime_helper_program_frame(&mut vm, owner, &code_block);
        let boundary_snapshot = HeapMutationSnapshot::capture(&vm);
        let region = vm.enter_no_gc_execution_region();
        let mut host = ThrowingHost {
            thrown,
            dispatch_roots: Vec::new(),
            dispatch_heap_no_gc_depths: Vec::new(),
        };

        let outcome = vm.execute_generated_single_dispatch_exit_transaction(
            GeneratedSingleDispatchExitTransaction {
                resume: GeneratedSingleDispatchResume {
                    owner,
                    frame,
                    bytecode_index: BytecodeIndex::from_offset(0),
                },
                requires_no_gc_exit_reentry: true,
                may_throw: false,
            },
            &code_block,
            &mut host,
            |_, _| Ok(()),
        );

        assert_eq!(
            outcome,
            SingleDispatchOutcome::Failed(ExecutionError::BaselineGeneratedExecutionRejected)
        );
        assert_eq!(host.dispatch_heap_no_gc_depths, vec![0]);
        assert!(!host.dispatch_roots[0]
            .iter()
            .any(|record| record.target == thrown_cell));
        assert_eq!(vm.exception_state().pending(), None);
        assert!(exception_targeted_roots(&vm).is_empty());
        assert_vm_and_heap_no_gc_scope_depth(&vm, 1);
        boundary_snapshot.assert_heap_and_targeted_roots_unchanged(&vm);
        vm.leave_no_gc_execution_region(region).unwrap();
        boundary_snapshot.assert_current_no_gc_scope_depth(&vm, 0);
        if vm.execution.frame(frame).is_some() {
            vm.execution.pop_frame(&mut vm.registers, frame).unwrap();
        }
        vm.execution.leave(entry).unwrap();
    }

    #[test]
    fn vm_generated_single_dispatch_caught_throw_clears_unwind_pending_exception_root() {
        struct ThrowThenCoreHost {
            core: CoreOpcodeDispatchHost,
            thrown: RuntimeValue,
            dispatches: Vec<(BytecodeIndex, Option<CoreOpcode>)>,
        }

        impl DispatchHost for ThrowThenCoreHost {
            fn dispatch_instruction(
                &mut self,
                state: &mut DispatchState<'_>,
                instruction: DispatchInstruction<'_>,
            ) -> DispatchOutcome {
                self.dispatches.push((
                    instruction.bytecode_index,
                    CoreOpcode::from_opcode(instruction.opcode),
                ));
                if self.dispatches.len() == 1 {
                    DispatchOutcome::Throw(self.thrown)
                } else {
                    self.core.dispatch_instruction(state, instruction)
                }
            }
        }

        let catch_register = local(0);
        let code_block = linked_p6_test_code_block(vec![
            typed_core_instruction(0, CoreOpcode::NewObject),
            typed_core_instruction_with_operands(
                1,
                CoreOpcode::TakeException,
                vec![Operand::Register(catch_register)],
            ),
            typed_core_instruction_with_operands(
                2,
                CoreOpcode::Return,
                vec![Operand::Register(catch_register)],
            ),
        ])
        .with_side_tables(LinkedSideTables {
            handlers: vec![HandlerInfo {
                range: HandlerRange::Bytecode(BytecodeRange {
                    start: BytecodeIndex::from_offset(0),
                    end: BytecodeIndex::from_offset(1),
                }),
                target: HandlerTarget::Bytecode(BytecodeIndex::from_offset(1)),
                kind: HandlerKind::Catch,
            }],
            ..LinkedSideTables::default()
        });
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let (_thrown_string, thrown, thrown_cell) =
            heap_bound_string_value(&mut vm.heap, "caught generated throw");
        let owner = register_test_code_block(&mut vm, code_block.clone());
        let (entry, frame) = enter_runtime_helper_program_frame(&mut vm, owner, &code_block);
        let region = vm.enter_no_gc_execution_region();
        let mut host = ThrowThenCoreHost {
            core: CoreOpcodeDispatchHost::new(),
            thrown,
            dispatches: Vec::new(),
        };

        let outcome = vm.execute_generated_single_dispatch_exit_transaction(
            GeneratedSingleDispatchExitTransaction {
                resume: GeneratedSingleDispatchResume {
                    owner,
                    frame,
                    bytecode_index: BytecodeIndex::from_offset(0),
                },
                requires_no_gc_exit_reentry: true,
                may_throw: true,
            },
            &code_block,
            &mut host,
            |_, _| Ok(()),
        );
        assert_eq!(
            outcome,
            SingleDispatchOutcome::Jump(BytecodeIndex::from_offset(1))
        );

        let completion = vm.finish_generated_single_dispatch_handoff_in_current_region(
            GeneratedSingleDispatchResume {
                owner,
                frame,
                bytecode_index: BytecodeIndex::from_offset(0),
            },
            outcome,
            &code_block,
            &mut host,
            DispatchConfig::default(),
        );

        assert_eq!(completion, ExecutionCompletion::Returned(thrown));
        assert_eq!(
            host.dispatches,
            vec![
                (BytecodeIndex::from_offset(0), Some(CoreOpcode::NewObject)),
                (
                    BytecodeIndex::from_offset(1),
                    Some(CoreOpcode::TakeException)
                ),
                (BytecodeIndex::from_offset(2), Some(CoreOpcode::Return)),
            ]
        );
        assert_eq!(vm.exception_state().pending(), None);
        assert_eq!(
            vm.exception_state().last(),
            Some(PendingException { value: thrown })
        );
        assert!(!vm
            .exception_state()
            .root_descriptors(vm.heap().id())
            .iter()
            .any(|root| root.source == ExceptionRootSource::UnwindPendingException));
        vm.leave_no_gc_execution_region(region).unwrap();
        vm.sync_exception_targeted_roots().unwrap();
        assert_eq!(
            exception_targeted_roots(&vm),
            vec![TargetedRootRecord {
                root: ExceptionRootSource::LastException.root_record(vm.heap().id()),
                target: thrown_cell,
            }]
        );

        if vm.execution.frame(frame).is_some() {
            vm.execution.pop_frame(&mut vm.registers, frame).unwrap();
        }
        vm.execution.leave(entry).unwrap();
    }

    #[test]
    fn vm_generated_single_dispatch_after_dispatch_failure_rolls_back_masked_throw_exception() {
        struct ThrowingHost {
            thrown: RuntimeValue,
        }

        impl DispatchHost for ThrowingHost {
            fn dispatch_instruction(
                &mut self,
                _state: &mut DispatchState<'_>,
                _instruction: DispatchInstruction<'_>,
            ) -> DispatchOutcome {
                DispatchOutcome::Throw(self.thrown)
            }
        }

        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let (_thrown_string, thrown, _thrown_cell) =
            heap_bound_string_value(&mut vm.heap, "masked generated throw");
        let code_block =
            linked_p6_test_code_block(vec![typed_core_instruction(0, CoreOpcode::NewObject)]);
        let owner = register_test_code_block(&mut vm, code_block.clone());
        let (entry, frame) = enter_runtime_helper_program_frame(&mut vm, owner, &code_block);
        let boundary_snapshot = HeapMutationSnapshot::capture(&vm);
        let region = vm.enter_no_gc_execution_region();

        let outcome = vm.execute_generated_single_dispatch_exit_transaction(
            GeneratedSingleDispatchExitTransaction {
                resume: GeneratedSingleDispatchResume {
                    owner,
                    frame,
                    bytecode_index: BytecodeIndex::from_offset(0),
                },
                requires_no_gc_exit_reentry: true,
                may_throw: true,
            },
            &code_block,
            &mut ThrowingHost { thrown },
            |_, _| Err(ExecutionError::ExpectedObject),
        );

        assert_eq!(
            outcome,
            SingleDispatchOutcome::Failed(ExecutionError::ExpectedObject)
        );
        assert_eq!(vm.exception_state().pending(), None);
        assert!(vm
            .exception_state()
            .root_descriptors(vm.heap().id())
            .is_empty());
        assert!(exception_targeted_roots(&vm).is_empty());
        assert_vm_and_heap_no_gc_scope_depth(&vm, 1);
        boundary_snapshot.assert_heap_and_targeted_roots_unchanged(&vm);
        vm.leave_no_gc_execution_region(region).unwrap();
        boundary_snapshot.assert_current_no_gc_scope_depth(&vm, 0);
        if vm.execution.frame(frame).is_some() {
            vm.execution.pop_frame(&mut vm.registers, frame).unwrap();
        }
        vm.execution.leave(entry).unwrap();
    }

    #[test]
    fn vm_generated_runtime_helper_execute_code_block_dispatches_installed_load_string() {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let literal_key = 17;
        let literal_text = "runtime literal";
        let (owner, code_block) = register_runtime_helper_load_string_code_block_with_root_map(
            &mut vm,
            literal_key,
            literal_text,
        );
        let artifact = vm
            .install_baseline_generated_code_artifact(
                owner,
                JitCodeId(915),
                BaselineGeneratedCodeBodyId(1015),
                BaselineInstallDependencyPolicy::Allow,
            )
            .unwrap();
        let fallback_count_before = vm.tiering_integration().fallback_records().len();
        let mut host = CoreOpcodeDispatchHost::new();

        let (completion, boundary_snapshot) =
            execute_registered_code_block_with_boundary_snapshot_and_arguments(
                &mut vm,
                owner,
                &code_block,
                &mut host,
                Vec::new(),
            );

        let returned_string = if let ExecutionCompletion::Returned(value) = completion {
            value
        } else {
            unreachable!("expected returned string, got {completion:?}");
        };
        assert_heap_published_cell_type(&vm, returned_string, CellType::String);
        assert!(vm.heap().allocation_records().len() > boundary_snapshot.allocation_record_count);
        assert_eq!(
            vm.heap().targeted_roots().records(),
            boundary_snapshot.targeted_roots.as_slice()
        );
        boundary_snapshot.assert_no_gc_scope_depth(0);
        boundary_snapshot.assert_current_no_gc_scope_depth(&vm, 0);
        assert_eq!(
            vm.tiering_integration().fallback_records().len(),
            fallback_count_before,
            "runtime-helper handoff should not be recorded as a generated fallback"
        );
        assert_latest_generated_entry_evidence(&vm, owner, artifact);
        let generated_artifact = vm
            .tiering_integration()
            .entry_decisions()
            .last()
            .and_then(|record| record.baseline_entry_gate.as_ref())
            .and_then(|gate| gate.generated_artifact.clone())
            .expect("generated artifact evidence");
        let (helper_opcode, helper_root_count) = generated_artifact
            .runtime_helper_plan()
            .and_then(|plan| {
                plan.proof_at(0)
                    .map(|proof| (proof.proof.contract.opcode, proof.proof.root_count))
            })
            .expect("load string helper proof");
        assert_eq!(helper_opcode, CoreOpcode::LoadString);
        assert_eq!(helper_root_count, 1);
        assert_runtime_string_equals(
            &mut vm,
            &mut host,
            returned_string,
            literal_key,
            literal_text,
        );
    }

