    #[test]
    fn vm_ordinary_call_link_direct_dispatch_reuses_metadata_without_new_observation() {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let function_unlinked = js_call_return_41_function_code_block().unlinked().clone();
        let function_blocks = vm
            .install_source_function_blocks(vec![function_unlinked])
            .expect("owned function executable call code");
        let callee_owner = function_blocks[0].id;
        let mut host = RecordingCoreHost::with_function_code_blocks(function_blocks);
        let callee = load_function_value_for_test(&mut vm, &mut host, 0);
        let first_this = create_empty_object_for_test(&mut vm, &mut host);
        let second_this = create_empty_object_for_test(&mut vm, &mut host);
        host.clear_observations();

        let code_block = linked_p6_test_code_block_with_parameters(
            vec![
                typed_core_instruction_with_operands(
                    0,
                    CoreOpcode::CallWithThis,
                    vec![
                        Operand::Register(local(0)),
                        Operand::Register(argument_including_this(1)),
                        Operand::Register(argument_including_this(2)),
                        Operand::UnsignedImmediate(0),
                    ],
                ),
                typed_core_instruction_with_operands(
                    1,
                    CoreOpcode::Return,
                    vec![Operand::Register(local(0))],
                ),
            ],
            3,
        );
        let owner = register_test_code_block(&mut vm, code_block.clone());
        let fallback_count_before = vm.tiering_integration().fallback_records().len();

        let (first_completion, _) =
            execute_registered_code_block_with_boundary_snapshot_and_arguments(
                &mut vm,
                owner,
                &code_block,
                &mut host,
                vec![RuntimeValue::undefined(), callee, first_this],
            );

        assert_eq!(
            first_completion,
            ExecutionCompletion::Returned(RuntimeValue::from_i32(41))
        );
        assert_eq!(vm.tiering_integration().call_observations().len(), 1);
        assert_eq!(
            vm.tiering_integration()
                .call_link_inline_cache_attachment_records()
                .len(),
            1
        );
        assert!(
            !host.core.has_call_observation_record(),
            "cold ordinary call observation should be drained after metadata recording"
        );

        host.clear_observations();
        let call_observation_count_after_first = vm.tiering_integration().call_observations().len();
        let attachment_count_after_first = vm
            .tiering_integration()
            .call_link_inline_cache_attachment_records()
            .len();
        let call_link_probe_miss_count_after_first = vm
            .tiering_integration()
            .generated_call_link_probe_misses()
            .len();
        let call_link_probe_blocked_count_after_first = vm
            .tiering_integration()
            .generated_call_link_probe_blocked_records()
            .len();
        let direct_call_transaction_count_after_first = vm
            .tiering_integration()
            .generated_direct_call_transaction_records()
            .len();

        let (second_completion, boundary_snapshot) =
            execute_registered_code_block_with_boundary_snapshot_and_arguments(
                &mut vm,
                owner,
                &code_block,
                &mut host,
                vec![RuntimeValue::undefined(), callee, second_this],
            );

        assert_eq!(second_completion, first_completion);
        assert_eq!(
            vm.tiering_integration().call_observations().len(),
            call_observation_count_after_first,
            "monomorphic ordinary CallWithThis should use the call-link fast path after metadata attachment"
        );
        assert_eq!(
            vm.tiering_integration()
                .call_link_inline_cache_attachment_records()
                .len(),
            attachment_count_after_first,
            "ordinary call-link fast path should not duplicate active attachment metadata"
        );
        assert_eq!(
            vm.tiering_integration()
                .generated_call_link_probe_misses()
                .len(),
            call_link_probe_miss_count_after_first
        );
        assert_eq!(
            vm.tiering_integration()
                .generated_call_link_probe_blocked_records()
                .len(),
            call_link_probe_blocked_count_after_first
        );
        assert_eq!(
            vm.tiering_integration().fallback_records().len(),
            fallback_count_before
        );
        let direct_call_transactions = vm
            .tiering_integration()
            .generated_direct_call_transaction_records();
        assert_eq!(
            direct_call_transactions.len(),
            direct_call_transaction_count_after_first + 1,
            "ordinary CallLinkInfo fast path should publish one direct-call transaction"
        );
        let direct_call_transaction = direct_call_transactions.last().unwrap();
        assert_eq!(direct_call_transaction.caller, owner);
        let expected_route = match baseline_native_entry_callable_kind_for_owner(&vm, callee_owner)
        {
            Some(BaselineNativeEntryCallableKind::P6Arm64EmittedSemanticCAbiEntry)
                if vm.can_execute_p6_arm64_emitted_native_entry() =>
            {
                VmGeneratedDirectCallTransactionRoute::NativeEntry
            }
            Some(BaselineNativeEntryCallableKind::P6X86_64EmittedSemanticCAbiEntry)
                if vm.can_execute_p6_x86_64_emitted_native_entry() =>
            {
                VmGeneratedDirectCallTransactionRoute::NestedInterpreterFallback
            }
            _ => VmGeneratedDirectCallTransactionRoute::GeneratedEntry,
        };
        assert_eq!(
            direct_call_transaction.route,
            expected_route,
            "host-callable x86_64 metadata keeps this fixture admission-only, host-blocked metadata materializes generated fallback residency, and the ARM64 return seed can call the callee native entry"
        );
        assert!(
            !host.core.has_call_observation_record(),
            "fast ordinary call-link dispatch must drain the interpreter's pending call observation"
        );
        boundary_snapshot.assert_no_gc_scope_depth(0);
        boundary_snapshot.assert_current_no_gc_scope_depth(&vm, 0);
    }

