    fn vm_generated_nullish_not_equal_loop_uses_iterative_resume_trampoline() {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let function_unlinked = js_call_return_41_function_code_block().unlinked().clone();
        let function_blocks = vm
            .install_source_function_blocks(vec![function_unlinked])
            .expect("owned function executable call code");
        let mut host = RecordingCoreHost::with_function_code_blocks(function_blocks);
        let callee = load_function_value_for_test(&mut vm, &mut host, 0);
        let object = create_empty_object_for_test(&mut vm, &mut host);
        host.clear_observations();

        let code_block =
            generated_js_call_loop_return_sum_with_nullish_not_equal_condition_code_block();
        let owner = register_test_code_block(&mut vm, code_block.clone());
        let artifact = install_typed_baseline_for_test(&mut vm, owner, 1227);
        let fallback_count_before = vm.tiering_integration().fallback_records().len();
        let call_observation_count_before = vm.tiering_integration().call_observations().len();
        let call_link_attachment_count_before = vm
            .tiering_integration()
            .call_link_inline_cache_attachment_records()
            .len();
        let call_link_probe_miss_count_before = vm
            .tiering_integration()
            .generated_call_link_probe_misses()
            .len();

        let (completion, boundary_snapshot) =
            execute_registered_code_block_with_boundary_snapshot_and_arguments(
                &mut vm,
                owner,
                &code_block,
                &mut host,
                vec![RuntimeValue::undefined(), callee, object],
            );

        assert_eq!(
            completion,
            ExecutionCompletion::Returned(RuntimeValue::from_i32(41 * 512))
        );
        assert_eq!(
            host.dispatches
                .iter()
                .filter(|(_, index, opcode)| {
                    *index == BytecodeIndex::from_offset(7) && *opcode == Some(CoreOpcode::NotEqual)
                })
                .count(),
            0,
            "object != null is a no-call loose-equality case and should stay in generated code"
        );
        assert_eq!(
            host.dispatches
                .iter()
                .filter(|(_, index, opcode)| {
                    *index == BytecodeIndex::from_offset(9) && *opcode == Some(CoreOpcode::Call)
                })
                .count(),
            1,
            "the repeated same-frame generated resumes should reuse the attached call-link sidecar without recursive host dispatch"
        );
        assert_eq!(
            vm.tiering_integration().fallback_records().len(),
            fallback_count_before,
            "the generated loop should not fall back after setup telemetry"
        );
        assert_eq!(
            vm.tiering_integration().call_observations().len(),
            call_observation_count_before + 1
        );
        assert_eq!(
            vm.tiering_integration()
                .call_link_inline_cache_attachment_records()
                .len()
                - call_link_attachment_count_before,
            1
        );
        assert_eq!(
            vm.tiering_integration()
                .generated_call_link_probe_misses()
                .len(),
            call_link_probe_miss_count_before
        );
        assert_eq!(vm.execution_context_stack().entry_depth(), 0);
        assert_eq!(vm.execution_context_stack().frame_depth(), 0);
        boundary_snapshot.assert_no_gc_scope_depth(0);
        boundary_snapshot.assert_current_no_gc_scope_depth(&vm, 0);
        assert_latest_generated_entry_evidence(&vm, owner, artifact.clone());
    }

