    #[cfg(all(unix, target_arch = "x86_64"))]
    #[test]
    fn vm_p16c_cold_generated_js_call_handoff_uses_vm_owned_nested_callee_entry_and_records_metadata(
    ) {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let function_unlinked = p6_int32_arithmetic_code_block().unlinked().clone();
        let function_blocks = vm
            .install_source_function_blocks(vec![function_unlinked])
            .expect("owned P16c function code");
        let callee_owner = function_blocks[0].id;
        let mut host = RecordingCoreHost::with_function_code_blocks(function_blocks);
        let callee = load_function_value_for_test(&mut vm, &mut host, 0);
        host.clear_observations();

        let code_block = generated_js_call_return_consumed_code_block();
        let owner = register_test_code_block(&mut vm, code_block.clone());
        let artifact = install_typed_baseline_for_test(&mut vm, owner, 2_261);
        let bytecode_snapshot = artifact.eligibility_proof.bytecode_snapshot_fingerprint();
        let counts_before = p6_semantic_install_side_effect_counts(&vm);
        let auto_count_before = vm
            .tiering_integration()
            .baseline_entry_auto_materializations()
            .len();
        let entry_decision_count_before = vm.tiering_integration().entry_decisions().len();

        let (completion, boundary_snapshot) =
            execute_registered_code_block_with_boundary_snapshot_and_arguments(
                &mut vm,
                owner,
                &code_block,
                &mut host,
                vec![RuntimeValue::undefined(), callee],
            );

        assert_eq!(
            completion,
            ExecutionCompletion::Returned(RuntimeValue::from_i32(43))
        );
        assert_eq!(
            host.dispatches
                .iter()
                .map(|(_, index, opcode)| (*index, *opcode))
                .collect::<Vec<_>>(),
            vec![(BytecodeIndex::from_offset(1), Some(CoreOpcode::Call))],
            "cold generated JS-call handoff should resume the caller in generated code after the VM-owned call boundary"
        );
        assert_eq!(
            p6_semantic_install_side_effect_counts(&vm),
            P6SemanticInstallSideEffectCounts {
                materializations: counts_before.materializations + 2,
                platform_residencies: counts_before.platform_residencies + 2,
                installs: counts_before.installs + 2,
                readiness: counts_before.readiness + 4,
                provenance: counts_before.provenance + 2,
            }
        );
        let supplemental_record = vm
            .tiering_integration()
            .baseline_entry_auto_materializations()[auto_count_before..]
            .iter()
            .find(|record| record.owner == owner)
            .expect("P16c generated caller supplemental native materialization");
        assert_eq!(
            supplemental_record.native,
            BaselineEntryAutoNativeMaterializationOutcome::Installed
        );
        assert_eq!(supplemental_record.generated, None);
        let callee_decision = vm.tiering_integration().entry_decisions()
            [entry_decision_count_before..]
            .iter()
            .find(|decision| decision.owner == callee_owner)
            .expect("P16c cold generated callee Function entry decision");
        assert_eq!(callee_decision.entry_kind, ExecutionEntryKind::Function);
        assert_eq!(
            callee_decision.decision,
            TierEntryDecision::EnterNative {
                tier: JitType::Baseline
            }
        );
        assert_eq!(
            callee_decision.execution_path,
            TierEntryExecutionPath::NativeCode(JitType::Baseline)
        );
        let [observation] = vm.tiering_integration().call_observations() else {
            panic!("expected one P16c cold generated call observation");
        };
        assert_eq!(observation.owner, owner);
        assert_eq!(observation.bytecode_index, BytecodeIndex::from_offset(1));
        assert_eq!(observation.opcode, CoreOpcode::Call);
        assert_eq!(observation.bytecode_snapshot, bytecode_snapshot);
        assert_eq!(
            observation.descriptor.outcome,
            CallObservationOutcome::Returned
        );
        assert_eq!(observation.descriptor.target_code_block, Some(callee_owner));
        assert_eq!(
            vm.tiering_integration()
                .call_link_boundary_validation_records()
                .len(),
            1
        );
        assert_eq!(
            vm.tiering_integration()
                .call_link_attachment_plan_records()
                .len(),
            1
        );
        assert_eq!(
            vm.tiering_integration()
                .call_link_inline_cache_attachment_records()
                .len(),
            1
        );
        boundary_snapshot.assert_no_gc_scope_depth(0);
        boundary_snapshot.assert_current_no_gc_scope_depth(&vm, 0);
        assert_eq!(vm.gc_execution_state().no_gc_scope_depth(), 0);
        assert_eq!(vm.heap().no_gc_scope_depth(), 0);
    }

