    #[cfg(all(unix, target_arch = "x86_64"))]
    #[test]
    fn vm_p16c_cold_real_p9_js_call_exit_uses_vm_owned_nested_callee_entry_and_records_metadata() {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let (callee_owner, callee_code_block) =
            register_vm_owned_function_code_block(&mut vm, p6_int32_arithmetic_code_block());
        let mut host =
            RecordingCoreHost::with_function_code_blocks(vec![InterpreterFunctionCodeBlock::new(
                callee_owner,
                callee_code_block,
            )]);
        let callee = load_function_value_for_test(&mut vm, &mut host, 0);
        host.clear_observations();

        let fixture = install_real_p9_retained_js_call_native_exit(
            &mut vm,
            1_913,
            generated_js_call_return_consumed_code_block(),
            CoreOpcode::Call,
        );
        let counts_before = p6_semantic_install_side_effect_counts(&vm);
        let fallback_count_before = vm.tiering_integration().fallback_records().len();
        let entry_decision_count_before = vm.tiering_integration().entry_decisions().len();
        let bytecode_snapshot = fixture
            .readiness
            .bytecode_snapshot
            .expect("P9 readiness bytecode snapshot");

        let (completion, boundary_snapshot) =
            execute_registered_code_block_with_boundary_snapshot_and_arguments(
                &mut vm,
                fixture.owner,
                &fixture.code_block,
                &mut host,
                vec![RuntimeValue::undefined(), callee],
            );

        assert_eq!(
            completion,
            ExecutionCompletion::Returned(RuntimeValue::from_i32(43))
        );
        assert_eq!(
            host.dispatches
                .iter()
                .map(|(_, index, opcode)| (*index, *opcode))
                .collect::<Vec<_>>(),
            vec![
                (BytecodeIndex::from_offset(1), Some(CoreOpcode::Call)),
                (BytecodeIndex::from_offset(2), Some(CoreOpcode::AddInt32)),
                (BytecodeIndex::from_offset(3), Some(CoreOpcode::Return)),
            ],
            "cold P9 JS-call exit should not run the P6 callee through legacy direct interpreter dispatch"
        );
        assert_eq!(
            p6_semantic_install_side_effect_counts(&vm),
            P6SemanticInstallSideEffectCounts {
                materializations: counts_before.materializations + 1,
                platform_residencies: counts_before.platform_residencies + 1,
                installs: counts_before.installs + 1,
                readiness: counts_before.readiness + 2,
                provenance: counts_before.provenance + 1,
            }
        );
        let callee_decision = vm.tiering_integration().entry_decisions()
            [entry_decision_count_before..]
            .iter()
            .find(|decision| decision.owner == callee_owner)
            .expect("P16c P9 callee Function entry decision");
        assert_eq!(callee_decision.entry_kind, ExecutionEntryKind::Function);
        assert_eq!(
            callee_decision.decision,
            TierEntryDecision::EnterNative {
                tier: JitType::Baseline
            }
        );
        assert_eq!(
            vm.tiering_integration().fallback_records().len(),
            fallback_count_before,
            "P9 call exit should not record arithmetic fallback telemetry"
        );
        let [observation] = vm.tiering_integration().call_observations() else {
            panic!("expected one P16c P9 call observation");
        };
        assert_eq!(observation.owner, fixture.owner);
        assert_eq!(observation.bytecode_index, BytecodeIndex::from_offset(1));
        assert_eq!(observation.bytecode_snapshot, bytecode_snapshot);
        assert_eq!(
            observation.descriptor.outcome,
            CallObservationOutcome::Returned
        );
        assert_eq!(observation.descriptor.target_code_block, Some(callee_owner));
        assert_eq!(
            vm.tiering_integration()
                .call_link_boundary_validation_records()
                .len(),
            1
        );
        assert_eq!(
            vm.tiering_integration()
                .call_link_attachment_plan_records()
                .len(),
            1
        );
        assert_eq!(
            vm.tiering_integration()
                .call_link_inline_cache_attachment_records()
                .len(),
            1
        );
        boundary_snapshot.assert_no_gc_scope_depth(0);
        boundary_snapshot.assert_current_no_gc_scope_depth(&vm, 0);
        assert_eq!(vm.gc_execution_state().no_gc_scope_depth(), 0);
        assert_eq!(vm.heap().no_gc_scope_depth(), 0);
    }

    #[cfg(all(unix, target_arch = "x86_64"))]
    #[test]
    fn vm_p9_real_emitted_native_call_exit_uses_existing_direct_call_transaction() {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let function_unlinked = js_call_return_41_function_code_block().unlinked().clone();
        let function_blocks = vm
            .install_source_function_blocks(vec![function_unlinked])
            .expect("owned function executable call code");
        let mut host = RecordingCoreHost::with_function_code_blocks(function_blocks);
        let callee = load_function_value_for_test(&mut vm, &mut host, 0);
        host.clear_observations();

        let fixture = install_real_p9_retained_js_call_native_exit(
            &mut vm,
            1_910,
            generated_native_call_return_object_code_block(),
            CoreOpcode::Call,
        );
        let fallback_count_before = vm.tiering_integration().fallback_records().len();
        let (first_completion, _) =
            execute_registered_code_block_with_boundary_snapshot_and_arguments(
                &mut vm,
                fixture.owner,
                &fixture.code_block,
                &mut host,
                vec![RuntimeValue::undefined(), callee],
            );
        assert_eq!(
            first_completion,
            ExecutionCompletion::Returned(RuntimeValue::from_i32(41))
        );
        let first_sample = vm
            .code_blocks
            .get(fixture.owner)
            .expect("registered P9 owner")
            .code_block()
            .side_tables()
            .value_profiles()
            .bucket_samples[0];
        assert_eq!(first_sample.bytecode_index, BytecodeIndex::from_offset(1));
        assert_eq!(first_sample.bucket.kind, ValueProfileBucketKind::Sample);
        assert_eq!(first_sample.value, RuntimeValue::from_i32(41));
        assert_eq!(first_sample.sample_count, 1);
        assert_eq!(
            vm.code_blocks
                .get(fixture.owner)
                .expect("registered P9 owner")
                .code_block()
                .side_tables()
                .value_profiles()
                .jit_storage
                .raw_value_for_slot(first_sample.bucket.slot),
            Some(RuntimeValue::from_i32(41).encoded())
        );
        assert_eq!(
            vm.tiering_integration()
                .call_link_inline_cache_attachment_records()
                .len(),
            1,
            "first P9 exit should fall back precisely and attach the call-link metadata"
        );
        assert_eq!(
            vm.tiering_integration().fallback_records().len(),
            fallback_count_before,
            "P9 call fallback must not record arithmetic fallback telemetry"
        );

        host.clear_observations();
        let fallback_count_after_first = vm.tiering_integration().fallback_records().len();
        let (second_completion, boundary_snapshot) =
            execute_registered_code_block_with_boundary_snapshot_and_arguments(
                &mut vm,
                fixture.owner,
                &fixture.code_block,
                &mut host,
                vec![RuntimeValue::undefined(), callee],
            );

        assert_eq!(second_completion, first_completion);
        let second_sample = vm
            .code_blocks
            .get(fixture.owner)
            .expect("registered P9 owner")
            .code_block()
            .side_tables()
            .value_profiles()
            .bucket_samples[0];
        assert_eq!(second_sample.value, RuntimeValue::from_i32(41));
        assert_eq!(
            second_sample.sample_count, 1,
            "warmed P9 owner post-call reentry samples through native raw storage, not VM telemetry"
        );
        assert_eq!(
            vm.code_blocks
                .get(fixture.owner)
                .expect("registered P9 owner")
                .code_block()
                .side_tables()
                .value_profiles()
                .jit_storage
                .raw_value_for_slot(second_sample.bucket.slot),
            Some(RuntimeValue::from_i32(41).encoded())
        );
        assert_eq!(
            host.dispatches
                .iter()
                .map(|(_, index, opcode)| (*index, *opcode))
                .collect::<Vec<_>>(),
            Vec::<(BytecodeIndex, Option<CoreOpcode>)>::new(),
            "P9 direct dispatch should return into the owner native post-call block instead of VM-resuming the caller continuation PC"
        );
        assert_eq!(
            vm.tiering_integration().fallback_records().len(),
            fallback_count_after_first
        );
        assert!(vm
            .tiering_integration()
            .generated_call_link_probe_misses()
            .is_empty());
        assert!(vm
            .tiering_integration()
            .generated_call_link_probe_blocked_records()
            .is_empty());
        boundary_snapshot.assert_no_gc_scope_depth(0);
        boundary_snapshot.assert_current_no_gc_scope_depth(&vm, 0);
    }

    #[cfg(all(unix, target_arch = "x86_64"))]
    #[test]
    fn vm_generated_origin_direct_call_uses_owner_p9_post_call_reentry() {
        for (case_index, opcode) in [CoreOpcode::Call, CoreOpcode::CallWithThis]
            .into_iter()
            .enumerate()
        {
            let mut vm = Vm::new(VmConfig::baseline_allowed());
            let function_unlinked = js_call_return_41_function_code_block().unlinked().clone();
            let function_blocks = vm
                .install_source_function_blocks(vec![function_unlinked])
                .expect("owned generated-origin function code");
            let callee_owner = function_blocks[0].id;
            install_typed_baseline_for_test(&mut vm, callee_owner, 2_292 + case_index as u64);
            let mut host = RecordingCoreHost::with_function_code_blocks(function_blocks);
            let callee = load_function_value_for_test(&mut vm, &mut host, 0);
            host.clear_observations();

            let (name, code_block, arguments) = match opcode {
                CoreOpcode::Call => (
                    "Call",
                    generated_native_call_return_object_code_block(),
                    vec![RuntimeValue::undefined(), callee],
                ),
                CoreOpcode::CallWithThis => (
                    "CallWithThis",
                    generated_js_call_with_this_return_result_code_block(),
                    vec![
                        RuntimeValue::undefined(),
                        callee,
                        RuntimeValue::from_i32(99),
                    ],
                ),
                _ => unreachable!("generated owner reentry test opcode"),
            };
            let fixture = install_real_p9_retained_js_call_native_exit(
                &mut vm,
                1_930 + case_index as u64,
                code_block,
                opcode,
            );
            install_typed_baseline_for_test(&mut vm, fixture.owner, 2_294 + case_index as u64);

            let (first_completion, _) =
                execute_registered_code_block_with_boundary_snapshot_and_arguments(
                    &mut vm,
                    fixture.owner,
                    &fixture.code_block,
                    &mut host,
                    arguments.clone(),
                );
            assert_eq!(
                first_completion,
                ExecutionCompletion::Returned(RuntimeValue::from_i32(41)),
                "{name}: first generated call"
            );
            let first_sample = vm
                .code_blocks
                .get(fixture.owner)
                .expect("registered generated-origin P9 owner")
                .code_block()
                .side_tables()
                .value_profiles()
                .bucket_samples[0];
            assert_eq!(first_sample.bytecode_index, BytecodeIndex::from_offset(1));
            assert_eq!(first_sample.value, RuntimeValue::from_i32(41));
            assert_eq!(first_sample.sample_count, 1, "{name}: cold VM sample");
            assert_eq!(
                vm.tiering_integration()
                    .call_link_inline_cache_attachment_records()
                    .len(),
                1,
                "{name}: cold generated call should attach call-link metadata"
            );

            let transaction_count_before = vm
                .tiering_integration()
                .generated_direct_call_transaction_records()
                .len();
            let fallback_count_before = vm.tiering_integration().fallback_records().len();
            host.clear_observations();

            let (second_completion, boundary_snapshot) =
                execute_registered_code_block_with_boundary_snapshot_and_arguments(
                    &mut vm,
                    fixture.owner,
                    &fixture.code_block,
                    &mut host,
                    arguments,
                );

            assert_eq!(
                second_completion, first_completion,
                "{name}: generated-origin owner reentry completion"
            );
            let second_sample = vm
                .code_blocks
                .get(fixture.owner)
                .expect("registered generated-origin P9 owner")
                .code_block()
                .side_tables()
                .value_profiles()
                .bucket_samples[0];
            assert_eq!(second_sample.value, RuntimeValue::from_i32(41));
            assert_eq!(
                second_sample.sample_count, 1,
                "{name}: generated-origin direct call should let the owner native post-call block profile the result"
            );
            assert_eq!(
                vm.code_blocks
                    .get(fixture.owner)
                    .expect("registered generated-origin P9 owner")
                    .code_block()
                    .side_tables()
                    .value_profiles()
                    .jit_storage
                    .raw_value_for_slot(second_sample.bucket.slot),
                Some(RuntimeValue::from_i32(41).encoded()),
                "{name}: owner native reentry should publish the raw JIT profile value"
            );
            let transactions = vm
                .tiering_integration()
                .generated_direct_call_transaction_records();
            assert_eq!(transactions.len(), transaction_count_before + 1);
            assert_eq!(transactions.last().unwrap().caller, fixture.owner);
            assert_eq!(
                transactions.last().unwrap().outcome,
                VmGeneratedDirectCallTransactionOutcome::Continue
            );
            assert_eq!(
                host.dispatches
                    .iter()
                    .map(|(_, index, opcode)| (*index, *opcode))
                    .collect::<Vec<_>>(),
                Vec::<(BytecodeIndex, Option<CoreOpcode>)>::new(),
                "{name}: native owner reentry should not VM-dispatch the caller resume bytecode"
            );
            assert_eq!(
                vm.tiering_integration().fallback_records().len(),
                fallback_count_before,
                "{name}: generated-origin owner reentry should not add fallback telemetry"
            );
            boundary_snapshot.assert_no_gc_scope_depth(0);
            boundary_snapshot.assert_current_no_gc_scope_depth(&vm, 0);
        }
    }

