    #[cfg(all(unix, target_arch = "x86_64"))]
    #[test]
    fn vm_p9_call_exit_consults_owner_post_call_proof_before_handoff() {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let function_blocks = vm
            .install_source_function_blocks(vec![js_call_return_41_function_code_block()
                .unlinked()
                .clone()])
            .expect("owned function executable call code");
        let mut host = RecordingCoreHost::with_function_code_blocks(function_blocks);
        let callee = load_function_value_for_test(&mut vm, &mut host, 0);
        host.clear_observations();

        let fixture = install_real_p9_retained_js_call_native_exit(
            &mut vm,
            1_927,
            generated_native_call_return_object_code_block(),
            CoreOpcode::Call,
        );
        mutate_real_p9_retained_js_call_native_exit_table(&mut vm, &fixture, |table| {
            let proof = table
                .owner_continuation_native_binding
                .as_mut()
                .and_then(|binding| {
                    binding
                        .call_continuations
                        .iter_mut()
                        .find(|continuation| continuation.encoded_payload == fixture.call_payload)
                })
                .and_then(|continuation| continuation.post_call_return_target_proof.as_mut())
                .expect("retained post-call proof");
            proof.reset_sp_offset = proof.reset_sp_offset.saturating_add(1);
        });

        let fallback_count_before = vm.tiering_integration().fallback_records().len();
        let (completion, boundary_snapshot) =
            execute_registered_code_block_with_boundary_snapshot_and_arguments(
                &mut vm,
                fixture.owner,
                &fixture.code_block,
                &mut host,
                vec![RuntimeValue::undefined(), callee],
            );

        assert_eq!(
            completion,
            ExecutionCompletion::Failed(ExecutionError::BaselineGeneratedExecutionRejected)
        );
        assert!(
            host.dispatches.is_empty(),
            "forged P9 post-call proof must be rejected before JS-call handoff dispatch"
        );
        assert!(vm.tiering_integration().call_observations().is_empty());
        assert_eq!(
            vm.tiering_integration().fallback_records().len(),
            fallback_count_before
        );
        boundary_snapshot.assert_no_gc_scope_depth(0);
        boundary_snapshot.assert_current_no_gc_scope_depth(&vm, 0);
    }

