    fn generated_direct_call_candidate_for_test(
        vm: &Vm,
        owner: CodeBlockId,
        bytecode_snapshot: BaselineBytecodeSnapshotFingerprint,
    ) -> GeneratedCallLinkCandidate {
        let attached_call_link_candidates = vm
            .code_blocks
            .attached_call_link_inline_cache_candidates_for_owner(
                owner,
                bytecode_snapshot,
                vm.tiering_integration()
                    .call_link_inline_cache_attachment_records(),
            );
        let generated_call_link_candidate_table = vm
            .tiering_integration()
            .generated_call_link_candidate_table_for_owner_with_attached(
                owner,
                bytecode_snapshot,
                &attached_call_link_candidates,
            )
            .expect("attached call-link candidate table");
        let [candidate] = generated_call_link_candidate_table.candidates() else {
            panic!(
                "expected exactly one generated call-link candidate, got {}",
                generated_call_link_candidate_table.len()
            )
        };
        candidate.clone()
    }

    fn dispatch_generated_direct_call_handoff_for_test<H: DispatchHost>(
        vm: &mut Vm,
        owner: CodeBlockId,
        code_block: &CodeBlock,
        host: &mut H,
        global_object: GlobalObjectId,
        callee: RuntimeValue,
        direct_call: BaselineGeneratedJsDirectCall,
    ) -> SingleDispatchOutcome {
        let callee_object = ObjectId(heap_cell_for_value(vm, callee));
        let entry = vm
            .execution
            .enter(ExecutionEntryRecord::Program(ProgramExecutionEntry {
                code_block: owner,
                global_object,
                this_value: RuntimeValue::undefined(),
            }));
        let frame = vm
            .execution
            .push_frame(
                &mut vm.registers,
                FramePushRequest {
                    code_block: Some(owner),
                    callee: None,
                    callee_value: None,
                    lexical_scope: None,
                    shape: code_block.unlinked().frame(),
                    argument_count_including_this: 2,
                    argument_values: vec![RuntimeValue::undefined(), callee],
                    start_bytecode_index: Some(BytecodeIndex::from_offset(1)),
                    return_bytecode_index: None,
                },
            )
            .unwrap();
        vm.execution
            .mark_top_bytecode_index(BytecodeIndex::from_offset(1));
        let no_gc_region = vm.enter_no_gc_execution_region();
        let outcome = vm.dispatch_generated_js_call_handoff_in_current_region(
            BaselineGeneratedJsCallHandoff {
                resume: BaselineGeneratedJsCallResume {
                    owner,
                    frame,
                    bytecode_index: BytecodeIndex::from_offset(1),
                    opcode: CoreOpcode::Call,
                },
                continuation: BaselineGeneratedJsCallHandoffContinuation::Call(
                    CallReturnContinuation {
                        caller_frame: frame,
                        callee_frame: None,
                        owner,
                        call_bytecode_index: BytecodeIndex::from_offset(1),
                        resume_bytecode_index: Some(BytecodeIndex::from_offset(2)),
                        destination: local(1),
                        argument_count_including_this: 1,
                        callee_value: Some(callee),
                        callee_object: Some(callee_object),
                        kind: CallReturnKind::Call,
                    },
                ),
                owner_continuation: None,
                direct_call: Some(Box::new(direct_call)),
                requires_no_gc_exit_reentry: true,
                may_throw: true,
            },
            code_block,
            host,
            DispatchConfig::default(),
        );
        vm.leave_no_gc_execution_region(no_gc_region).unwrap();
        if vm.execution.frame(frame).is_some() {
            vm.execution.pop_frame(&mut vm.registers, frame).unwrap();
        }
        vm.execution.leave(entry).unwrap();
        outcome
    }

    #[test]
    fn vm_generated_direct_call_rejects_forged_metadata_without_dispatch() {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let function_unlinked = js_call_return_41_function_code_block().unlinked().clone();
        let function_blocks = vm
            .install_source_function_blocks(vec![function_unlinked])
            .expect("owned function executable call code");
        let mut host = RecordingCoreHost::with_function_code_blocks(function_blocks);
        let callee = load_function_value_for_test(&mut vm, &mut host, 0);
        let callee_object = ObjectId(heap_cell_for_value(&vm, callee));
        host.clear_observations();

        let code_block = generated_js_call_return_consumed_code_block();
        let owner = register_test_code_block(&mut vm, code_block.clone());
        let artifact = install_typed_baseline_for_test(&mut vm, owner, 1225);

        let (first_completion, _) =
            execute_registered_code_block_with_boundary_snapshot_and_arguments(
                &mut vm,
                owner,
                &code_block,
                &mut host,
                vec![RuntimeValue::undefined(), callee],
            );
        assert_eq!(
            first_completion,
            ExecutionCompletion::Returned(RuntimeValue::from_i32(42))
        );
        let candidate = generated_direct_call_candidate_for_test(
            &vm,
            owner,
            artifact.eligibility_proof.bytecode_snapshot_fingerprint(),
        );
        let direct_call = BaselineGeneratedJsDirectCall {
            authorization: GeneratedCallLinkDirectCall::from_candidate(&candidate),
            candidate,
            callee_value: callee,
            callee_object,
            this_value: RuntimeValue::undefined(),
            this_object: None,
            argument_count_including_this: 1,
            setup_payload: None,
        };

        let mut forged_authorization = direct_call.clone();
        forged_authorization.authorization.attachment_ordinal = forged_authorization
            .authorization
            .attachment_ordinal
            .saturating_add(1);

        let mut forged_candidate_bci = direct_call.clone();
        forged_candidate_bci.candidate.bytecode_index = 99;
        forged_candidate_bci.authorization =
            GeneratedCallLinkDirectCall::from_candidate(&forged_candidate_bci.candidate);

        let mut forged_callee = direct_call.clone();
        forged_callee.callee_object = ObjectId(CellId(900_001));

        let mut forged_this = direct_call.clone();
        forged_this.this_value = RuntimeValue::from_bool(true);

        let mut forged_argument_count = direct_call.clone();
        forged_argument_count.argument_count_including_this = 2;

        let handoff_global_object = vm.allocate_global_object_cell().unwrap();
        vm.record_source_global_object(handoff_global_object)
            .unwrap();
        for forged in [
            forged_authorization,
            forged_candidate_bci,
            forged_callee,
            forged_this,
            forged_argument_count,
        ] {
            host.clear_observations();
            let targeted_roots_before = vm.heap().targeted_roots().records().to_vec();
            let entry_decision_count_before = vm.tiering_integration().entry_decisions().len();
            assert_eq!(
                dispatch_generated_direct_call_handoff_for_test(
                    &mut vm,
                    owner,
                    &code_block,
                    &mut host,
                    handoff_global_object,
                    callee,
                    forged,
                ),
                SingleDispatchOutcome::Failed(ExecutionError::BaselineGeneratedExecutionRejected)
            );
            assert!(
                host.dispatches.is_empty(),
                "forged direct-call handoff must be rejected before callee dispatch"
            );
            assert_eq!(vm.heap().no_gc_scope_depth(), 0);
            assert_eq!(
                vm.heap().targeted_roots().records(),
                targeted_roots_before.as_slice()
            );
            assert_eq!(
                vm.tiering_integration().entry_decisions().len(),
                entry_decision_count_before,
                "forged direct-call handoff must reject before callee entry"
            );
        }
    }

