    #[test]
    fn vm_call_link_safepoint_clears_metadata_only_attachment_with_dead_target_code_block() {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let function_unlinked = js_call_return_41_function_code_block().unlinked().clone();
        let function_blocks = vm
            .install_source_function_blocks(vec![function_unlinked])
            .expect("owned function executable call code");
        let mut host = RecordingCoreHost::with_function_code_blocks(function_blocks);
        let callee = load_function_value_for_test(&mut vm, &mut host, 0);
        host.clear_observations();

        let code_block = generated_js_call_return_consumed_code_block();
        let owner = register_test_code_block(&mut vm, code_block.clone());
        install_typed_baseline_for_test(&mut vm, owner, 1322);

        let (completion, _) = execute_registered_code_block_with_boundary_snapshot_and_arguments(
            &mut vm,
            owner,
            &code_block,
            &mut host,
            vec![RuntimeValue::undefined(), callee],
        );
        assert_eq!(
            completion,
            ExecutionCompletion::Returned(RuntimeValue::from_i32(42))
        );

        let attachment = vm
            .tiering_integration()
            .call_link_inline_cache_attachment_records()[0]
            .clone();
        let target_code_block = match &attachment
            .code_block_outcome
            .as_ref()
            .expect("accepted attachment has bytecode outcome")
            .target
        {
            CallTarget::MetadataOnlyMonomorphic { code_block, .. } => *code_block,
            target => panic!("expected metadata-only target, got {target:?}"),
        };
        let clear_count_before = vm
            .tiering_integration()
            .call_link_inline_cache_clear_records()
            .len();

        vm.clear_stale_metadata_only_call_link_inline_caches_at_safepoint(owner, &code_block);
        assert_eq!(
            vm.tiering_integration()
                .call_link_inline_cache_clear_records()
                .len(),
            clear_count_before,
            "live call-link target should not be cleared"
        );

        vm.heap
            .invalidate_cell(HeapCellInvalidationRequest {
                cell: target_code_block.0,
                reason: CellZapReason::Destruction,
            })
            .expect("invalidate target code block");

        vm.clear_stale_metadata_only_call_link_inline_caches_at_safepoint(owner, &code_block);

        let clears = vm
            .tiering_integration()
            .call_link_inline_cache_clear_records();
        assert_eq!(clears.len(), clear_count_before + 1);
        let clear = clears.last().expect("call-link clear record");
        assert_eq!(clear.attachment_ordinal, attachment.ordinal);
        assert_eq!(
            clear.lifecycle,
            VmCallLinkInlineCacheClearLifecycle::Cleared
        );
        let VmCallLinkInlineCacheClearOutcome::Accepted { outcome } = &clear.outcome else {
            panic!("expected accepted call-link clear, got {:?}", clear.outcome);
        };
        assert_eq!(outcome.target, CallTarget::Unlinked);
        assert_eq!(outcome.mode, crate::bytecode::ic::CallLinkMode::Init);

        let registered_code_block = vm
            .code_blocks
            .get(owner)
            .expect("registered owner code block")
            .code_block();
        // Clone so no `Ref` borrow of the registry table outlives into the later
        // `&mut vm` safepoint call (table now lives behind a `RefCell`).
        let call = registered_code_block.side_tables().inline_caches().calls
            [attachment.slot.0 as usize]
            .clone();
        assert_eq!(call.mode, crate::bytecode::ic::CallLinkMode::Init);
        assert_eq!(call.target, CallTarget::Unlinked);

        vm.clear_stale_metadata_only_call_link_inline_caches_at_safepoint(owner, &code_block);
        assert_eq!(
            vm.tiering_integration()
                .call_link_inline_cache_clear_records()
                .len(),
            clear_count_before + 1,
            "accepted clear records should suppress repeated stale clears until lifecycle retirement lands"
        );
    }

    // Batch 1 (call-dispatch constant-factor): a callee/owner with NO registered
    // plans must SKIP the five idempotent IC/tiering safepoint passes in both the
    // prologue and epilogue, and produce an identical result. We observe the skip
    // through the full-branch invocation counter (it stays 0 across a full
    // execute_code_block) and the presence predicate (false for this owner).
    #[test]
    fn vm_safepoint_passes_skipped_for_owner_with_no_registered_plans() {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let mut host = RecordingCoreHost::with_function_blocks(Vec::new());

        let code_block = p6_int32_return_42_code_block();
        let owner = register_test_code_block(&mut vm, code_block.clone());

        // No plans/candidates registered for this owner -> predicate is false.
        assert!(
            !vm.tiering_integration()
                .owner_has_any_safepoint_plan_work(owner),
            "fresh owner with no registered plans must report no safepoint work"
        );
        assert_eq!(vm.safepoint_pass_full_branch_invocations(), 0);

        let (completion, _) = execute_registered_code_block_with_boundary_snapshot_and_arguments(
            &mut vm,
            owner,
            &code_block,
            &mut host,
            vec![RuntimeValue::undefined()],
        );

        // Result is correct (observably identical to running the passes)...
        assert_eq!(
            completion,
            ExecutionCompletion::Returned(RuntimeValue::from_i32(42))
        );
        // ...and BOTH the prologue and epilogue safepoints skipped the five
        // passes: the full-branch counter never advanced.
        assert_eq!(
            vm.safepoint_pass_full_branch_invocations(),
            0,
            "prologue + epilogue safepoints must skip the five passes when the owner has no plans"
        );
    }

    // Batch 1 + Batch 2: a callee/owner WITH a registered plan (here a live
    // call-link IC attachment record) takes the FULL safepoint path while it is
    // still attaching/transitioning that work. Batch 1 alone re-ran the five
    // idempotent passes on EVERY subsequent call; Batch 2's memo collapses the
    // steady state to a skip. This test pins both halves of the invariant: the
    // FIRST encounter of registered work runs the full path (the counter
    // advances), and a forced plan mutation re-arms the full path (the guard does
    // NOT skip when there is genuinely new plan work). The pure steady-state skip
    // and the fingerprint-change resume are pinned by
    // vm_safepoint_passes_skipped_in_steady_state_and_resume_on_mutation.
    #[test]
    fn vm_safepoint_passes_run_full_path_for_owner_with_registered_plan() {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let function_unlinked = js_call_return_41_function_code_block().unlinked().clone();
        let function_blocks = vm
            .install_source_function_blocks(vec![function_unlinked])
            .expect("owned function executable call code");
        let mut host = RecordingCoreHost::with_function_code_blocks(function_blocks);
        let callee = load_function_value_for_test(&mut vm, &mut host, 0);
        host.clear_observations();

        let code_block = generated_js_call_return_consumed_code_block();
        let owner = register_test_code_block(&mut vm, code_block.clone());
        install_typed_baseline_for_test(&mut vm, owner, 1322);

        let before_first = vm.safepoint_pass_full_branch_invocations();
        let (completion, _) = execute_registered_code_block_with_boundary_snapshot_and_arguments(
            &mut vm,
            owner,
            &code_block,
            &mut host,
            vec![RuntimeValue::undefined(), callee],
        );
        assert_eq!(
            completion,
            ExecutionCompletion::Returned(RuntimeValue::from_i32(42))
        );

        // The first run attached a call-link IC for this owner, so the predicate
        // must now report registered work, and the attaching run took the full
        // safepoint path (the counter advanced while the IC was materialized).
        assert!(
            !vm.tiering_integration()
                .call_link_inline_cache_attachment_records()
                .is_empty(),
            "first run must attach a call-link IC for the owner"
        );
        assert!(
            vm.tiering_integration()
                .owner_has_any_safepoint_plan_work(owner),
            "owner with a registered call-link IC attachment must report safepoint work"
        );
        assert!(
            vm.safepoint_pass_full_branch_invocations() > before_first,
            "the first encounter of registered plan work must run the full safepoint path"
        );

        // Drive to steady state so the memo engages (counter freezes across a
        // step), then force a genuine plan mutation: the next run must RESUME the
        // full path -- the guard must not skip when new plan work is registered.
        let mut prev = vm.safepoint_pass_full_branch_invocations();
        for _ in 0..8 {
            let (completion, _) =
                execute_registered_code_block_with_boundary_snapshot_and_arguments(
                    &mut vm,
                    owner,
                    &code_block,
                    &mut host,
                    vec![RuntimeValue::undefined(), callee],
                );
            assert_eq!(
                completion,
                ExecutionCompletion::Returned(RuntimeValue::from_i32(42))
            );
            let now = vm.safepoint_pass_full_branch_invocations();
            if now == prev {
                break;
            }
            prev = now;
        }

        let bytecode_snapshot =
            BaselineBytecodeEligibilityProof::fingerprint_code_block_snapshot(&code_block)
                .expect("owner code block fingerprint");
        vm.tiering_integration_mut()
            .record_call_link_attachment_plan(VmCallLinkAttachmentPlanRequest {
                boundary_validation_ordinal: 0,
                owner,
                frame: Some(CallFrameId(1)),
                bytecode_index: BytecodeIndex::from_offset(0),
                opcode: CoreOpcode::Call,
                bytecode_snapshot,
                slot: InlineCacheSlotId(9),
            });
        let before = vm.safepoint_pass_full_branch_invocations();
        let (completion, _) = execute_registered_code_block_with_boundary_snapshot_and_arguments(
            &mut vm,
            owner,
            &code_block,
            &mut host,
            vec![RuntimeValue::undefined(), callee],
        );
        assert_eq!(
            completion,
            ExecutionCompletion::Returned(RuntimeValue::from_i32(42))
        );
        assert!(
            vm.safepoint_pass_full_branch_invocations() > before,
            "a forced plan mutation must re-arm the full safepoint path for an owner with registered plans"
        );
    }

    // Batch 2 (call-dispatch constant-factor): an owner that HAS plans but is in
    // STEADY STATE (no six-table plan mutation and an unchanged CodeBlock
    // fingerprint since its last full pass) must SKIP the five idempotent passes
    // via the safepoint memo -- the full-branch counter stops advancing across
    // further calls. It must RESUME advancing after (a) a forced plan mutation
    // (plan_generation bump) or (b) a CodeBlock fingerprint change (memo-key
    // mismatch). This is the Rust analogue of C++ JSC materializing call links
    // per-LINK (LLIntSlowPaths.cpp setUpCall/linkFor): once a link is
    // materialized and nothing changes, the per-call work disappears.
    #[test]
    fn vm_safepoint_passes_skipped_in_steady_state_and_resume_on_mutation() {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let function_unlinked = js_call_return_41_function_code_block().unlinked().clone();
        let function_blocks = vm
            .install_source_function_blocks(vec![function_unlinked])
            .expect("owned function executable call code");
        let mut host = RecordingCoreHost::with_function_code_blocks(function_blocks);
        let callee = load_function_value_for_test(&mut vm, &mut host, 0);
        host.clear_observations();

        let code_block = generated_js_call_return_consumed_code_block();
        let owner = register_test_code_block(&mut vm, code_block.clone());
        install_typed_baseline_for_test(&mut vm, owner, 1322);

        // Run 1: attaches the owner's call-link IC and records the memo. This is
        // a full path (the attachment is this owner's first plan).
        let run = |vm: &mut Vm, host: &mut RecordingCoreHost| {
            let (completion, _) =
                execute_registered_code_block_with_boundary_snapshot_and_arguments(
                    vm,
                    owner,
                    &code_block,
                    host,
                    vec![RuntimeValue::undefined(), callee],
                );
            assert_eq!(
                completion,
                ExecutionCompletion::Returned(RuntimeValue::from_i32(42))
            );
        };
        run(&mut vm, &mut host);
        assert!(
            vm.tiering_integration()
                .owner_has_any_safepoint_plan_work(owner),
            "first run must attach a call-link IC for the owner"
        );
        assert!(
            vm.ic_tiering_safepoint_memo_contains_for_test(owner),
            "the full path must record a memo for the owner"
        );

        // Run 2: still warming (the second run can take the full path while the
        // attachment lifecycle settles). After it, the owner is in steady state.
        run(&mut vm, &mut host);

        // STEADY STATE: a further run must SKIP both safepoints -> counter frozen.
        let steady = vm.safepoint_pass_full_branch_invocations();
        run(&mut vm, &mut host);
        run(&mut vm, &mut host);
        assert_eq!(
            vm.safepoint_pass_full_branch_invocations(),
            steady,
            "steady-state runs with no plan mutation and unchanged fingerprint must skip the five passes"
        );

        // RESUME on a forced PLAN MUTATION: a genuine six-table mutation bumps the
        // global plan_generation, so every memo (including this owner's) mismatches
        // and the next safepoint takes the full path. Use a call-link attachment
        // plan record (boundary_validation_ordinal 0 has no match -> a Rejected
        // record is still pushed, which still bumps the epoch -- exactly the
        // omission-proof behavior the coverage test asserts).
        let bytecode_snapshot =
            BaselineBytecodeEligibilityProof::fingerprint_code_block_snapshot(&code_block)
                .expect("owner code block fingerprint");
        let generation_before = vm.tiering_integration().plan_generation();
        vm.tiering_integration_mut()
            .record_call_link_attachment_plan(VmCallLinkAttachmentPlanRequest {
                boundary_validation_ordinal: 0,
                owner,
                frame: Some(CallFrameId(1)),
                bytecode_index: BytecodeIndex::from_offset(0),
                opcode: CoreOpcode::Call,
                bytecode_snapshot,
                slot: InlineCacheSlotId(7),
            });
        assert!(
            vm.tiering_integration().plan_generation() > generation_before,
            "the forced plan mutation must bump plan_generation"
        );
        let before_mutation_resume = vm.safepoint_pass_full_branch_invocations();
        run(&mut vm, &mut host);
        assert!(
            vm.safepoint_pass_full_branch_invocations() > before_mutation_resume,
            "a plan-generation bump must force the full safepoint path on the next run"
        );

        // Back to steady state (the resume run re-recorded the memo at the new
        // plan_generation): confirm the counter freezes again before the next case.
        let steady_again = vm.safepoint_pass_full_branch_invocations();
        run(&mut vm, &mut host);
        assert_eq!(
            vm.safepoint_pass_full_branch_invocations(),
            steady_again,
            "after re-recording the memo the owner must return to the steady-state skip"
        );

        // RESUME on a FINGERPRINT CHANGE: poke the memo's stored fingerprint to a
        // structurally distinct value so the memo key mismatches even though
        // plan_generation is unchanged. The next safepoint must take the full path.
        let distinct = generated_native_call_return_object_code_block();
        let distinct_fingerprint =
            BaselineBytecodeEligibilityProof::fingerprint_code_block_snapshot(&distinct)
                .expect("distinct code block fingerprint");
        assert!(
            vm.corrupt_ic_tiering_safepoint_memo_fingerprint_for_test(owner, distinct_fingerprint),
            "owner must have a memo entry to corrupt"
        );
        let before_fingerprint_resume = vm.safepoint_pass_full_branch_invocations();
        run(&mut vm, &mut host);
        assert!(
            vm.safepoint_pass_full_branch_invocations() > before_fingerprint_resume,
            "a CodeBlock fingerprint change must force the full safepoint path on the next run"
        );
    }

    #[test]
    fn vm_generated_call_observation_records_native_target_metadata_only() {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let mut host = RecordingCoreHost::with_function_blocks(Vec::new());
        let constructor = load_object_constructor_value_for_test(&mut vm, &mut host);
        host.clear_observations();

        let code_block = generated_native_call_return_object_code_block();
        let owner = register_test_code_block(&mut vm, code_block.clone());
        let inline_caches_before = code_block.side_tables().inline_caches().clone();
        let fallback_count_before = vm.tiering_integration().fallback_records().len();
        let artifact = install_typed_baseline_for_test(&mut vm, owner, 1125);
        let bytecode_snapshot = artifact.eligibility_proof.bytecode_snapshot_fingerprint();
        let generated_artifacts_before = vm
            .tiering_integration()
            .baseline_generated_code_artifacts()
            .to_vec();

        let (completion, boundary_snapshot) =
            execute_registered_code_block_with_boundary_snapshot_and_arguments(
                &mut vm,
                owner,
                &code_block,
                &mut host,
                vec![RuntimeValue::undefined(), constructor],
            );

        let returned = if let ExecutionCompletion::Returned(value) = completion {
            value
        } else {
            unreachable!("expected native call return, got {completion:?}");
        };
        assert_heap_published_cell_type(&vm, returned, CellType::Object);
        let call_dispatch = host
            .dispatches
            .iter()
            .position(|(_, index, opcode)| {
                *index == BytecodeIndex::from_offset(1) && *opcode == Some(CoreOpcode::Call)
            })
            .expect("generated native call dispatch");
        let observations = vm.tiering_integration().call_observations();
        assert_eq!(observations.len(), 1);
        let observation = &observations[0];
        assert_eq!(observation.owner, owner);
        assert_eq!(observation.frame, Some(host.dispatches[call_dispatch].0));
        assert_eq!(observation.bytecode_index, BytecodeIndex::from_offset(1));
        assert_eq!(observation.opcode, CoreOpcode::Call);
        assert_eq!(observation.bytecode_snapshot, bytecode_snapshot);
        let descriptor = &observation.descriptor;
        assert_eq!(
            descriptor.target_kind,
            CallObservationTargetKind::NativeFunction {
                native: "ObjectConstructor".to_owned(),
                intrinsic: None,
            }
        );
        assert_eq!(descriptor.outcome, CallObservationOutcome::Returned);
        assert_eq!(descriptor.provided_argument_count, 0);
        assert_eq!(descriptor.argument_count_including_this, 1);
        assert_eq!(descriptor.callee_value_kind, ValueKind::Cell);
        assert!(descriptor.callee_object.is_some());
        assert_eq!(
            descriptor.callee_object,
            Some(ObjectId(heap_cell_for_value(&vm, constructor)))
        );
        assert_eq!(descriptor.root_safety, CallObservationRootSafety::RootSafe);
        assert_eq!(
            descriptor.direct_call_readiness,
            CallObservationDirectCallReadiness::Disallowed
        );
        assert!(descriptor.may_call_js);
        assert_eq!(descriptor.validate(), Ok(()));
        assert!(
            vm.tiering_integration()
                .call_link_descriptor_records()
                .is_empty(),
            "native call observations must not create JS call-link descriptors"
        );
        assert!(vm
            .tiering_integration()
            .call_link_boundary_validation_records()
            .is_empty());
        assert!(vm
            .tiering_integration()
            .call_link_attachment_plan_records()
            .is_empty());
        assert!(vm
            .tiering_integration()
            .call_link_attachment_install_rechecks()
            .is_empty());
        assert!(vm
            .tiering_integration()
            .call_link_inline_cache_attachment_records()
            .is_empty());
        assert!(host.dispatch_roots[call_dispatch].iter().any(|record| {
            descriptor
                .callee_object
                .is_some_and(|object| record.target == object.0)
        }));
        assert_eq!(
            *code_block.side_tables().inline_caches(),
            inline_caches_before,
            "native call observation must not mutate bytecode IC metadata"
        );
        assert_eq!(
            vm.tiering_integration().fallback_records().len(),
            fallback_count_before,
            "native call handoff should not be recorded as a generic generated fallback"
        );
        assert_eq!(
            vm.tiering_integration().baseline_generated_code_artifacts(),
            generated_artifacts_before.as_slice()
        );
        assert_eq!(
            vm.heap().targeted_roots().records(),
            boundary_snapshot.targeted_roots.as_slice()
        );
        boundary_snapshot.assert_no_gc_scope_depth(0);
        boundary_snapshot.assert_current_no_gc_scope_depth(&vm, 0);
        assert_latest_generated_entry_evidence(&vm, owner, artifact);
    }

