    #[test]
    fn vm_generated_call_observation_rejects_forged_call_continuation_fields_without_dispatch() {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let mut host =
            RecordingCoreHost::with_function_blocks(vec![js_call_return_41_function_code_block()]);
        let callee = load_function_value_for_test(&mut vm, &mut host, 0);
        host.clear_observations();

        let code_block = generated_js_call_return_consumed_code_block();
        let owner = register_test_code_block(&mut vm, code_block.clone());
        let global_object = vm.allocate_global_object_cell().unwrap();
        vm.record_source_global_object(global_object).unwrap();
        let entry = vm
            .execution
            .enter(ExecutionEntryRecord::Program(ProgramExecutionEntry {
                code_block: owner,
                global_object,
                this_value: RuntimeValue::undefined(),
            }));
        let frame = vm
            .execution
            .push_frame(
                &mut vm.registers,
                FramePushRequest {
                    code_block: Some(owner),
                    callee: None,
                    callee_value: None,
                    lexical_scope: None,
                    shape: code_block.unlinked().frame(),
                    argument_count_including_this: 2,
                    argument_values: vec![RuntimeValue::undefined(), callee],
                    start_bytecode_index: Some(BytecodeIndex::from_offset(0)),
                    return_bytecode_index: None,
                },
            )
            .unwrap();

        let valid_continuation = CallReturnContinuation {
            caller_frame: frame,
            callee_frame: None,
            owner,
            call_bytecode_index: BytecodeIndex::from_offset(1),
            resume_bytecode_index: Some(BytecodeIndex::from_offset(2)),
            destination: local(1),
            argument_count_including_this: 1,
            callee_value: Some(callee),
            callee_object: Some(ObjectId(heap_cell_for_value(&vm, callee))),
            kind: CallReturnKind::Call,
        };
        let valid = BaselineGeneratedJsCallHandoff {
            resume: BaselineGeneratedJsCallResume {
                owner,
                frame,
                bytecode_index: BytecodeIndex::from_offset(1),
                opcode: CoreOpcode::Call,
            },
            continuation: BaselineGeneratedJsCallHandoffContinuation::Call(valid_continuation),
            owner_continuation: None,
            direct_call: None,
            requires_no_gc_exit_reentry: true,
            may_throw: true,
        };

        for forged in [
            BaselineGeneratedJsCallHandoff {
                continuation: BaselineGeneratedJsCallHandoffContinuation::Call(
                    CallReturnContinuation {
                        destination: local(2),
                        ..valid_continuation
                    },
                ),
                ..valid.clone()
            },
            BaselineGeneratedJsCallHandoff {
                continuation: BaselineGeneratedJsCallHandoffContinuation::Call(
                    CallReturnContinuation {
                        resume_bytecode_index: Some(BytecodeIndex::from_offset(3)),
                        ..valid_continuation
                    },
                ),
                ..valid.clone()
            },
            BaselineGeneratedJsCallHandoff {
                continuation: BaselineGeneratedJsCallHandoffContinuation::Call(
                    CallReturnContinuation {
                        argument_count_including_this: 2,
                        ..valid_continuation
                    },
                ),
                ..valid.clone()
            },
            BaselineGeneratedJsCallHandoff {
                continuation: BaselineGeneratedJsCallHandoffContinuation::Call(
                    CallReturnContinuation {
                        callee_value: Some(RuntimeValue::undefined()),
                        callee_object: None,
                        ..valid_continuation
                    },
                ),
                ..valid.clone()
            },
        ] {
            assert_eq!(
                vm.dispatch_generated_js_call_handoff_in_current_region(
                    forged,
                    &code_block,
                    &mut host,
                    DispatchConfig::default(),
                ),
                SingleDispatchOutcome::Failed(ExecutionError::BaselineGeneratedExecutionRejected)
            );
        }

        assert!(host.dispatches.is_empty());
        assert!(vm.tiering_integration().call_observations().is_empty());
        vm.execution.pop_frame(&mut vm.registers, frame).unwrap();
        vm.execution.leave(entry).unwrap();
    }

    #[test]
    fn vm_generated_call_observation_rejects_forged_owner_continuation_site_without_dispatch() {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let mut host =
            RecordingCoreHost::with_function_blocks(vec![js_call_return_41_function_code_block()]);
        let callee = load_function_value_for_test(&mut vm, &mut host, 0);
        let callee_object = ObjectId(heap_cell_for_value(&vm, callee));
        host.clear_observations();

        let code_block = owner_continuation_vm_call_code_block(CoreOpcode::Call);
        let owner = register_test_code_block(&mut vm, code_block.clone());
        let artifact = install_typed_baseline_for_test(&mut vm, owner, 1233);
        let mut forged_owner_continuation = *artifact
            .owner_continuation_map()
            .expect("owner continuation map")
            .call_site_for_bytecode_index(BytecodeIndex::from_offset(1))
            .expect("call owner continuation site");
        forged_owner_continuation.destination = local(2);

        let global_object = vm.allocate_global_object_cell().unwrap();
        vm.record_source_global_object(global_object).unwrap();
        let entry = vm
            .execution
            .enter(ExecutionEntryRecord::Program(ProgramExecutionEntry {
                code_block: owner,
                global_object,
                this_value: RuntimeValue::undefined(),
            }));
        let frame = vm
            .execution
            .push_frame(
                &mut vm.registers,
                FramePushRequest {
                    code_block: Some(owner),
                    callee: None,
                    callee_value: None,
                    lexical_scope: None,
                    shape: code_block.unlinked().frame(),
                    argument_count_including_this: 1,
                    argument_values: vec![RuntimeValue::undefined()],
                    start_bytecode_index: Some(BytecodeIndex::from_offset(1)),
                    return_bytecode_index: None,
                },
            )
            .unwrap();
        let window = vm.execution.top_frame().unwrap().register_window;
        vm.registers.write(window, local(2), callee).unwrap();
        vm.execution
            .mark_top_bytecode_index(BytecodeIndex::from_offset(1));

        let no_gc_region = vm.enter_no_gc_execution_region();
        let outcome = vm.dispatch_generated_js_call_handoff_in_current_region(
            BaselineGeneratedJsCallHandoff {
                resume: BaselineGeneratedJsCallResume {
                    owner,
                    frame,
                    bytecode_index: BytecodeIndex::from_offset(1),
                    opcode: CoreOpcode::Call,
                },
                continuation: BaselineGeneratedJsCallHandoffContinuation::Call(
                    CallReturnContinuation {
                        caller_frame: frame,
                        callee_frame: None,
                        owner,
                        call_bytecode_index: BytecodeIndex::from_offset(1),
                        resume_bytecode_index: Some(BytecodeIndex::from_offset(2)),
                        destination: local(1),
                        argument_count_including_this: 1,
                        callee_value: Some(callee),
                        callee_object: Some(callee_object),
                        kind: CallReturnKind::Call,
                    },
                ),
                owner_continuation: Some(forged_owner_continuation),
                direct_call: None,
                requires_no_gc_exit_reentry: true,
                may_throw: true,
            },
            &code_block,
            &mut host,
            DispatchConfig::default(),
        );
        vm.leave_no_gc_execution_region(no_gc_region).unwrap();

        assert_eq!(
            outcome,
            SingleDispatchOutcome::Failed(ExecutionError::BaselineGeneratedExecutionRejected)
        );
        assert!(host.dispatches.is_empty());
        assert!(vm.tiering_integration().call_observations().is_empty());
        vm.execution.pop_frame(&mut vm.registers, frame).unwrap();
        vm.execution.leave(entry).unwrap();
    }

    #[test]
    fn vm_call_link_boundary_validation_rejects_unregistered_target_without_mutating_evidence() {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let code_block = generated_js_call_return_consumed_code_block();
        let owner = register_test_code_block(&mut vm, code_block.clone());
        let bytecode_snapshot =
            BaselineBytecodeEligibilityProof::fingerprint_code_block_snapshot(&code_block)
                .expect("bytecode snapshot");
        let frame = CallFrameId(900);
        let bytecode_index = BytecodeIndex::from_offset(1);
        let executable = crate::runtime::ExecutableId(CellId(404));
        let target_code_block = CodeBlockId(CellId(405));

        let observation = vm
            .tiering_integration_mut()
            .record_call_observation(VmCallObservationRequest {
                owner,
                frame: Some(frame),
                bytecode_index,
                opcode: CoreOpcode::Call,
                bytecode_snapshot,
                descriptor: CallObservationDescriptor {
                    owner,
                    frame,
                    bytecode_index: bytecode_index.offset(),
                    opcode: CoreOpcode::Call,
                    destination: local(1),
                    callee_register: argument_including_this(1),
                    callee_value_kind: ValueKind::Cell,
                    callee_object: Some(ObjectId(CellId(406))),
                    this_source: CallObservationThisSource::ImplicitUndefined,
                    this_value_kind: ValueKind::Undefined,
                    this_object: None,
                    provided_argument_count: 0,
                    argument_count_including_this: 1,
                    target_kind: CallObservationTargetKind::BytecodeFunction { function_index: 0 },
                    target_executable: Some(executable),
                    target_code_block: Some(target_code_block),
                    outcome: CallObservationOutcome::Returned,
                    may_call_js: true,
                    root_safety: CallObservationRootSafety::RootSafe,
                    direct_call_readiness: CallObservationDirectCallReadiness::Disallowed,
                },
            })
            .expect("metadata-only forged call observation");
        let descriptor_before = vm.tiering_integration().call_link_descriptor_records()[0].clone();

        let validation = vm
            .record_metadata_only_call_link_boundary_validation_for_observation(observation.ordinal)
            .expect("boundary validation record");

        assert_eq!(validation.descriptor_ordinal, descriptor_before.ordinal);
        assert_eq!(
            validation.outcome,
            VmCallLinkBoundaryValidationOutcome::Rejected(
                VmCallLinkBoundaryValidationRejection::Target(
                    VmCallLinkTargetValidationRejection::ExecutableNotRegistered { executable }
                )
            )
        );
        assert_eq!(
            vm.tiering_integration().call_link_descriptor_records()[0],
            descriptor_before,
            "registry validation must not mutate descriptor evidence"
        );
        assert_eq!(
            vm.tiering_integration()
                .call_link_boundary_validation_records(),
            std::slice::from_ref(&validation)
        );
        assert!(
            vm.tiering_integration()
                .call_link_attachment_plan_records()
                .is_empty(),
            "rejected target validation must not create attachment plans"
        );
        assert!(
            vm.tiering_integration()
                .call_link_attachment_install_rechecks()
                .is_empty(),
            "rejected target validation must not create install rechecks"
        );
        assert!(
            vm.tiering_integration()
                .call_link_inline_cache_attachment_records()
                .is_empty(),
            "rejected target validation must not attach call IC metadata"
        );
    }

    #[test]
    fn vm_generated_js_call_observation_handoff_records_throw_and_preserves_unwind() {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let (_thrown_string, thrown, thrown_cell) =
            heap_bound_string_value(&mut vm.heap, "generated call throw");
        let mut host = RecordingCoreHost::with_function_blocks(vec![
            js_call_throw_argument_function_code_block(),
        ]);
        let callee = load_function_value_for_test(&mut vm, &mut host, 0);
        let callee_cell = heap_cell_for_value(&vm, callee);
        host.clear_observations();

        let code_block = generated_js_call_throwing_code_block();
        let owner = register_test_code_block(&mut vm, code_block.clone());
        let inline_caches_before = code_block.side_tables().inline_caches().clone();
        let fallback_count_before = vm.tiering_integration().fallback_records().len();
        let artifact = install_typed_baseline_for_test(&mut vm, owner, 1023);
        let bytecode_snapshot = artifact.eligibility_proof.bytecode_snapshot_fingerprint();
        let generated_artifacts_before = vm
            .tiering_integration()
            .baseline_generated_code_artifacts()
            .to_vec();

        let (completion, boundary_snapshot) =
            execute_registered_code_block_with_boundary_snapshot_and_arguments(
                &mut vm,
                owner,
                &code_block,
                &mut host,
                vec![RuntimeValue::undefined(), callee, thrown],
            );

        let pending = if let ExecutionCompletion::Threw(pending) = completion {
            pending
        } else {
            unreachable!("expected generated call throw, got {completion:?}");
        };
        assert_eq!(pending.value, thrown);
        assert_eq!(vm.exception_state().pending(), Some(pending));
        let throw_origin = vm
            .exception_state()
            .unwind_state()
            .origin_frame()
            .expect("throw origin frame");
        assert_eq!(host.dispatches[0].0, throw_origin);
        assert_eq!(
            host.dispatches
                .iter()
                .map(|(_, index, opcode)| (*index, *opcode))
                .collect::<Vec<_>>(),
            vec![
                (BytecodeIndex::from_offset(1), Some(CoreOpcode::Call)),
                (BytecodeIndex::from_offset(0), Some(CoreOpcode::Throw)),
            ]
        );
        assert_eq!(
            vm.exception_state().unwind_state().popped_frames(),
            &[host.dispatches[0].0]
        );
        assert!(host.dispatch_roots[0]
            .iter()
            .any(|record| record.target == callee_cell));
        assert!(host.dispatch_roots[0]
            .iter()
            .any(|record| record.target == thrown_cell));
        assert!(
            !host.core.has_call_observation_record(),
            "throwing generated call handoff should drain the local call record"
        );
        let observations = vm.tiering_integration().call_observations();
        assert_eq!(observations.len(), 1);
        let observation = &observations[0];
        assert_eq!(observation.owner, owner);
        assert_eq!(observation.frame, Some(host.dispatches[0].0));
        assert_eq!(observation.bytecode_index, BytecodeIndex::from_offset(1));
        assert_eq!(observation.opcode, CoreOpcode::Call);
        assert_eq!(observation.bytecode_snapshot, bytecode_snapshot);
        let descriptor = &observation.descriptor;
        assert_eq!(descriptor.owner, owner);
        assert_eq!(descriptor.frame, host.dispatches[0].0);
        assert_eq!(descriptor.bytecode_index, 1);
        assert_eq!(descriptor.opcode, CoreOpcode::Call);
        assert_eq!(descriptor.callee_object, Some(ObjectId(callee_cell)));
        assert_eq!(descriptor.provided_argument_count, 1);
        assert_eq!(descriptor.argument_count_including_this, 2);
        assert_eq!(
            descriptor.target_kind,
            CallObservationTargetKind::BytecodeFunction { function_index: 0 }
        );
        assert_eq!(descriptor.outcome, CallObservationOutcome::Threw);
        assert_eq!(descriptor.root_safety, CallObservationRootSafety::RootSafe);
        assert_eq!(
            descriptor.direct_call_readiness,
            CallObservationDirectCallReadiness::Disallowed
        );
        assert_eq!(descriptor.validate(), Ok(()));
        assert!(
            vm.tiering_integration()
                .call_link_descriptor_records()
                .is_empty(),
            "throwing call observations must not create returned-call descriptors"
        );
        assert!(vm
            .tiering_integration()
            .call_link_boundary_validation_records()
            .is_empty());
        assert!(vm
            .tiering_integration()
            .call_link_attachment_plan_records()
            .is_empty());
        assert!(vm
            .tiering_integration()
            .call_link_attachment_install_rechecks()
            .is_empty());
        assert!(vm
            .tiering_integration()
            .call_link_inline_cache_attachment_records()
            .is_empty());
        assert_eq!(
            *code_block.side_tables().inline_caches(),
            inline_caches_before,
            "throwing call observation handoff must not mutate bytecode IC metadata"
        );

        let exception_plan = vm
            .exception_state()
            .targeted_root_plan(vm.heap())
            .expect("exception targeted root plan");
        assert_eq!(exception_plan.records().len(), 3);
        assert!(exception_plan
            .records()
            .iter()
            .all(|record| record.target == thrown_cell));
        assert_eq!(exception_targeted_roots(&vm), exception_plan.records());
        let non_exception_roots = vm
            .heap()
            .targeted_roots()
            .records()
            .iter()
            .copied()
            .filter(|record| !exception_plan.records().contains(record))
            .collect::<Vec<_>>();
        assert_eq!(non_exception_roots, boundary_snapshot.targeted_roots);
        assert!(!non_exception_roots
            .iter()
            .any(|record| record.target == callee_cell));
        assert!(!non_exception_roots
            .iter()
            .any(|record| record.target == thrown_cell));
        boundary_snapshot.assert_no_gc_scope_depth(0);
        boundary_snapshot.assert_current_no_gc_scope_depth(&vm, 0);
        assert_eq!(
            vm.tiering_integration().fallback_records().len(),
            fallback_count_before,
            "JS Call handoff should not be recorded as a generic generated fallback"
        );
        assert_eq!(
            vm.tiering_integration().baseline_generated_code_artifacts(),
            generated_artifacts_before.as_slice()
        );
        assert_latest_generated_entry_evidence(&vm, owner, artifact);
    }

    #[test]
    fn vm_generated_call_with_this_handoff_runs_call_then_generated_continuation_consumes_return_value(
    ) {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let mut host =
            RecordingCoreHost::with_function_blocks(vec![js_call_return_41_function_code_block()]);
        let callee = load_function_value_for_test(&mut vm, &mut host, 0);
        let callee_cell = heap_cell_for_value(&vm, callee);
        host.clear_observations();

        let code_block = generated_js_call_with_this_return_consumed_code_block();
        let owner = register_test_code_block(&mut vm, code_block.clone());
        let fallback_count_before = vm.tiering_integration().fallback_records().len();
        let artifact = install_typed_baseline_for_test(&mut vm, owner, 1122);

        let (completion, boundary_snapshot) =
            execute_registered_code_block_with_boundary_snapshot_and_arguments(
                &mut vm,
                owner,
                &code_block,
                &mut host,
                vec![
                    RuntimeValue::undefined(),
                    callee,
                    RuntimeValue::from_i32(13),
                ],
            );

        assert_eq!(
            completion,
            ExecutionCompletion::Returned(RuntimeValue::from_i32(42))
        );
        assert_eq!(
            host.dispatches
                .iter()
                .map(|(_, index, opcode)| (*index, *opcode))
                .collect::<Vec<_>>(),
            vec![
                (
                    BytecodeIndex::from_offset(1),
                    Some(CoreOpcode::CallWithThis)
                ),
                (BytecodeIndex::from_offset(0), Some(CoreOpcode::LoadInt32)),
                (BytecodeIndex::from_offset(1), Some(CoreOpcode::Return)),
            ]
        );
        assert!(host.dispatch_roots[0]
            .iter()
            .any(|record| record.target == callee_cell));
        assert_eq!(
            vm.tiering_integration().fallback_records().len(),
            fallback_count_before,
            "CallWithThis handoff should not be recorded as a generic generated fallback"
        );
        assert_eq!(
            vm.heap().targeted_roots().records(),
            boundary_snapshot.targeted_roots.as_slice()
        );
        boundary_snapshot.assert_no_gc_scope_depth(0);
        boundary_snapshot.assert_current_no_gc_scope_depth(&vm, 0);
        assert_latest_generated_entry_evidence(&vm, owner, artifact);
    }

    #[test]
    fn vm_generated_call_observation_with_this_handoff_records_explicit_heap_this_value() {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let (_this_object, this_value, this_cell) = heap_bound_object_value(&mut vm.heap);
        let function_unlinked = js_call_return_this_function_code_block().unlinked().clone();
        let function_blocks = vm
            .install_source_function_blocks(vec![function_unlinked])
            .expect("owned function executable call code");
        let expected_target_code_block = function_blocks[0].id;
        let expected_target_executable = function_blocks[0]
            .code_block
            .link_context()
            .owner_executable
            .expect("owned function executable");
        let mut host = RecordingCoreHost::with_function_code_blocks(function_blocks);
        let callee = load_function_value_for_test(&mut vm, &mut host, 0);
        let callee_cell = heap_cell_for_value(&vm, callee);
        host.clear_observations();

        let code_block = generated_js_call_with_this_return_result_code_block();
        let owner = register_test_code_block(&mut vm, code_block.clone());
        let inline_caches_before = code_block.side_tables().inline_caches().clone();
        let fallback_count_before = vm.tiering_integration().fallback_records().len();
        let artifact = install_typed_baseline_for_test(&mut vm, owner, 1124);
        let bytecode_snapshot = artifact.eligibility_proof.bytecode_snapshot_fingerprint();
        let entry_artifacts_before = vm.tiering_integration().baseline_entry_artifacts().to_vec();
        let generated_artifacts_before = vm
            .tiering_integration()
            .baseline_generated_code_artifacts()
            .to_vec();

        let (completion, boundary_snapshot) =
            execute_registered_code_block_with_boundary_snapshot_and_arguments(
                &mut vm,
                owner,
                &code_block,
                &mut host,
                vec![RuntimeValue::undefined(), callee, this_value],
            );

        assert_eq!(completion, ExecutionCompletion::Returned(this_value));
        let dispatches = host
            .dispatches
            .iter()
            .map(|(_, index, opcode)| (*index, *opcode))
            .collect::<Vec<_>>();
        if vm.can_execute_p6_x86_64_emitted_native_entry() {
            assert_eq!(
                dispatches,
                vec![(
                    BytecodeIndex::from_offset(1),
                    Some(CoreOpcode::CallWithThis)
                )]
            );
        } else {
            assert_eq!(
                dispatches.first().copied(),
                Some((
                    BytecodeIndex::from_offset(1),
                    Some(CoreOpcode::CallWithThis)
                ))
            );
        }
        assert!(host.dispatch_roots[0]
            .iter()
            .any(|record| record.target == callee_cell));
        assert!(host.dispatch_roots[0]
            .iter()
            .any(|record| record.target == this_cell));
        assert!(
            !host.core.has_call_observation_record(),
            "generated CallWithThis handoff should drain the local call record"
        );
        let observations = vm.tiering_integration().call_observations();
        assert_eq!(observations.len(), 1);
        let observation = &observations[0];
        assert_eq!(observation.owner, owner);
        assert_eq!(observation.frame, Some(host.dispatches[0].0));
        assert_eq!(observation.bytecode_index, BytecodeIndex::from_offset(1));
        assert_eq!(observation.opcode, CoreOpcode::CallWithThis);
        assert_eq!(observation.bytecode_snapshot, bytecode_snapshot);
        let descriptor = &observation.descriptor;
        assert_eq!(descriptor.owner, owner);
        assert_eq!(descriptor.frame, host.dispatches[0].0);
        assert_eq!(descriptor.bytecode_index, 1);
        assert_eq!(descriptor.opcode, CoreOpcode::CallWithThis);
        assert_eq!(descriptor.destination, local(1));
        assert_eq!(descriptor.callee_register, argument_including_this(1));
        assert_eq!(descriptor.callee_object, Some(ObjectId(callee_cell)));
        assert_eq!(
            descriptor.this_source,
            CallObservationThisSource::ExplicitRegister(argument_including_this(2))
        );
        assert_eq!(descriptor.this_value_kind, ValueKind::Cell);
        assert_eq!(descriptor.this_object, Some(ObjectId(this_cell)));
        assert_eq!(descriptor.provided_argument_count, 0);
        assert_eq!(descriptor.argument_count_including_this, 1);
        assert_eq!(
            descriptor.target_kind,
            CallObservationTargetKind::BytecodeFunction { function_index: 0 }
        );
        assert_eq!(
            descriptor.target_executable,
            Some(expected_target_executable)
        );
        assert_eq!(
            descriptor.target_code_block,
            Some(expected_target_code_block)
        );
        assert_eq!(descriptor.outcome, CallObservationOutcome::Returned);
        assert!(descriptor.may_call_js);
        assert_eq!(descriptor.root_safety, CallObservationRootSafety::RootSafe);
        assert_eq!(
            descriptor.direct_call_readiness,
            CallObservationDirectCallReadiness::Disallowed
        );
        assert_eq!(descriptor.validate(), Ok(()));
        let readiness = vm.tiering_integration().call_link_readiness_records();
        assert_eq!(readiness.len(), 1);
        assert_eq!(readiness[0].owner, observation.owner);
        assert_eq!(readiness[0].frame, observation.frame);
        assert_eq!(readiness[0].bytecode_index, observation.bytecode_index);
        assert_eq!(readiness[0].opcode, CoreOpcode::CallWithThis);
        assert_eq!(
            readiness[0].bytecode_snapshot,
            observation.bytecode_snapshot
        );
        assert_eq!(readiness[0].observation_ordinal, observation.ordinal);
        let [call_link_record] = vm.tiering_integration().call_link_descriptor_records() else {
            assert_eq!(
                vm.tiering_integration()
                    .call_link_descriptor_records()
                    .len(),
                1,
                "expected one metadata-only CallWithThis descriptor"
            );
            return;
        };
        assert_eq!(
            readiness[0].call_link_descriptor_ordinal,
            Some(call_link_record.ordinal)
        );
        assert!(!readiness[0]
            .blockers
            .contains(CallLinkReadinessBlocker::DirectCallDisallowed));
        assert!(!readiness[0]
            .blockers
            .contains(CallLinkReadinessBlocker::MissingCallSiteMetadata));
        assert!(readiness[0]
            .blockers
            .contains(CallLinkReadinessBlocker::MissingCallBoundary));
        assert!(!readiness[0]
            .blockers
            .contains(CallLinkReadinessBlocker::MissingExecutableTarget));
        assert!(!readiness[0]
            .blockers
            .contains(CallLinkReadinessBlocker::MissingTargetCodeBlock));
        assert!(readiness[0]
            .blockers
            .contains(CallLinkReadinessBlocker::MayCallJsBoundary));
        assert_eq!(call_link_record.owner, owner);
        assert_eq!(call_link_record.frame, observation.frame);
        assert_eq!(call_link_record.bytecode_index, observation.bytecode_index);
        assert_eq!(call_link_record.opcode, observation.opcode);
        assert_eq!(
            call_link_record.bytecode_snapshot,
            observation.bytecode_snapshot
        );
        assert_eq!(call_link_record.observation_ordinal, observation.ordinal);
        assert_eq!(call_link_record.readiness_ordinal, readiness[0].ordinal);
        assert_eq!(
            call_link_record.lifecycle,
            VmCallLinkDescriptorLifecycle::MetadataOnly
        );
        assert_eq!(call_link_record.blockers, readiness[0].blockers);
        assert_eq!(
            call_link_record.descriptor,
            CallLinkInfoDescriptor {
                mode: CallLinkMode::Init,
                call_kind: LinkedCallKind::Call,
                owner: Some(owner),
                executable: Some(expected_target_executable),
                callee: Some(ObjectId(callee_cell)),
                target_code_block: Some(expected_target_code_block),
                boundary: None,
                slow_path_count: 1,
                max_argument_count_including_this: 1,
            }
        );
        let [boundary_validation] = vm
            .tiering_integration()
            .call_link_boundary_validation_records()
        else {
            assert_eq!(
                vm.tiering_integration()
                    .call_link_boundary_validation_records()
                    .len(),
                1,
                "expected one metadata-only CallWithThis boundary validation"
            );
            return;
        };
        let expected_boundary =
            CallBoundaryId(CALL_LINK_BOUNDARY_ID_BASE + call_link_record.ordinal);
        assert_eq!(
            boundary_validation.descriptor_ordinal,
            call_link_record.ordinal
        );
        assert_eq!(
            boundary_validation.outcome,
            VmCallLinkBoundaryValidationOutcome::Accepted {
                target: VmCallLinkTargetValidation {
                    executable: expected_target_executable,
                    target_code_block: expected_target_code_block,
                    callee: ObjectId(callee_cell),
                    specialization: CodeSpecialization::Call,
                },
                boundary: CallBoundaryMetadata {
                    id: expected_boundary,
                    owner: Some(owner),
                    abi: EntryAbi::LlIntCompatible,
                    entry_kind: EntrypointKind::InterpreterThunk,
                    native_symbol: None,
                    arguments: vec![AbiValue::JsValue],
                    returns: vec![AbiValue::JsValue],
                    registers: Vec::new(),
                    frame_slots: Vec::new(),
                    requires_vm_entry_scope: true,
                    may_call_js: true,
                    may_throw: true,
                },
                descriptor: CallLinkInfoDescriptor {
                    mode: CallLinkMode::Init,
                    call_kind: LinkedCallKind::Call,
                    owner: Some(owner),
                    executable: Some(expected_target_executable),
                    callee: Some(ObjectId(callee_cell)),
                    target_code_block: Some(expected_target_code_block),
                    boundary: Some(expected_boundary),
                    slow_path_count: 1,
                    max_argument_count_including_this: 1,
                },
                remaining_blockers: {
                    let mut blockers = crate::jit::CallLinkReadinessBlockers::empty();
                    blockers.insert(CallLinkReadinessBlocker::MayCallJsBoundary);
                    blockers
                },
            }
        );
        let [attachment_plan] = vm.tiering_integration().call_link_attachment_plan_records() else {
            assert_eq!(
                vm.tiering_integration()
                    .call_link_attachment_plan_records()
                    .len(),
                1,
                "expected one metadata-only CallWithThis attachment plan"
            );
            return;
        };
        assert_eq!(
            attachment_plan.boundary_validation_ordinal,
            boundary_validation.ordinal
        );
        assert_eq!(
            attachment_plan.descriptor_ordinal,
            Some(call_link_record.ordinal)
        );
        assert_eq!(
            attachment_plan.lifecycle,
            VmCallLinkAttachmentPlanLifecycle::MetadataOnly
        );
        let VmCallLinkAttachmentPlanOutcome::Planned { plan } = &attachment_plan.outcome else {
            panic!(
                "expected planned metadata-only CallWithThis attachment, got {:?}",
                attachment_plan.outcome
            );
        };
        assert_eq!(plan.owner, owner);
        assert_eq!(plan.opcode, CoreOpcode::CallWithThis);
        assert_eq!(plan.bytecode_index, observation.bytecode_index.offset());
        assert_eq!(plan.descriptor.boundary, Some(expected_boundary));
        assert_eq!(plan.boundary.id, expected_boundary);
        assert_eq!(
            plan.planned_stub_kind,
            InlineCacheStubKind::HandlerWithCallLinkInfo
        );
        assert!(!plan
            .remaining_blockers
            .contains(CallLinkReadinessBlocker::DirectCallDisallowed));
        assert!(plan
            .remaining_blockers
            .contains(CallLinkReadinessBlocker::MayCallJsBoundary));
        assert!(plan.stub.code.is_none());
        assert!(plan.stub.cases.is_empty());
        assert!(plan.stub.weak_structures.is_empty());
        assert!(plan.stub.barrier_metadata.is_empty());
        assert_eq!(plan.stub.call_links, vec![plan.descriptor]);
        let plan_table = vm
            .tiering_integration()
            .call_link_attachment_plan_table_for_owner(owner, bytecode_snapshot)
            .expect("CallWithThis attachment plan table");
        assert_eq!(plan_table.len(), 1);
        assert_eq!(&plan_table.plans()[0], plan.as_ref());
        let [install_recheck] = vm
            .tiering_integration()
            .call_link_attachment_install_rechecks()
        else {
            assert_eq!(
                vm.tiering_integration()
                    .call_link_attachment_install_rechecks()
                    .len(),
                1,
                "expected one metadata-only CallWithThis install recheck"
            );
            return;
        };
        assert_eq!(install_recheck.owner, owner);
        assert_eq!(install_recheck.slot, plan.slot);
        assert_eq!(
            install_recheck.attachment_plan_ordinal,
            attachment_plan.ordinal
        );
        assert_eq!(
            install_recheck.boundary_validation_ordinal,
            Some(boundary_validation.ordinal)
        );
        assert_eq!(
            install_recheck.descriptor_ordinal,
            Some(call_link_record.ordinal)
        );
        assert_eq!(
            install_recheck.observation_ordinal,
            Some(observation.ordinal)
        );
        assert_eq!(
            install_recheck.outcome,
            VmCallLinkAttachmentInstallRecheckOutcome::Accepted
        );
        let [call_link_attachment] = vm
            .tiering_integration()
            .call_link_inline_cache_attachment_records()
        else {
            assert_eq!(
                vm.tiering_integration()
                    .call_link_inline_cache_attachment_records()
                    .len(),
                1,
                "expected one metadata-only CallWithThis inline-cache attachment"
            );
            return;
        };
        assert_eq!(call_link_attachment.owner, owner);
        assert_eq!(call_link_attachment.slot, plan.slot);
        assert_eq!(
            call_link_attachment.bytecode_index,
            observation.bytecode_index
        );
        assert_eq!(
            call_link_attachment.attachment_plan_ordinal,
            attachment_plan.ordinal
        );
        assert_eq!(
            call_link_attachment.install_recheck_ordinal,
            install_recheck.ordinal
        );
        assert_eq!(
            call_link_attachment.lifecycle,
            VmCallLinkInlineCacheAttachmentLifecycle::Active
        );
        let VmCallLinkInlineCacheAttachmentOutcome::Accepted {
            outcome: code_block_outcome,
        } = &call_link_attachment.outcome
        else {
            panic!(
                "expected accepted metadata-only CallWithThis inline-cache attachment, got {:?}",
                call_link_attachment.outcome
            );
        };
        assert_eq!(code_block_outcome.slot, plan.slot.0 as usize);
        assert_eq!(
            code_block_outcome.bytecode_index,
            observation.bytecode_index
        );
        assert_eq!(code_block_outcome.opcode, CoreOpcode::CallWithThis);
        assert_eq!(
            code_block_outcome.call_type,
            crate::bytecode::ic::CallType::Call
        );
        assert_ne!(
            code_block_outcome.call_type,
            crate::bytecode::ic::CallType::DirectCall
        );
        assert_eq!(
            code_block_outcome.mode,
            crate::bytecode::ic::CallLinkMode::Monomorphic
        );
        assert_eq!(code_block_outcome.specialization, CodeSpecialization::Call);
        assert_eq!(
            code_block_outcome.target,
            CallTarget::MetadataOnlyMonomorphic {
                callee: ObjectId(callee_cell),
                executable: expected_target_executable,
                code_block: expected_target_code_block,
                boundary: expected_boundary,
            }
        );
        let registered_code_block = vm
            .code_blocks
            .get(owner)
            .expect("registered owner code block")
            .code_block();
        let registered_inline_caches = registered_code_block.side_tables().inline_caches().clone();
        assert_eq!(
            &registered_inline_caches.property_accesses, &inline_caches_before.property_accesses,
            "CallWithThis attachment must not mutate property IC metadata"
        );
        assert_eq!(
            &registered_inline_caches.structure_stubs, &inline_caches_before.structure_stubs,
            "CallWithThis attachment must not create structure stubs"
        );
        assert_eq!(
            &registered_inline_caches.iteration_modes, &inline_caches_before.iteration_modes,
            "CallWithThis attachment must not mutate iteration metadata"
        );
        assert_ne!(
            &registered_inline_caches.calls, &inline_caches_before.calls,
            "accepted metadata-only CallWithThis attachment should update call IC metadata"
        );
        assert_eq!(
            &registered_inline_caches.calls[plan.slot.0 as usize].target,
            &code_block_outcome.target
        );
        assert_eq!(
            vm.heap().targeted_roots().records(),
            boundary_snapshot.targeted_roots.as_slice()
        );
        assert!(!vm
            .heap()
            .targeted_roots()
            .records()
            .iter()
            .any(|record| record.target == callee_cell));
        assert!(!vm
            .heap()
            .targeted_roots()
            .records()
            .iter()
            .any(|record| record.target == this_cell));
        boundary_snapshot.assert_no_gc_scope_depth(0);
        boundary_snapshot.assert_current_no_gc_scope_depth(&vm, 0);
        assert_eq!(
            vm.tiering_integration().fallback_records().len(),
            fallback_count_before,
            "CallWithThis handoff should not record a generic fallback for the nested return callee"
        );
        assert!(vm.code_block_owner_is_live(expected_target_code_block));
        let entry_artifacts_after = vm.tiering_integration().baseline_entry_artifacts();
        assert!(
            entry_artifacts_after.starts_with(entry_artifacts_before.as_slice()),
            "CallWithThis handoff should preserve existing native entry artifacts while materializing the nested callee"
        );
        let new_entry_artifacts = &entry_artifacts_after[entry_artifacts_before.len()..];
        let generated_artifacts_after =
            vm.tiering_integration().baseline_generated_code_artifacts();
        assert!(
            generated_artifacts_after.starts_with(generated_artifacts_before.as_slice()),
            "CallWithThis handoff should preserve existing generated artifacts while materializing the nested callee"
        );
        let new_generated_artifacts =
            &generated_artifacts_after[generated_artifacts_before.len()..];
        let nested_auto_record = vm
            .tiering_integration()
            .baseline_entry_auto_materializations()
            .iter()
            .find(|record| record.owner == expected_target_code_block)
            .expect("nested CallWithThis callee should have an auto materialization record");
        match nested_auto_record.native {
            BaselineEntryAutoNativeMaterializationOutcome::Installed => {
                assert!(new_entry_artifacts
                    .iter()
                    .any(|artifact| artifact.owner == expected_target_code_block));
                if baseline_native_entry_for_owner_is_host_callable(&vm, expected_target_code_block)
                {
                    assert_eq!(nested_auto_record.generated, None);
                    assert_eq!(new_generated_artifacts.len(), 0);
                } else {
                    assert_eq!(
                        nested_auto_record.generated,
                        Some(BaselineEntryAutoGeneratedMaterializationOutcome::Installed)
                    );
                    assert_eq!(new_generated_artifacts.len(), 1);
                    assert_eq!(new_generated_artifacts[0].owner, expected_target_code_block);
                }
            }
            BaselineEntryAutoNativeMaterializationOutcome::SkippedDisabledNativeEntry
            | BaselineEntryAutoNativeMaterializationOutcome::SkippedHostBlockedX86_64NativeEntry
            | BaselineEntryAutoNativeMaterializationOutcome::SkippedMissingNativeEntryGate
            | BaselineEntryAutoNativeMaterializationOutcome::Failed { .. } => {
                assert_eq!(
                    nested_auto_record.generated,
                    Some(BaselineEntryAutoGeneratedMaterializationOutcome::Installed)
                );
                assert_eq!(new_generated_artifacts.len(), 1);
                assert_eq!(new_generated_artifacts[0].owner, expected_target_code_block);
            }
        }
        assert_latest_generated_entry_evidence(&vm, owner, artifact);
    }

    #[test]
    fn vm_generated_call_with_this_handoff_roots_heap_throw_and_unwinds() {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let (_this_object, this_value, this_cell) = heap_bound_object_value(&mut vm.heap);
        let (_thrown_string, thrown, thrown_cell) =
            heap_bound_string_value(&mut vm.heap, "generated call with this throw");
        let mut host = RecordingCoreHost::with_function_blocks(vec![
            js_call_throw_argument_function_code_block(),
        ]);
        let callee = load_function_value_for_test(&mut vm, &mut host, 0);
        let callee_cell = heap_cell_for_value(&vm, callee);
        host.clear_observations();

        let code_block = generated_js_call_with_this_throwing_code_block();
        let owner = register_test_code_block(&mut vm, code_block.clone());
        let fallback_count_before = vm.tiering_integration().fallback_records().len();
        let artifact = install_typed_baseline_for_test(&mut vm, owner, 1123);

        let (completion, boundary_snapshot) =
            execute_registered_code_block_with_boundary_snapshot_and_arguments(
                &mut vm,
                owner,
                &code_block,
                &mut host,
                vec![RuntimeValue::undefined(), callee, this_value, thrown],
            );

        let pending = if let ExecutionCompletion::Threw(pending) = completion {
            pending
        } else {
            unreachable!("expected generated CallWithThis throw, got {completion:?}");
        };
        assert_eq!(pending.value, thrown);
        assert_eq!(vm.exception_state().pending(), Some(pending));
        let throw_origin = vm
            .exception_state()
            .unwind_state()
            .origin_frame()
            .expect("throw origin frame");
        assert_eq!(host.dispatches[0].0, throw_origin);
        assert_eq!(
            host.dispatches
                .iter()
                .map(|(_, index, opcode)| (*index, *opcode))
                .collect::<Vec<_>>(),
            vec![
                (
                    BytecodeIndex::from_offset(1),
                    Some(CoreOpcode::CallWithThis)
                ),
                (BytecodeIndex::from_offset(0), Some(CoreOpcode::Throw)),
            ]
        );
        assert_eq!(
            vm.exception_state().unwind_state().popped_frames(),
            &[host.dispatches[0].0]
        );
        assert!(host.dispatch_roots[0]
            .iter()
            .any(|record| record.target == callee_cell));
        assert!(host.dispatch_roots[0]
            .iter()
            .any(|record| record.target == this_cell));
        assert!(host.dispatch_roots[0]
            .iter()
            .any(|record| record.target == thrown_cell));
        assert!(
            vm.tiering_integration()
                .call_link_descriptor_records()
                .is_empty(),
            "throwing CallWithThis observations must not create returned-call descriptors"
        );
        assert!(vm
            .tiering_integration()
            .call_link_boundary_validation_records()
            .is_empty());
        assert!(vm
            .tiering_integration()
            .call_link_attachment_plan_records()
            .is_empty());
        assert!(vm
            .tiering_integration()
            .call_link_attachment_install_rechecks()
            .is_empty());
        assert!(vm
            .tiering_integration()
            .call_link_inline_cache_attachment_records()
            .is_empty());

        let exception_plan = vm
            .exception_state()
            .targeted_root_plan(vm.heap())
            .expect("exception targeted root plan");
        assert_eq!(exception_plan.records().len(), 3);
        assert!(exception_plan
            .records()
            .iter()
            .all(|record| record.target == thrown_cell));
        assert_eq!(exception_targeted_roots(&vm), exception_plan.records());
        let non_exception_roots = vm
            .heap()
            .targeted_roots()
            .records()
            .iter()
            .copied()
            .filter(|record| !exception_plan.records().contains(record))
            .collect::<Vec<_>>();
        assert_eq!(non_exception_roots, boundary_snapshot.targeted_roots);
        assert!(!non_exception_roots
            .iter()
            .any(|record| record.target == callee_cell));
        assert!(!non_exception_roots
            .iter()
            .any(|record| record.target == this_cell));
        assert!(!non_exception_roots
            .iter()
            .any(|record| record.target == thrown_cell));
        boundary_snapshot.assert_no_gc_scope_depth(0);
        boundary_snapshot.assert_current_no_gc_scope_depth(&vm, 0);
        assert_eq!(
            vm.tiering_integration().fallback_records().len(),
            fallback_count_before,
            "CallWithThis handoff should not be recorded as a generic generated fallback"
        );
        assert_latest_generated_entry_evidence(&vm, owner, artifact);
    }

    #[test]
    fn vm_generated_property_handoff_runs_get_by_name_then_generated_continuation_consumes_result()
    {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let mut host = RecordingCoreHost::with_function_blocks(Vec::new());
        let object = create_data_property_object_for_test(&mut vm, &mut host);
        let object_cell = heap_cell_for_value(&vm, object);
        host.clear_observations();

        let code_block = generated_property_get_by_name_return_consumed_code_block();
        let owner = register_test_code_block(&mut vm, code_block.clone());
        let inline_caches_before = code_block.side_tables().inline_caches().clone();
        let fallback_count_before = vm.tiering_integration().fallback_records().len();
        let artifact = install_typed_baseline_for_test(&mut vm, owner, 1024);
        assert!(artifact.runtime_helper_plan().is_none());
        assert!(artifact.property_handoff_plan().is_some());

        let (warmup_completion, _) =
            execute_registered_code_block_with_boundary_snapshot_and_arguments(
                &mut vm,
                owner,
                &code_block,
                &mut host,
                vec![RuntimeValue::undefined(), object],
            );
        assert_eq!(
            warmup_completion,
            ExecutionCompletion::Returned(RuntimeValue::from_i32(42))
        );
        host.clear_observations();

        let (completion, boundary_snapshot) =
            execute_registered_code_block_with_boundary_snapshot_and_arguments(
                &mut vm,
                owner,
                &code_block,
                &mut host,
                vec![RuntimeValue::undefined(), object],
            );

        assert_eq!(
            completion,
            ExecutionCompletion::Returned(RuntimeValue::from_i32(42))
        );
        assert_eq!(
            host.dispatches
                .iter()
                .map(|(_, index, opcode)| (*index, *opcode))
                .collect::<Vec<_>>(),
            vec![(BytecodeIndex::from_offset(1), Some(CoreOpcode::GetByName))]
        );
        assert!(host.dispatch_roots[0]
            .iter()
            .any(|record| record.target == object_cell));
        assert!(host
            .targeted_root_syncs
            .iter()
            .any(|(_, desired)| desired.iter().any(|record| record.target == object_cell)));
        assert!(
            !host.core.has_property_lookup_record(),
            "generated property handoff should drain the local lookup record"
        );
        let observations = vm.tiering_integration().property_load_observations();
        assert_eq!(observations.len(), 2);
        let observation = &observations[1];
        assert_eq!(
            observation.bytecode_snapshot,
            BaselineBytecodeEligibilityProof::fingerprint_code_block_snapshot(&code_block).unwrap()
        );
        assert_eq!(observation.owner, owner);
        assert_eq!(observation.frame, Some(host.dispatches[0].0));
        assert_eq!(observation.bytecode_index, BytecodeIndex::from_offset(1));
        assert_eq!(observation.descriptor.owner, owner);
        assert_eq!(observation.descriptor.slot, InlineCacheSlotId(0));
        assert_eq!(observation.descriptor.bytecode_index, 1);
        assert_eq!(
            observation.descriptor.cache_kind,
            InlineCacheKind::PropertyLoad
        );
        assert_eq!(
            observation.descriptor.fallback,
            InlineCacheFallbackSemantics::SlowPathLookup
        );
        assert_eq!(
            observation.descriptor.key,
            crate::jit::CacheKey::Property(PropertyKey::from_identifier(Identifier::from_atom(
                AtomId::from_table_slot(PROPERTY_HANDOFF_KEY)
            ),))
        );
        assert_eq!(
            observation.descriptor.base_object,
            Some(ObjectId(object_cell))
        );
        assert_eq!(
            observation.descriptor.holder_object,
            Some(ObjectId(object_cell))
        );
        assert_ne!(
            observation.descriptor.base_structure,
            Some(StructureId::INVALID)
        );
        assert!(observation.descriptor.base_structure.is_some());
        assert_eq!(observation.descriptor.offset, Some(PropertyOffset::new(0)));
        assert_eq!(observation.descriptor.prototype_depth, 0);
        assert_eq!(
            observation.descriptor.chain,
            vec![PropertyLoadObservationChainEntry {
                object: ObjectId(object_cell),
                structure: observation.descriptor.base_structure.unwrap(),
                next_prototype: None,
            }]
        );
        assert_eq!(
            observation.descriptor.observed_access_case_kind,
            Some(AccessCaseKind::Load)
        );
        assert!(!observation.descriptor.may_call_js);
        assert_eq!(
            observation.descriptor.cacheability,
            PropertyCacheability::Allowed
        );
        assert_eq!(
            observation.descriptor.readiness,
            PropertyLoadObservationReadiness::ReadyForAttachment
        );
        assert!(!observation
            .descriptor
            .readiness
            .blockers()
            .contains(PropertyLoadObservationBlocker::MissingBaseStructureGuard));
        assert!(!observation
            .descriptor
            .readiness
            .blockers()
            .contains(PropertyLoadObservationBlocker::MissingOffset));
        assert_eq!(observation.descriptor.validate(), Ok(()));
        let access_case_plans = vm.tiering_integration().property_load_access_case_plans();
        assert_eq!(access_case_plans.len(), 1);
        let plan_record = &access_case_plans[0];
        assert!(observation.ordinal < plan_record.ordinal);
        assert_eq!(plan_record.observation_ordinal, observation.ordinal);
        assert_eq!(plan_record.owner, owner);
        assert_eq!(plan_record.frame, Some(host.dispatches[0].0));
        assert_eq!(plan_record.bytecode_index, BytecodeIndex::from_offset(1));
        assert_eq!(plan_record.bytecode_snapshot, observation.bytecode_snapshot);
        assert_eq!(plan_record.plan.owner, owner);
        assert_eq!(plan_record.plan.slot, InlineCacheSlotId(0));
        assert_eq!(plan_record.plan.bytecode_index, 1);
        assert_eq!(plan_record.plan.key, observation.descriptor.key);
        assert_eq!(plan_record.plan.access_case.kind, AccessCaseKind::Load);
        assert_eq!(plan_record.plan.access_case.key, observation.descriptor.key);
        assert_eq!(
            plan_record.plan.access_case.base_structure,
            observation.descriptor.base_structure
        );
        assert_eq!(
            plan_record.plan.access_case.offset,
            observation.descriptor.offset
        );
        assert_eq!(plan_record.plan.access_case.holder, None);
        assert_eq!(plan_record.plan.access_case.new_structure, None);
        assert!(!plan_record.plan.access_case.via_global_proxy);
        assert!(!plan_record.plan.access_case.may_call_js);
        assert!(plan_record.plan.access_case.dependencies.is_empty());
        assert_eq!(
            *code_block.side_tables().inline_caches(),
            inline_caches_before,
            "property handoff slow dispatch must not mutate bytecode IC metadata"
        );
        assert_eq!(
            vm.tiering_integration().fallback_records().len(),
            fallback_count_before,
            "property handoff should not be recorded as a generic generated fallback"
        );
        assert_eq!(
            vm.heap().targeted_roots().records(),
            boundary_snapshot.targeted_roots.as_slice()
        );
        boundary_snapshot.assert_no_gc_scope_depth(0);
        boundary_snapshot.assert_current_no_gc_scope_depth(&vm, 0);
        assert_latest_generated_entry_evidence(&vm, owner, artifact);
    }

    #[test]
    fn vm_generated_resume_rebuilds_property_sidecars_for_same_execution_loop() {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let mut host = RecordingCoreHost::with_function_blocks(Vec::new());
        let object = create_data_property_object_for_test(&mut vm, &mut host);
        host.clear_observations();

        let code_block = generated_property_get_by_name_loop_return_sum_code_block();
        let owner = register_test_code_block(&mut vm, code_block.clone());
        let artifact = install_typed_baseline_for_test(&mut vm, owner, 1025);

        let (completion, boundary_snapshot) =
            execute_registered_code_block_with_boundary_snapshot_and_arguments(
                &mut vm,
                owner,
                &code_block,
                &mut host,
                vec![RuntimeValue::undefined(), object],
            );

        assert_eq!(
            completion,
            ExecutionCompletion::Returned(RuntimeValue::from_i32(82))
        );
        assert_eq!(
            host.dispatches
                .iter()
                .filter(|(_, index, opcode)| {
                    *index == BytecodeIndex::from_offset(6)
                        && *opcode == Some(CoreOpcode::GetByName)
                })
            .count(),
            2,
            "the first loop load should consume the initial IC countdown, the second should attach metadata, then the generated resume should use the active property sidecar"
        );
        assert!(
            host.property_load_probes.is_empty(),
            "same-execution resume should use the newly attached load metadata without recording another generated load probe"
        );
        assert_eq!(
            vm.tiering_integration().property_load_observations().len(),
            2
        );
        assert_eq!(
            vm.tiering_integration()
                .property_inline_cache_attachment_records()
                .len(),
            1
        );
        assert!(vm
            .tiering_integration()
            .generated_property_load_probe_misses()
            .is_empty());
        boundary_snapshot.assert_no_gc_scope_depth(0);
        boundary_snapshot.assert_current_no_gc_scope_depth(&vm, 0);
        assert_latest_generated_entry_evidence(&vm, owner, artifact);
    }

