    #[test]
    fn vm_generated_property_store_sidecar_skips_known_structure_mismatch_before_probe() {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let mut host = RecordingCoreHost::with_function_blocks(Vec::new());
        let first_object = create_data_property_object_for_test(&mut vm, &mut host);
        // C++ JSC: a known structure mismatch needs a genuinely different shape.
        // Same-shape siblings now share a structure id (Structure::
        // addPropertyTransition), so the second object carries an extra own
        // property to occupy a distinct structure while still holding
        // PROPERTY_HANDOFF_KEY.
        let second_object =
            create_data_property_object_with_distinct_structure_for_test(&mut vm, &mut host);
        host.clear_observations();

        let code_block = generated_property_put_by_name_return_value_code_block();
        let owner = register_test_code_block(&mut vm, code_block.clone());
        let artifact = install_typed_baseline_for_test(&mut vm, owner, 11_500);

        let warmup = execute_registered_code_block_with_host_and_arguments(
            &mut vm,
            owner,
            &code_block,
            &mut host,
            vec![RuntimeValue::undefined(), first_object],
        );
        assert_eq!(
            warmup,
            ExecutionCompletion::Returned(RuntimeValue::from_i32(43))
        );
        assert!(vm
            .tiering_integration()
            .property_store_access_case_plans()
            .iter()
            .all(
                |plan| plan.owner != owner || plan.bytecode_index != BytecodeIndex::from_offset(1)
            ));

        host.clear_observations();
        let first = execute_registered_code_block_with_host_and_arguments(
            &mut vm,
            owner,
            &code_block,
            &mut host,
            vec![RuntimeValue::undefined(), first_object],
        );
        assert_eq!(
            first,
            ExecutionCompletion::Returned(RuntimeValue::from_i32(43))
        );
        let first_plan = vm
            .tiering_integration()
            .property_store_access_case_plans()
            .iter()
            .find(|plan| {
                plan.owner == owner && plan.bytecode_index == BytecodeIndex::from_offset(1)
            })
            .expect("first owner store plan")
            .clone();
        host.clear_observations();
        let second = execute_registered_code_block_with_host_and_arguments(
            &mut vm,
            owner,
            &code_block,
            &mut host,
            vec![RuntimeValue::undefined(), second_object],
        );
        assert_eq!(
            second,
            ExecutionCompletion::Returned(RuntimeValue::from_i32(43))
        );
        assert!(
            host.property_store_probes.is_empty(),
            "known-wrong structure should fall through sidecar guards without a host probe"
        );
        assert!(host
            .dispatches
            .iter()
            .any(|(_, index, opcode)| *index == BytecodeIndex::from_offset(1)
                && *opcode == Some(CoreOpcode::PutByName)));
        assert!(vm
            .tiering_integration()
            .generated_property_store_probe_misses()
            .is_empty());

        let owner_plans = vm
            .tiering_integration()
            .property_store_access_case_plans()
            .iter()
            .filter(|plan| {
                plan.owner == owner && plan.bytecode_index == BytecodeIndex::from_offset(1)
            })
            .collect::<Vec<_>>();
        assert_eq!(owner_plans.len(), 2);
        let second_plan = owner_plans
            .into_iter()
            .find(|plan| plan.ordinal != first_plan.ordinal)
            .expect("second structure store plan")
            .clone();
        assert_ne!(
            first_plan.plan.access_case.base_structure,
            second_plan.plan.access_case.base_structure
        );

        host.clear_observations();
        let third = execute_registered_code_block_with_host_and_arguments(
            &mut vm,
            owner,
            &code_block,
            &mut host,
            vec![RuntimeValue::undefined(), second_object],
        );
        assert_eq!(
            third,
            ExecutionCompletion::Returned(RuntimeValue::from_i32(43))
        );
        assert_eq!(
            host.property_store_probes,
            vec![(
                BytecodeIndex::from_offset(1),
                second_object,
                RuntimeValue::from_i32(43)
            )]
        );
        assert_eq!(
            host.property_store_probe_base_structures,
            vec![second_plan.plan.access_case.base_structure]
        );
        assert_eq!(
            host.property_store_mutations,
            vec![(
                second_object,
                RuntimeValue::from_i32(43),
                second_plan.plan.key
            )]
        );
        assert!(host.dispatches.is_empty());
        assert!(vm
            .tiering_integration()
            .generated_property_store_probe_misses()
            .is_empty());
        assert_latest_generated_entry_evidence(&vm, owner, artifact);
    }

