    #[test]
    fn vm_generated_property_load_sidecar_skips_known_structure_mismatch_before_probe() {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let mut host = RecordingCoreHost::with_function_blocks(Vec::new());
        let first_object = create_data_property_object_for_test(&mut vm, &mut host);
        // C++ JSC: a known structure mismatch needs a genuinely different shape.
        // Same-shape siblings now share a structure id (Structure::
        // addPropertyTransition), so the second object carries an extra own
        // property to occupy a distinct structure while still holding
        // PROPERTY_HANDOFF_KEY at offset 0.
        let second_object =
            create_data_property_object_with_distinct_structure_for_test(&mut vm, &mut host);
        host.clear_observations();

        let code_block = generated_property_get_by_name_return_consumed_code_block();
        let owner = register_test_code_block(&mut vm, code_block.clone());
        let artifact = install_typed_baseline_for_test(&mut vm, owner, 11_280);

        let warmup = execute_registered_code_block_with_host_and_arguments(
            &mut vm,
            owner,
            &code_block,
            &mut host,
            vec![RuntimeValue::undefined(), first_object],
        );
        assert_eq!(
            warmup,
            ExecutionCompletion::Returned(RuntimeValue::from_i32(42))
        );
        assert!(vm
            .tiering_integration()
            .property_load_access_case_plans()
            .is_empty());

        host.clear_observations();
        let first = execute_registered_code_block_with_host_and_arguments(
            &mut vm,
            owner,
            &code_block,
            &mut host,
            vec![RuntimeValue::undefined(), first_object],
        );
        assert_eq!(
            first,
            ExecutionCompletion::Returned(RuntimeValue::from_i32(42))
        );
        let first_plan = vm.tiering_integration().property_load_access_case_plans()[0].clone();

        host.clear_observations();
        let second = execute_registered_code_block_with_host_and_arguments(
            &mut vm,
            owner,
            &code_block,
            &mut host,
            vec![RuntimeValue::undefined(), second_object],
        );
        assert_eq!(
            second,
            ExecutionCompletion::Returned(RuntimeValue::from_i32(42))
        );
        assert!(
            host.property_load_probes.is_empty(),
            "known-wrong structure should fall through sidecar guards without a host probe"
        );
        assert!(host
            .dispatches
            .iter()
            .any(|(_, index, opcode)| *index == BytecodeIndex::from_offset(1)
                && *opcode == Some(CoreOpcode::GetByName)));
        assert!(vm
            .tiering_integration()
            .generated_property_load_probe_misses()
            .is_empty());

        let plans = vm.tiering_integration().property_load_access_case_plans();
        assert_eq!(plans.len(), 2);
        let second_plan = plans
            .iter()
            .find(|plan| plan.ordinal != first_plan.ordinal)
            .expect("second structure load plan")
            .clone();
        assert_ne!(
            first_plan.plan.access_case.base_structure,
            second_plan.plan.access_case.base_structure
        );

        host.clear_observations();
        let third = execute_registered_code_block_with_host_and_arguments(
            &mut vm,
            owner,
            &code_block,
            &mut host,
            vec![RuntimeValue::undefined(), second_object],
        );
        assert_eq!(
            third,
            ExecutionCompletion::Returned(RuntimeValue::from_i32(42))
        );
        assert_eq!(
            host.property_load_probes,
            vec![(BytecodeIndex::from_offset(1), second_object)]
        );
        assert_eq!(
            host.property_load_probe_base_structures,
            vec![second_plan.plan.access_case.base_structure]
        );
        assert!(host.dispatches.is_empty());
        assert!(vm
            .tiering_integration()
            .generated_property_load_probe_misses()
            .is_empty());
        assert_latest_generated_entry_evidence(&vm, owner, artifact);
    }

