    #[test]
    fn vm_generated_property_load_sidecar_rejects_inexact_destination_root_sync() {
        for case in 0..3 {
            let mut vm = Vm::new(VmConfig::baseline_allowed());
            let mut host = RecordingCoreHost::with_function_blocks(Vec::new());
            let child = create_empty_object_for_test(&mut vm, &mut host);
            let wrong = create_empty_object_for_test(&mut vm, &mut host);
            let extra = create_empty_object_for_test(&mut vm, &mut host);
            let wrong_cell = heap_cell_for_value(&vm, wrong);
            let extra_cell = heap_cell_for_value(&vm, extra);
            let object = create_data_property_object_with_value_for_test(&mut vm, &mut host, child);
            host.clear_observations();

            let code_block = generated_property_get_by_name_throwing_code_block();
            let owner = register_test_code_block(&mut vm, code_block.clone());
            let artifact = install_typed_baseline_for_test(&mut vm, owner, 1132 + case);

            let warmup = execute_registered_code_block_with_host_and_arguments(
                &mut vm,
                owner,
                &code_block,
                &mut host,
                vec![RuntimeValue::undefined(), object],
            );
            assert_eq!(warmup, ExecutionCompletion::Returned(child));
            assert!(vm
                .tiering_integration()
                .property_load_access_case_plans()
                .is_empty());

            host.clear_observations();
            let first = execute_registered_code_block_with_host_and_arguments(
                &mut vm,
                owner,
                &code_block,
                &mut host,
                vec![RuntimeValue::undefined(), object],
            );
            assert_eq!(first, ExecutionCompletion::Returned(child));
            assert_eq!(
                vm.tiering_integration()
                    .property_load_access_case_plans()
                    .len(),
                1
            );

            host.clear_observations();
            let tamper = match case {
                0 => DestinationRootSyncTamper::Omit,
                1 => DestinationRootSyncTamper::WrongTarget(wrong_cell),
                _ => DestinationRootSyncTamper::Extra(extra_cell),
            };
            let fallback_count_before_second = vm.tiering_integration().fallback_records().len();
            let (second, boundary_snapshot) = {
                let mut tampering_host = TamperingDestinationRootSyncHost {
                    inner: &mut host,
                    tamper,
                };
                execute_registered_code_block_with_boundary_snapshot_and_arguments(
                    &mut vm,
                    owner,
                    &code_block,
                    &mut tampering_host,
                    vec![RuntimeValue::undefined(), object],
                )
            };

            assert_eq!(
                second,
                ExecutionCompletion::Failed(ExecutionError::BaselineGeneratedExecutionRejected),
                "unexpected root-sync outcome for {tamper:?}"
            );
            assert_eq!(
                host.property_load_probes,
                vec![(BytecodeIndex::from_offset(1), object)]
            );
            assert!(host.dispatches.is_empty());
            assert_eq!(
                vm.tiering_integration().fallback_records().len(),
                fallback_count_before_second,
                "rejected root sync should not record a generated fallback"
            );
            assert_eq!(
                vm.heap().targeted_roots().records(),
                boundary_snapshot.targeted_roots.as_slice()
            );
            boundary_snapshot.assert_no_gc_scope_depth(0);
            boundary_snapshot.assert_current_no_gc_scope_depth(&vm, 0);
            assert_latest_generated_entry_evidence(&vm, owner, artifact);
        }
    }

