        host.set_identifier_data_property_for_test(object, 777, RuntimeValue::from_i32(1))
            .expect("shape transition");
        let dispatches = vm.drain_property_load_guard_watchpoint_events_for_test(&mut host);
        assert_eq!(dispatches.len(), 1);
        assert!(matches!(
            vm.tiering_integration()
                .property_inline_cache_attachment_records()[0]
                .lifecycle,
            VmPropertyInlineCacheAttachmentLifecycle::Cleared { .. }
        ));

        let replacement_artifact = install_typed_baseline_for_test(&mut vm, owner, 1162);
        assert_eq!(
            replacement_artifact
                .eligibility_proof
                .bytecode_snapshot_fingerprint(),
            bytecode_snapshot
        );
