    #[test]
    fn vm_live_structure_watchpoints_materialize_guarded_get_and_dispatch_fired_event() {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let mut host = RecordingCoreHost::with_function_blocks(Vec::new());
        let (object, _) = create_prototype_data_property_object_for_test(&mut vm, &mut host);
        host.clear_observations();

        let code_block = generated_property_get_by_name_return_consumed_code_block();
        let owner = register_test_code_block(&mut vm, code_block.clone());
        let artifact = install_typed_baseline_for_test(&mut vm, owner, 1144);
        let bytecode_snapshot = artifact.eligibility_proof.bytecode_snapshot_fingerprint();

        let first = execute_registered_code_block_with_host_and_arguments(
            &mut vm,
            owner,
            &code_block,
            &mut host,
            vec![RuntimeValue::undefined(), object],
        );
        assert_eq!(
            first,
            ExecutionCompletion::Returned(RuntimeValue::from_i32(42))
        );
        let guard_plan = vm.tiering_integration().property_load_guard_plans()[0].clone();

        let materialization = accepted_guarded_materialization_for_plan(&vm, &guard_plan);
        assert_eq!(
            materialization.outcome,
            VmPropertyLoadGuardWatchpointMaterializationOutcome::Accepted { binding_count: 2 }
        );
        assert!(materialization
            .bindings
            .iter()
            .all(|binding| binding.sampled_state == WatchpointState::Clear));
        let attachment = accepted_guarded_attachment_for_plan(&vm, &guard_plan);
        assert_eq!(
            attachment.kind,
            VmPropertyInlineCacheAttachmentKind::GuardedPrototypeDataLoad
        );
        assert!(vm
            .tiering_integration()
            .property_load_guarded_candidate_table_for_owner(owner, bytecode_snapshot)
            .expect("attached guarded candidate table")
            .is_empty());

        let binding = materialization.bindings[0].clone();
        host.set_identifier_data_property_for_test(object, 777, RuntimeValue::from_i32(1))
            .expect("shape transition");
        let dispatches = vm.drain_property_load_guard_watchpoint_events_for_test(&mut host);
        assert_eq!(dispatches.len(), 1);
        assert_eq!(
            dispatches[0].outcome,
            VmPropertyLoadGuardWatchpointEventDispatchOutcome::Accepted {
                invalidation_count: 1
            }
        );
        let invalidation = vm
            .tiering_integration()
            .property_load_guard_watchpoint_invalidations()
            .last()
            .expect("watchpoint invalidation");
        assert!(matches!(
            invalidation.outcome,
            super::tiering::VmPropertyLoadGuardWatchpointInvalidationOutcome::Accepted { .. }
        ));
        let fired_generation = match &invalidation.outcome {
            super::tiering::VmPropertyLoadGuardWatchpointInvalidationOutcome::Accepted {
                fired_generation,
                ..
            } => *fired_generation,
            _ => unreachable!("checked accepted invalidation"),
        };
        assert_eq!(
            vm.tiering_integration()
                .property_load_guard_watchpoint_materializations()[0]
                .lifecycle,
            VmPropertyLoadGuardWatchpointMaterializationLifecycle::Invalidated {
                invalidation_ordinal: invalidation.ordinal,
                dependency_ordinal: binding.dependency_ordinal,
                set_id: binding.set_id,
                generation: fired_generation,
            }
        );
        assert!(vm
            .tiering_integration()
            .baseline_generated_code_invalidations()
            .last()
            .is_some_and(|record| record.artifact_id == Some(artifact.id)));
        assert!(vm
            .tiering_integration()
            .property_load_guarded_candidate_table_for_owner(owner, bytecode_snapshot)
            .expect("invalidated live guarded candidate table")
            .is_empty());

        host.clear_observations();
        let second = execute_registered_code_block_with_host_and_arguments(
            &mut vm,
            owner,
            &code_block,
            &mut host,
            vec![RuntimeValue::undefined(), object],
        );
        assert_eq!(
            second,
            ExecutionCompletion::Returned(RuntimeValue::from_i32(42))
        );
        assert_latest_generated_entry_invalidated(&vm, owner, artifact);
    }

