    #[test]
    fn vm_generated_property_handoff_rejects_forged_miss_handoff_before_host_dispatch() {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let mut host = RecordingCoreHost::with_function_blocks(Vec::new());
        let code_block = generated_property_get_by_name_return_consumed_code_block();
        let owner = register_test_code_block(&mut vm, code_block.clone());
        let frame = CallFrameId(900);
        let index = BytecodeIndex::from_offset(1);

        let mut wrong_owner = property_handoff_site(owner, index, PROPERTY_HANDOFF_KEY);
        wrong_owner.cold_miss_handoff.owner = CodeBlockId(CellId(901));
        assert_eq!(
            vm.dispatch_generated_property_handoff_in_current_region(
                forged_property_handoff(owner, frame, wrong_owner),
                &code_block,
                &mut host,
                DispatchConfig::default(),
            ),
            SingleDispatchOutcome::Failed(ExecutionError::BaselineGeneratedExecutionRejected)
        );
        assert!(host.dispatches.is_empty());

        let mut wrong_slot = property_handoff_site(owner, index, PROPERTY_HANDOFF_KEY);
        wrong_slot.cold_miss_handoff.slot = InlineCacheSlotId(99);
        assert_eq!(
            vm.dispatch_generated_property_handoff_in_current_region(
                forged_property_handoff(owner, frame, wrong_slot),
                &code_block,
                &mut host,
                DispatchConfig::default(),
            ),
            SingleDispatchOutcome::Failed(ExecutionError::BaselineGeneratedExecutionRejected)
        );
        assert!(host.dispatches.is_empty());

        let mut wrong_index = property_handoff_site(owner, index, PROPERTY_HANDOFF_KEY);
        wrong_index.cold_miss_handoff.bytecode_index = 99;
        assert_eq!(
            vm.dispatch_generated_property_handoff_in_current_region(
                forged_property_handoff(owner, frame, wrong_index),
                &code_block,
                &mut host,
                DispatchConfig::default(),
            ),
            SingleDispatchOutcome::Failed(ExecutionError::BaselineGeneratedExecutionRejected)
        );
        assert!(host.dispatches.is_empty());

        let mut wrong_kind = property_handoff_site(owner, index, PROPERTY_HANDOFF_KEY);
        wrong_kind.cold_miss_handoff.cache_kind = InlineCacheKind::ElementLoad;
        assert_eq!(
            vm.dispatch_generated_property_handoff_in_current_region(
                forged_property_handoff(owner, frame, wrong_kind),
                &code_block,
                &mut host,
                DispatchConfig::default(),
            ),
            SingleDispatchOutcome::Failed(ExecutionError::BaselineGeneratedExecutionRejected)
        );
        assert!(host.dispatches.is_empty());

        let mut wrong_miss = property_handoff_site(owner, index, PROPERTY_HANDOFF_KEY);
        wrong_miss.cold_miss_handoff.miss_kind = InlineCacheMissKind::CaseMiss;
        assert_eq!(
            vm.dispatch_generated_property_handoff_in_current_region(
                forged_property_handoff(owner, frame, wrong_miss),
                &code_block,
                &mut host,
                DispatchConfig::default(),
            ),
            SingleDispatchOutcome::Failed(ExecutionError::BaselineGeneratedExecutionRejected)
        );
        assert!(host.dispatches.is_empty());

        let mut wrong_boundary = property_handoff_site(owner, index, PROPERTY_HANDOFF_KEY);
        wrong_boundary.cold_miss_handoff.boundary = Some(CallBoundaryId(77));
        assert_eq!(
            vm.dispatch_generated_property_handoff_in_current_region(
                forged_property_handoff(owner, frame, wrong_boundary),
                &code_block,
                &mut host,
                DispatchConfig::default(),
            ),
            SingleDispatchOutcome::Failed(ExecutionError::BaselineGeneratedExecutionRejected)
        );
        assert!(host.dispatches.is_empty());

        let mut wrong_call_link = property_handoff_site(owner, index, PROPERTY_HANDOFF_KEY);
        wrong_call_link.cold_miss_handoff.call_link = Some(CallLinkInfoDescriptor {
            mode: CallLinkMode::Init,
            call_kind: LinkedCallKind::Call,
            owner: Some(owner),
            executable: None,
            callee: None,
            target_code_block: None,
            boundary: None,
            slow_path_count: 0,
            max_argument_count_including_this: 1,
        });
        assert_eq!(
            vm.dispatch_generated_property_handoff_in_current_region(
                forged_property_handoff(owner, frame, wrong_call_link),
                &code_block,
                &mut host,
                DispatchConfig::default(),
            ),
            SingleDispatchOutcome::Failed(ExecutionError::BaselineGeneratedExecutionRejected)
        );
        assert!(host.dispatches.is_empty());

        let mut wrong_preserves = property_handoff_site(owner, index, PROPERTY_HANDOFF_KEY);
        wrong_preserves
            .cold_miss_handoff
            .preserves_operand_registers = false;
        assert_eq!(
            vm.dispatch_generated_property_handoff_in_current_region(
                forged_property_handoff(owner, frame, wrong_preserves),
                &code_block,
                &mut host,
                DispatchConfig::default(),
            ),
            SingleDispatchOutcome::Failed(ExecutionError::BaselineGeneratedExecutionRejected)
        );
        assert!(host.dispatches.is_empty());

        let mut wrong_fallback = property_handoff_site(owner, index, PROPERTY_HANDOFF_KEY);
        wrong_fallback.cold_miss_handoff.fallback =
            InlineCacheFallbackSemantics::MegamorphicGeneric;
        assert_eq!(
            vm.dispatch_generated_property_handoff_in_current_region(
                forged_property_handoff(owner, frame, wrong_fallback),
                &code_block,
                &mut host,
                DispatchConfig::default(),
            ),
            SingleDispatchOutcome::Failed(ExecutionError::BaselineGeneratedExecutionRejected)
        );
        assert!(host.dispatches.is_empty());
        assert!(
            vm.tiering_integration()
                .property_load_observations()
                .is_empty(),
            "rejected-before-dispatch property handoffs must not record observations"
        );
    }

    #[test]
    fn vm_generated_property_handoff_roots_heap_throw_and_cleans_property_roots() {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let (_thrown_string, thrown, thrown_cell) =
            heap_bound_string_value(&mut vm.heap, "generated property throw");
        let mut host = RecordingCoreHost::with_function_blocks(vec![
            getter_throw_capture_function_code_block(),
        ]);
        let object = create_throwing_getter_object_for_test(&mut vm, &mut host, thrown);
        let object_cell = heap_cell_for_value(&vm, object);
        host.clear_observations();

        let code_block = generated_property_get_by_name_throwing_code_block();
        let owner = register_test_code_block(&mut vm, code_block.clone());
        let fallback_count_before = vm.tiering_integration().fallback_records().len();
        let artifact = install_typed_baseline_for_test(&mut vm, owner, 1025);

        let (completion, boundary_snapshot) =
            execute_registered_code_block_with_boundary_snapshot_and_arguments(
                &mut vm,
                owner,
                &code_block,
                &mut host,
                vec![RuntimeValue::undefined(), object],
            );

        let pending = if let ExecutionCompletion::Threw(pending) = completion {
            pending
        } else {
            unreachable!("expected generated property throw, got {completion:?}");
        };
        assert_eq!(pending.value, thrown);
        assert_eq!(vm.exception_state().pending(), Some(pending));
        assert_eq!(
            host.dispatches
                .first()
                .map(|(_, index, opcode)| (*index, *opcode)),
            Some((BytecodeIndex::from_offset(1), Some(CoreOpcode::GetByName)))
        );
        assert_eq!(
            vm.exception_state()
                .unwind_state()
                .origin_frame()
                .expect("throw origin frame"),
            host.dispatches[0].0
        );
        assert_eq!(
            vm.exception_state().unwind_state().popped_frames(),
            &[host.dispatches[0].0]
        );
        assert!(host.dispatch_roots[0]
            .iter()
            .any(|record| record.target == object_cell));

        let exception_plan = vm
            .exception_state()
            .targeted_root_plan(vm.heap())
            .expect("exception targeted root plan");
        assert_eq!(exception_plan.records().len(), 3);
        assert!(exception_plan
            .records()
            .iter()
            .all(|record| record.target == thrown_cell));
        assert_eq!(exception_targeted_roots(&vm), exception_plan.records());
        let non_exception_roots = vm
            .heap()
            .targeted_roots()
            .records()
            .iter()
            .copied()
            .filter(|record| !exception_plan.records().contains(record))
            .collect::<Vec<_>>();
        assert_eq!(non_exception_roots, boundary_snapshot.targeted_roots);
        assert!(!non_exception_roots
            .iter()
            .any(|record| record.target == object_cell));
        assert!(!non_exception_roots
            .iter()
            .any(|record| record.target == thrown_cell));
        boundary_snapshot.assert_no_gc_scope_depth(0);
        boundary_snapshot.assert_current_no_gc_scope_depth(&vm, 0);
        assert_eq!(
            vm.tiering_integration().fallback_records().len(),
            fallback_count_before,
            "property handoff should not be recorded as a generic generated fallback"
        );
        assert_latest_generated_entry_evidence(&vm, owner, artifact);
    }

