    #[test]
    fn vm_generated_runtime_helper_new_object_dispatches_and_returns_heap_cell() {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let (owner, code_block) =
            register_runtime_helper_new_object_code_block_with_root_map(&mut vm);
        let artifact = runtime_helper_shadow_artifact(owner, 901);
        let helper_index = BytecodeIndex::from_offset(0);
        let proofs = [BaselineGeneratedRuntimeHelperProof::new(
            helper_index,
            new_object_runtime_boundary_proof(owner, helper_index),
        )];
        let plan = runtime_helper_plan_for_block(&code_block, &proofs);
        let (entry, frame) = enter_runtime_helper_program_frame(&mut vm, owner, &code_block);
        let boundary_snapshot = HeapMutationSnapshot::capture(&vm);
        boundary_snapshot.assert_no_gc_scope_depth(0);
        let region = vm.enter_no_gc_execution_region();
        assert_vm_and_heap_no_gc_scope_depth(&vm, 1);
        let mut host = RecordingCoreHost::with_function_blocks(Vec::new());

        let completion = vm
            .execute_baseline_generated_code_with_runtime_helper_plan_in_current_region(
                BaselineGeneratedRuntimeHelperExecutionRequest {
                    artifact: &artifact,
                    owner,
                    code_block: &code_block,
                    expected_frame: frame,
                    runtime_helper_plan: plan,
                },
                &mut host,
                DispatchConfig::default(),
            );

        assert_vm_and_heap_no_gc_scope_depth(&vm, 1);
        assert!(
            host.dispatch_heap_no_gc_depths.contains(&0),
            "runtime-helper single-dispatch should run with heap no-GC suspended"
        );
        let returned = if let ExecutionCompletion::Returned(value) = completion {
            value
        } else {
            unreachable!("expected returned object, got {completion:?}");
        };
        let cell = heap_cell_for_returned_value(&vm, returned);
        let allocation = vm
            .heap()
            .allocation_records()
            .iter()
            .find(|record| record.response.cell == cell)
            .expect("returned object allocation");
        assert_eq!(
            allocation.response.metadata.type_info.cell_type,
            CellType::Object
        );
        assert!(allocation.published);
        assert!(vm.heap().allocation_records().len() > boundary_snapshot.allocation_record_count);
        assert_eq!(
            vm.heap().targeted_roots().records(),
            boundary_snapshot.targeted_roots.as_slice()
        );
        assert_eq!(
            vm.execution_context_stack()
                .frame(frame)
                .expect("active frame")
                .bytecode_index,
            Some(BytecodeIndex::from_offset(1))
        );

        vm.leave_no_gc_execution_region(region).unwrap();
        boundary_snapshot.assert_current_no_gc_scope_depth(&vm, 0);
        if vm.execution.frame(frame).is_some() {
            vm.execution.pop_frame(&mut vm.registers, frame).unwrap();
        }
        vm.execution.leave(entry).unwrap();
    }

