    #[test]
    fn vm_generated_runtime_helper_handoff_rejects_forged_metadata_without_dispatch() {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let (owner, code_block) =
            register_runtime_helper_new_object_code_block_with_root_map(&mut vm);
        let (entry, frame) = enter_runtime_helper_program_frame(&mut vm, owner, &code_block);
        let valid = forged_runtime_helper_handoff(
            owner,
            frame,
            BytecodeIndex::from_offset(0),
            CoreOpcode::NewObject,
            CompilerSafepointId(1),
            BytecodeRootMapId(42),
            1,
        );
        let mut cases = vec![
            BaselineGeneratedRuntimeHelperHandoff {
                safepoint: CompilerSafepointId(99),
                ..valid
            },
            BaselineGeneratedRuntimeHelperHandoff {
                root_map: BytecodeRootMapId(99),
                ..valid
            },
            BaselineGeneratedRuntimeHelperHandoff {
                root_count: 2,
                ..valid
            },
            BaselineGeneratedRuntimeHelperHandoff {
                resume: BaselineGeneratedRuntimeHelperResume {
                    opcode: CoreOpcode::NewArray,
                    ..valid.resume
                },
                ..valid
            },
            BaselineGeneratedRuntimeHelperHandoff {
                resume: BaselineGeneratedRuntimeHelperResume {
                    bytecode_index: BytecodeIndex::from_offset(1),
                    ..valid.resume
                },
                ..valid
            },
            BaselineGeneratedRuntimeHelperHandoff {
                resume: BaselineGeneratedRuntimeHelperResume {
                    frame: CallFrameId(frame.0.saturating_add(1)),
                    ..valid.resume
                },
                ..valid
            },
            BaselineGeneratedRuntimeHelperHandoff {
                requires_no_gc_exit_reentry: false,
                ..valid
            },
            BaselineGeneratedRuntimeHelperHandoff {
                may_throw: false,
                ..valid
            },
        ];

        for handoff in cases.drain(..) {
            let boundary_snapshot = HeapMutationSnapshot::capture(&vm);
            let region = vm.enter_no_gc_execution_region();
            let mut host = RecordingCoreHost::with_function_blocks(Vec::new());

            let outcome = vm.dispatch_generated_runtime_helper_handoff_in_current_region(
                handoff,
                &code_block,
                &mut host,
            );

            assert!(
                matches!(
                    outcome,
                    SingleDispatchOutcome::Failed(
                        ExecutionError::BaselineGeneratedExecutionRejected
                            | ExecutionError::GcBoundaryViolation
                    )
                ),
                "unexpected forged handoff outcome: {outcome:?}"
            );
            assert!(host.dispatches.is_empty());
            assert_vm_and_heap_no_gc_scope_depth(&vm, 1);
            boundary_snapshot.assert_heap_and_targeted_roots_unchanged(&vm);
            vm.leave_no_gc_execution_region(region).unwrap();
            boundary_snapshot.assert_current_no_gc_scope_depth(&vm, 0);
        }

        if vm.execution.frame(frame).is_some() {
            vm.execution.pop_frame(&mut vm.registers, frame).unwrap();
        }
        vm.execution.leave(entry).unwrap();
    }

