    #[cfg(all(unix, target_arch = "x86_64"))]
    #[test]
    fn vm_p7b_real_emitted_native_new_object_rejects_missing_and_forged_retained_metadata() {
        enum ForgedSiteCase {
            MissingRetainedSite,
            WrongOpcode,
            WrongSafepoint,
            WrongRootMap,
            WrongRootCount,
            StaleCodeBlockSnapshot,
            NoGcFlagMismatch,
            MayThrowMismatch,
        }

        let cases = [
            ForgedSiteCase::MissingRetainedSite,
            ForgedSiteCase::WrongOpcode,
            ForgedSiteCase::WrongSafepoint,
            ForgedSiteCase::WrongRootMap,
            ForgedSiteCase::WrongRootCount,
            ForgedSiteCase::StaleCodeBlockSnapshot,
            ForgedSiteCase::NoGcFlagMismatch,
            ForgedSiteCase::MayThrowMismatch,
        ];

        for (case_index, case) in cases.into_iter().enumerate() {
            let mut vm = Vm::new(VmConfig::baseline_allowed());
            let fixture = install_real_p6_retained_new_object_runtime_helper_native_exit(
                &mut vm,
                1_660 + case_index as u64,
            );
            let mut code_block = fixture.code_block.clone();
            match case {
                ForgedSiteCase::MissingRetainedSite => {
                    let table = vm
                        .p6_x86_64_callable_retained_return_tables
                        .iter_mut()
                        .find(|table| {
                            table.owner == fixture.owner
                                && table.readiness_ordinal == fixture.readiness.ordinal
                        })
                        .expect("real retained P6 native-exit table");
                    table.runtime_helper_exit_sites.clear();
                }
                ForgedSiteCase::WrongOpcode => {
                    mutate_real_p6_retained_runtime_helper_native_exit_site(
                        &mut vm,
                        &fixture,
                        |site| site.opcode = CoreOpcode::NewArray,
                    );
                }
                ForgedSiteCase::WrongSafepoint => {
                    mutate_real_p6_retained_runtime_helper_native_exit_site(
                        &mut vm,
                        &fixture,
                        |site| site.safepoint = CompilerSafepointId(99),
                    );
                }
                ForgedSiteCase::WrongRootMap => {
                    mutate_real_p6_retained_runtime_helper_native_exit_site(
                        &mut vm,
                        &fixture,
                        |site| site.root_map = BytecodeRootMapId(99),
                    );
                }
                ForgedSiteCase::WrongRootCount => {
                    mutate_real_p6_retained_runtime_helper_native_exit_site(
                        &mut vm,
                        &fixture,
                        |site| site.root_count = 2,
                    );
                }
                ForgedSiteCase::StaleCodeBlockSnapshot => {
                    code_block = runtime_helper_load_undefined_return_code_block();
                    *vm.code_blocks
                        .code_block_mut_for_test(fixture.owner)
                        .expect("registered helper owner") = code_block.clone();
                }
                ForgedSiteCase::NoGcFlagMismatch => {
                    mutate_real_p6_retained_runtime_helper_native_exit_site(
                        &mut vm,
                        &fixture,
                        |site| site.requires_no_gc_exit_reentry = false,
                    );
                }
                ForgedSiteCase::MayThrowMismatch => {
                    mutate_real_p6_retained_runtime_helper_native_exit_site(
                        &mut vm,
                        &fixture,
                        |site| site.may_throw = false,
                    );
                }
            }

            let (entry, frame) =
                enter_runtime_helper_program_frame(&mut vm, fixture.owner, &code_block);
            let fallback_count_before = vm.tiering_integration().fallback_records().len();
            let boundary_snapshot = HeapMutationSnapshot::capture(&vm);
            let region = vm.enter_no_gc_execution_region();
            let dispatch = fixture.dispatch(frame);
            let mut host = RecordingCoreHost::with_function_blocks(Vec::new());

            let completion = match vm
                .execute_p6_x86_64_callable_retained_native_exit_payload_in_current_region(
                    &code_block,
                    &dispatch,
                    fixture.helper_payload,
                    &mut host,
                    DispatchConfig::default(),
                ) {
                BaselineNativeEntryVmExecution::Native(completion) => completion,
                BaselineNativeEntryVmExecution::InterpreterFallback(completion) => completion,
                BaselineNativeEntryVmExecution::DeferredRootedInterpreterFallback {
                    completion,
                    ..
                } => completion,
                BaselineNativeEntryVmExecution::P9OwnerPostCallReentry(_) => {
                    ExecutionCompletion::Failed(ExecutionError::BaselineGeneratedExecutionRejected)
                }
                BaselineNativeEntryVmExecution::P6SideExitReentry(_) => {
                    ExecutionCompletion::Failed(ExecutionError::BaselineGeneratedExecutionRejected)
                }
            };

            assert!(
                matches!(
                    completion,
                    ExecutionCompletion::Failed(
                        ExecutionError::BaselineGeneratedExecutionRejected
                            | ExecutionError::GcBoundaryViolation
                    )
                ),
                "case {case_index}: unexpected forged metadata completion {completion:?}"
            );
            assert!(
                host.dispatches.is_empty(),
                "case {case_index}: forged helper metadata dispatched bytecode"
            );
            assert_eq!(
                vm.tiering_integration().fallback_records().len(),
                fallback_count_before,
                "case {case_index}: forged helper metadata recorded fallback telemetry"
            );
            assert_vm_and_heap_no_gc_scope_depth(&vm, 1);
            boundary_snapshot.assert_heap_and_targeted_roots_unchanged(&vm);

            vm.leave_no_gc_execution_region(region).unwrap();
            boundary_snapshot.assert_current_no_gc_scope_depth(&vm, 0);
            if vm.execution.frame(frame).is_some() {
                vm.execution.pop_frame(&mut vm.registers, frame).unwrap();
            }
            vm.execution.leave(entry).unwrap();
        }
    }

    #[cfg(all(unix, target_arch = "x86_64"))]
    #[test]
    fn vm_p7b_real_emitted_native_new_object_preserves_no_gc_roots_and_exception_state() {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let fixture =
            install_real_p6_retained_new_object_runtime_helper_native_exit(&mut vm, 1_690);
        let (entry, frame) =
            enter_runtime_helper_program_frame(&mut vm, fixture.owner, &fixture.code_block);
        let (proven_object, proven_value, proven_cell) = heap_bound_object_value(&mut vm.heap);
        let (unproven_object, unproven_value, unproven_cell) =
            heap_bound_object_value(&mut vm.heap);
        let window = vm
            .execution
            .frame(frame)
            .expect("active helper frame")
            .register_window;
        vm.registers
            .write(window, local(0), proven_value)
            .expect("write proven root slot");
        vm.registers
            .write(window, local(1), unproven_value)
            .expect("write unproven root slot");
        let boundary_snapshot = HeapMutationSnapshot::capture(&vm);
        let region = vm.enter_no_gc_execution_region();
        let dispatch = fixture.dispatch(frame);
        let mut host = RecordingCoreHost::with_function_blocks(Vec::new());

        let completion = match vm
            .execute_p6_x86_64_callable_retained_native_exit_payload_in_current_region(
                &fixture.code_block,
                &dispatch,
                fixture.helper_payload,
                &mut host,
                DispatchConfig::default(),
            ) {
            BaselineNativeEntryVmExecution::Native(completion) => completion,
            BaselineNativeEntryVmExecution::InterpreterFallback(completion) => completion,
            BaselineNativeEntryVmExecution::DeferredRootedInterpreterFallback {
                completion,
                ..
            } => completion,
            BaselineNativeEntryVmExecution::P9OwnerPostCallReentry(_) => {
                ExecutionCompletion::Failed(ExecutionError::BaselineGeneratedExecutionRejected)
            }
            BaselineNativeEntryVmExecution::P6SideExitReentry(_) => {
                ExecutionCompletion::Failed(ExecutionError::BaselineGeneratedExecutionRejected)
            }
        };

        assert!(matches!(completion, ExecutionCompletion::Returned(_)));
        assert_vm_and_heap_no_gc_scope_depth(&vm, 1);
        assert!(host.dispatch_roots[0]
            .iter()
            .any(|record| record.target == proven_cell));
        assert!(!host.dispatch_roots[0]
            .iter()
            .any(|record| record.target == unproven_cell));
        assert_eq!(
            vm.heap().targeted_roots().records(),
            boundary_snapshot.targeted_roots.as_slice()
        );
        assert!(vm.exceptions.pending().is_none());

        vm.leave_no_gc_execution_region(region).unwrap();
        boundary_snapshot.assert_current_no_gc_scope_depth(&vm, 0);
        if vm.execution.frame(frame).is_some() {
            vm.execution.pop_frame(&mut vm.registers, frame).unwrap();
        }
        vm.execution.leave(entry).unwrap();
        drop(proven_object);
        drop(unproven_object);
    }

    #[cfg(all(unix, target_arch = "x86_64"))]
    #[test]
    fn vm_p7_p6_retained_runtime_helper_native_exit_new_object_dispatches_without_fallback_telemetry(
    ) {
        let mut generated_vm = Vm::new(VmConfig::baseline_allowed());
        let (generated_owner, generated_code_block) =
            register_runtime_helper_new_object_code_block_with_root_map(&mut generated_vm);
        generated_vm
            .install_baseline_generated_code_artifact(
                generated_owner,
                JitCodeId(1_431),
                BaselineGeneratedCodeBodyId(1_531),
                BaselineInstallDependencyPolicy::Allow,
            )
            .expect("generated runtime-helper artifact");
        let generated_completion = execute_registered_code_block_with_host(
            &mut generated_vm,
            generated_owner,
            &generated_code_block,
            &mut RecordingCoreHost::with_function_blocks(Vec::new()),
        );
        let generated_result_type = match generated_completion {
            ExecutionCompletion::Returned(value) => {
                heap_cell_type_for_returned_value(&generated_vm, value)
            }
            completion => unreachable!("expected generated helper object, got {completion:?}"),
        };

        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let fixture =
            install_synthetic_p6_retained_new_object_runtime_helper_native_exit(&mut vm, 901);
        let (entry, frame) =
            enter_runtime_helper_program_frame(&mut vm, fixture.owner, &fixture.code_block);
        let (proven_object, proven_value, proven_cell) = heap_bound_object_value(&mut vm.heap);
        let (unproven_object, unproven_value, unproven_cell) =
            heap_bound_object_value(&mut vm.heap);
        let window = vm
            .execution
            .frame(frame)
            .expect("active helper frame")
            .register_window;
        vm.registers
            .write(window, local(0), proven_value)
            .expect("write proven root slot");
        vm.registers
            .write(window, local(1), unproven_value)
            .expect("write unproven root slot");
        let fallback_count_before = vm.tiering_integration().fallback_records().len();
        let boundary_snapshot = HeapMutationSnapshot::capture(&vm);
        let region = vm.enter_no_gc_execution_region();
        let dispatch = fixture.dispatch(frame);
        let mut host = RecordingCoreHost::with_function_blocks(Vec::new());

        let completion = match vm
            .execute_p6_x86_64_callable_retained_native_exit_payload_in_current_region(
                &fixture.code_block,
                &dispatch,
                fixture.helper_payload,
                &mut host,
                DispatchConfig::default(),
            ) {
            BaselineNativeEntryVmExecution::Native(completion) => completion,
            BaselineNativeEntryVmExecution::InterpreterFallback(completion) => {
                unreachable!("retained runtime-helper native exit must not be arithmetic fallback: {completion:?}")
            }
            BaselineNativeEntryVmExecution::DeferredRootedInterpreterFallback {
                completion,
                ..
            } => {
                unreachable!("retained runtime-helper native exit must not be rooted arithmetic fallback: {completion:?}")
            }
            BaselineNativeEntryVmExecution::P9OwnerPostCallReentry(_) => {
                ExecutionCompletion::Failed(ExecutionError::BaselineGeneratedExecutionRejected)
            }
            BaselineNativeEntryVmExecution::P6SideExitReentry(_) => {
                ExecutionCompletion::Failed(ExecutionError::BaselineGeneratedExecutionRejected)
            }
        };

        assert_vm_and_heap_no_gc_scope_depth(&vm, 1);
        assert_eq!(
            host.dispatches
                .first()
                .map(|(_, index, opcode)| (*index, *opcode)),
            Some((BytecodeIndex::from_offset(0), Some(CoreOpcode::NewObject)))
        );
        assert_eq!(host.dispatch_heap_no_gc_depths.first().copied(), Some(0));
        assert!(host.dispatch_roots[0]
            .iter()
            .any(|record| record.target == proven_cell));
        assert!(!host.dispatch_roots[0]
            .iter()
            .any(|record| record.target == unproven_cell));
        let returned = match completion {
            ExecutionCompletion::Returned(value) => value,
            completion => unreachable!("expected retained helper object, got {completion:?}"),
        };
        assert_eq!(
            heap_cell_type_for_returned_value(&vm, returned),
            generated_result_type
        );
        assert_eq!(
            vm.tiering_integration().fallback_records().len(),
            fallback_count_before,
            "retained runtime-helper native exit must not record arithmetic/generated fallback telemetry"
        );
        assert_eq!(
            vm.heap().targeted_roots().records(),
            boundary_snapshot.targeted_roots.as_slice()
        );

        vm.leave_no_gc_execution_region(region).unwrap();
        boundary_snapshot.assert_current_no_gc_scope_depth(&vm, 0);
        if vm.execution.frame(frame).is_some() {
            vm.execution.pop_frame(&mut vm.registers, frame).unwrap();
        }
        vm.execution.leave(entry).unwrap();
        drop(proven_object);
        drop(unproven_object);
    }

