    #[cfg(unix)]
    #[test]
    fn vm_p6_semantic_callable_install_preserves_disabled_readiness_and_exact_proof() {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let owner = register_test_code_block(&mut vm, p6_int32_arithmetic_code_block());
        let request = p6_semantic_install_request(owner, 733);
        let before = p6_semantic_install_side_effect_counts(&vm);

        let record = vm
            .install_p6_x86_64_callable_semantic_baseline_native_entry(request)
            .expect("accepted P6 semantic byte install");
        let enabled_readiness = record
            .enabled_readiness
            .as_ref()
            .expect("callable install records enabled readiness");

        assert_eq!(record.owner, owner);
        assert_eq!(
            record.semantic_emission.authority,
            crate::jit::P6X86_64BaselineSemanticByteEmissionAuthority::NonExecutableCallableSemanticBytesOnlyNoVmOrPlatformAuthority
        );
        let install_proof = record
            .install
            .eligibility_proof
            .as_ref()
            .expect("P6 callable install preserves eligibility proof");
        assert_eq!(install_proof, &record.eligibility_proof);
        assert_eq!(
            install_proof.opcode_subset(),
            BaselineSupportedOpcodeSubset::P6ConstantsMovesReturnInt32Arithmetic
        );
        assert_eq!(
            enabled_readiness.body_capability,
            Some(BaselineGeneratedCodeBodyCapability::from_eligibility_proof(
                install_proof
            ))
        );
        assert_eq!(
            record
                .artifact
                .machine_code
                .expect("machine code")
                .range
                .size_bytes,
            record.semantic_emission.linked_image.output_size_bytes
        );
        assert_eq!(
            record.machine_code_emission.linked_size_bytes,
            record.semantic_emission.linked_image.output_size_bytes
        );
        assert!(record
            .link_finalization
            .validate_accepted_with_byte_evidence()
            .is_ok());
        assert_eq!(
            record.materialization.outcome,
            BaselineExecutableMaterializationOutcome::Accepted
        );
        assert_eq!(record.platform_residency_index, before.platform_residencies);
        assert_eq!(
            vm.baseline_platform_executable_residencies.len(),
            before.platform_residencies + 1
        );
        assert_eq!(
            record.install.outcome,
            BaselineInstallOutcome::InstalledButEntryDisabled
        );
        assert_eq!(
            record.disabled_readiness.outcome,
            BaselineNativeEntryReadinessOutcome::ReadyButExecutionDisabled
        );
        assert_eq!(
            record.disabled_readiness.execution_policy,
            BaselineNativeEntryExecutionPolicy::Disabled
        );
        assert!(record.disabled_readiness.callable.is_none());
        assert_eq!(
            enabled_readiness.outcome,
            BaselineNativeEntryReadinessOutcome::Ready
        );
        assert_eq!(
            enabled_readiness.execution_policy,
            BaselineNativeEntryExecutionPolicy::Enabled
        );
        assert_eq!(
            enabled_readiness.callable.map(|callable| callable.kind()),
            Some(BaselineNativeEntryCallableKind::P6X86_64EmittedSemanticCAbiEntry)
        );
        assert_eq!(
            enabled_readiness
                .callable
                .map(|callable| callable.descriptor()),
            enabled_readiness.descriptor
        );
        assert_eq!(
            enabled_readiness.descriptor,
            record.disabled_readiness.descriptor
        );
        assert_eq!(
            record.emission_provenance.outcome,
            BaselineMachineCodeEmissionProvenanceOutcome::Accepted
        );
        assert_eq!(
            record.emission_provenance.materialization_ordinal,
            record.materialization.ordinal
        );
        assert_eq!(
            record.emission_provenance.native_entry_readiness_ordinal,
            enabled_readiness.ordinal
        );
        assert_eq!(
            vm.tiering_integration()
                .baseline_machine_code_emission_provenance_records()
                .last(),
            Some(&record.emission_provenance)
        );

        let installed_code_block = vm
            .code_blocks
            .get(owner)
            .expect("registered P6 semantic code block")
            .code_block()
            .clone();
        assert_eq!(
            installed_code_block.entrypoints().baseline_jit(),
            Some(request.slot)
        );
        assert_eq!(
            p6_semantic_install_side_effect_counts(&vm),
            P6SemanticInstallSideEffectCounts {
                materializations: before.materializations + 1,
                platform_residencies: before.platform_residencies + 1,
                installs: before.installs + 1,
                readiness: before.readiness + 2,
                provenance: before.provenance + 1,
            }
        );
    }

