    #[cfg(unix)]
    #[test]
    fn vm_retained_return_table_preserves_x86_single_native_reentry_target_metadata() {
        let code_block = linked_p6_test_code_block_with_parameters(
            vec![
                typed_core_instruction_with_operands(
                    0,
                    CoreOpcode::LoadInt32,
                    vec![Operand::Register(local(0)), Operand::SignedImmediate(99)],
                ),
                typed_core_instruction_with_operands(
                    1,
                    CoreOpcode::ToNumber,
                    vec![
                        Operand::Register(local(0)),
                        Operand::Register(argument_including_this(1)),
                    ],
                ),
                typed_core_instruction_with_operands(
                    2,
                    CoreOpcode::Return,
                    vec![Operand::Register(local(0))],
                ),
            ],
            2,
        );
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let owner = register_test_code_block(&mut vm, code_block);
        let record = vm
            .install_p6_x86_64_callable_semantic_baseline_native_entry(p6_semantic_install_request(
                owner, 745,
            ))
            .expect("accepted x86 callable side-exit install");
        let readiness = record
            .enabled_readiness
            .as_ref()
            .expect("callable install records enabled readiness");
        let stub = record
            .semantic_emission
            .side_exit_return_stubs
            .iter()
            .find(|stub| {
                stub.bytecode_index == BytecodeIndex::from_offset(1)
                    && stub.reason
                        == P6X86_64BaselineSelectedSideExitReason::UnsupportedToNumberOperand
            })
            .expect("x86 single-resume side-exit stub");
        assert_eq!(
            stub.resume_bytecode_index,
            Some(BytecodeIndex::from_offset(2))
        );
        assert!(stub.resume_entry_offset.is_some());
        assert_eq!(
            stub.native_reentry_targets,
            vec![P6BaselineNativeReentryTargetRecord {
                resume_bytecode_index: stub.resume_bytecode_index.unwrap(),
                resume_entry_offset: stub.resume_entry_offset.unwrap(),
            }]
        );

        let table = vm
            .p6_x86_64_callable_retained_return_tables
            .iter()
            .find(|table| table.owner == owner && table.readiness_ordinal == readiness.ordinal)
            .expect("retained x86 side-exit table");
        let site = table
            .side_exit_sites
            .iter()
            .find(|site| site.encoded_payload == stub.encoded_payload)
            .expect("retained x86 side-exit site");
        assert_eq!(site.resume_bytecode_index, stub.resume_bytecode_index);
        assert_eq!(site.resume_entry_offset, stub.resume_entry_offset);
        assert_eq!(site.native_reentry_targets, stub.native_reentry_targets);
    }

    #[cfg(unix)]
    #[test]
    fn vm_retained_return_table_preserves_arm64_dormant_jump_if_false_native_reentry_targets() {
        let code_block = p8b_jump_if_false_code_block(P8bTruthinessSource::Bool(false));
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let owner = register_test_code_block(&mut vm, code_block.clone());
        let record = vm
            .install_p6_x86_64_callable_semantic_baseline_native_entry(p6_semantic_install_request(
                owner, 746,
            ))
            .expect("accepted callable install for retained table shell");
        let readiness = record
            .enabled_readiness
            .as_ref()
            .expect("callable install records enabled readiness");
        let backedge_safepoints = p14_x86_64_backedge_safepoint_authorities_for_code_block(
            owner,
            record.eligibility_proof.bytecode_snapshot_fingerprint(),
            &code_block,
        );
        let lowering = plan_p6_x86_64_baseline_lowering(
            P6X86_64BaselineLoweringRequest::new_with_backedge_safepoints(
                owner,
                &code_block,
                record.eligibility_proof.clone(),
                &backedge_safepoints,
            ),
        )
        .expect("JumpIfFalse lowering for dormant ARM64 metadata");
        let backend_contract = record_p6_x86_64_baseline_backend_contract_from_plan(&lowering.plan)
            .expect("x86 semantic contract for dormant ARM64 metadata stand-in");
        let selection = select_p6_x86_64_baseline_instructions(&backend_contract)
            .expect("dormant ARM64 branch-aware selection");
        let arm64_semantic =
            crate::jit::arm64_baseline::emit_p6_arm64_dormant_branch_aware_callable_semantic_bytes_for_test(
                backend_contract,
                selection,
            )
            .expect("dormant ARM64 branch-aware semantic emission");
        assert_eq!(arm64_semantic.side_exit_return_stubs.len(), 1);
        let stub = &arm64_semantic.side_exit_return_stubs[0];
        assert_eq!(stub.bytecode_index, BytecodeIndex::from_offset(1));
        assert_eq!(
            stub.reason,
            P6X86_64BaselineSelectedSideExitReason::UnsupportedTruthinessOperand
        );
        assert_eq!(stub.resume_bytecode_index, None);
        assert_eq!(stub.resume_entry_offset, None);
        assert_eq!(
            stub.native_reentry_targets
                .iter()
                .map(|target| target.resume_bytecode_index)
                .collect::<Vec<_>>(),
            vec![BytecodeIndex::from_offset(4), BytecodeIndex::from_offset(2)]
        );

        vm.retain_p6_x86_64_callable_retained_return_table(
            owner,
            &record.artifact,
            &arm64_semantic,
            None,
            &record.materialization,
            &record.install,
            readiness,
        );
        let table = vm
            .p6_x86_64_callable_retained_return_tables
            .iter()
            .rev()
            .find(|table| table.owner == owner && table.readiness_ordinal == readiness.ordinal)
            .expect("retained ARM64 dormant side-exit table");
        assert_eq!(table.side_exit_sites.len(), 1);
        let site = &table.side_exit_sites[0];
        assert_eq!(site.resume_bytecode_index, None);
        assert_eq!(site.resume_entry_offset, None);
        assert_eq!(site.native_reentry_targets, stub.native_reentry_targets);

        let rejected = p6_arm64_reject_side_exit_reentry_execution(
            BaselineNativeEntryVmExecution::P6SideExitReentry(
                P6CallableSideExitNativeReentryInvocation {
                    entry_offset: site.native_reentry_targets[0].resume_entry_offset,
                },
            ),
        );
        match rejected {
            BaselineNativeEntryVmExecution::Native(ExecutionCompletion::Failed(
                ExecutionError::BaselineGeneratedExecutionRejected,
            )) => {}
            _ => panic!("public ARM64 side-exit reentry guard must remain rejected"),
        }
    }

    #[cfg(all(unix, target_arch = "x86_64"))]
    #[test]
    fn vm_p6_semantic_callable_native_ready_subset_matches_interpreter_matrix() {
        struct NativeReadyCase {
            name: &'static str,
            code_block: CodeBlock,
            expected: ExecutionCompletion,
            expected_opcodes: &'static [CoreOpcode],
        }

        let cases = vec![
            NativeReadyCase {
                name: "undefined move return",
                code_block: linked_p6_test_code_block(vec![
                    typed_core_instruction_with_operands(
                        0,
                        CoreOpcode::LoadUndefined,
                        vec![Operand::Register(local(0))],
                    ),
                    typed_core_instruction_with_operands(
                        1,
                        CoreOpcode::Move,
                        vec![Operand::Register(local(1)), Operand::Register(local(0))],
                    ),
                    typed_core_instruction_with_operands(
                        2,
                        CoreOpcode::Return,
                        vec![Operand::Register(local(1))],
                    ),
                ]),
                expected: ExecutionCompletion::Returned(RuntimeValue::undefined()),
                expected_opcodes: &[
                    CoreOpcode::LoadUndefined,
                    CoreOpcode::Move,
                    CoreOpcode::Return,
                ],
            },
            NativeReadyCase {
                name: "null move return",
                code_block: linked_p6_test_code_block(vec![
                    typed_core_instruction_with_operands(
                        0,
                        CoreOpcode::LoadNull,
                        vec![Operand::Register(local(0))],
                    ),
                    typed_core_instruction_with_operands(
                        1,
                        CoreOpcode::Move,
                        vec![Operand::Register(local(1)), Operand::Register(local(0))],
                    ),
                    typed_core_instruction_with_operands(
                        2,
                        CoreOpcode::Return,
                        vec![Operand::Register(local(1))],
                    ),
                ]),
                expected: ExecutionCompletion::Returned(RuntimeValue::null()),
                expected_opcodes: &[CoreOpcode::LoadNull, CoreOpcode::Move, CoreOpcode::Return],
            },
            NativeReadyCase {
                name: "true move return",
                code_block: linked_p6_test_code_block(vec![
                    typed_core_instruction_with_operands(
                        0,
                        CoreOpcode::LoadBool,
                        vec![Operand::Register(local(0)), Operand::UnsignedImmediate(1)],
                    ),
                    typed_core_instruction_with_operands(
                        1,
                        CoreOpcode::Move,
                        vec![Operand::Register(local(1)), Operand::Register(local(0))],
                    ),
                    typed_core_instruction_with_operands(
                        2,
                        CoreOpcode::Return,
                        vec![Operand::Register(local(1))],
                    ),
                ]),
                expected: ExecutionCompletion::Returned(RuntimeValue::from_bool(true)),
                expected_opcodes: &[CoreOpcode::LoadBool, CoreOpcode::Move, CoreOpcode::Return],
            },
            NativeReadyCase {
                name: "false move return",
                code_block: linked_p6_test_code_block(vec![
                    typed_core_instruction_with_operands(
                        0,
                        CoreOpcode::LoadBool,
                        vec![Operand::Register(local(0)), Operand::UnsignedImmediate(0)],
                    ),
                    typed_core_instruction_with_operands(
                        1,
                        CoreOpcode::Move,
                        vec![Operand::Register(local(1)), Operand::Register(local(0))],
                    ),
                    typed_core_instruction_with_operands(
                        2,
                        CoreOpcode::Return,
                        vec![Operand::Register(local(1))],
                    ),
                ]),
                expected: ExecutionCompletion::Returned(RuntimeValue::from_bool(false)),
                expected_opcodes: &[CoreOpcode::LoadBool, CoreOpcode::Move, CoreOpcode::Return],
            },
            NativeReadyCase {
                name: "int32 move return",
                code_block: linked_p6_test_code_block(vec![
                    typed_core_instruction_with_operands(
                        0,
                        CoreOpcode::LoadInt32,
                        vec![Operand::Register(local(0)), Operand::SignedImmediate(42)],
                    ),
                    typed_core_instruction_with_operands(
                        1,
                        CoreOpcode::Move,
                        vec![Operand::Register(local(1)), Operand::Register(local(0))],
                    ),
                    typed_core_instruction_with_operands(
                        2,
                        CoreOpcode::Return,
                        vec![Operand::Register(local(1))],
                    ),
                ]),
                expected: ExecutionCompletion::Returned(RuntimeValue::from_i32(42)),
                expected_opcodes: &[CoreOpcode::LoadInt32, CoreOpcode::Move, CoreOpcode::Return],
            },
            NativeReadyCase {
                name: "mixed constants before returned int32",
                code_block: linked_p6_test_code_block(vec![
                    typed_core_instruction_with_operands(
                        0,
                        CoreOpcode::LoadUndefined,
                        vec![Operand::Register(local(0))],
                    ),
                    typed_core_instruction_with_operands(
                        1,
                        CoreOpcode::LoadNull,
                        vec![Operand::Register(local(1))],
                    ),
                    typed_core_instruction_with_operands(
                        2,
                        CoreOpcode::LoadBool,
                        vec![Operand::Register(local(2)), Operand::UnsignedImmediate(1)],
                    ),
                    typed_core_instruction_with_operands(
                        3,
                        CoreOpcode::LoadInt32,
                        vec![Operand::Register(local(3)), Operand::SignedImmediate(42)],
                    ),
                    typed_core_instruction_with_operands(
                        4,
                        CoreOpcode::Move,
                        vec![Operand::Register(local(4)), Operand::Register(local(3))],
                    ),
                    typed_core_instruction_with_operands(
                        5,
                        CoreOpcode::Return,
                        vec![Operand::Register(local(4))],
                    ),
                ]),
                expected: ExecutionCompletion::Returned(RuntimeValue::from_i32(42)),
                expected_opcodes: &[
                    CoreOpcode::LoadUndefined,
                    CoreOpcode::LoadNull,
                    CoreOpcode::LoadBool,
                    CoreOpcode::LoadInt32,
                    CoreOpcode::Move,
                    CoreOpcode::Return,
                ],
            },
            NativeReadyCase {
                name: "add int32",
                code_block: linked_p6_test_code_block(vec![
                    typed_core_instruction_with_operands(
                        0,
                        CoreOpcode::LoadInt32,
                        vec![Operand::Register(local(0)), Operand::SignedImmediate(40)],
                    ),
                    typed_core_instruction_with_operands(
                        1,
                        CoreOpcode::LoadInt32,
                        vec![Operand::Register(local(1)), Operand::SignedImmediate(2)],
                    ),
                    typed_core_instruction_with_operands(
                        2,
                        CoreOpcode::AddInt32,
                        vec![
                            Operand::Register(local(2)),
                            Operand::Register(local(0)),
                            Operand::Register(local(1)),
                        ],
                    ),
                    typed_core_instruction_with_operands(
                        3,
                        CoreOpcode::Return,
                        vec![Operand::Register(local(2))],
                    ),
                ]),
                expected: ExecutionCompletion::Returned(RuntimeValue::from_i32(42)),
                expected_opcodes: &[CoreOpcode::AddInt32, CoreOpcode::Return],
            },
            NativeReadyCase {
                name: "sub int32",
                code_block: linked_p6_test_code_block(vec![
                    typed_core_instruction_with_operands(
                        0,
                        CoreOpcode::LoadInt32,
                        vec![Operand::Register(local(0)), Operand::SignedImmediate(50)],
                    ),
                    typed_core_instruction_with_operands(
                        1,
                        CoreOpcode::LoadInt32,
                        vec![Operand::Register(local(1)), Operand::SignedImmediate(8)],
                    ),
                    typed_core_instruction_with_operands(
                        2,
                        CoreOpcode::SubInt32,
                        vec![
                            Operand::Register(local(2)),
                            Operand::Register(local(0)),
                            Operand::Register(local(1)),
                        ],
                    ),
                    typed_core_instruction_with_operands(
                        3,
                        CoreOpcode::Return,
                        vec![Operand::Register(local(2))],
                    ),
                ]),
                expected: ExecutionCompletion::Returned(RuntimeValue::from_i32(42)),
                expected_opcodes: &[CoreOpcode::SubInt32, CoreOpcode::Return],
            },
            NativeReadyCase {
                name: "mul int32",
                code_block: linked_p6_test_code_block(vec![
                    typed_core_instruction_with_operands(
                        0,
                        CoreOpcode::LoadInt32,
                        vec![Operand::Register(local(0)), Operand::SignedImmediate(6)],
                    ),
                    typed_core_instruction_with_operands(
                        1,
                        CoreOpcode::LoadInt32,
                        vec![Operand::Register(local(1)), Operand::SignedImmediate(7)],
                    ),
                    typed_core_instruction_with_operands(
                        2,
                        CoreOpcode::MulInt32,
                        vec![
                            Operand::Register(local(2)),
                            Operand::Register(local(0)),
                            Operand::Register(local(1)),
                        ],
                    ),
                    typed_core_instruction_with_operands(
                        3,
                        CoreOpcode::Return,
                        vec![Operand::Register(local(2))],
                    ),
                ]),
                expected: ExecutionCompletion::Returned(RuntimeValue::from_i32(42)),
                expected_opcodes: &[CoreOpcode::MulInt32, CoreOpcode::Return],
            },
        ];

        for (case_index, case) in cases.into_iter().enumerate() {
            assert_code_block_contains_core_opcodes(&case.code_block, case.expected_opcodes);
            let expected = execute_interpreter_registered_code_block(&case.code_block, Vec::new());
            assert_eq!(expected, case.expected, "{}", case.name);

            let mut vm = Vm::new(VmConfig::baseline_allowed());
            let owner = register_test_code_block(&mut vm, case.code_block.clone());
            let record = vm
                .install_p6_x86_64_callable_semantic_baseline_native_entry(
                    p6_semantic_install_request(owner, 780 + case_index as u64),
                )
                .expect("accepted P6 callable semantic install");
            let readiness_ordinal = assert_p6_callable_emitted_readiness(&record);
            let fallback_count_before = vm.tiering_integration().fallback_records().len();
            let launch_descriptor_count_before = vm.entry_state().launch_descriptors().len();
            let mut host = InterpreterDispatchMustNotRun;

            let completion = execute_registered_code_block_with_host(
                &mut vm,
                owner,
                &case.code_block,
                &mut host,
            );

            assert_eq!(completion, expected, "{}", case.name);
            assert_eq!(
                vm.tiering_integration().fallback_records().len(),
                fallback_count_before,
                "{}",
                case.name
            );
            assert_latest_p6_callable_native_completion(
                &vm,
                owner,
                readiness_ordinal,
                launch_descriptor_count_before,
            );
        }
    }

