        let table = vm
            .p6_x86_64_callable_retained_return_tables
            .iter_mut()
            .find(|table| table.owner == owner && table.readiness_ordinal == readiness.ordinal)
            .expect("P14 retained return table");
        table.loop_backedge_sites[0].target_instruction_offset =
            record.semantic_emission.linked_image.output_size_bytes;
        let profile_count_before = vm.tiering_integration().profile_records().len();
