    #[test]
    fn vm_p6_semantic_install_rejects_root_maps_handlers_and_stale_proof_before_materialization() {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let owner = vm.allocate_code_block_cell().unwrap();
        let root_mapped = p6_int32_arithmetic_code_block().with_side_tables(LinkedSideTables {
            root_maps: vec![runtime_helper_root_map(
                owner,
                BytecodeIndex::from_offset(0),
                BytecodeRootMapId(42),
            )],
            ..LinkedSideTables::default()
        });
        vm.code_blocks.register(owner, root_mapped);
        let request = p6_semantic_install_request(owner, 750);
        let before = p6_semantic_install_side_effect_counts(&vm);
        let error = vm
            .install_p6_x86_64_semantic_baseline_native_entry(request)
            .expect_err("root maps reject P6 semantic install");
        assert!(matches!(
            error,
            P6X86_64SemanticBaselineNativeEntryInstallError::EligibilityProof { .. }
                | P6X86_64SemanticBaselineNativeEntryInstallError::Lowering { .. }
        ));
        assert_p6_semantic_install_rejected_without_side_effects(&vm, owner, request.slot, before);

        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let owner = vm.allocate_code_block_cell().unwrap();
        let start = BytecodeIndex::from_offset(0);
        let end = BytecodeIndex::from_offset(1);
        let handler_mapped = p6_int32_arithmetic_code_block().with_side_tables(LinkedSideTables {
            handlers: vec![HandlerInfo {
                range: HandlerRange::Bytecode(BytecodeRange { start, end }),
                target: HandlerTarget::Bytecode(end),
                kind: HandlerKind::Catch,
            }],
            ..LinkedSideTables::default()
        });
        vm.code_blocks.register(owner, handler_mapped);
        let request = p6_semantic_install_request(owner, 751);
        let before = p6_semantic_install_side_effect_counts(&vm);
        let error = vm
            .install_p6_x86_64_semantic_baseline_native_entry(request)
            .expect_err("handlers reject P6 semantic install");
        assert!(matches!(
            error,
            P6X86_64SemanticBaselineNativeEntryInstallError::EligibilityProof { .. }
                | P6X86_64SemanticBaselineNativeEntryInstallError::Lowering { .. }
        ));
        assert_p6_semantic_install_rejected_without_side_effects(&vm, owner, request.slot, before);

        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let owner = register_test_code_block(&mut vm, p6_int32_arithmetic_code_block());
        let request = p6_semantic_install_request(owner, 752);
        let before = p6_semantic_install_side_effect_counts(&vm);
        let error = vm
            .install_p6_x86_64_semantic_baseline_native_entry_for_test(
                request,
                P6X86_64SemanticBaselineNativeEntryReadinessMode::DisabledOnly,
                P6X86_64SemanticBaselineNativeEntryInstallMode::ReplaceCurrentCodeBlockBeforeMaterializationForTest(
                    Box::new(linked_interpreter_test_code_block_with_opcodes(
                        CodeBlockLifecycleState::LinkedInterpreter,
                        &[CoreOpcode::LoadInt32, CoreOpcode::Return, CoreOpcode::Return],
                    )),
                ),
            )
            .expect_err("stale P6 semantic proof rejects before materialization");
        assert!(matches!(
            error,
            P6X86_64SemanticBaselineNativeEntryInstallError::CurrentCodeBlockSnapshotMismatch { .. }
        ));
        assert_p6_semantic_install_rejected_without_side_effects(&vm, owner, request.slot, before);
    }

