    #[cfg(unix)]
    #[test]
    fn vm_p15_auto_installs_generated_entry_when_emitted_native_is_not_host_callable() {
        let code_block = p6_int32_arithmetic_code_block();
        let expected = execute_interpreter_registered_code_block(&code_block, Vec::new());
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let owner = register_test_code_block(&mut vm, code_block.clone());
        let counts_before = p6_semantic_install_side_effect_counts(&vm);
        let generated_artifact_count_before = vm
            .tiering_integration()
            .baseline_generated_code_artifacts()
            .len();
        let launch_descriptor_count_before = vm.entry_state().launch_descriptors().len();
        let mut host = InterpreterDispatchMustNotRun;

        let completion =
            execute_registered_code_block_with_host(&mut vm, owner, &code_block, &mut host);

        assert_eq!(completion, expected);
        assert!(vm.tiering_integration().fallback_records().is_empty());
        assert_eq!(
            p6_semantic_install_side_effect_counts(&vm),
            P6SemanticInstallSideEffectCounts {
                materializations: counts_before.materializations + 1,
                platform_residencies: counts_before.platform_residencies + 1,
                installs: counts_before.installs + 1,
                readiness: counts_before.readiness + 2,
                provenance: counts_before.provenance + 1,
            }
        );
        let [auto_record] = vm
            .tiering_integration()
            .baseline_entry_auto_materializations()
        else {
            panic!(
                "expected exactly one auto materialization, found {}",
                vm.tiering_integration()
                    .baseline_entry_auto_materializations()
                    .len()
            );
        };
        assert_eq!(auto_record.owner, owner);
        assert_eq!(
            auto_record.native,
            BaselineEntryAutoNativeMaterializationOutcome::Installed
        );
        let [entry_decision] = vm.tiering_integration().entry_decisions() else {
            panic!(
                "expected exactly one committed P15 entry decision, found {}",
                vm.tiering_integration().entry_decisions().len()
            );
        };

        if vm.can_execute_p6_x86_64_emitted_native_entry() {
            assert_eq!(auto_record.generated, None);
            assert_eq!(
                vm.tiering_integration()
                    .baseline_generated_code_artifacts()
                    .len(),
                generated_artifact_count_before
            );
            assert_eq!(
                entry_decision.decision,
                TierEntryDecision::EnterNative {
                    tier: JitType::Baseline
                }
            );
            assert_eq!(
                entry_decision
                    .baseline_entry_gate
                    .as_ref()
                    .map(|gate| gate.outcome),
                Some(BaselineEntryGateOutcome::NativeEntryReady)
            );
            assert_eq!(
                entry_decision.execution_path,
                TierEntryExecutionPath::NativeCode(JitType::Baseline)
            );
            assert_eq!(
                vm.entry_state().launch_descriptors().len(),
                launch_descriptor_count_before + 1
            );
        } else {
            assert_eq!(
                auto_record.generated,
                Some(BaselineEntryAutoGeneratedMaterializationOutcome::Installed)
            );
            assert_eq!(
                vm.tiering_integration()
                    .baseline_generated_code_artifacts()
                    .len(),
                generated_artifact_count_before + 1
            );
            assert!(vm
                .tiering_integration()
                .baseline_generated_code_artifacts()
                .iter()
                .any(|artifact| artifact.owner == owner));
            assert_eq!(
                entry_decision.decision,
                TierEntryDecision::EnterOptimized {
                    tier: JitType::Baseline
                }
            );
            assert_eq!(
                entry_decision
                    .baseline_entry_gate
                    .as_ref()
                    .map(|gate| gate.outcome),
                Some(BaselineEntryGateOutcome::Eligible)
            );
            assert_eq!(
                entry_decision.execution_path,
                TierEntryExecutionPath::GeneratedCode(JitType::Baseline)
            );
            assert_eq!(
                vm.entry_state().launch_descriptors().len(),
                launch_descriptor_count_before
            );
        }
        assert_eq!(entry_decision.fallback_record_index, None);
        assert_eq!(vm.gc_execution_state().no_gc_scope_depth(), 0);
        assert_eq!(vm.heap().no_gc_scope_depth(), 0);
    }

