    #[cfg(all(unix, target_arch = "x86_64"))]
    #[test]
    fn vm_p16b_interpreter_call_uses_vm_owned_nested_callee_entry_and_auto_installs_native() {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let (callee_owner, callee_code_block) =
            register_vm_owned_function_code_block(&mut vm, p6_int32_arithmetic_code_block());
        let caller_code_block = ordinary_call_to_function_index_code_block(CoreOpcode::Call);
        let caller_owner = register_test_code_block(&mut vm, caller_code_block.clone());
        let counts_before = p6_semantic_install_side_effect_counts(&vm);
        let mut host =
            RecordingCoreHost::with_function_code_blocks(vec![InterpreterFunctionCodeBlock::new(
                callee_owner,
                callee_code_block,
            )]);

        let completion = execute_registered_code_block_with_host(
            &mut vm,
            caller_owner,
            &caller_code_block,
            &mut host,
        );

        assert_eq!(
            completion,
            ExecutionCompletion::Returned(RuntimeValue::from_i32(42))
        );
        assert_eq!(
            p6_semantic_install_side_effect_counts(&vm),
            P6SemanticInstallSideEffectCounts {
                materializations: counts_before.materializations + 1,
                platform_residencies: counts_before.platform_residencies + 1,
                installs: counts_before.installs + 1,
                readiness: counts_before.readiness + 2,
                provenance: counts_before.provenance + 1,
            }
        );
        let callee_decision = vm
            .tiering_integration()
            .entry_decisions()
            .iter()
            .find(|record| record.owner == callee_owner)
            .expect("callee Function entry decision");
        assert_eq!(callee_decision.entry_kind, ExecutionEntryKind::Function);
        assert_eq!(
            callee_decision.decision,
            TierEntryDecision::EnterNative {
                tier: JitType::Baseline
            }
        );
        let [call_observation] = vm.tiering_integration().call_observations() else {
            panic!(
                "expected one interpreter-origin call observation, found {}",
                vm.tiering_integration().call_observations().len()
            );
        };
        assert_eq!(call_observation.owner, caller_owner);
        assert_eq!(call_observation.opcode, CoreOpcode::Call);
        assert_eq!(
            call_observation.descriptor.target_code_block,
            Some(callee_owner)
        );
        assert_eq!(
            vm.tiering_integration()
                .call_link_boundary_validation_records()
                .len(),
            1
        );
        assert_eq!(
            vm.tiering_integration()
                .call_link_attachment_plan_records()
                .len(),
            1
        );
        assert_eq!(
            vm.tiering_integration()
                .call_link_attachment_install_rechecks()
                .len(),
            1
        );
        assert_eq!(
            vm.tiering_integration()
                .call_link_inline_cache_attachment_records()
                .len(),
            1
        );
        assert!(!host
            .dispatches
            .iter()
            .any(|(_, _, opcode)| *opcode == Some(CoreOpcode::AddInt32)));
        assert_eq!(vm.execution_context_stack().frame_depth(), 0);
        assert_eq!(vm.execution_context_stack().entry_depth(), 0);
        assert_eq!(vm.gc_execution_state().no_gc_scope_depth(), 0);
        assert_eq!(vm.heap().no_gc_scope_depth(), 0);
    }

