    #[test]
    fn vm_p18a_interpreter_construct_uses_vm_owned_nested_construct_entry_and_auto_installs_native()
    {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let function_unlinked = p6_int32_arithmetic_code_block().unlinked().clone();
        let function_blocks = vm
            .install_source_function_blocks(vec![function_unlinked])
            .expect("owned P18a construct function code");
        let construct_owner = function_blocks[0]
            .construct_id
            .expect("construct-specialized code block");
        let caller_code_block = ordinary_construct_to_function_index_code_block();
        let caller_owner = register_test_code_block(&mut vm, caller_code_block.clone());
        let counts_before = p6_semantic_install_side_effect_counts(&vm);
        let mut host = RecordingCoreHost::with_function_code_blocks(function_blocks);

        let completion = execute_registered_code_block_with_host(
            &mut vm,
            caller_owner,
            &caller_code_block,
            &mut host,
        );

        let ExecutionCompletion::Returned(value) = completion else {
            panic!("expected constructed object, got {completion:?}");
        };
        assert!(value.as_cell().is_some());
        assert_ne!(value, RuntimeValue::from_i32(42));
        assert_eq!(
            p6_semantic_install_side_effect_counts(&vm),
            P6SemanticInstallSideEffectCounts {
                materializations: counts_before.materializations + 1,
                platform_residencies: counts_before.platform_residencies + 1,
                installs: counts_before.installs + 1,
                readiness: counts_before.readiness + 2,
                provenance: counts_before.provenance + 1,
            }
        );
        let construct_decision = vm
            .tiering_integration()
            .entry_decisions()
            .iter()
            .find(|record| record.owner == construct_owner)
            .expect("callee Construct entry decision");
        assert_eq!(construct_decision.entry_kind, ExecutionEntryKind::Construct);
        assert_eq!(
            construct_decision.decision,
            TierEntryDecision::EnterNative {
                tier: JitType::Baseline
            }
        );
        assert!(!host
            .dispatches
            .iter()
            .any(|(_, _, opcode)| *opcode == Some(CoreOpcode::AddInt32)));
        assert_eq!(vm.execution_context_stack().frame_depth(), 0);
        assert_eq!(vm.execution_context_stack().entry_depth(), 0);
        assert_eq!(vm.gc_execution_state().no_gc_scope_depth(), 0);
        assert_eq!(vm.heap().no_gc_scope_depth(), 0);
    }

