    #[derive(Clone, Copy, Debug)]
    enum P18ConstructFallbackCase {
        MissingConstructMapping,
        UnregisteredConstructTarget,
        DeadConstructTarget,
        StaleConstructSnapshot,
        CallSpecializedConstructTarget,
    }

    fn p18_construct_fallback_function_entry(
        vm: &mut Vm,
        case: P18ConstructFallbackCase,
    ) -> InterpreterFunctionCodeBlock {
        match case {
            P18ConstructFallbackCase::MissingConstructMapping => {
                let (call_owner, call_code_block) =
                    register_vm_owned_function_code_block(vm, p6_int32_arithmetic_code_block());
                let executable = vm
                    .executables
                    .executable_for_code_block(call_owner)
                    .expect("call executable");
                let construct_owner = vm.allocate_code_block_cell().unwrap();
                let construct_code_block =
                    construct_code_block_for_executable(&call_code_block, executable);
                vm.code_blocks
                    .register(construct_owner, construct_code_block.clone());
                InterpreterFunctionCodeBlock::new(call_owner, call_code_block)
                    .with_construct(construct_owner, construct_code_block)
            }
            P18ConstructFallbackCase::UnregisteredConstructTarget => {
                let (call_owner, call_code_block) =
                    register_vm_owned_function_code_block(vm, p6_int32_arithmetic_code_block());
                let executable = vm
                    .executables
                    .executable_for_code_block(call_owner)
                    .expect("call executable");
                let construct_code_block =
                    construct_code_block_for_executable(&call_code_block, executable);
                InterpreterFunctionCodeBlock::new(call_owner, call_code_block)
                    .with_construct(CodeBlockId(CellId(98_100)), construct_code_block)
            }
            P18ConstructFallbackCase::CallSpecializedConstructTarget => {
                let (call_owner, call_code_block) =
                    register_vm_owned_function_code_block(vm, p6_int32_arithmetic_code_block());
                InterpreterFunctionCodeBlock::new(call_owner, call_code_block.clone())
                    .with_construct(call_owner, call_code_block)
            }
            P18ConstructFallbackCase::DeadConstructTarget => {
                let function_unlinked = p6_int32_arithmetic_code_block().unlinked().clone();
                let mut function_blocks = vm
                    .install_source_function_blocks(vec![function_unlinked])
                    .expect("owned P18a function code");
                let entry = function_blocks.remove(0);
                let construct_owner = entry.construct_id.expect("construct owner");
                vm.heap
                    .invalidate_cell(HeapCellInvalidationRequest {
                        cell: construct_owner.0,
                        reason: CellZapReason::Destruction,
                    })
                    .expect("invalidate construct target");
                entry
            }
            P18ConstructFallbackCase::StaleConstructSnapshot => {
                let function_unlinked = p6_int32_arithmetic_code_block().unlinked().clone();
                let mut function_blocks = vm
                    .install_source_function_blocks(vec![function_unlinked])
                    .expect("owned P18a function code");
                let mut entry = function_blocks.remove(0);
                let construct_code_block = entry
                    .construct_code_block
                    .as_ref()
                    .expect("construct code block");
                let executable = construct_code_block
                    .link_context()
                    .owner_executable
                    .expect("construct executable");
                let stale_body = linked_p6_test_code_block(vec![
                    typed_core_instruction_with_operands(
                        0,
                        CoreOpcode::LoadInt32,
                        vec![Operand::Register(local(0)), Operand::SignedImmediate(7)],
                    ),
                    typed_core_instruction_with_operands(
                        1,
                        CoreOpcode::Return,
                        vec![Operand::Register(local(0))],
                    ),
                ]);
                entry.construct_code_block = Some(Rc::new(construct_code_block_for_executable(
                    &stale_body,
                    executable,
                )));
                entry
            }
        }
    }

    #[test]
    fn vm_p18a_construct_validation_fallbacks_run_direct_without_p15_side_effects() {
        for case in [
            P18ConstructFallbackCase::MissingConstructMapping,
            P18ConstructFallbackCase::UnregisteredConstructTarget,
            P18ConstructFallbackCase::DeadConstructTarget,
            P18ConstructFallbackCase::StaleConstructSnapshot,
            P18ConstructFallbackCase::CallSpecializedConstructTarget,
        ] {
            let mut vm = Vm::new(VmConfig::baseline_allowed());
            let function_entry = p18_construct_fallback_function_entry(&mut vm, case);
            let caller_code_block = ordinary_construct_to_function_index_code_block();
            let caller_owner = register_test_code_block(&mut vm, caller_code_block.clone());
            let counts_before = p6_semantic_install_side_effect_counts(&vm);
            let mut host = RecordingCoreHost::with_function_code_blocks(vec![function_entry]);

            let completion = execute_registered_code_block_with_host(
                &mut vm,
                caller_owner,
                &caller_code_block,
                &mut host,
            );

            let ExecutionCompletion::Returned(value) = completion else {
                panic!("expected fallback constructed object for {case:?}, got {completion:?}");
            };
            assert!(value.as_cell().is_some(), "{case:?}");
            assert_eq!(
                p6_semantic_install_side_effect_counts(&vm),
                counts_before,
                "{case:?} fallback must not auto-install a native entry"
            );
            assert!(
                vm.tiering_integration()
                    .entry_decisions()
                    .iter()
                    .all(|decision| decision.entry_kind != ExecutionEntryKind::Construct),
                "{case:?} fallback must not enter through the VM Construct entry"
            );
            assert!(
                host.dispatches.iter().any(|(_, index, opcode)| {
                    *index == BytecodeIndex::from_offset(0)
                        && *opcode == Some(CoreOpcode::LoadInt32)
                }),
                "{case:?} fallback should preserve direct interpreter body dispatch"
            );
        }
    }

