    #[test]
    fn vm_p17_reflect_apply_throw_preserves_pending_exception_and_cleans_no_gc() {
        let throwing_callee = linked_p6_test_code_block_with_parameters(
            vec![typed_core_instruction_with_operands(
                0,
                CoreOpcode::Throw,
                vec![Operand::Register(argument_including_this(0))],
            )],
            1,
        );
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let (callee_owner, callee_code_block) =
            register_vm_owned_function_code_block(&mut vm, throwing_callee);
        let caller_code_block = p17_reflect_apply_code_block();
        let caller_owner = register_test_code_block(&mut vm, caller_code_block.clone());
        let mut host = RecordingCoreHost::with_function_code_blocks_and_identifier_texts(
            vec![InterpreterFunctionCodeBlock::new(
                callee_owner,
                callee_code_block,
            )],
            p17_function_value_identifier_texts(),
        );

        let completion = execute_registered_code_block_with_host(
            &mut vm,
            caller_owner,
            &caller_code_block,
            &mut host,
        );

        let pending = PendingException {
            value: RuntimeValue::undefined(),
        };
        assert_eq!(completion, ExecutionCompletion::Threw(pending));
        assert_eq!(vm.exception_state().pending(), Some(pending));
        assert_eq!(vm.execution_context_stack().frame_depth(), 0);
        assert_eq!(vm.execution_context_stack().entry_depth(), 0);
        assert_eq!(vm.gc_execution_state().no_gc_scope_depth(), 0);
        assert_eq!(vm.heap().no_gc_scope_depth(), 0);
        assert!(exception_targeted_roots(&vm).is_empty());
    }

