    #[cfg(all(unix, target_arch = "x86_64"))]
    #[test]
    fn vm_p6_semantic_callable_primitive_strict_equality_side_exits_slow_cases() {
        struct StrictEqualitySideExitCase {
            name: &'static str,
            opcode: CoreOpcode,
            left: RuntimeValue,
            right: RuntimeValue,
            expected_value: RuntimeValue,
            operand_index: u32,
            register: VirtualRegister,
            value_kind: ValueKind,
        }

        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let mut setup_host = RecordingCoreHost::with_function_blocks(Vec::new());
        let object = create_empty_object_for_test(&mut vm, &mut setup_host);
        let unknown = RuntimeValue::from_encoded(EncodedJsValue(0xff));
        let cases = vec![
            StrictEqualitySideExitCase {
                name: "left double side exit",
                opcode: CoreOpcode::StrictEqual,
                left: RuntimeValue::from_double(1.0),
                right: RuntimeValue::from_i32(1),
                expected_value: RuntimeValue::from_bool(true),
                operand_index: 1,
                register: argument_including_this(1),
                value_kind: ValueKind::Double,
            },
            StrictEqualitySideExitCase {
                name: "right double side exit",
                opcode: CoreOpcode::StrictNotEqual,
                left: RuntimeValue::from_i32(1),
                right: RuntimeValue::from_double(1.0),
                expected_value: RuntimeValue::from_bool(false),
                operand_index: 2,
                register: argument_including_this(2),
                value_kind: ValueKind::Double,
            },
            StrictEqualitySideExitCase {
                name: "raw unequal cell side exit",
                opcode: CoreOpcode::StrictEqual,
                left: object,
                right: RuntimeValue::from_i32(1),
                expected_value: RuntimeValue::from_bool(false),
                operand_index: 1,
                register: argument_including_this(1),
                value_kind: ValueKind::Cell,
            },
            StrictEqualitySideExitCase {
                name: "unknown side exit",
                opcode: CoreOpcode::StrictEqual,
                left: RuntimeValue::from_i32(1),
                right: unknown,
                expected_value: RuntimeValue::from_bool(false),
                operand_index: 2,
                register: argument_including_this(2),
                value_kind: ValueKind::Unknown,
            },
        ];

        for (case_index, case) in cases.into_iter().enumerate() {
            let code_block = linked_p6_test_code_block_with_parameters(
                vec![
                    typed_core_instruction_with_operands(
                        0,
                        case.opcode,
                        vec![
                            Operand::Register(local(0)),
                            Operand::Register(argument_including_this(1)),
                            Operand::Register(argument_including_this(2)),
                        ],
                    ),
                    typed_core_instruction_with_operands(
                        1,
                        CoreOpcode::Return,
                        vec![Operand::Register(local(0))],
                    ),
                ],
                3,
            );
            let arguments = vec![RuntimeValue::undefined(), case.left, case.right];
            let expected = ExecutionCompletion::Returned(case.expected_value);

            let owner = register_test_code_block(&mut vm, code_block.clone());
            let record = vm
                .install_p6_x86_64_callable_semantic_baseline_native_entry(
                    p6_semantic_install_request(owner, 2_860 + case_index as u64),
                )
                .expect("accepted P6 primitive strict equality callable semantic install");
            assert_eq!(
                record.eligibility_proof.opcode_subset(),
                BaselineSupportedOpcodeSubset::P6ConstantsMovesReturnInt32ArithmeticBitwiseRelationalJumpsPrimitiveTruthinessPrimitiveBoolean
            );
            assert_p6_callable_side_exit_stub(
                &record,
                BytecodeIndex::from_offset(0),
                P6X86_64BaselineSelectedSideExitReason::UnsupportedStrictEqualityOperand,
            );
            let readiness_ordinal = assert_p6_callable_emitted_readiness(&record);
            let fallback_count_before = vm.tiering_integration().fallback_records().len();
            let launch_descriptor_count_before = vm.entry_state().launch_descriptors().len();
            let mut host = RecordingCoreHost::with_function_blocks(Vec::new());

            let completion = execute_registered_code_block_with_host_and_arguments(
                &mut vm,
                owner,
                &code_block,
                &mut host,
                arguments,
            );

            assert_eq!(completion, expected, "{}", case.name);
            assert_eq!(
                host.dispatches.first().map(|dispatch| dispatch.1),
                Some(BytecodeIndex::from_offset(0))
            );
            assert_eq!(
                host.dispatches.first().and_then(|dispatch| dispatch.2),
                Some(case.opcode)
            );
            assert_latest_p6_callable_side_exit_fallback(
                &vm,
                owner,
                fallback_count_before,
                BytecodeIndex::from_offset(0),
                case.opcode,
                Some(
                    GeneratedBaselineFallbackCause::UnsupportedStrictEqualityOperand {
                        operand_index: case.operand_index,
                        register: case.register,
                        value_kind: case.value_kind,
                    },
                ),
            );
            assert_latest_p6_callable_side_exit_decision(
                &vm,
                owner,
                readiness_ordinal,
                launch_descriptor_count_before,
                TierEntryExecutionPath::Interpreter,
            );
        }
    }

    #[cfg(all(unix, target_arch = "x86_64"))]
    #[test]
    fn vm_p6_semantic_callable_primitive_to_number_matches_interpreter_without_fallback() {
        struct ToNumberCase {
            name: &'static str,
            value: RuntimeValue,
        }

        let cases = vec![
            ToNumberCase {
                name: "int32 pass-through",
                value: RuntimeValue::from_i32(-7),
            },
            ToNumberCase {
                name: "double pass-through",
                value: RuntimeValue::from_double(-0.0),
            },
            ToNumberCase {
                name: "true to int32 one",
                value: RuntimeValue::from_bool(true),
            },
            ToNumberCase {
                name: "false to int32 zero",
                value: RuntimeValue::from_bool(false),
            },
            ToNumberCase {
                name: "null to int32 zero",
                value: RuntimeValue::null(),
            },
            ToNumberCase {
                name: "undefined to pure NaN",
                value: RuntimeValue::undefined(),
            },
        ];

        for (case_index, case) in cases.into_iter().enumerate() {
            let code_block = linked_p6_test_code_block_with_parameters(
                vec![
                    typed_core_instruction_with_operands(
                        0,
                        CoreOpcode::ToNumber,
                        vec![
                            Operand::Register(local(0)),
                            Operand::Register(argument_including_this(1)),
                        ],
                    ),
                    typed_core_instruction_with_operands(
                        1,
                        CoreOpcode::Return,
                        vec![Operand::Register(local(0))],
                    ),
                ],
                2,
            );
            let arguments = vec![RuntimeValue::undefined(), case.value];
            let expected =
                execute_interpreter_registered_code_block(&code_block, arguments.clone());

            let mut vm = Vm::new(VmConfig::baseline_allowed());
            let owner = register_test_code_block(&mut vm, code_block.clone());
            let record = vm
                .install_p6_x86_64_callable_semantic_baseline_native_entry(
                    p6_semantic_install_request(owner, 2_840 + case_index as u64),
                )
                .expect("accepted P6 primitive ToNumber callable semantic install");
            assert_eq!(
                record.eligibility_proof.opcode_subset(),
                BaselineSupportedOpcodeSubset::P6ConstantsMovesReturnInt32ArithmeticBitAndOrNoCallLooseEqualityRelationalPrimitiveToNumber
            );
            assert_p6_callable_side_exit_stub(
                &record,
                BytecodeIndex::from_offset(0),
                P6X86_64BaselineSelectedSideExitReason::UnsupportedToNumberOperand,
            );
            let readiness_ordinal = assert_p6_callable_emitted_readiness(&record);
            let fallback_count_before = vm.tiering_integration().fallback_records().len();
            let launch_descriptor_count_before = vm.entry_state().launch_descriptors().len();
            let mut host = InterpreterDispatchMustNotRun;

            let completion = execute_registered_code_block_with_host_and_arguments(
                &mut vm,
                owner,
                &code_block,
                &mut host,
                arguments,
            );

            if completion_returned_double_nan(&expected) {
                assert!(
                    completion_returned_double_nan(&completion),
                    "{} native completion must preserve JSC pure NaN result",
                    case.name
                );
            } else {
                assert_eq!(completion, expected, "{}", case.name);
            }
            assert_eq!(
                vm.tiering_integration().fallback_records().len(),
                fallback_count_before,
                "{}",
                case.name
            );
            assert_latest_p6_callable_native_completion(
                &vm,
                owner,
                readiness_ordinal,
                launch_descriptor_count_before,
            );
        }
    }

    #[cfg(all(unix, target_arch = "x86_64"))]
    #[test]
    fn vm_p6_semantic_callable_primitive_to_number_side_exits_cell_unknown_before_write() {
        let code_block = linked_p6_test_code_block_with_parameters(
            vec![
                typed_core_instruction_with_operands(
                    0,
                    CoreOpcode::LoadInt32,
                    vec![Operand::Register(local(0)), Operand::SignedImmediate(99)],
                ),
                typed_core_instruction_with_operands(
                    1,
                    CoreOpcode::ToNumber,
                    vec![
                        Operand::Register(local(0)),
                        Operand::Register(argument_including_this(1)),
                    ],
                ),
                typed_core_instruction_with_operands(
                    2,
                    CoreOpcode::Return,
                    vec![Operand::Register(local(0))],
                ),
            ],
            2,
        );
        let unsupported = RuntimeValue::from_encoded(EncodedJsValue(0xff));
        let arguments = vec![RuntimeValue::undefined(), unsupported];
        let expected = execute_interpreter_registered_code_block(&code_block, arguments.clone());

        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let owner = register_test_code_block(&mut vm, code_block.clone());
        let record = vm
            .install_p6_x86_64_callable_semantic_baseline_native_entry(p6_semantic_install_request(
                owner, 2_846,
            ))
            .expect("accepted P6 primitive ToNumber callable semantic install");
        assert_eq!(
            record.eligibility_proof.opcode_subset(),
            BaselineSupportedOpcodeSubset::P6ConstantsMovesReturnInt32ArithmeticBitAndOrNoCallLooseEqualityRelationalPrimitiveToNumber
        );
        assert_p6_callable_side_exit_stub(
            &record,
            BytecodeIndex::from_offset(1),
            P6X86_64BaselineSelectedSideExitReason::UnsupportedToNumberOperand,
        );
        let side_exit_stub = record
            .semantic_emission
            .side_exit_return_stubs
            .iter()
            .find(|stub| stub.bytecode_index == BytecodeIndex::from_offset(1))
            .expect("ToNumber side-exit return stub");
        assert_eq!(
            side_exit_stub.resume_bytecode_index,
            Some(BytecodeIndex::from_offset(2))
        );
        assert!(side_exit_stub.resume_entry_offset.is_some());
        let readiness_ordinal = assert_p6_callable_emitted_readiness(&record);
        let fallback_count_before = vm.tiering_integration().fallback_records().len();
        let launch_descriptor_count_before = vm.entry_state().launch_descriptors().len();
        let mut host = RecordingCoreHost::with_function_blocks(Vec::new());

        let completion = execute_registered_code_block_with_host_and_arguments(
            &mut vm,
            owner,
            &code_block,
            &mut host,
            arguments,
        );

        assert_eq!(completion, expected);
        assert_eq!(
            host.dispatches
                .iter()
                .map(|(_, index, opcode)| (*index, *opcode))
                .collect::<Vec<_>>(),
            vec![(BytecodeIndex::from_offset(1), Some(CoreOpcode::ToNumber))]
        );
        assert_eq!(
            host.dispatches.first().map(|dispatch| dispatch.1),
            Some(BytecodeIndex::from_offset(1))
        );
        assert_eq!(
            host.dispatches.first().and_then(|dispatch| dispatch.2),
            Some(CoreOpcode::ToNumber)
        );
        assert_latest_p6_callable_side_exit_fallback(
            &vm,
            owner,
            fallback_count_before,
            BytecodeIndex::from_offset(1),
            CoreOpcode::ToNumber,
            Some(
                GeneratedBaselineFallbackCause::UnsupportedPrimitiveNumericCoercionOperand {
                    operand_index: 1,
                    register: argument_including_this(1),
                    value_kind: unsupported.kind(),
                },
            ),
        );
        assert_latest_p6_callable_side_exit_decision(
            &vm,
            owner,
            readiness_ordinal,
            launch_descriptor_count_before,
            TierEntryExecutionPath::Interpreter,
        );
    }

    #[cfg(all(unix, target_arch = "x86_64"))]
    #[test]
    fn vm_p6_semantic_callable_primitive_to_number_string_side_exit_dispatches_once_then_resumes_at_next_pc(
    ) {
        const STRING_LITERAL_KEY: u32 = 90_900;

        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let mut host = RecordingCoreHost::with_function_blocks(Vec::new());
        let string_code_block = linked_p6_test_code_block_with_parameters_and_string_literals(
            vec![
                typed_core_instruction_with_operands(
                    0,
                    CoreOpcode::LoadString,
                    vec![
                        Operand::Register(local(0)),
                        Operand::IdentifierIndex(STRING_LITERAL_KEY),
                    ],
                ),
                typed_core_instruction_with_operands(
                    1,
                    CoreOpcode::Return,
                    vec![Operand::Register(local(0))],
                ),
            ],
            1,
            vec![(STRING_LITERAL_KEY, "21".to_string())],
        );
        let string_owner = register_test_code_block(&mut vm, string_code_block.clone());
        let string_value = match execute_registered_code_block_with_host_and_arguments(
            &mut vm,
            string_owner,
            &string_code_block,
            &mut host,
            vec![RuntimeValue::undefined()],
        ) {
            ExecutionCompletion::Returned(value) => value,
            completion => panic!("expected string setup to return a value, got {completion:?}"),
        };
        host.clear_observations();

        let code_block = linked_p6_test_code_block_with_parameters(
            vec![
                typed_core_instruction_with_operands(
                    0,
                    CoreOpcode::LoadInt32,
                    vec![Operand::Register(local(0)), Operand::SignedImmediate(99)],
                ),
                typed_core_instruction_with_operands(
                    1,
                    CoreOpcode::ToNumber,
                    vec![
                        Operand::Register(local(0)),
                        Operand::Register(argument_including_this(1)),
                    ],
                ),
                typed_core_instruction_with_operands(
                    2,
                    CoreOpcode::AddInt32,
                    vec![
                        Operand::Register(local(2)),
                        Operand::Register(local(0)),
                        Operand::Register(local(0)),
                    ],
                ),
                typed_core_instruction_with_operands(
                    3,
                    CoreOpcode::Return,
                    vec![Operand::Register(local(2))],
                ),
            ],
            2,
        );
        let owner = register_test_code_block(&mut vm, code_block.clone());
        let record = vm
            .install_p6_x86_64_callable_semantic_baseline_native_entry(p6_semantic_install_request(
                owner, 2_847,
            ))
            .expect("accepted P6 primitive ToNumber string side-exit callable semantic install");
        assert_p6_callable_side_exit_stub(
            &record,
            BytecodeIndex::from_offset(1),
            P6X86_64BaselineSelectedSideExitReason::UnsupportedToNumberOperand,
        );
        let readiness_ordinal = assert_p6_callable_emitted_readiness(&record);
        let fallback_count_before = vm.tiering_integration().fallback_records().len();
        let launch_descriptor_count_before = vm.entry_state().launch_descriptors().len();

        let completion = execute_registered_code_block_with_host_and_arguments(
            &mut vm,
            owner,
            &code_block,
            &mut host,
            vec![RuntimeValue::undefined(), string_value],
        );

        assert_eq!(
            completion,
            ExecutionCompletion::Returned(RuntimeValue::from_i32(42))
        );
        assert_eq!(
            host.dispatches
                .iter()
                .map(|(_, index, opcode)| (*index, *opcode))
                .collect::<Vec<_>>(),
            vec![(BytecodeIndex::from_offset(1), Some(CoreOpcode::ToNumber))],
            "ToNumber should be dispatched once before reentering the emitted native continuation at the next bytecode"
        );
        let fallbacks = vm.tiering_integration().fallback_records();
        assert_eq!(fallbacks.len(), fallback_count_before + 1);
        let side_exit_fallback = &fallbacks[fallback_count_before];
        assert_eq!(side_exit_fallback.owner, owner);
        assert_eq!(
            side_exit_fallback.result.bytecode_index,
            Some(BytecodeIndex::from_offset(1))
        );
        assert_eq!(
            side_exit_fallback.generated_baseline,
            Some(GeneratedBaselineFallbackRecord {
                bytecode_index: BytecodeIndex::from_offset(1),
                opcode: GeneratedBaselineFallbackOpcode::Core(CoreOpcode::ToNumber),
                cause: GeneratedBaselineFallbackCause::UnsupportedPrimitiveNumericCoercionOperand {
                    operand_index: 1,
                    register: argument_including_this(1),
                    value_kind: string_value.kind(),
                },
            })
        );
        assert_latest_p6_callable_side_exit_decision(
            &vm,
            owner,
            readiness_ordinal,
            launch_descriptor_count_before,
            TierEntryExecutionPath::NativeCode(JitType::Baseline),
        );
    }

    #[cfg(all(unix, target_arch = "x86_64"))]
    #[test]
    fn vm_p6_semantic_callable_int32_relational_matches_interpreter_for_locals_and_arguments() {
        struct RelationalCase {
            name: &'static str,
            opcode: CoreOpcode,
            code_block: CodeBlock,
            arguments: Vec<RuntimeValue>,
            expected: RuntimeValue,
            comparison_bytecode_index: BytecodeIndex,
        }

        let cases = vec![
            RelationalCase {
                name: "local less than true",
                opcode: CoreOpcode::LessThanInt32,
                code_block: linked_p6_test_code_block(vec![
                    typed_core_instruction_with_operands(
                        0,
                        CoreOpcode::LoadInt32,
                        vec![Operand::Register(local(0)), Operand::SignedImmediate(-3)],
                    ),
                    typed_core_instruction_with_operands(
                        1,
                        CoreOpcode::LoadInt32,
                        vec![Operand::Register(local(1)), Operand::SignedImmediate(7)],
                    ),
                    typed_core_instruction_with_operands(
                        2,
                        CoreOpcode::LessThanInt32,
                        vec![
                            Operand::Register(local(2)),
                            Operand::Register(local(0)),
                            Operand::Register(local(1)),
                        ],
                    ),
                    typed_core_instruction_with_operands(
                        3,
                        CoreOpcode::Return,
                        vec![Operand::Register(local(2))],
                    ),
                ]),
                arguments: Vec::new(),
                expected: RuntimeValue::from_bool(true),
                comparison_bytecode_index: BytecodeIndex::from_offset(2),
            },
            RelationalCase {
                name: "local less equal false",
                opcode: CoreOpcode::LessEqualInt32,
                code_block: linked_p6_test_code_block(vec![
                    typed_core_instruction_with_operands(
                        0,
                        CoreOpcode::LoadInt32,
                        vec![Operand::Register(local(0)), Operand::SignedImmediate(8)],
                    ),
                    typed_core_instruction_with_operands(
                        1,
                        CoreOpcode::LoadInt32,
                        vec![Operand::Register(local(1)), Operand::SignedImmediate(3)],
                    ),
                    typed_core_instruction_with_operands(
                        2,
                        CoreOpcode::LessEqualInt32,
                        vec![
                            Operand::Register(local(2)),
                            Operand::Register(local(0)),
                            Operand::Register(local(1)),
                        ],
                    ),
                    typed_core_instruction_with_operands(
                        3,
                        CoreOpcode::Return,
                        vec![Operand::Register(local(2))],
                    ),
                ]),
                arguments: Vec::new(),
                expected: RuntimeValue::from_bool(false),
                comparison_bytecode_index: BytecodeIndex::from_offset(2),
            },
            RelationalCase {
                name: "local greater than true",
                opcode: CoreOpcode::GreaterThanInt32,
                code_block: linked_p6_test_code_block(vec![
                    typed_core_instruction_with_operands(
                        0,
                        CoreOpcode::LoadInt32,
                        vec![Operand::Register(local(0)), Operand::SignedImmediate(9)],
                    ),
                    typed_core_instruction_with_operands(
                        1,
                        CoreOpcode::LoadInt32,
                        vec![Operand::Register(local(1)), Operand::SignedImmediate(-2)],
                    ),
                    typed_core_instruction_with_operands(
                        2,
                        CoreOpcode::GreaterThanInt32,
                        vec![
                            Operand::Register(local(2)),
                            Operand::Register(local(0)),
                            Operand::Register(local(1)),
                        ],
                    ),
                    typed_core_instruction_with_operands(
                        3,
                        CoreOpcode::Return,
                        vec![Operand::Register(local(2))],
                    ),
                ]),
                arguments: Vec::new(),
                expected: RuntimeValue::from_bool(true),
                comparison_bytecode_index: BytecodeIndex::from_offset(2),
            },
            RelationalCase {
                name: "argument greater equal false",
                opcode: CoreOpcode::GreaterEqualInt32,
                code_block: linked_p6_test_code_block_with_parameters(
                    vec![
                        typed_core_instruction_with_operands(
                            0,
                            CoreOpcode::GreaterEqualInt32,
                            vec![
                                Operand::Register(local(0)),
                                Operand::Register(argument_including_this(1)),
                                Operand::Register(argument_including_this(2)),
                            ],
                        ),
                        typed_core_instruction_with_operands(
                            1,
                            CoreOpcode::Return,
                            vec![Operand::Register(local(0))],
                        ),
                    ],
                    3,
                ),
                arguments: vec![
                    RuntimeValue::undefined(),
                    RuntimeValue::from_i32(2),
                    RuntimeValue::from_i32(5),
                ],
                expected: RuntimeValue::from_bool(false),
                comparison_bytecode_index: BytecodeIndex::from_offset(0),
            },
        ];

        for (case_index, case) in cases.into_iter().enumerate() {
            assert_code_block_contains_core_opcodes(&case.code_block, &[case.opcode]);
            let expected =
                execute_interpreter_registered_code_block(&case.code_block, case.arguments.clone());
            assert_eq!(
                expected,
                ExecutionCompletion::Returned(case.expected),
                "{} interpreter",
                case.name
            );

            let mut vm = Vm::new(VmConfig::baseline_allowed());
            let owner = register_test_code_block(&mut vm, case.code_block.clone());
            let record = vm
                .install_p6_x86_64_callable_semantic_baseline_native_entry(
                    p6_semantic_install_request(owner, 2_820 + case_index as u64),
                )
                .expect("accepted P6 relational callable semantic install");
            assert_eq!(
                record.eligibility_proof.opcode_subset(),
                BaselineSupportedOpcodeSubset::P6ConstantsMovesReturnInt32ArithmeticBitAndOrEqualityRelational
            );
            assert_p6_callable_side_exit_stub(
                &record,
                case.comparison_bytecode_index,
                P6X86_64BaselineSelectedSideExitReason::NonInt32Operand,
            );
            let readiness_ordinal = assert_p6_callable_emitted_readiness(&record);
            let fallback_count_before = vm.tiering_integration().fallback_records().len();
            let launch_descriptor_count_before = vm.entry_state().launch_descriptors().len();
            let mut host = InterpreterDispatchMustNotRun;

            let completion = execute_registered_code_block_with_host_and_arguments(
                &mut vm,
                owner,
                &case.code_block,
                &mut host,
                case.arguments,
            );

            assert_eq!(completion, expected, "{}", case.name);
            assert_eq!(
                vm.tiering_integration().fallback_records().len(),
                fallback_count_before,
                "{}",
                case.name
            );
            assert_latest_p6_callable_native_completion(
                &vm,
                owner,
                readiness_ordinal,
                launch_descriptor_count_before,
            );
        }
    }

