    #[cfg(all(unix, target_arch = "x86_64"))]
    #[test]
    fn vm_p6_semantic_callable_side_exit_matrix_matches_interpreter_at_precise_pc() {
        struct SideExitCase {
            name: &'static str,
            code_block: CodeBlock,
            bytecode_index: BytecodeIndex,
            opcode: CoreOpcode,
            side_exit_reason: P6X86_64BaselineSelectedSideExitReason,
            generated_cause: Option<GeneratedBaselineFallbackCause>,
            expected_execution_path: TierEntryExecutionPath,
        }

        let cases = vec![
            SideExitCase {
                name: "add overflow",
                code_block: linked_p6_test_code_block(vec![
                    typed_core_instruction_with_operands(
                        0,
                        CoreOpcode::LoadInt32,
                        vec![
                            Operand::Register(local(0)),
                            Operand::SignedImmediate(i32::MAX),
                        ],
                    ),
                    typed_core_instruction_with_operands(
                        1,
                        CoreOpcode::LoadInt32,
                        vec![Operand::Register(local(1)), Operand::SignedImmediate(1)],
                    ),
                    typed_core_instruction_with_operands(
                        2,
                        CoreOpcode::AddInt32,
                        vec![
                            Operand::Register(local(2)),
                            Operand::Register(local(0)),
                            Operand::Register(local(1)),
                        ],
                    ),
                    typed_core_instruction_with_operands(
                        3,
                        CoreOpcode::Return,
                        vec![Operand::Register(local(2))],
                    ),
                ]),
                bytecode_index: BytecodeIndex::from_offset(2),
                opcode: CoreOpcode::AddInt32,
                side_exit_reason: P6X86_64BaselineSelectedSideExitReason::Overflow,
                generated_cause: Some(GeneratedBaselineFallbackCause::Int32Overflow),
                expected_execution_path: TierEntryExecutionPath::NativeCode(JitType::Baseline),
            },
            SideExitCase {
                name: "sub overflow",
                code_block: linked_p6_test_code_block(vec![
                    typed_core_instruction_with_operands(
                        0,
                        CoreOpcode::LoadInt32,
                        vec![
                            Operand::Register(local(0)),
                            Operand::SignedImmediate(i32::MIN),
                        ],
                    ),
                    typed_core_instruction_with_operands(
                        1,
                        CoreOpcode::LoadInt32,
                        vec![Operand::Register(local(1)), Operand::SignedImmediate(1)],
                    ),
                    typed_core_instruction_with_operands(
                        2,
                        CoreOpcode::SubInt32,
                        vec![
                            Operand::Register(local(2)),
                            Operand::Register(local(0)),
                            Operand::Register(local(1)),
                        ],
                    ),
                    typed_core_instruction_with_operands(
                        3,
                        CoreOpcode::Return,
                        vec![Operand::Register(local(2))],
                    ),
                ]),
                bytecode_index: BytecodeIndex::from_offset(2),
                opcode: CoreOpcode::SubInt32,
                side_exit_reason: P6X86_64BaselineSelectedSideExitReason::Overflow,
                generated_cause: Some(GeneratedBaselineFallbackCause::Int32Overflow),
                expected_execution_path: TierEntryExecutionPath::NativeCode(JitType::Baseline),
            },
            SideExitCase {
                name: "mul overflow",
                code_block: linked_p6_test_code_block(vec![
                    typed_core_instruction_with_operands(
                        0,
                        CoreOpcode::LoadInt32,
                        vec![
                            Operand::Register(local(0)),
                            Operand::SignedImmediate(46_341),
                        ],
                    ),
                    typed_core_instruction_with_operands(
                        1,
                        CoreOpcode::LoadInt32,
                        vec![
                            Operand::Register(local(1)),
                            Operand::SignedImmediate(46_341),
                        ],
                    ),
                    typed_core_instruction_with_operands(
                        2,
                        CoreOpcode::MulInt32,
                        vec![
                            Operand::Register(local(2)),
                            Operand::Register(local(0)),
                            Operand::Register(local(1)),
                        ],
                    ),
                    typed_core_instruction_with_operands(
                        3,
                        CoreOpcode::Return,
                        vec![Operand::Register(local(2))],
                    ),
                ]),
                bytecode_index: BytecodeIndex::from_offset(2),
                opcode: CoreOpcode::MulInt32,
                side_exit_reason: P6X86_64BaselineSelectedSideExitReason::Overflow,
                generated_cause: Some(GeneratedBaselineFallbackCause::Int32Overflow),
                expected_execution_path: TierEntryExecutionPath::NativeCode(JitType::Baseline),
            },
            SideExitCase {
                name: "non-int32 operand",
                code_block: linked_p6_test_code_block(vec![
                    typed_core_instruction_with_operands(
                        0,
                        CoreOpcode::LoadBool,
                        vec![Operand::Register(local(0)), Operand::UnsignedImmediate(1)],
                    ),
                    typed_core_instruction_with_operands(
                        1,
                        CoreOpcode::LoadInt32,
                        vec![Operand::Register(local(1)), Operand::SignedImmediate(1)],
                    ),
                    typed_core_instruction_with_operands(
                        2,
                        CoreOpcode::AddInt32,
                        vec![
                            Operand::Register(local(2)),
                            Operand::Register(local(0)),
                            Operand::Register(local(1)),
                        ],
                    ),
                    typed_core_instruction_with_operands(
                        3,
                        CoreOpcode::Return,
                        vec![Operand::Register(local(2))],
                    ),
                ]),
                bytecode_index: BytecodeIndex::from_offset(2),
                opcode: CoreOpcode::AddInt32,
                side_exit_reason: P6X86_64BaselineSelectedSideExitReason::NonInt32Operand,
                generated_cause: None,
                expected_execution_path: TierEntryExecutionPath::NativeCode(JitType::Baseline),
            },
            SideExitCase {
                name: "bitand non-int32 operand",
                code_block: linked_p6_test_code_block(vec![
                    typed_core_instruction_with_operands(
                        0,
                        CoreOpcode::LoadInt32,
                        vec![Operand::Register(local(0)), Operand::SignedImmediate(7)],
                    ),
                    typed_core_instruction_with_operands(
                        1,
                        CoreOpcode::LoadUndefined,
                        vec![Operand::Register(local(1))],
                    ),
                    typed_core_instruction_with_operands(
                        2,
                        CoreOpcode::BitAndInt32,
                        vec![
                            Operand::Register(local(2)),
                            Operand::Register(local(0)),
                            Operand::Register(local(1)),
                        ],
                    ),
                    typed_core_instruction_with_operands(
                        3,
                        CoreOpcode::Return,
                        vec![Operand::Register(local(2))],
                    ),
                ]),
                bytecode_index: BytecodeIndex::from_offset(2),
                opcode: CoreOpcode::BitAndInt32,
                side_exit_reason: P6X86_64BaselineSelectedSideExitReason::NonInt32Operand,
                generated_cause: None,
                expected_execution_path: TierEntryExecutionPath::Interpreter,
            },
            SideExitCase {
                name: "right shift non-int32 operand",
                code_block: linked_p6_test_code_block(vec![
                    typed_core_instruction_with_operands(
                        0,
                        CoreOpcode::LoadInt32,
                        vec![Operand::Register(local(0)), Operand::SignedImmediate(-8)],
                    ),
                    typed_core_instruction_with_operands(
                        1,
                        CoreOpcode::LoadUndefined,
                        vec![Operand::Register(local(1))],
                    ),
                    typed_core_instruction_with_operands(
                        2,
                        CoreOpcode::RightShiftInt32,
                        vec![
                            Operand::Register(local(2)),
                            Operand::Register(local(0)),
                            Operand::Register(local(1)),
                        ],
                    ),
                    typed_core_instruction_with_operands(
                        3,
                        CoreOpcode::Return,
                        vec![Operand::Register(local(2))],
                    ),
                ]),
                bytecode_index: BytecodeIndex::from_offset(2),
                opcode: CoreOpcode::RightShiftInt32,
                side_exit_reason: P6X86_64BaselineSelectedSideExitReason::NonInt32Operand,
                generated_cause: None,
                expected_execution_path: TierEntryExecutionPath::Interpreter,
            },
            SideExitCase {
                name: "equal non-int32 operand",
                code_block: linked_p6_test_code_block(vec![
                    typed_core_instruction_with_operands(
                        0,
                        CoreOpcode::LoadBool,
                        vec![Operand::Register(local(0)), Operand::UnsignedImmediate(1)],
                    ),
                    typed_core_instruction_with_operands(
                        1,
                        CoreOpcode::LoadInt32,
                        vec![Operand::Register(local(1)), Operand::SignedImmediate(1)],
                    ),
                    typed_core_instruction_with_operands(
                        2,
                        CoreOpcode::Equal,
                        vec![
                            Operand::Register(local(2)),
                            Operand::Register(local(0)),
                            Operand::Register(local(1)),
                        ],
                    ),
                    typed_core_instruction_with_operands(
                        3,
                        CoreOpcode::Return,
                        vec![Operand::Register(local(2))],
                    ),
                ]),
                bytecode_index: BytecodeIndex::from_offset(2),
                opcode: CoreOpcode::Equal,
                side_exit_reason: P6X86_64BaselineSelectedSideExitReason::NonInt32Operand,
                generated_cause: None,
                expected_execution_path: TierEntryExecutionPath::Interpreter,
            },
            SideExitCase {
                name: "relational non-int32 operand",
                code_block: linked_p6_test_code_block(vec![
                    typed_core_instruction_with_operands(
                        0,
                        CoreOpcode::LoadUndefined,
                        vec![Operand::Register(local(0))],
                    ),
                    typed_core_instruction_with_operands(
                        1,
                        CoreOpcode::LoadInt32,
                        vec![Operand::Register(local(1)), Operand::SignedImmediate(1)],
                    ),
                    typed_core_instruction_with_operands(
                        2,
                        CoreOpcode::LessThanInt32,
                        vec![
                            Operand::Register(local(2)),
                            Operand::Register(local(0)),
                            Operand::Register(local(1)),
                        ],
                    ),
                    typed_core_instruction_with_operands(
                        3,
                        CoreOpcode::Return,
                        vec![Operand::Register(local(2))],
                    ),
                ]),
                bytecode_index: BytecodeIndex::from_offset(2),
                opcode: CoreOpcode::LessThanInt32,
                side_exit_reason: P6X86_64BaselineSelectedSideExitReason::NonInt32Operand,
                generated_cause: None,
                expected_execution_path: TierEntryExecutionPath::Interpreter,
            },
            SideExitCase {
                name: "mul negative zero",
                code_block: linked_p6_test_code_block(vec![
                    typed_core_instruction_with_operands(
                        0,
                        CoreOpcode::LoadInt32,
                        vec![Operand::Register(local(0)), Operand::SignedImmediate(-1)],
                    ),
                    typed_core_instruction_with_operands(
                        1,
                        CoreOpcode::LoadInt32,
                        vec![Operand::Register(local(1)), Operand::SignedImmediate(0)],
                    ),
                    typed_core_instruction_with_operands(
                        2,
                        CoreOpcode::MulInt32,
                        vec![
                            Operand::Register(local(2)),
                            Operand::Register(local(0)),
                            Operand::Register(local(1)),
                        ],
                    ),
                    typed_core_instruction_with_operands(
                        3,
                        CoreOpcode::Return,
                        vec![Operand::Register(local(2))],
                    ),
                ]),
                bytecode_index: BytecodeIndex::from_offset(2),
                opcode: CoreOpcode::MulInt32,
                side_exit_reason: P6X86_64BaselineSelectedSideExitReason::NegativeZero,
                generated_cause: None,
                expected_execution_path: TierEntryExecutionPath::NativeCode(JitType::Baseline),
            },
        ];

        for (case_index, case) in cases.into_iter().enumerate() {
            assert_code_block_contains_core_opcodes(
                &case.code_block,
                &[case.opcode, CoreOpcode::Return],
            );
            let expected = execute_interpreter_registered_code_block(&case.code_block, Vec::new());

            let mut vm = Vm::new(VmConfig::baseline_allowed());
            let owner = register_test_code_block(&mut vm, case.code_block.clone());
            let record = vm
                .install_p6_x86_64_callable_semantic_baseline_native_entry(
                    p6_semantic_install_request(owner, 790 + case_index as u64),
                )
                .expect("accepted P6 callable semantic install");
            let readiness_ordinal = assert_p6_callable_emitted_readiness(&record);
            assert_p6_callable_side_exit_stub(&record, case.bytecode_index, case.side_exit_reason);
            let fallback_count_before = vm.tiering_integration().fallback_records().len();
            let launch_descriptor_count_before = vm.entry_state().launch_descriptors().len();
            let mut host = RecordingCoreHost::with_function_blocks(Vec::new());

            let completion = execute_registered_code_block_with_host(
                &mut vm,
                owner,
                &case.code_block,
                &mut host,
            );

            assert_eq!(completion, expected, "{}", case.name);
            assert_eq!(
                host.dispatches.first().map(|dispatch| dispatch.1),
                Some(case.bytecode_index),
                "{}",
                case.name
            );
            assert_eq!(
                host.dispatches.first().and_then(|dispatch| dispatch.2),
                Some(case.opcode),
                "{}",
                case.name
            );
            assert_latest_p6_callable_side_exit_fallback(
                &vm,
                owner,
                fallback_count_before,
                case.bytecode_index,
                case.opcode,
                case.generated_cause,
            );
            assert_latest_p6_callable_side_exit_decision(
                &vm,
                owner,
                readiness_ordinal,
                launch_descriptor_count_before,
                case.expected_execution_path,
            );
        }
    }

    #[cfg(all(unix, target_arch = "x86_64"))]
    #[test]
    fn vm_p6_semantic_callable_side_exit_payload_resumes_native_continuation_after_precise_pc_dispatch(
    ) {
        let code_block = linked_p6_test_code_block(vec![
            typed_core_instruction_with_operands(
                0,
                CoreOpcode::LoadInt32,
                vec![
                    Operand::Register(local(0)),
                    Operand::SignedImmediate(i32::MAX),
                ],
            ),
            typed_core_instruction_with_operands(
                1,
                CoreOpcode::LoadInt32,
                vec![Operand::Register(local(1)), Operand::SignedImmediate(1)],
            ),
            typed_core_instruction_with_operands(
                2,
                CoreOpcode::AddInt32,
                vec![
                    Operand::Register(local(2)),
                    Operand::Register(local(0)),
                    Operand::Register(local(1)),
                ],
            ),
            typed_core_instruction_with_operands(
                3,
                CoreOpcode::Return,
                vec![Operand::Register(local(2))],
            ),
        ]);
        let expected = execute_interpreter_registered_code_block(&code_block, Vec::new());

        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let owner = register_test_code_block(&mut vm, code_block.clone());
        let record = vm
            .install_p6_x86_64_callable_semantic_baseline_native_entry(p6_semantic_install_request(
                owner, 771,
            ))
            .expect("accepted P6 callable semantic install");
        let enabled_readiness = record
            .enabled_readiness
            .as_ref()
            .expect("callable install records enabled readiness");
        assert_eq!(
            enabled_readiness.callable.map(|callable| callable.kind()),
            Some(BaselineNativeEntryCallableKind::P6X86_64EmittedSemanticCAbiEntry)
        );
        let overflow_stub = record
            .semantic_emission
            .side_exit_return_stubs
            .iter()
            .find(|stub| {
                stub.bytecode_index == BytecodeIndex::from_offset(2)
                    && stub.reason == P6X86_64BaselineSelectedSideExitReason::Overflow
            })
            .expect("overflow side-exit return stub for AddInt32");
        assert_eq!(
            P6X86_64BaselineSideExitReturnPayload::decode(overflow_stub.encoded_payload.raw_bits())
                .map(P6X86_64BaselineSideExitReturnPayload::side_exit_index),
            Some(overflow_stub.side_exit_index)
        );
        let fallback_count_before = vm.tiering_integration().fallback_records().len();
        let mut host = RecordingCoreHost::with_function_blocks(Vec::new());

        let completion =
            execute_registered_code_block_with_host(&mut vm, owner, &code_block, &mut host);

        assert_eq!(completion, expected);
        assert_eq!(
            host.dispatches.first().map(|dispatch| dispatch.1),
            Some(BytecodeIndex::from_offset(2))
        );
        assert_eq!(
            host.dispatches.first().and_then(|dispatch| dispatch.2),
            Some(CoreOpcode::AddInt32)
        );
        assert_eq!(
            vm.tiering_integration().fallback_records().len(),
            fallback_count_before + 1
        );
        let fallback = vm
            .tiering_integration()
            .fallback_records()
            .last()
            .expect("P6 callable side-exit fallback telemetry");
        assert_eq!(
            fallback.result.bytecode_index,
            Some(BytecodeIndex::from_offset(2))
        );
        assert_eq!(
            fallback.generated_baseline,
            Some(GeneratedBaselineFallbackRecord {
                bytecode_index: BytecodeIndex::from_offset(2),
                opcode: GeneratedBaselineFallbackOpcode::Core(CoreOpcode::AddInt32),
                cause: GeneratedBaselineFallbackCause::Int32Overflow,
            })
        );
        let entry_decision = vm
            .tiering_integration()
            .entry_decisions()
            .last()
            .expect("P6 callable side-exit decision");
        assert_eq!(
            entry_decision.decision,
            TierEntryDecision::EnterNative {
                tier: JitType::Baseline
            }
        );
        assert_eq!(
            entry_decision
                .baseline_entry_gate
                .as_ref()
                .and_then(|gate| gate.native_entry_readiness_ordinal),
            Some(enabled_readiness.ordinal)
        );
        assert_eq!(
            vm.tiering_integration()
                .diagnostics()
                .last()
                .expect("P6 callable side-exit diagnostic")
                .execution_path,
            TierEntryExecutionPath::NativeCode(JitType::Baseline)
        );
    }

    #[cfg(all(unix, target_arch = "x86_64"))]
    #[test]
    fn vm_p6_semantic_callable_unmatched_side_exit_payload_rejects_without_generic_replay() {
        let code_block = linked_p6_test_code_block(vec![
            typed_core_instruction_with_operands(
                0,
                CoreOpcode::LoadInt32,
                vec![
                    Operand::Register(local(0)),
                    Operand::SignedImmediate(i32::MAX),
                ],
            ),
            typed_core_instruction_with_operands(
                1,
                CoreOpcode::LoadInt32,
                vec![Operand::Register(local(1)), Operand::SignedImmediate(1)],
            ),
            typed_core_instruction_with_operands(
                2,
                CoreOpcode::AddInt32,
                vec![
                    Operand::Register(local(2)),
                    Operand::Register(local(0)),
                    Operand::Register(local(1)),
                ],
            ),
            typed_core_instruction_with_operands(
                3,
                CoreOpcode::Return,
                vec![Operand::Register(local(2))],
            ),
        ]);
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let owner = register_test_code_block(&mut vm, code_block.clone());
        let record = vm
            .install_p6_x86_64_callable_semantic_baseline_native_entry(p6_semantic_install_request(
                owner, 774,
            ))
            .expect("accepted P6 callable semantic install");
        let enabled_readiness = record
            .enabled_readiness
            .as_ref()
            .expect("callable install records enabled readiness");
        let overflow_stub = record
            .semantic_emission
            .side_exit_return_stubs
            .iter()
            .find(|stub| {
                stub.bytecode_index == BytecodeIndex::from_offset(2)
                    && stub.reason == P6X86_64BaselineSelectedSideExitReason::Overflow
            })
            .expect("overflow side-exit return stub for AddInt32");
        let table = vm
            .p6_x86_64_callable_retained_return_tables
            .iter_mut()
            .find(|table| {
                table.owner == owner && table.readiness_ordinal == enabled_readiness.ordinal
            })
            .expect("retained callable side-exit table");
        let site = table
            .side_exit_sites
            .iter_mut()
            .find(|site| site.encoded_payload == overflow_stub.encoded_payload)
            .expect("retained overflow side-exit site");
        site.encoded_payload =
            P6X86_64BaselineSideExitReturnPayload::encode(site.side_exit_index.saturating_add(100));
        assert_ne!(site.encoded_payload, overflow_stub.encoded_payload);
        let fallback_count_before = vm.tiering_integration().fallback_records().len();
        let mut host = RecordingCoreHost::with_function_blocks(Vec::new());

        let completion =
            execute_registered_code_block_with_host(&mut vm, owner, &code_block, &mut host);

        assert_eq!(
            completion,
            ExecutionCompletion::Failed(ExecutionError::BaselineGeneratedExecutionRejected)
        );
        assert!(
            host.dispatches.is_empty(),
            "unmatched native side-exit return must not replay interpreter bytecode"
        );
        assert_eq!(
            vm.tiering_integration().fallback_records().len(),
            fallback_count_before
        );
        assert_eq!(vm.gc_execution_state().no_gc_scope_depth(), 0);
        assert_eq!(vm.heap().no_gc_scope_depth(), 0);
        assert_eq!(vm.exception_state().pending(), None);
        assert!(exception_targeted_roots(&vm).is_empty());
    }

    #[cfg(all(unix, target_arch = "x86_64"))]
    #[test]
    fn vm_p6_semantic_callable_stale_snapshot_falls_back_without_launch_metadata() {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let (owner, _) =
            register_compiler_produced_program_code_block_with_executable(&mut vm, "42;", 772);
        let record = vm
            .install_p6_x86_64_callable_semantic_baseline_native_entry(p6_semantic_install_request(
                owner, 772,
            ))
            .expect("accepted P6 callable semantic install");
        let enabled_readiness = record
            .enabled_readiness
            .as_ref()
            .expect("callable install records enabled readiness");
        let launch_descriptor_count_before = vm.entry_state().launch_descriptors().len();
        let readiness_count_before = vm
            .tiering_integration()
            .baseline_native_entry_readiness_records()
            .len();
        let code_block_publication_count_before = vm
            .code_blocks
            .get(owner)
            .expect("registered source code block before stale callable attempt")
            .executable_entry_publications()
            .len();
        let executable = vm
            .code_blocks
            .get(owner)
            .expect("registered source code block before stale callable executable lookup")
            .code_block()
            .link_context()
            .owner_executable;
        let executable_publication_count_before = executable.and_then(|executable| {
            vm.executable_registry()
                .script(executable)
                .map(|record| record.publications().len())
        });

        let stale_code_block = compiler_produced_program_code_block("7;", 772);
        let mut host = CoreOpcodeDispatchHost::new();
        let completion =
            execute_registered_code_block_with_host(&mut vm, owner, &stale_code_block, &mut host);

        assert_eq!(
            completion,
            ExecutionCompletion::Returned(RuntimeValue::from_i32(7))
        );
        let entry_decision = vm
            .tiering_integration()
            .entry_decisions()
            .last()
            .expect("stale P6 callable native entry decision");
        assert_eq!(
            entry_decision
                .baseline_entry_gate
                .as_ref()
                .and_then(|gate| gate.native_entry_readiness_ordinal),
            Some(enabled_readiness.ordinal)
        );
        assert_eq!(
            vm.tiering_integration()
                .diagnostics()
                .last()
                .expect("stale P6 callable fallback diagnostic")
                .execution_path,
            TierEntryExecutionPath::Interpreter
        );
        assert_eq!(
            vm.entry_state().launch_descriptors().len(),
            launch_descriptor_count_before
        );
        assert_eq!(
            vm.tiering_integration()
                .baseline_native_entry_readiness_records()
                .len(),
            readiness_count_before
        );
        assert_eq!(
            vm.code_blocks
                .get(owner)
                .expect("registered source code block after stale callable attempt")
                .executable_entry_publications()
                .len(),
            code_block_publication_count_before
        );
        assert_eq!(
            executable.and_then(|executable| {
                vm.executable_registry()
                    .script(executable)
                    .map(|record| record.publications().len())
            }),
            executable_publication_count_before
        );
    }

    #[test]
    fn vm_p6_semantic_descriptor_only_materialization_is_not_callable() {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let owner = register_test_code_block(&mut vm, p6_int32_arithmetic_code_block());
        let artifact = baseline_artifact(owner, 773);
        let link_finalization = baseline_link_finalization_with_byte_evidence(&artifact);
        let executable_residency =
            baseline_executable_residency_with_byte_evidence(&link_finalization);
        let materialization = vm.materialize_baseline_executable_artifact(
            owner,
            &artifact,
            &link_finalization,
            &executable_residency,
        );
        assert_eq!(
            materialization.outcome,
            BaselineExecutableMaterializationOutcome::Accepted
        );
        let install_record = vm.install_baseline_artifact(
            owner,
            artifact,
            Some(&materialization),
            JitCodeSlot(773),
            BaselineInstallDependencyPolicy::Allow,
        );
        assert_eq!(
            install_record.outcome,
            BaselineInstallOutcome::InstalledButEntryDisabled
        );
        let descriptor = install_record
            .artifact
            .expect("installed descriptor-only artifact")
            .validate_native_entry_descriptor()
            .expect("native entry descriptor");
        let readiness =
            vm.tiering
                .record_baseline_native_entry_readiness(BaselineNativeEntryReadinessRequest {
                    owner,
                    materialization: &materialization,
                    install: &install_record,
                    execution_policy: BaselineNativeEntryExecutionPolicy::Enabled,
                    callable: Some(
                        BaselineNativeEntryCallableAuthority::new_p6_x86_64_emitted_semantic_c_abi_entry(
                            descriptor,
                        ),
                    ),
                });
        assert_eq!(
            readiness.outcome,
            BaselineNativeEntryReadinessOutcome::Ready
        );
        assert!(vm.baseline_platform_executable_residencies.is_empty());
        let launch_descriptor_count_before = vm.entry_state().launch_descriptors().len();

        let installed_code_block = vm
            .code_blocks
            .get(owner)
            .expect("registered descriptor-only code block")
            .code_block()
            .clone();
        let mut host = CoreOpcodeDispatchHost::new();
        let completion = execute_registered_code_block_with_host(
            &mut vm,
            owner,
            &installed_code_block,
            &mut host,
        );

        assert_eq!(
            completion,
            ExecutionCompletion::Returned(RuntimeValue::from_i32(42))
        );
        assert_eq!(
            vm.tiering_integration()
                .entry_decisions()
                .last()
                .expect("descriptor-only native entry decision")
                .decision,
            TierEntryDecision::EnterNative {
                tier: JitType::Baseline
            }
        );
        assert_eq!(
            vm.tiering_integration()
                .diagnostics()
                .last()
                .expect("descriptor-only fallback diagnostic")
                .execution_path,
            TierEntryExecutionPath::Interpreter
        );
        assert_eq!(
            vm.entry_state().launch_descriptors().len(),
            launch_descriptor_count_before
        );
    }

    #[test]
    fn vm_baseline_install_uses_generated_entry_after_disabled_native_install() {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let (owner, code_block) =
            register_compiler_produced_program_code_block_with_executable(&mut vm, "42;", 33);
        let artifact = baseline_artifact(owner, 33);
        let link_finalization = baseline_link_finalization(&artifact);
        let executable_residency = baseline_executable_residency(&link_finalization);
        let materialization = vm.materialize_baseline_executable_artifact(
            owner,
            &artifact,
            &link_finalization,
            &executable_residency,
        );
        assert_eq!(
            materialization.outcome,
            BaselineExecutableMaterializationOutcome::Accepted
        );
        assert!(vm.baseline_platform_executable_residencies.is_empty());
        let install_record = vm.install_baseline_artifact(
            owner,
            artifact,
            Some(&materialization),
            JitCodeSlot(33),
            BaselineInstallDependencyPolicy::Allow,
        );
        assert_eq!(
            install_record.outcome,
            BaselineInstallOutcome::InstalledButEntryDisabled
        );
        let readiness = vm
            .tiering_integration()
            .baseline_native_entry_readiness_records()
            .last()
            .expect("native entry readiness after baseline install");
        let readiness_ordinal = readiness.ordinal;
        assert_eq!(
            readiness.outcome,
            BaselineNativeEntryReadinessOutcome::ReadyButExecutionDisabled
        );
        assert_eq!(readiness.install_ordinal, install_record.ordinal);

        let global_object = vm.allocate_global_object_cell().unwrap();
        vm.record_source_global_object(global_object).unwrap();
        let entry = vm
            .execution
            .enter(crate::interpreter::ExecutionEntryRecord::Program(
                ProgramExecutionEntry {
                    code_block: owner,
                    global_object,
                    this_value: RuntimeValue::undefined(),
                },
            ));
        let frame = vm
            .execution
            .push_frame(
                &mut vm.registers,
                FramePushRequest {
                    code_block: Some(owner),
                    callee: None,
                    callee_value: None,
                    lexical_scope: None,
                    shape: code_block.unlinked().frame(),
                    argument_count_including_this: 1,
                    argument_values: Vec::new(),
                    start_bytecode_index: Some(BytecodeIndex::from_offset(0)),
                    return_bytecode_index: None,
                },
            )
            .unwrap();
        let mut host = InterpreterDispatchMustNotRun;
        let launch_descriptor_count_before = vm.entry_state().launch_descriptors().len();
        let fallback_count_before = vm.tiering_integration().fallback_records().len();

        let installed_code_block = vm
            .code_blocks
            .get(owner)
            .expect("registered installed baseline code block")
            .code_block()
            .clone();
        let completion = vm.execute_code_block(
            owner,
            &installed_code_block,
            &mut host,
            DispatchConfig::default(),
        );

        if vm.execution.frame(frame).is_some() {
            vm.execution.pop_frame(&mut vm.registers, frame).unwrap();
        }
        vm.execution.leave(entry).unwrap();
        assert_eq!(
            completion,
            ExecutionCompletion::Returned(RuntimeValue::from_i32(42))
        );
        let entry_decision = vm
            .tiering_integration()
            .entry_decisions()
            .last()
            .expect("entry decision after install");
        assert_eq!(
            entry_decision
                .baseline_entry_gate
                .as_ref()
                .map(|gate| gate.outcome),
            Some(super::tiering::BaselineEntryGateOutcome::Eligible)
        );
        assert_eq!(
            entry_decision
                .baseline_entry_gate
                .as_ref()
                .and_then(|gate| gate.native_entry_readiness_ordinal),
            Some(readiness_ordinal)
        );
        let generated_artifact = entry_decision
            .baseline_entry_gate
            .as_ref()
            .and_then(|gate| gate.generated_artifact.clone())
            .expect("disabled native entry should not suppress generated artifact");
        assert_eq!(generated_artifact.owner, owner);
        assert_eq!(
            entry_decision.decision,
            TierEntryDecision::EnterOptimized {
                tier: JitType::Baseline
            }
        );
        assert_eq!(
            vm.entry_state().launch_descriptors().len(),
            launch_descriptor_count_before
        );
        let registered = vm
            .code_blocks
            .get(owner)
            .expect("registered source code block after generated entry");
        let executable = registered
            .code_block()
            .link_context()
            .owner_executable
            .expect("top-level source code block executable owner");
        let executable_record = vm
            .executable_registry()
            .script(executable)
            .expect("registered top-level source executable");
        assert!(executable_record.publications().is_empty());
        assert!(executable_record
            .executable()
            .base
            .entrypoints
            .call
            .cached_baseline_arity_publication()
            .is_none());
        assert!(executable_record
            .executable()
            .base
            .entrypoints
            .construct
            .cached_baseline_arity_publication()
            .is_none());
        assert!(registered.executable_entry_publications().is_empty());
        assert!(registered
            .executable_entrypoints()
            .call
            .cached_baseline_arity_publication()
            .is_none());
        assert!(registered
            .executable_entrypoints()
            .construct
            .cached_baseline_arity_publication()
            .is_none());
        assert!(vm.baseline_platform_executable_residencies.is_empty());
        assert_eq!(
            entry_decision.execution_path,
            TierEntryExecutionPath::GeneratedCode(JitType::Baseline)
        );
        assert_eq!(
            vm.tiering_integration().fallback_records().len(),
            fallback_count_before
        );
        assert_eq!(
            vm.tiering_integration()
                .diagnostics()
                .last()
                .expect("diagnostic after install")
                .execution_path,
            TierEntryExecutionPath::GeneratedCode(JitType::Baseline)
        );
    }

