    #[test]
    fn vm_native_entry_enabled_stale_bytecode_snapshot_falls_back_to_interpreter() {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let (owner, _) =
            register_compiler_produced_program_code_block_with_executable(&mut vm, "42;", 134);
        let readiness = install_enabled_native_entry(&mut vm, owner, 134);
        assert_eq!(
            readiness.outcome,
            BaselineNativeEntryReadinessOutcome::Ready
        );
        let launch_descriptor_count_before = vm.entry_state().launch_descriptors().len();
        let code_block_publication_count_before = vm
            .code_blocks
            .get(owner)
            .expect("registered source code block before stale attempt")
            .executable_entry_publications()
            .len();
        let executable = vm
            .code_blocks
            .get(owner)
            .expect("registered source code block before stale executable lookup")
            .code_block()
            .link_context()
            .owner_executable;
        let executable_publication_count_before = executable.and_then(|executable| {
            vm.executable_registry()
                .script(executable)
                .map(|record| record.publications().len())
        });

        let stale_code_block = compiler_produced_program_code_block("7;", 134);
        let mut host = CoreOpcodeDispatchHost::new();
        let completion =
            execute_registered_code_block_with_host(&mut vm, owner, &stale_code_block, &mut host);

        assert_eq!(
            completion,
            ExecutionCompletion::Returned(RuntimeValue::from_i32(7))
        );
        let entry_decision = vm
            .tiering_integration()
            .entry_decisions()
            .last()
            .expect("stale native entry decision");
        assert_eq!(
            entry_decision.decision,
            TierEntryDecision::EnterNative {
                tier: JitType::Baseline
            }
        );
        assert_eq!(
            vm.tiering_integration()
                .diagnostics()
                .last()
                .expect("stale fallback diagnostic")
                .execution_path,
            TierEntryExecutionPath::Interpreter
        );
        assert_eq!(
            vm.entry_state().launch_descriptors().len(),
            launch_descriptor_count_before
        );
        assert_eq!(
            vm.code_blocks
                .get(owner)
                .expect("registered source code block after stale attempt")
                .executable_entry_publications()
                .len(),
            code_block_publication_count_before
        );
        assert_eq!(
            executable.and_then(|executable| {
                vm.executable_registry()
                    .script(executable)
                    .map(|record| record.publications().len())
            }),
            executable_publication_count_before
        );
    }

    #[test]
    fn vm_native_entry_disabled_stale_bytecode_snapshot_does_not_publish_launch_metadata() {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let (owner, _) =
            register_compiler_produced_program_code_block_with_executable(&mut vm, "42;", 234);
        let artifact = baseline_artifact(owner, 234);
        let link_finalization = baseline_link_finalization(&artifact);
        let executable_residency = baseline_executable_residency(&link_finalization);
        let materialization = vm.materialize_baseline_executable_artifact(
            owner,
            &artifact,
            &link_finalization,
            &executable_residency,
        );
        assert_eq!(
            materialization.outcome,
            BaselineExecutableMaterializationOutcome::Accepted
        );
        let install_record = vm.install_baseline_artifact(
            owner,
            artifact,
            Some(&materialization),
            JitCodeSlot(234),
            BaselineInstallDependencyPolicy::Allow,
        );
        assert_eq!(
            install_record.outcome,
            BaselineInstallOutcome::InstalledButEntryDisabled
        );
        let readiness = vm
            .tiering_integration()
            .baseline_native_entry_readiness_records()
            .last()
            .expect("disabled native readiness");
        assert_eq!(
            readiness.outcome,
            BaselineNativeEntryReadinessOutcome::ReadyButExecutionDisabled
        );
        assert!(readiness.bytecode_snapshot.is_some());
        let launch_descriptor_count_before = vm.entry_state().launch_descriptors().len();
        let code_block_publication_count_before = vm
            .code_blocks
            .get(owner)
            .expect("registered source code block before stale disabled attempt")
            .executable_entry_publications()
            .len();
        let executable = vm
            .code_blocks
            .get(owner)
            .expect("registered source code block before stale disabled executable lookup")
            .code_block()
            .link_context()
            .owner_executable;
        let executable_publication_count_before = executable.and_then(|executable| {
            vm.executable_registry()
                .script(executable)
                .map(|record| record.publications().len())
        });

        let stale_code_block = compiler_produced_program_code_block("7;", 234);
        let mut host = CoreOpcodeDispatchHost::new();
        let completion =
            execute_registered_code_block_with_host(&mut vm, owner, &stale_code_block, &mut host);

        assert_eq!(
            completion,
            ExecutionCompletion::Returned(RuntimeValue::from_i32(7))
        );
        let entry_decision = vm
            .tiering_integration()
            .entry_decisions()
            .last()
            .expect("stale disabled native entry decision");
        assert_eq!(
            entry_decision.decision,
            TierEntryDecision::FallbackToInterpreter {
                attempted_tier: JitType::Baseline,
                reason: TierEntryFallbackReason::NativeEntryDisabled
            }
        );
        assert_eq!(
            entry_decision
                .baseline_entry_gate
                .as_ref()
                .map(|gate| gate.outcome),
            Some(super::tiering::BaselineEntryGateOutcome::NativeEntryReadyButExecutionDisabled)
        );
        assert_eq!(
            vm.entry_state().launch_descriptors().len(),
            launch_descriptor_count_before
        );
        assert_eq!(
            vm.code_blocks
                .get(owner)
                .expect("registered source code block after stale disabled attempt")
                .executable_entry_publications()
                .len(),
            code_block_publication_count_before
        );
        assert_eq!(
            executable.and_then(|executable| {
                vm.executable_registry()
                    .script(executable)
                    .map(|record| record.publications().len())
            }),
            executable_publication_count_before
        );
    }

