    fn vm_native_entry_shim_fallback_records_telemetry_before_interpreter_fallback() {
        let code_block = linked_p6_test_code_block_with_parameters(
            vec![
                typed_core_instruction_with_operands(
                    0,
                    CoreOpcode::LoadInt32,
                    vec![Operand::Register(local(0)), Operand::SignedImmediate(2)],
                ),
                typed_core_instruction_with_operands(
                    1,
                    CoreOpcode::AddInt32,
                    vec![
                        Operand::Register(local(1)),
                        Operand::Register(argument_including_this(1)),
                        Operand::Register(local(0)),
                    ],
                ),
                typed_core_instruction_with_operands(
                    2,
                    CoreOpcode::Return,
                    vec![Operand::Register(local(1))],
                ),
            ],
            2,
        );
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let owner = register_test_code_block(&mut vm, code_block);
        let readiness = install_enabled_native_entry(&mut vm, owner, 136);
        assert_eq!(
            readiness.outcome,
            BaselineNativeEntryReadinessOutcome::Ready
        );
        let installed_code_block = vm
            .code_blocks
            .get(owner)
            .expect("registered P6 code block")
            .code_block()
            .clone();
        let fallback_count_before = vm.tiering_integration().fallback_records().len();
        let mut host = CoreOpcodeDispatchHost::new();

        let completion = execute_registered_code_block_with_host_and_arguments(
            &mut vm,
            owner,
            &installed_code_block,
            &mut host,
            vec![RuntimeValue::undefined(), RuntimeValue::from_bool(true)],
        );

        assert_eq!(
            completion,
            ExecutionCompletion::Returned(RuntimeValue::from_i32(3))
        );
        assert_latest_generated_fallback(
            &vm,
            owner,
            fallback_count_before,
            BytecodeIndex::from_offset(1),
            CoreOpcode::AddInt32,
            GeneratedBaselineFallbackCause::NonNumberOperand {
                operand_index: 1,
                register: argument_including_this(1),
                value_kind: ValueKind::Boolean,
            },
        );
        assert_eq!(
            vm.tiering_integration()
                .entry_decisions()
                .last()
                .expect("native fallback entry decision")
                .execution_path,
            TierEntryExecutionPath::NativeCode(JitType::Baseline)
        );
        assert_eq!(
            vm.tiering_integration()
                .diagnostics()
                .last()
                .expect("native fallback diagnostic")
                .execution_path,
            TierEntryExecutionPath::Interpreter
        );
    }

