    #[test]
    fn vm_native_launch_metadata_pads_to_code_block_formals() {
        let mut vm = Vm::new(VmConfig::baseline_allowed());
        let owner = CodeBlockId(CellId(990));
        let block = CodeBlock::from_unlinked(
            UnlinkedCodeBlock::new(
                CodeKind::Function,
                PackedInstructionStream::from_typed_placeholder(vec![TypedInstruction {
                    opcode: Opcode::Reserved,
                    width: OperandWidth::Narrow,
                    operands: Vec::new(),
                    schema: None,
                    bytecode_index: Some(BytecodeIndex::from_offset(0)),
                }]),
            )
            .with_frame(RegisterFrameShape {
                num_parameters_including_this: 4,
                num_vars: 0,
                num_callee_locals: 0,
                num_temporaries: 0,
                special: Default::default(),
            }),
            LinkContext::default(),
        );
        let global_object = vm.allocate_global_object_cell().unwrap();
        vm.record_source_global_object(global_object).unwrap();
        let entry = vm
            .execution
            .enter(ExecutionEntryRecord::Program(ProgramExecutionEntry {
                code_block: owner,
                global_object,
                this_value: RuntimeValue::undefined(),
            }));
        let frame = vm
            .execution
            .push_frame(
                &mut vm.registers,
                FramePushRequest {
                    code_block: Some(owner),
                    callee: None,
                    callee_value: None,
                    lexical_scope: None,
                    shape: block.unlinked().frame(),
                    argument_count_including_this: 1,
                    argument_values: Vec::new(),
                    start_bytecode_index: Some(BytecodeIndex::from_offset(0)),
                    return_bytecode_index: None,
                },
            )
            .unwrap();

        let (_scope, call_frame) = vm
            .baseline_native_entry_launch_metadata(
                owner,
                &block,
                crate::interpreter::ExecutionEntryKind::Program,
            )
            .expect("launch metadata");

        assert_eq!(call_frame.argument_count_including_this, 1);
        assert_eq!(call_frame.provided_argument_count, 0);
        assert_eq!(call_frame.padded_argument_count, 4);
        vm.execution.pop_frame(&mut vm.registers, frame).unwrap();
        vm.execution.leave(entry).unwrap();
    }

    #[test]
    fn vm_execute_source_keeps_global_targeted_root_live() {
        let mut vm = Vm::new(VmConfig::baseline_allowed());

        let completion = vm.execute_source(source("42;")).unwrap();

        assert_eq!(
            completion,
            ExecutionCompletion::Returned(RuntimeValue::from_i32(42))
        );
        let plan = vm
            .global_runtime_state()
            .global_root_plan(vm.heap().id())
            .unwrap();
        let [descriptor] = plan.descriptors() else {
            assert_eq!(
                plan.descriptors().len(),
                1,
                "expected one global root descriptor"
            );
            return;
        };
        let record = descriptor.record;
        assert_eq!(record.root.kind, RootKind::ExplicitRoot);
        assert_eq!(record.root.id, global_root_id(descriptor.global));
        assert_eq!(vm.heap().targeted_roots().records(), &[record]);

        let allocation = vm
            .heap()
            .allocation_records()
            .iter()
            .find(|allocation| allocation.response.cell == record.target)
            .expect("global root target allocation");
        assert_eq!(
            allocation.response.metadata.type_info.cell_type,
            CellType::GlobalObject
        );

        assert_eq!(
            vm.heap().root_marking_plan().planned_steps(),
            Ok(vec![RootPlanStep::TargetedPrecise {
                root: record.root,
                target: record.target,
                reason: crate::gc::RootMarkReason::ProtectedValues
            }])
        );
    }

    #[test]
    fn vm_execute_source_keeps_thrown_string_exception_targeted_roots_live() {
        let mut vm = Vm::new(VmConfig::baseline_allowed());

        let completion = vm.execute_source(source("throw \"boom\";")).unwrap();

        let pending = if let ExecutionCompletion::Threw(pending) = completion {
            pending
        } else {
            unreachable!("expected thrown completion, got {completion:?}");
        };
        assert_eq!(vm.exception_state().pending(), Some(pending));
        let plan = vm
            .exception_state()
            .targeted_root_plan(vm.heap())
            .expect("exception targeted root plan");
        assert_eq!(plan.records().len(), 3);
        let exception_roots = exception_targeted_roots(&vm);
        assert_eq!(exception_roots, plan.records());
        assert!(plan
            .records()
            .iter()
            .all(|record| record.root.kind == RootKind::VMRegister));
        assert!(plan
            .records()
            .iter()
            .all(|record| record.target == plan.records()[0].target));

        let steps = vm
            .heap()
            .root_marking_plan()
            .planned_steps()
            .expect("root marking plan");
        for record in plan.records() {
            assert!(steps.contains(&RootPlanStep::TargetedPrecise {
                root: record.root,
                target: record.target,
                reason: RootMarkReason::StrongReferences,
            }));
        }
    }

    #[test]
    fn vm_baseline_fallback_syncs_exception_roots_for_thrown_value() {
        struct ThrowValueHost {
            value: RuntimeValue,
        }

        impl DispatchHost for ThrowValueHost {
            fn dispatch_instruction(
                &mut self,
                _state: &mut DispatchState<'_>,
                _instruction: DispatchInstruction<'_>,
            ) -> DispatchOutcome {
                DispatchOutcome::Throw(self.value)
            }
        }

        let mut vm = Vm::new(VmConfig::default());
        let (_string, value, cell) = heap_bound_string_value(&mut vm.heap, "fallback");
        let code_block_id = vm.allocate_code_block_cell().unwrap();
        let global_object_id = vm.allocate_global_object_cell().unwrap();
        let block = CodeBlock::from_unlinked(
            UnlinkedCodeBlock::new(
                CodeKind::Function,
                PackedInstructionStream::from_typed_placeholder(vec![TypedInstruction {
                    opcode: Opcode::Reserved,
                    width: OperandWidth::Narrow,
                    operands: Vec::new(),
                    schema: None,
                    bytecode_index: Some(BytecodeIndex::from_offset(0)),
                }]),
            )
            .with_frame(RegisterFrameShape {
                num_parameters_including_this: 1,
                num_vars: 1,
                num_callee_locals: 0,
                num_temporaries: 0,
                special: Default::default(),
            }),
            LinkContext::default(),
        );
        vm.execution
            .enter(crate::interpreter::ExecutionEntryRecord::Program(
                ProgramExecutionEntry {
                    code_block: code_block_id,
                    global_object: global_object_id,
                    this_value: RuntimeValue::undefined(),
                },
            ));
        let frame = vm
            .execution
            .push_frame(
                &mut vm.registers,
                FramePushRequest {
                    code_block: Some(code_block_id),
                    callee: None,
                    callee_value: None,
                    lexical_scope: None,
                    shape: block.unlinked().frame(),
                    argument_count_including_this: 1,
                    argument_values: Vec::new(),
                    start_bytecode_index: Some(BytecodeIndex::from_offset(0)),
                    return_bytecode_index: None,
                },
            )
            .unwrap();

        let completion = vm.execute_baseline_fallback(
            BaselineFallbackRequest::new(code_block_id, frame, BytecodeIndex::from_offset(0)),
            &block,
            &mut ThrowValueHost { value },
            DispatchConfig::default(),
        );

        let pending = if let ExecutionCompletion::Threw(pending) = completion {
            pending
        } else {
            unreachable!("expected thrown completion, got {completion:?}");
        };
        assert_eq!(vm.exception_state().pending(), Some(pending));
        assert_eq!(vm.gc_execution_state().no_gc_scope_depth(), 0);
        let plan = vm
            .exception_state()
            .targeted_root_plan(vm.heap())
            .expect("exception targeted root plan");
        assert_eq!(plan.records().len(), 3);
        assert!(plan.records().iter().all(|record| record.target == cell));
        assert_eq!(exception_targeted_roots(&vm), plan.records());
    }

