    #[test]
    fn vm_generated_get_global_lexical_fallback_single_dispatch_resumes_to_call() {
        let mut vm = Vm::new(VmConfig::baseline_allowed());

        let completion = vm
            .execute_source(source("let f = function() { return 41; }; f();"))
            .unwrap();

        assert_eq!(
            completion,
            ExecutionCompletion::Returned(RuntimeValue::from_i32(41))
        );
        let fallback = vm
            .tiering_integration()
            .fallback_records()
            .iter()
            .find(|record| {
                matches!(
                    record.generated_baseline,
                    Some(GeneratedBaselineFallbackRecord {
                        opcode: GeneratedBaselineFallbackOpcode::Core(CoreOpcode::GetGlobalLexical),
                        cause: GeneratedBaselineFallbackCause::UnsupportedOpcode,
                        ..
                    })
                )
            })
            .expect("generated GetGlobalLexical fallback telemetry");
        let summary = vm
            .tiering_integration()
            .baseline_generated_execution_summaries()
            .iter()
            .find(|summary| summary.owner == fallback.owner)
            .expect("generated execution summary for source program");

        assert!(
            summary.js_call_count >= 1,
            "GetGlobalLexical single dispatch should resume generated execution at the following Call"
        );
        assert_eq!(
            vm.tiering_integration().call_observations().len(),
            1,
            "resumed generated call should record the cold call-link observation"
        );
        assert_eq!(
            vm.tiering_integration()
                .call_link_inline_cache_attachment_records()
                .len(),
            1,
            "cold call should attach monomorphic call-link metadata after the resumed generated call"
        );
    }

