    #[test]
    fn vm_global_root_sync_rejects_unknown_targets_without_partial_registration() {
        let mut vm = Vm::new(VmConfig::default());
        let good_global = vm.allocate_global_object_cell().unwrap();
        let fake_global = GlobalObjectId(ObjectId(CellId(99)));

        vm.global_runtime_state_mut()
            .describe_global(GlobalObjectRecord {
                id: good_global,
                object_value: RuntimeValue::undefined(),
                default_structure_epoch: 0,
                script_execution_status: ScriptExecutionStatus::Running,
            })
            .unwrap();
        vm.global_runtime_state_mut()
            .describe_global(GlobalObjectRecord {
                id: fake_global,
                object_value: RuntimeValue::undefined(),
                default_structure_epoch: 0,
                script_execution_status: ScriptExecutionStatus::Running,
            })
            .unwrap();

        assert_eq!(
            vm.sync_global_targeted_roots(),
            Err(HeapIntegrationError::UnknownCell(CellId(99)))
        );
        assert!(vm.heap().targeted_roots().records().is_empty());
    }

