    #[test]
    fn vm_program_entry_global_object_uses_distinct_published_heap_cell() {
        let mut vm = Vm::new(VmConfig::default());
        let code_block_id = vm.allocate_code_block_cell().unwrap();
        let global_object_id = vm.allocate_global_object_cell().unwrap();

        let entry = vm
            .execution
            .enter(ExecutionEntryRecord::Program(ProgramExecutionEntry {
                code_block: code_block_id,
                global_object: global_object_id,
                this_value: RuntimeValue::undefined(),
            }));
        let active = vm.execution.active_entry().expect("active program entry");
        let program = if let ExecutionEntryRecord::Program(program) = &active.record {
            program
        } else {
            unreachable!("expected program entry");
        };
        assert_eq!(program.code_block, code_block_id);
        assert_eq!(program.global_object, global_object_id);
        let GlobalObjectId(ObjectId(global_object_cell)) = program.global_object;
        assert_ne!(global_object_cell, program.code_block.0);

        let allocation = vm
            .heap()
            .allocation_records()
            .iter()
            .find(|record| record.response.cell == global_object_cell)
            .expect("program global object heap allocation");
        assert_eq!(
            allocation.response.metadata.type_info.cell_type,
            CellType::GlobalObject
        );
        assert_eq!(
            allocation.request.metadata.type_info.cell_type,
            CellType::GlobalObject
        );
        assert!(allocation.published);

        vm.execution.leave(entry).unwrap();
    }

    #[test]
    fn vm_source_completion_matches_interpreter_only_and_baseline_allowed_modes() {
        let mut interpreter_vm = Vm::new(VmConfig::interpreter_only());
        let mut baseline_vm = Vm::new(VmConfig::baseline_allowed());
        let text = "6 * 7;";

        let interpreter_completion = interpreter_vm.execute_source(source(text)).unwrap();
        let baseline_completion = baseline_vm.execute_source(source(text)).unwrap();

        assert_eq!(interpreter_completion, baseline_completion);
        assert_eq!(
            baseline_completion,
            ExecutionCompletion::Returned(RuntimeValue::from_i32(42))
        );
        assert!(interpreter_vm
            .tiering_integration()
            .fallback_records()
            .is_empty());
        assert_eq!(
            interpreter_vm.tiering_integration().entry_decisions()[0].decision,
            TierEntryDecision::Interpret {
                reason: TierEntryInterpretReason::PolicyRequiresInterpreter
            }
        );
        assert_eq!(
            interpreter_vm.tiering_integration().entry_decisions()[0].execution_path,
            TierEntryExecutionPath::Interpreter
        );

        let baseline_decision = &baseline_vm.tiering_integration().entry_decisions()[0];
        assert_eq!(baseline_decision.requested_tier, Some(JitType::Baseline));
        if baseline_vm.can_execute_p6_x86_64_emitted_native_entry() {
            assert_eq!(
                baseline_decision.decision,
                TierEntryDecision::EnterNative {
                    tier: JitType::Baseline
                }
            );
        } else {
            assert_eq!(
                baseline_decision.decision,
                TierEntryDecision::EnterOptimized {
                    tier: JitType::Baseline
                }
            );
        }
        assert_host_supported_baseline_source_execution_path(
            &baseline_vm,
            baseline_decision.execution_path,
        );
        assert_host_supported_baseline_source_execution_path(
            &baseline_vm,
            baseline_vm.tiering_integration().diagnostics()[0].execution_path,
        );
        assert!(baseline_vm
            .tiering_integration()
            .fallback_records()
            .is_empty());
    }

