    #[test]
    fn vm_proxy_property_traps_route_through_reflect_operations() {
        let mut vm = Vm::new(VmConfig::default());

        let completion = vm
            .execute_source(source(
                "let target = { value: 10 }; \
                 let proto = { inherited: 40 }; \
                 let replacement = { inherited: 41 }; \
                 let seen = \"\"; \
                 let proxy = new Proxy(target, { \
                     get: function(target, key, receiver) { \
                         seen = seen + \"g\" + key; \
                         return Reflect.get(target, key, receiver) + 1; \
                     }, \
                     set: function(target, key, value, receiver) { \
                         seen = seen + \"s\" + key; \
                         target[key] = value + 2; \
                         return true; \
                     }, \
                     has: function(target, key) { \
                         seen = seen + \"h\" + key; \
                         return key === \"value\" || Reflect.has(target, key); \
                     }, \
                     deleteProperty: function(target, key) { \
                         seen = seen + \"d\" + key; \
                         return Reflect.deleteProperty(target, key); \
                     }, \
                     ownKeys: function(target) { \
                         seen = seen + \"o\"; \
                         return [\"extra\", \"value\"]; \
                     }, \
                     getPrototypeOf: function(target) { \
                         seen = seen + \"p\"; \
                         return proto; \
                     }, \
                     setPrototypeOf: function(target, value) { \
                         seen = seen + \"q\"; \
                         return value === replacement; \
                     } \
                 }); \
                 proxy.value = 20; \
                 let keys = Reflect.ownKeys(proxy); \
                 let read = proxy.value; \
                 let deleted = delete proxy.value; \
                 read === 23 \
                     && Reflect.has(proxy, \"value\") \
                     && deleted \
                     && keys[0] === \"extra\" \
                     && keys[1] === \"value\" \
                     && Reflect.getPrototypeOf(proxy) === proto \
                     && Reflect.setPrototypeOf(proxy, replacement) \
                     && seen === \"svalueogvaluedvaluehvaluepq\";",
            ))
            .unwrap();

        assert_eq!(
            completion,
            ExecutionCompletion::Returned(RuntimeValue::from_bool(true))
        );
    }

    #[test]
    fn vm_proxy_apply_and_revocable_behaviour() {
        let mut vm = Vm::new(VmConfig::default());

        let completion = vm
            .execute_source(source(
                "function add(a, b) { return this.base + a + b; } \
                 let called = 0; \
                 let callable = new Proxy(add, { \
                     apply: function(target, thisArg, argumentsList) { \
                         called = called + 1; \
                         return Reflect.apply(target, { base: thisArg.base + 1 }, argumentsList) + 1; \
                     } \
                 }); \
                 let applied = Reflect.apply(callable, { base: 1 }, [20, 20]); \
                 let direct = callable.call({ base: 2 }, 10, 10); \
                 let pair = Proxy.revocable({ value: 5 }, { \
                     get: function(target, key) { return target[key] + 1; } \
                 }); \
                 let before = pair.proxy.value; \
                 pair.revoke(); \
                 let revoked = false; \
                 try { pair.proxy.value; } catch (error) { revoked = error instanceof TypeError; } \
                 applied === 43 \
                     && direct === 24 \
                     && called === 2 \
                     && before === 6 \
                     && revoked;",
            ))
            .unwrap();

        assert_eq!(
            completion,
            ExecutionCompletion::Returned(RuntimeValue::from_bool(true))
        );
    }

